# v159 : MODULE CAISSE / POINT DE VENTE (POS)
#   Sessions de caisse + ventes + items + paiements.
#   Réutilise stock_items (produits), stock_movements (décrément stock),
#   caisses (solde physique) et caisse_operations (traçabilité).
# ════════════════════════════════════════════════════════════════════
POS_PAYMENT_METHODS = {
    'cash':         '💵 Espèces',
    'mobile_money': '📱 Mobile Money',
    'carte':        '💳 Carte bancaire',
}
try:
    from models import get_db as _gdb_pos
    _pos = _gdb_pos()
    _pos.executescript('''
        CREATE TABLE IF NOT EXISTS caisse_sessions (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            caisse_id INTEGER,
            user_id INTEGER,
            user_name TEXT,
            opening_balance REAL DEFAULT 0,
            closing_balance REAL,
            expected_balance REAL,
            total_ventes REAL DEFAULT 0,
            nb_ventes INTEGER DEFAULT 0,
            status TEXT DEFAULT 'ouverte',
            notes TEXT,
            opened_at TEXT DEFAULT (datetime('now')),
            closed_at TEXT
        );
        CREATE TABLE IF NOT EXISTS ventes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            reference TEXT UNIQUE,
            caisse_session_id INTEGER,
            caisse_id INTEGER,
            client_id INTEGER,
            client_name TEXT,
            total_amount REAL NOT NULL DEFAULT 0,
            payment_method TEXT DEFAULT 'cash',
            amount_paid REAL DEFAULT 0,
            change_due REAL DEFAULT 0,
            status TEXT DEFAULT 'validee',
            created_by INTEGER,
            created_by_name TEXT,
            created_at TEXT DEFAULT (datetime('now')),
            FOREIGN KEY (caisse_session_id) REFERENCES caisse_sessions(id)
        );
        CREATE TABLE IF NOT EXISTS vente_items (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            vente_id INTEGER NOT NULL,
            product_id INTEGER,
            designation TEXT,
            quantity REAL NOT NULL DEFAULT 1,
            unit_price REAL NOT NULL DEFAULT 0,
            line_total REAL NOT NULL DEFAULT 0,
            FOREIGN KEY (vente_id) REFERENCES ventes(id)
        );
        CREATE TABLE IF NOT EXISTS paiements (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            vente_id INTEGER NOT NULL,
            amount REAL NOT NULL,
            method TEXT DEFAULT 'cash',
            created_at TEXT DEFAULT (datetime('now')),
            FOREIGN KEY (vente_id) REFERENCES ventes(id)
        );
        CREATE INDEX IF NOT EXISTS idx_ventes_session ON ventes(caisse_session_id);
        CREATE INDEX IF NOT EXISTS idx_vente_items_vente ON vente_items(vente_id);
        CREATE INDEX IF NOT EXISTS idx_paiements_vente ON paiements(vente_id);
        CREATE INDEX IF NOT EXISTS idx_sessions_user ON caisse_sessions(user_id, status);
        CREATE TABLE IF NOT EXISTS rapport_heures_montants (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            client_name TEXT,
            type_label TEXT,
            montant REAL,
            updated_at TEXT,
            UNIQUE(client_name, type_label)
        );
    ''')
    _pos.commit()
    _flpos = _pos.execute("SELECT value FROM app_settings WHERE key='v159_pos_perms'").fetchone()
    if not _flpos:
        for _r in ('admin', 'caissiere', 'dg', 'directeur', 'comptable', 'comptabilite', 'tresorerie'):
            try:
                if not _pos.execute("SELECT 1 FROM permissions WHERE role=? AND permission='pos_vente'", (_r,)).fetchone():
                    _pos.execute("INSERT INTO permissions (role, permission) VALUES (?, 'pos_vente')", (_r,))
            except: pass
        try: _pos.execute("INSERT OR REPLACE INTO app_settings (key, value, updated_at) VALUES ('v159_pos_perms','1',datetime('now'))")
        except: pass
        _pos.commit()
    _pos.close()
    print("[v159-POS] Tables POS (caisse_sessions/ventes/vente_items/paiements) OK", flush=True)
except Exception as _e:
    print(f"[v159-POS] Migration err : {_e}", flush=True)


def get_user_pending_tasks(user_id, user_role=None):
    """v139 / v141 / v150 : Récupère toutes les tâches en attente d'un utilisateur selon son rôle.
    v141 : Correction des URL → toutes vérifiées contre les routes réelles.
    v150 : Admin ne voit QUE ses tâches personnelles (pas les validations globales DG/RH/Compta)
    pour éviter d'avoir à clôturer des tâches qui ne le concernent pas."""
    from models import get_db as _gdb_pt
    conn = _gdb_pt()
    result = {
        'interventions':     [],
        'projets':           [],
        'notifications':     [],
        'validations':       [],
        'rapports':          [],
        'remontees':         [],
        'devis':             [],
        'commandes':         [],
        'others':            [],
    }
    
    # v150 : Admin n'agit pas comme un acteur métier dans la clôture → 
    # On exclut les validations globales (OV à valider, demandes MG, etc.)
    # qui sont normalement le travail d'un DG/RH ou compta.
    # Admin ne voit que ses propres tâches personnelles : interventions assignées,
    # projets coordonnés, notifications HIGH lues, devis créés par lui, etc.
    is_admin_silent = (user_role == 'admin')
    
    try:
        # 1. Interventions assignées non clôturées
        try:
            # v160 : statuts terminaux RÉELS de l'app = 'livre','terminee' (+ legacy).
            # Avant, 'livre'/'terminee' n'étaient pas exclus → une intervention livrée
            # comptait à vie comme tâche en attente et bloquait la clôture de journée.
            rows = conn.execute("""SELECT id, reference, type, status, scheduled_date, client_name
                FROM interventions
                WHERE technician_id=? AND status NOT IN
                    ('cloturee','annulee','close','termine','terminee','livre','reporte')
                ORDER BY scheduled_date, id LIMIT 50""", (user_id,)).fetchall()
            for r in rows:
                result['interventions'].append({
                    'id': r['id'], 'task_type': 'intervention',
                    'label': f"{r['reference']} — {r['type']} ({r['client_name'] or 'sans client'})",
                    # v141 : /interventions/<id> n'existe pas, on utilise /fiche
                    'link': f"/interventions/{r['id']}/fiche",
                    'status': r['status'], 'date': r['scheduled_date'],
                })
        except: pass
        
        # 2. Projets dont l'utilisateur est coordinateur et non clôturés
        try:
            rows = conn.execute("""SELECT id, reference, title, status, current_step, progress_pct
                FROM wf_projects
                WHERE coordinator_id=? AND status NOT IN ('cloture','annule')
                ORDER BY id DESC LIMIT 30""", (user_id,)).fetchall()
            for r in rows:
                result['projets'].append({
                    'id': r['id'], 'task_type': 'projet',
                    'label': f"{r['reference']} — {r['title']} ({r['progress_pct']}%)",
                    'link': f"/projects/{r['id']}",  # ✅ existe
                    'status': r['status'],
                })
        except: pass
        
        # 3. Notifications importantes non lues (priority high)
        # v147 : Filtrage par module selon le rôle de l'utilisateur
        # Chaque rôle ne voit dans sa clôture journalière que les notifications qui le concernent
        try:
            # Définition des modules pertinents par rôle
            role_modules_map = {
                # Techniciens : interventions, remontées, projets, tech
                'technicien':        ['interventions','remontees','tech','projets','pointage'],
                'tech_chef':         ['interventions','remontees','tech','projets','pointage'],
                'chef_chantier':     ['interventions','remontees','tech','projets','pointage'],
                'centre_technique':  ['interventions','remontees','tech','projets','pointage'],
                'informatique':      ['interventions','remontees','tech','it','pointage'],
                # Comptable : compta, factures, trésorerie, paie
                'comptable':         ['comptabilite','factures','tresorerie','paie','pointage'],
                'comptabilite':      ['comptabilite','factures','tresorerie','paie','pointage'],
                # Caissière : trésorerie, factures (paiements)
                'caissiere':         ['tresorerie','factures','comptabilite','pointage'],
                # Agent recouvreur : factures recouvrement
                'agent_recouvreur':  ['factures','recouvrement','clients','pointage'],
                # Gestion projet : projets, remontées
                'gestionnaire_projet': ['projets','interventions','remontees','clients','devis','pointage'],
                'coordinateur':      ['projets','interventions','remontees','clients','devis','pointage'],
                # Commercial : devis, clients, prospects
                'commercial':        ['devis','clients','prospects','factures','pointage'],
                # MG / Conciergerie
                'moyens_generaux':   ['mg','achats','stock','pointage'],
                'mg':                ['mg','achats','stock','pointage'],
                'conciergerie':      ['conciergerie','mg','pointage'],
                # RH : voit tout RH + tâches sensibles
                'rh':                None,  # None = pas de filtre (tout voir)
                'directrice_rh':     None,
                # DG : voit tout
                'dg':                None,
                'directeur':         None,
                'admin':             None,
            }
            
            allowed_modules = role_modules_map.get(user_role)
            
            if allowed_modules is None:
                # Rôle privilégié → toutes les notifications HIGH
                rows = conn.execute("""SELECT id, title, link, priority, module
                    FROM notifications
                    WHERE user_id=? AND COALESCE(read,0)=0 AND COALESCE(priority,'normal') IN ('high','urgent','critical')
                    ORDER BY id DESC LIMIT 30""", (user_id,)).fetchall()
            else:
                # Rôle filtré → uniquement les notifications des modules pertinents
                placeholders = ','.join(['?'] * len(allowed_modules))
                rows = conn.execute(f"""SELECT id, title, link, priority, module
                    FROM notifications
                    WHERE user_id=? AND COALESCE(read,0)=0 
                          AND COALESCE(priority,'normal') IN ('high','urgent','critical')
                          AND (module IN ({placeholders}) OR module IS NULL OR module = '')
                    ORDER BY id DESC LIMIT 30""", [user_id] + allowed_modules).fetchall()
            
            for r in rows:
                target_link = r['link'] if r['link'] else f"/notifications/read/{r['id']}"
                result['notifications'].append({
                    'id': r['id'], 'task_type': 'notification',
                    'label': f"{r['title']}", 'link': target_link,
                    'priority': r['priority'],
                })
        except: pass
        
        # 4. Validations en attente selon le rôle
        # v150 : Admin n'agit pas sur les validations globales dans la clôture
        if user_role in ('dg', 'directeur') and not is_admin_silent:
            # Ordres de virement à valider
            try:
                rows = conn.execute("""SELECT id, reference, beneficiaire, montant
                    FROM ordres_virement WHERE statut IN ('en_attente_dg','en_attente_validation','attente_dg')
                    ORDER BY id DESC LIMIT 30""").fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'ordre_virement',
                        'label': f"OV {r['reference']} — {r['beneficiaire']} ({r['montant']:,.0f} F)",
                        'link': '/ordres-virement', 'status': 'à valider',
                    })
            except: pass
        
        # v142 / v150 / v152 : Comptabilité — factures à éditer (FRI)
        # v152 : Exclure les factures reportées au lendemain (deadline > today)
        if user_role in ('comptable', 'comptabilite') and not is_admin_silent:
            try:
                today_dt = datetime.now().strftime('%Y-%m-%d')
                rows = conn.execute("""SELECT fri.id, fri.amount, fr.reference as fr_ref, fr.client_name
                    FROM field_report_invoices fri
                    JOIN field_reports fr ON fr.id = fri.field_report_id
                    WHERE fri.status='a_facturer' AND fri.emitted_at IS NULL
                          AND (fri.deadline_edit IS NULL OR fri.deadline_edit <= ?)
                    ORDER BY fri.created_at LIMIT 30""", (today_dt,)).fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'facture_a_editer',
                        'label': f"🧾 Facture à éditer {r['fr_ref']} — {r['client_name']} ({r['amount']:,.0f} XOF)",
                        'link': '/recouvrement/factures-a-editer', 'status': 'à éditer',
                        'priority': 'high',
                    })
            except: pass
            # Acomptes en attente de comptabilisation
            try:
                rows = conn.execute("""SELECT id, reference, montant, libelle
                    FROM caisse_operations WHERE statut='en_attente_compta'
                    ORDER BY id DESC LIMIT 20""").fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'caisse_op',
                        'label': f"Op caisse #{r['id']} — {r['libelle'] or '?'} ({r['montant']:,.0f} F)",
                        'link': '/comptabilite/caisses', 'status': 'à comptabiliser',
                    })
            except: pass
        
        if user_role in ('moyens_generaux', 'mg') and not is_admin_silent:
            # Demandes MG en attente (table achats_demandes)
            try:
                rows = conn.execute("""SELECT id, reference, designation, statut
                    FROM achats_demandes WHERE statut IN ('en_attente','soumise','transmise')
                    ORDER BY id DESC LIMIT 30""").fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'demande_achat',
                        'label': f"Demande {r['reference']} — {r['designation'] or '?'}",
                        # v141 : pas de route détail, on pointe vers la liste achats
                        'link': '/achats', 'status': r['statut'],
                    })
            except: pass
        
        # 5. Remontées non encore traitées (auteur du user)
        try:
            rows = conn.execute("""SELECT id, reference, type_info, priorite, statut
                FROM field_reports
                WHERE auteur_id=? AND statut IN ('recue','en_analyse','en_execution')
                  AND (traiter_le IS NULL OR traiter_le='' OR traiter_le <= date('now','localtime'))
                ORDER BY id DESC LIMIT 20""", (user_id,)).fetchall()
            for r in rows:
                result['remontees'].append({
                    'id': r['id'], 'task_type': 'field_report',
                    'label': f"{r['reference']} — {r['type_info']} ({r['priorite']})",
                    'link': f"/field-reports/{r['id']}",  # ✅ existe
                    'status': r['statut'],
                })
        except: pass
        
        # v142 / v150 / v156 : Coordinateur — remontées non traitées (visibilité globale)
        # v156 : Exclure les remontées 'executee' (passées en décision facturation DG/RH)
        if user_role in ('coordinateur', 'gestionnaire_projet', 'resp_projet') and not is_admin_silent:
            try:
                rows = conn.execute("""SELECT id, reference, type_info, priorite, statut, client_name
                    FROM field_reports
                    WHERE statut IN ('recue','en_analyse','en_execution')
                      AND (traiter_le IS NULL OR traiter_le='' OR traiter_le <= date('now','localtime'))
                    ORDER BY id DESC LIMIT 50""").fetchall()
                # Filtrer pour éviter les doublons avec les remontées de l'auteur
                existing_ids = {r['id'] for r in result['remontees']}
                for r in rows:
                    if r['id'] in existing_ids: continue
                    result['remontees'].append({
                        'id': r['id'], 'task_type': 'field_report_coord',
                        'label': f"📋 {r['reference']} — {r['type_info']} ({r['client_name'] or 'sans client'})",
                        'link': f"/field-reports/{r['id']}",
                        'status': r['statut'],
                        'priority': 'high' if r['priorite'] in ('urgent','critique') else 'medium',
                    })
            except: pass
        
        # 6. Devis non envoyés ou en cours
        if user_role in ('commercial', 'dg', 'coordinateur') and not is_admin_silent:
            try:
                rows = conn.execute("""SELECT id, reference, client_name, total_ttc, status
                    FROM devis WHERE created_by=? AND status IN ('brouillon','envoye','en_negociation')
                    ORDER BY id DESC LIMIT 20""", (user_id,)).fetchall()
                for r in rows:
                    result['devis'].append({
                        'id': r['id'], 'task_type': 'devis',
                        'label': f"{r['reference']} — {r['client_name']} ({r['total_ttc']:,.0f} F)",
                        # v141 : /devis/<id> n'existe pas, on utilise /devis/edit/<id>
                        'link': f"/devis/edit/{r['id']}",
                        'status': r['status'],
                    })
            except: pass
        
        # v157 : Visites à traiter par le commercial (pour faire un proforma)
        if user_role in ('commercial', 'dg') and not is_admin_silent:
            try:
                rows = conn.execute("""SELECT id, client_name, visit_date, site_name
                    FROM visit_reports
                    WHERE (proforma_ref IS NULL OR proforma_ref = '')
                          AND COALESCE(status, 'pending') != 'classee'
                    ORDER BY id DESC LIMIT 20""").fetchall()
                for r in rows:
                    result['others'].append({
                        'id': r['id'], 'task_type': 'visite',
                        'label': f"📋 Visite à traiter : {r['client_name']} — {r['site_name'] or 'site'} ({r['visit_date'] or '?'})",
                        'link': f"/visites/{r['id']}", 'status': 'à transformer en proforma',
                        'priority': 'high',
                    })
            except Exception as _e: print(f"[v157] visites pending err : {_e}", flush=True)
            
            # v157 : Remontées de type "nouveau projet" à transformer en devis
            try:
                rows = conn.execute("""SELECT id, reference, type_info, client_name, description
                    FROM field_reports
                    WHERE LOWER(COALESCE(type_info,'')) LIKE '%nouveau%projet%'
                          OR LOWER(COALESCE(type_info,'')) LIKE '%nouveau_projet%'
                          OR LOWER(COALESCE(type_info,'')) LIKE '%installation%'
                          OR LOWER(COALESCE(type_info,'')) LIKE '%projet neuf%'
                    AND statut IN ('recue','en_analyse')
                    ORDER BY id DESC LIMIT 15""").fetchall()
                for r in rows:
                    result['others'].append({
                        'id': r['id'], 'task_type': 'remontee_projet',
                        'label': f"🎯 Nouveau projet à traiter : {r['reference']} — {r['client_name']}",
                        'link': f"/field-reports/{r['id']}", 'status': 'à transformer en devis',
                        'priority': 'high',
                    })
            except Exception as _e: print(f"[v157] remontees projet err : {_e}", flush=True)
        
        # v142 / v150 : Agent recouvreur — factures à envoyer/déposer
        if user_role == 'agent_recouvreur' and not is_admin_silent:
            try:
                rows = conn.execute("""SELECT id, invoice_number, amount FROM field_report_invoices
                    WHERE status IN ('facture_editee','en_recouvrement')
                    ORDER BY emitted_at LIMIT 30""").fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'facture_recouvrement',
                        'label': f"📤 Facture {r['invoice_number'] or '#'+str(r['id'])} à recouvrer ({r['amount']:,.0f} XOF)",
                        'link': '/recouvrement', 'status': 'à envoyer',
                        'priority': 'high',
                    })
            except: pass
        
        # v142 / v150 : Caissière — paiements en attente de validation
        if user_role == 'caissiere' and not is_admin_silent:
            try:
                rows = conn.execute("""SELECT id, invoice_number, amount FROM field_report_invoices
                    WHERE status='caisse_choisie'
                    ORDER BY recovery_sent_at LIMIT 30""").fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'paiement_caisse',
                        'label': f"💵 Paiement {r['invoice_number'] or '#'+str(r['id'])} à valider ({r['amount']:,.0f} XOF)",
                        'link': '/caissiere/paiements', 'status': 'à encaisser',
                        'priority': 'high',
                    })
            except: pass
        
        # v142 : DG/RH — décisions de facturation en attente
        if user_role in ('dg', 'directeur', 'rh', 'directrice_rh', 'admin'):
            try:
                rows = conn.execute("""SELECT id, reference, client_name FROM field_reports
                    WHERE statut='executee' AND facturable IS NULL
                    ORDER BY executed_at LIMIT 30""").fetchall()
                for r in rows:
                    result['validations'].append({
                        'id': r['id'], 'task_type': 'decision_facturation',
                        'label': f"💰 Décision facturation : {r['reference']} ({r['client_name']})",
                        'link': f"/field-reports/{r['id']}", 'status': 'à décider',
                        'priority': 'high',
                    })
            except: pass
        
        # v162 : (ancien bloc « factures à éditer » retiré — il faisait doublon avec le bloc ci-dessus,
        # ignorait la date de report (deadline_edit) et incluait à tort l'admin, ce qui ramenait
        # à la clôture des factures déjà éditées/reportées et empêchait la comptable de clôturer.)
    finally:
        conn.close()
    
    total = sum(len(v) for v in result.values())
    result['_total'] = total
    return result


def get_or_create_today_closure(user_id):
    """v139 : Retourne (ou crée) la clôture du jour pour cet utilisateur."""
    today = datetime.now().strftime('%Y-%m-%d')
    conn = _gdb()
    row = conn.execute("SELECT * FROM daily_closures WHERE user_id=? AND date_closure=?",
        (user_id, today)).fetchone()
    if not row:
        conn.execute("INSERT INTO daily_closures (user_id, date_closure, status, created_at) VALUES (?,?,?,datetime('now'))",
            (user_id, today, 'en_attente'))
        conn.commit()
        row = conn.execute("SELECT * FROM daily_closures WHERE user_id=? AND date_closure=?",
            (user_id, today)).fetchone()
    conn.close()
    return dict(row) if row else None


