def _rh_bypass(user, perm):
    """v133 / v135 / v137 : Bypass étendu pour la gestionnaire RH.
    v137 : Détection robuste — matche le rôle RH sous diverses variantes
    ('rh', 'RH', 'rh ', 'directrice_rh', 'responsable_rh', 'manager_rh',
    'ressources_humaines', 'human_resources') ET aussi via le DÉPARTEMENT du user
    (si département contient 'rh', 'ressources_humaines', 'human').
    
    Bypass TOTAL des permissions sauf les routes ultra-sensibles (admin only).
    Le user a explicitement demandé que la RH ait accès à tout sans devoir être admin."""
    if not user: return False
    
    role = (user.get('role') or '').strip().lower()
    dept = (user.get('department') or '').strip().lower()
    
    # v137 : Liste robuste de variantes de rôle RH
    RH_ROLE_VARIANTS = {
        'rh', 'r.h', 'r.h.',
        'directrice_rh', 'directeur_rh', 'direct_rh',
        'responsable_rh', 'manager_rh', 'gestionnaire_rh',
        'ressources_humaines', 'ressource_humaines',
        'human_resources', 'hr', 'h.r', 'h.r.',
    }
    
    # v137 : Détection RH par rôle (variantes) ou par département
    is_rh_role = role in RH_ROLE_VARIANTS or role.replace(' ', '').replace('-', '_') in RH_ROLE_VARIANTS
    is_rh_dept = (
        'ressources_humaines' in dept.replace('-', '_').replace(' ', '_') or
        'ressources humaines' in dept or
        dept == 'rh' or dept.startswith('rh ') or dept.endswith(' rh') or
        'human_resources' in dept.replace('-', '_').replace(' ', '_') or
        'human resources' in dept
    )
    
    is_rh = is_rh_role or is_rh_dept
    
    if not is_rh:
        return False
    
    # v135 : Liste des permissions super-sensibles RÉSERVÉES strictement à l'admin
    ADMIN_ONLY_HARD_PERMS = {
        'hard_delete', 'system_config', 'backup_restore', 'database_admin',
    }
    if perm in ADMIN_ONLY_HARD_PERMS:
        return False
    
    # RH (détectée par rôle ou département) → bypass total
    return True


def permission_required(perm):
    def decorator(f):
        @functools.wraps(f)
        def decorated(*args, **kwargs):
            if 'user_id' not in session:
                return redirect(url_for('login'))
            user = get_user_by_id(session['user_id'])
            if not user:
                flash("Accès non autorisé", "error")
                return redirect(url_for('dashboard'))
            # Le rôle 'admin' a accès à tout (admin override)
            if user['role'] == 'admin':
                return f(*args, **kwargs)
            # v133 : Bypass RH pour permissions RH naturelles
            if _rh_bypass(user, perm):
                return f(*args, **kwargs)
            if not has_permission(user['role'], perm):
                flash("Accès non autorisé", "error")
                return redirect(url_for('dashboard'))
            return f(*args, **kwargs)
        return decorated
    return decorator


def permission_required_any(*perms):
    """Accès si l'utilisateur a AU MOINS UNE des permissions listées."""
    def decorator(f):
        @functools.wraps(f)
        def decorated(*args, **kwargs):
            if 'user_id' not in session:
                return redirect(url_for('login'))
            user = get_user_by_id(session['user_id'])
            if not user:
                flash("Accès non autorisé", "error")
                return redirect(url_for('dashboard'))
            if user['role'] == 'admin':
                return f(*args, **kwargs)
            # v133 : Bypass RH pour permissions RH naturelles
            if any(_rh_bypass(user, p) for p in perms):
                return f(*args, **kwargs)
            user_perms = get_role_permissions(user['role'])
            if not any(p in user_perms for p in perms):
                flash("Accès non autorisé", "error")
                return redirect(url_for('dashboard'))
            return f(*args, **kwargs)
        return decorated
    return decorator


def recharge_access_required(f):
    """v79 : Accès au module recharge Internet.
    Autorisé pour : admin, et les rôles/permissions IT, comptabilité, RH.
    Vérifie à la fois le rôle ET les permissions (souplesse selon config)."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        user = get_user_by_id(session['user_id'])
        if not user:
            flash("Accès non autorisé", "error")
            return redirect(url_for('dashboard'))
        role = user['role']
        # Admin et DG toujours autorisés
        if role in ('admin', 'dg', 'directeur'):
            return f(*args, **kwargs)
        # Rôles métier explicitement autorisés (compta, RH, IT)
        allowed_roles = ('rh', 'comptable', 'comptabilite', 'informaticien',
                         'informatique', 'it', 'finance')
        if role in allowed_roles:
            return f(*args, **kwargs)
        # Sinon vérifier les permissions (informatique, comptabilite)
        user_perms = get_role_permissions(role)
        if any(p in user_perms for p in ('informatique', 'comptabilite')):
            return f(*args, **kwargs)
        flash("Accès non autorisé", "error")
        return redirect(url_for('dashboard'))
    return decorated


def project_access_required(f):
    """v88 : Accès au module projets/Roadmap.
    Autorisé pour : admin, dg, directeur, coordinateur, gestionnaire_projet, resp_projet,
    commercial, comptable, technicien, magasinier, informaticien, etc."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        user = get_user_by_id(session['user_id'])
        if not user:
            flash("Accès non autorisé", "error")
            return redirect(url_for('dashboard'))
        role = user['role']
        allowed = ('admin', 'dg', 'directeur',
                   'coordinateur', 'gestionnaire_projet', 'resp_projet',  # v88 : 3 rôles équivalents
                   'commercial',
                   'comptable', 'comptabilite',
                   'technicien', 'tech_chef', 'centre_technique', 'chef_chantier',
                   'magasinier', 'mg', 'moyens_generaux',
                   'informaticien', 'informatique', 'rh')
        if role in allowed:
            return f(*args, **kwargs)
        perms = get_role_permissions(role)
        if any(p in perms for p in ('clients', 'centre_technique', 'mg_view', 'comptabilite', 'resp_projet')):
            return f(*args, **kwargs)
        flash("Accès non autorisé", "error")
        return redirect(url_for('dashboard'))
    return decorated


# v148 : Décorateur pour bloquer les Moyens Généraux sur certaines actions
def mg_forbidden(f):
    """v148 : Bloque les MG/magasinier sur les actions qui ne les concernent pas :
    - Assignation de techniciens à un projet
    - Planification des dates / coordinateur
    Le rôle MG doit se limiter à la préparation du matériel."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        user = get_user_by_id(session['user_id'])
        if not user:
            return redirect(url_for('login'))
        if user['role'] in ('mg', 'moyens_generaux', 'magasinier'):
            flash("⛔ Les Moyens Généraux ne peuvent pas effectuer cette action. "
                  "Cette tâche est réservée au coordinateur de projet ou à la direction.", "error")
            # Redirige vers le projet si pid présent
            pid = kwargs.get('pid')
            if pid: return redirect(f'/projects/{pid}')
            return redirect(url_for('dashboard'))
        return f(*args, **kwargs)
    return decorated


# v87 : Helper - liste des projets actifs où l'utilisateur est impliqué
# avec indicateur "c'est votre tour" selon le service responsable de l'étape actuelle
def _get_my_active_projects(user_id, user_role):
    """Retourne les projets actifs (non clôturés) où l'utilisateur a un rôle à jouer.
    Pour chaque projet, ajoute 'my_turn' = True si c'est à ce rôle d'agir maintenant."""
    # Mapping étape → rôles concernés (ceux qui doivent agir)
    STEP_ACTORS = {
        'valide':       ['commercial', 'admin', 'dg', 'directeur'],
        'demarre':      ['coordinateur', 'gestionnaire_projet', 'resp_projet', 'admin'],
        'preparation':  ['mg', 'magasinier', 'moyens_generaux', 'admin'],
        'planifie':     ['coordinateur', 'gestionnaire_projet', 'resp_projet', 'admin'],
        'execution':    ['technicien', 'tech_chef', 'chef_chantier', 'centre_technique', 'admin'],
        'travaux_fin':  ['coordinateur', 'gestionnaire_projet', 'resp_projet', 'admin'],
        'qc_valide':    ['coordinateur', 'gestionnaire_projet', 'resp_projet', 'admin'],
        'qc_rejete':    ['technicien', 'tech_chef', 'centre_technique', 'admin'],
        'livre':        ['comptabilite', 'comptable', 'admin'],
        'attente_solde':['comptabilite', 'comptable', 'admin'],
        'solde':        ['commercial', 'admin'],
        'contrat_oui':  ['commercial', 'admin'],
        'contrat_non':  ['commercial', 'admin'],
    }
    
    try:
        from models import get_db as _g
        conn = _g()
        # v88 : Rôles qui voient TOUS les projets actifs (par responsabilité métier)
        # - admin/dg/directeur (supervision)
        # - coordinateur/gestionnaire_projet/resp_projet (3 rôles équivalents : coordination)
        # - technicien/tech_chef/centre_technique (exécution, doivent connaître tous les chantiers)
        # - commercial (suit ses ventes)
        # - mg/magasinier (préparation matérielle)
        # - comptable/comptabilite (facturation)
        GLOBAL_VIEW_ROLES = ('admin', 'dg', 'directeur',
                             'coordinateur', 'gestionnaire_projet', 'resp_projet',
                             'technicien', 'tech_chef', 'centre_technique', 'chef_chantier',
                             'commercial', 'mg', 'magasinier', 'moyens_generaux',
                             'comptable', 'comptabilite')
        if user_role in GLOBAL_VIEW_ROLES:
            rows = conn.execute("""
                SELECT id, reference, title, client_name, status, current_step, progress_pct, 
                       coordinator_id, created_by, start_date, end_date_planned
                FROM wf_projects WHERE status != 'cloture'
                ORDER BY 
                    CASE WHEN status IN ('execution','travaux_fin','planifie') THEN 1 
                         WHEN status IN ('valide','demarre','preparation') THEN 2
                         ELSE 3 END,
                    created_at DESC LIMIT 30
            """).fetchall()
        else:
            # Autres rôles : seulement projets où impliqué directement
            rows = conn.execute("""
                SELECT DISTINCT p.id, p.reference, p.title, p.client_name, p.status, p.current_step,
                                p.progress_pct, p.coordinator_id, p.created_by,
                                p.start_date, p.end_date_planned
                FROM wf_projects p
                LEFT JOIN wf_project_team t ON t.project_id = p.id
                WHERE p.status != 'cloture'
                  AND (p.coordinator_id = ? OR p.created_by = ? OR t.user_id = ?)
                ORDER BY p.created_at DESC LIMIT 30
            """, (user_id, user_id, user_id)).fetchall()
        
        projects = []
        for r in rows:
            p = dict(r)
            # Enrichir avec step info
            info = PROJECT_STATUS_INFO.get(p['status'], {})
            p['step_label'] = info.get('label', p['status'])
            p['step_icon'] = info.get('icon', '📋')
            p['service_label'] = info.get('service_label', '')
            p['color'] = info.get('color', '#888')
            p['next_label'] = info.get('next_label', '')
            # C'est mon tour si mon rôle est dans les acteurs de l'étape courante
            actors = STEP_ACTORS.get(p['status'], [])
            p['my_turn'] = (user_role in actors) or (user_role == 'admin')
            projects.append(p)
        
        # Pour les rôles non-GLOBAL_VIEW : ajouter les projets où c'est leur tour
        if user_role not in GLOBAL_VIEW_ROLES:
            relevant_statuses = [st for st, actors in STEP_ACTORS.items() if user_role in actors]
            if relevant_statuses:
                placeholders = ','.join('?' * len(relevant_statuses))
                already_ids = [p['id'] for p in projects]
                ids_filter = f"AND id NOT IN ({','.join('?'*len(already_ids))})" if already_ids else ""
                extra = conn.execute(f"""
                    SELECT id, reference, title, client_name, status, current_step, progress_pct,
                           coordinator_id, created_by, start_date, end_date_planned
                    FROM wf_projects WHERE status IN ({placeholders}) {ids_filter}
                    ORDER BY created_at DESC LIMIT 20
                """, list(relevant_statuses) + already_ids).fetchall()
                for r in extra:
                    p = dict(r)
                    info = PROJECT_STATUS_INFO.get(p['status'], {})
                    p['step_label'] = info.get('label', p['status'])
                    p['step_icon'] = info.get('icon', '📋')
                    p['service_label'] = info.get('service_label', '')
                    p['color'] = info.get('color', '#888')
                    p['next_label'] = info.get('next_label', '')
                    p['my_turn'] = True
                    projects.append(p)
        
        conn.close()
        # Trier : mon tour d'abord
        projects.sort(key=lambda x: (not x.get('my_turn'), x.get('current_step', 0)))
        return projects[:15]
    except Exception as e:
        print(f"[_get_my_active_projects] erreur : {e}", flush=True)
        return []


@app.context_processor
def inject_globals():
    """Injecte les variables globales dans tous les templates."""
    ctx = {'current_user': None, 'permissions': [], 'pending_count': 0, 'unread_messages': 0, 'caisse_pending': 0, 'weekly_champion': None, 'show_champion': True, 'active_tenders': [], 'pending_absences': 0}
    if 'user_id' in session:
        user = get_user_by_id(session['user_id'])
        if user:
            perms = get_role_permissions(user['role'])
            # v133 / v137 : Si l'utilisateur est RH (rôle OU département), injecter
            # automatiquement TOUTES les permissions (sauf hard admin) pour que la
            # sidebar affiche tous les modules autorisés.
            if _rh_bypass(user, 'dashboard'):  # détection robuste rôle ou département
                # On lui donne accès complet via une perm virtuelle 'admin'
                perms = list(set(perms) | RH_NATURAL_PERMS | {'admin'})
            ctx['current_user'] = user
            ctx['permissions'] = perms
            ctx['user_role'] = user['role']
            ctx['can_edit'] = lambda module: (module + '_edit') in perms or 'admin' in perms
            ctx['pending_count'] = len(get_jobs_by_status('traite'))
            try: ctx['unread_messages'] = get_unread_count(user['id'])
            except: pass
            # Notification count
            try:
                from models import get_db as _ndb
                _nc = _ndb()
                ctx['notif_count'] = _nc.execute("SELECT COUNT(*) FROM notifications WHERE (user_id=? OR employee_id IN (SELECT id FROM employees WHERE email=?)) AND read=0",
                    (user['id'], user.get('email',''))).fetchone()[0]
                # v131 : Compteur de remontées en attente de création de projet/opportunité
                try:
                    ctx['nouveau_projet_count'] = _nc.execute(
                        "SELECT COUNT(*) FROM field_reports WHERE statut IN ('transformee_projet','transformee_opportunite') AND linked_project_id IS NULL"
                    ).fetchone()[0]
                except: ctx['nouveau_projet_count'] = 0
                # v141 : Indicateur de clôture journalière en attente
                try:
                    _today = datetime.now().strftime('%Y-%m-%d')
                    _cr = _nc.execute(
                        "SELECT status FROM daily_closures WHERE user_id=? AND date_closure=?",
                        (user['id'], _today)).fetchone()
                    # Pending = pas de clôture OU statut en_attente
                    ctx['closure_pending'] = (not _cr) or (_cr['status'] in ('en_attente', None))
                except: ctx['closure_pending'] = False
                # v143 / v144 : Compteur décisions de facturation en attente (pour DG/RH)
                # v144 : Inclut traitee + executee (rattrapage backlog)
                try:
                    if user['role'] in ('admin','dg','directeur','rh','directrice_rh'):
                        ctx['decisions_facturation_pending'] = _nc.execute(
                            "SELECT COUNT(*) FROM field_reports WHERE statut IN ('executee','traitee') "
                            "AND facturable IS NULL AND (linked_intervention_id IS NOT NULL OR type_info='rapport_heures')"
                        ).fetchone()[0]
                    else: ctx['decisions_facturation_pending'] = 0
                except: ctx['decisions_facturation_pending'] = 0
                # v147 : Compteur transferts caisse en attente (pour DG/RH)
                try:
                    if user['role'] in ('admin','dg','directeur','rh','directrice_rh'):
                        nb_vir = _nc.execute("SELECT COUNT(*) FROM caisse_virements WHERE status='en_attente'").fetchone()[0]
                        try:
                            nb_ov = _nc.execute(
                                "SELECT COUNT(*) FROM ordres_virement WHERE status IN ('en_attente','en_attente_dg','en_attente_validation','attente_dg')"
                            ).fetchone()[0]
                        except: nb_ov = 0
                        ctx['transferts_pending'] = nb_vir + nb_ov
                    else: ctx['transferts_pending'] = 0
                except: ctx['transferts_pending'] = 0
                # v159 : compteurs recouvrement + paiements à valider
                try:
                    ctx['recouvrement_pending'] = _nc.execute(
                        "SELECT COUNT(*) FROM field_report_invoices WHERE status='facture_editee'").fetchone()[0]
                except: ctx['recouvrement_pending'] = 0
                try:
                    ctx['paiements_a_valider_pending'] = _nc.execute(
                        "SELECT COUNT(*) FROM field_report_invoices WHERE status='caisse_choisie'").fetchone()[0]
                except: ctx['paiements_a_valider_pending'] = 0
                _nc.close()
            except:
                ctx['notif_count'] = 0
                ctx['nouveau_projet_count'] = 0
                ctx['closure_pending'] = False
                ctx['decisions_facturation_pending'] = 0
                ctx['transferts_pending'] = 0
                ctx['recouvrement_pending'] = 0
                ctx['paiements_a_valider_pending'] = 0
            if 'fichiers' in perms or 'admin' in perms:
                try:
                    from models import get_db as _gdb_abs
                    _ca = _gdb_abs()
                    ctx['pending_absences'] = _ca.execute("SELECT COUNT(*) FROM absences WHERE status='en_attente'").fetchone()[0]
                    _ca.close()
                except: pass
            # NOUVEAU v57 : compteur demandes MG en attente (pour les validateurs)
            if 'mg_valider' in perms or 'admin' in perms:
                try:
                    from models import get_db as _mg_db
                    _mg_c = _mg_db()
                    ctx['mg_pending_count'] = _mg_c.execute(
                        "SELECT COUNT(*) FROM achats_demandes WHERE status='en_attente'").fetchone()[0]
                    _mg_c.close()
                except: ctx['mg_pending_count'] = 0
            else:
                ctx['mg_pending_count'] = 0
            # v78/v79 : compteur alertes recharge Internet (IT + compta + RH + admin)
            _recharge_roles = user['role'] in ('admin', 'dg', 'directeur', 'rh', 'comptable',
                                               'comptabilite', 'informaticien', 'informatique', 'it', 'finance')
            _recharge_perms = any(p in perms for p in ('informatique', 'comptabilite'))
            if _recharge_roles or _recharge_perms:
                try:
                    from datetime import datetime as _dt_r, timedelta as _td_r
                    from models import get_db as _r_db
                    _rc = _r_db()
                    _rows = _rc.execute(
                        "SELECT next_due, alert_days_before FROM it_internet_recharge WHERE status='actif'").fetchall()
                    _rc.close()
                    _today = _dt_r.now().date()
                    _cnt = 0
                    for _row in _rows:
                        if not _row['next_due']: continue
                        try:
                            _due = _dt_r.strptime(_row['next_due'][:10], '%Y-%m-%d').date()
                            _dl = (_due - _today).days
                            if _dl <= int(_row['alert_days_before'] or 2):
                                _cnt += 1
                        except: pass
                    ctx['recharge_alerts_count'] = _cnt
                except: ctx['recharge_alerts_count'] = 0
            else:
                ctx['recharge_alerts_count'] = 0
            # v79 : liste détaillée des alertes recharge (pour affichage dashboards)
            if _recharge_roles or _recharge_perms:
                try:
                    from datetime import datetime as _dt_ra
                    from models import get_db as _ra_db
                    _rac = _ra_db()
                    _arows = [dict(r) for r in _rac.execute(
                        "SELECT * FROM it_internet_recharge WHERE status='actif' ORDER BY next_due ASC").fetchall()]
                    _rac.close()
                    _today2 = _dt_ra.now().date()
                    _alerts = []
                    for _r in _arows:
                        if not _r.get('next_due'): continue
                        try:
                            _due2 = _dt_ra.strptime(_r['next_due'][:10], '%Y-%m-%d').date()
                            _dl2 = (_due2 - _today2).days
                            if _dl2 <= int(_r.get('alert_days_before') or 2):
                                _r['days_left'] = _dl2
                                _r['is_overdue'] = _dl2 < 0
                                _alerts.append(_r)
                        except: pass
                    ctx['recharge_alerts'] = _alerts
                except: ctx['recharge_alerts'] = []
            else:
                ctx['recharge_alerts'] = []
            # v84 : compteur + liste notifications projet (selon rôle)
            try:
                _pn_conn = _gdb()
                _pn_rows = _pn_conn.execute("""SELECT n.*, p.reference as project_ref, p.title as project_title
                    FROM wf_project_notifications n
                    LEFT JOIN wf_projects p ON n.project_id = p.id
                    WHERE n.is_read=0 AND (n.target_role=? OR n.target_user_id=? OR ?='admin')
                    ORDER BY n.created_at DESC LIMIT 30""",
                    (user['role'], user['id'], user['role'])).fetchall()
                _pn_conn.close()
                ctx['project_notifs'] = [dict(r) for r in _pn_rows]
                ctx['project_notifs_count'] = len(_pn_rows)
            except:
                ctx['project_notifs'] = []
                ctx['project_notifs_count'] = 0
            
            # v87 : Liste des projets où l'utilisateur est impliqué (pour widget dashboard)
            try:
                _mp_projects = _get_my_active_projects(user['id'], user['role'])
                ctx['my_projects'] = _mp_projects
                ctx['my_projects_count'] = len(_mp_projects)
                ctx['my_projects_action_required'] = len([p for p in _mp_projects if p.get('my_turn')])
            except Exception as _e_mp:
                ctx['my_projects'] = []
                ctx['my_projects_count'] = 0
                ctx['my_projects_action_required'] = 0
            
            # v100 : Widget Remontées d'informations pour gestionnaire de projet
            try:
                _user_perms = ctx.get('permissions', [])
                if 'field_report_view_all' in _user_perms or 'admin' in _user_perms or user['role'] in ('gestionnaire_projet', 'admin', 'dg', 'directeur'):
                    from models import get_db as _frdb
                    _fc = _frdb()
                    # Stats globales
                    _stats = {row['statut']: row['nb'] for row in 
                             _fc.execute("SELECT statut, COUNT(*) as nb FROM field_reports GROUP BY statut").fetchall()}
                    _prios = {row['priorite']: row['nb'] for row in 
                             _fc.execute("SELECT priorite, COUNT(*) as nb FROM field_reports WHERE statut IN ('recue','en_analyse') GROUP BY priorite").fetchall()}
                    # 5 plus urgents à traiter
                    _to_treat_rows = _fc.execute("""SELECT * FROM field_reports 
                        WHERE statut IN ('recue', 'en_analyse')
                        ORDER BY 
                            CASE priorite 
                                WHEN 'urgent' THEN 1 
                                WHEN 'eleve' THEN 2 
                                WHEN 'moyen' THEN 3 
                                ELSE 4 
                            END, date_constat DESC LIMIT 5""").fetchall()
                    _to_treat = []
                    for _r in _to_treat_rows:
                        _d = dict(_r)
                        _pl = FIELD_REPORT_PRIORITIES.get(_d['priorite'], (_d['priorite'], '#888'))
                        _sl = FIELD_REPORT_STATUTS.get(_d['statut'], (_d['statut'], '#888'))
                        _d['priorite_label'] = _pl[0]; _d['priorite_color'] = _pl[1]
                        _d['statut_label'] = _sl[0]; _d['statut_color'] = _sl[1]
                        _d['type_label'] = FIELD_REPORT_TYPES.get(_d['type_info'], _d['type_info'])
                        _to_treat.append(_d)
                    _fc.close()
                    ctx['field_reports_summary'] = {
                        'recue': _stats.get('recue', 0),
                        'en_analyse': _stats.get('en_analyse', 0),
                        'urgent_count': _prios.get('urgent', 0),
                        'eleve_count': _prios.get('eleve', 0),
                        'total': sum(_stats.values()),
                        'to_treat': _to_treat,
                    }
            except Exception as _e_fr:
                pass
            
            # v102 : Badge "Demandes MG à valider" pour comptables/DG/directeur/admin
            ctx['compta_demandes_pending'] = 0
            try:
                if user['role'] in ('comptable', 'comptabilite', 'admin', 'dg', 'directeur'):
                    from models import get_db as _cmgdb
                    _cmg = _cmgdb()
                    ctx['compta_demandes_pending'] = _cmg.execute(
                        "SELECT COUNT(*) FROM achats_demandes WHERE compta_status='a_valider'").fetchone()[0]
                    _cmg.close()
            except Exception:
                pass
            
            if user['role'] in ('admin', 'dg', 'directeur'):
                try:
                    from models import get_db as _gdb
                    _c = _gdb()
                    ctx['caisse_pending'] = _c.execute("SELECT COUNT(*) FROM caisse_sorties WHERE status='en_attente'").fetchone()[0]
                    # Comptes clients en attente de validation
                    try:
                        ctx['pending_clients_count'] = _c.execute("SELECT COUNT(*) FROM client_users WHERE account_status='pending'").fetchone()[0]
                    except: ctx['pending_clients_count'] = 0
                    # Virements banque→caisse en attente
                    try:
                        ctx['pending_virements_count'] = _c.execute("SELECT COUNT(*) FROM caisse_virements WHERE status='en_attente'").fetchone()[0]
                    except: ctx['pending_virements_count'] = 0
                    # v120 : Ordres de virement unifiés en attente DG
                    try:
                        ctx['pending_ordres_count'] = _c.execute("SELECT COUNT(*) FROM ordres_virement WHERE status='en_attente'").fetchone()[0]
                    except: ctx['pending_ordres_count'] = 0
                    # Contrôle qualité en attente — v158 : UNIQUEMENT projets neufs (cohérent avec la liste)
                    try:
                        ctx['pending_cq_count'] = _c.execute("""SELECT COUNT(*) FROM interventions 
                            WHERE status='travaux_termines' AND COALESCE(cq_status,'')=''
                              AND LOWER(COALESCE(type,'')) IN ('installation','projet','projet_neuf','projet neuf','travaux_neufs')
                            """).fetchone()[0]
                    except: ctx['pending_cq_count'] = 0
                    # Livraisons à programmer / en attente
                    try:
                        ctx['pending_deliv_count'] = _c.execute("""SELECT COUNT(*) FROM interventions WHERE
                            (cq_status='passed' AND COALESCE(delivery_proposed_date,'')='') OR
                            (delivery_client_status='accepted' AND status!='livre') OR
                            (delivery_client_status='proposed')""").fetchone()[0]
                    except: ctx['pending_deliv_count'] = 0
                    # Demandes clients à traiter (statut soumise) — toujours réelles
                    try:
                        ctx['pending_requests_count'] = _c.execute(
                            "SELECT COUNT(*) FROM client_requests WHERE status='soumise'").fetchone()[0]
                    except: ctx['pending_requests_count'] = 0
                    # === Badges basés sur "last_seen" persisté en BDD (plus de fantômes au login) ===
                    u_id = session.get('user_id', 0)
                    user_seen = _c.execute(
                        "SELECT last_interventions_seen, last_my_interventions_seen, last_visites_seen FROM users WHERE id=?",
                        (u_id,)).fetchone()
                    user_seen = dict(user_seen) if user_seen else {}
                    # Si jamais "vu", on considère comme vu maintenant (pas de fantômes au tout premier login)
                    now_iso = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                    # Nouvelles interventions globales (admin/coord)
                    try:
                        last_seen = user_seen.get('last_interventions_seen') or now_iso
                        ctx['new_interventions_count'] = _c.execute(
                            """SELECT COUNT(*) FROM interventions
                               WHERE COALESCE(created_at, scheduled_date, '') > ?
                               AND status NOT IN ('livre','annule','annulee','termine','terminee')""",
                            (last_seen,)).fetchone()[0]
                    except: ctx['new_interventions_count'] = 0
                    # Nouvelles interventions du technicien connecté
                    try:
                        last_seen_t = user_seen.get('last_my_interventions_seen') or now_iso
                        ctx['my_interventions_count'] = _c.execute(
                            """SELECT COUNT(*) FROM interventions
                               WHERE technician_id=?
                               AND COALESCE(created_at, scheduled_date, '') > ?
                               AND status NOT IN ('livre','annule','annulee','termine','terminee')""",
                            (u_id, last_seen_t)).fetchone()[0]
                    except: ctx['my_interventions_count'] = 0
                    # Nouvelles visites
                    try:
                        last_seen_v = user_seen.get('last_visites_seen') or now_iso
                        ctx['new_visites_count'] = _c.execute(
                            """SELECT COUNT(*) FROM visits
                               WHERE COALESCE(created_at, date, '') > ?
                               AND COALESCE(statut,'en_attente') = 'en_attente'""",
                            (last_seen_v,)).fetchone()[0]
                    except: ctx['new_visites_count'] = 0
                    # Initialiser last_seen sur le premier login (pour éviter les fantômes)
                    if not user_seen.get('last_interventions_seen'):
                        try:
                            _c.execute("""UPDATE users SET 
                                last_interventions_seen=COALESCE(last_interventions_seen, ?),
                                last_my_interventions_seen=COALESCE(last_my_interventions_seen, ?),
                                last_visites_seen=COALESCE(last_visites_seen, ?)
                                WHERE id=?""", (now_iso, now_iso, now_iso, u_id))
                            _c.commit()
                        except: pass
                    _c.close()
                except: pass
            # Weekly champion
            try:
                from models import get_current_champion, update_weekly_champion, get_live_champion, get_db as _gdb_cp
                update_weekly_champion()
                champ = get_current_champion()
                live = get_live_champion()
                if champ:
                    ctx['weekly_champion'] = champ
                elif live:
                    ctx['weekly_champion'] = live
                # Check visibility setting
                _sc = _gdb_cp()
                try:
                    vis = _sc.execute("SELECT value FROM app_settings WHERE key='show_champion'").fetchone()
                    ctx['show_champion'] = (vis['value'] != '0') if vis else True
                except: ctx['show_champion'] = True
                try:
                    today = datetime.now().strftime('%Y-%m-%d')
                    tenders = [dict(r) for r in _sc.execute(
                        "SELECT * FROM tender_links WHERE active=1 AND (deadline='' OR deadline>=?) ORDER BY deadline", (today,)).fetchall()]
                    ctx['active_tenders'] = tenders
                except: pass
                # Interventions du jour pour le ticker (max 15)
                try:
                    today_s = datetime.now().strftime('%Y-%m-%d')
                    ctx['today_interventions'] = [dict(r) for r in _sc.execute(
                        """SELECT id, reference, title, client_name, status, type, progress
                           FROM interventions
                           WHERE scheduled_date=? AND status NOT IN ('annule','annulee')
                           ORDER BY scheduled_time, id LIMIT 15""", (today_s,)).fetchall()]
                except: ctx['today_interventions'] = []
                _sc.close()
            except: pass
    else:
        ctx['can_edit'] = lambda module: False
    return ctx


