def check_reminder_notifications():
    """Check all reminders (client + calendar) and create notifications for upcoming ones."""
    try:
        from models import get_db as _rdb
        conn = _rdb()
        today = datetime.now().strftime('%Y-%m-%d')
        tomorrow = (datetime.now() + timedelta(days=1)).strftime('%Y-%m-%d')
        
        # 1. Client reminders (due today or tomorrow)
        reminders = conn.execute(
            "SELECT cr.*, c.name as client_name FROM client_reminders cr LEFT JOIN clients c ON cr.client_id=c.id WHERE cr.done=0 AND cr.date IN (?,?)", (today, tomorrow)).fetchall()
        for rem in [dict(r) for r in reminders]:
            existing = conn.execute("SELECT id FROM notifications WHERE type='rappel' AND link=? AND created_at > datetime('now','-1 day')",
                (f"/clients/{rem['client_id']}?tab=reminders",)).fetchone()
            if not existing:
                users = conn.execute("SELECT id FROM users WHERE is_active=1").fetchall()
                prefix = "📅 Aujourd'hui" if rem['date'] == today else "⏰ Demain"
                for u in users:
                    conn.execute("INSERT INTO notifications (user_id, type, title, message, link) VALUES (?,?,?,?,?)",
                        (u['id'], 'rappel', f"{prefix} — {rem['title']}",
                         f"Rappel client {rem.get('client_name','?')} : {rem['title']} ({rem['date']})",
                         f"/clients/{rem['client_id']}?tab=reminders"))
        
        # 2. Calendar events (due today or tomorrow)
        events = conn.execute("SELECT * FROM calendar_events WHERE start_date IN (?,?)", (today, tomorrow)).fetchall()
        for ev in [dict(r) for r in events]:
            existing = conn.execute("SELECT id FROM notifications WHERE type='rappel' AND title LIKE ? AND created_at > datetime('now','-1 day')",
                (f"%{ev['title']}%",)).fetchone()
            if not existing:
                users = conn.execute("SELECT id FROM users WHERE is_active=1").fetchall()
                prefix = "📅 Aujourd'hui" if ev.get('start_date','') == today else "⏰ Demain"
                time_str = f" à {ev['event_time']}" if ev.get('event_time') else ''
                for u in users:
                    conn.execute("INSERT INTO notifications (user_id, type, title, message, link) VALUES (?,?,?,?,?)",
                        (u['id'], 'rappel', f"{prefix}{time_str} — {ev['title']}",
                         f"{ev.get('description','') or ev['title']}", "/rh/calendrier"))
        
        conn.commit(); conn.close()
    except Exception as e:
        try: conn.close()
        except: pass

@app.before_request
def check_session_timeout():
    """Déconnexion automatique après 30 min d'inactivité."""
    if 'user_id' in session:
        last = session.get('last_active')
        if last:
            try:
                last_dt = datetime.fromisoformat(last)
                if datetime.now() - last_dt > timedelta(minutes=30):
                    session.clear()
                    flash("Session expirée — veuillez vous reconnecter", "info")
                    return redirect(url_for('login'))
            except:
                pass
        session['last_active'] = datetime.now().isoformat()


# ============================================================
# CSRF PROTECTION (double-submit cookie pattern)
# ============================================================
import secrets as _csrf_secrets

# Routes exemptes de CSRF (pour les appels d'API JSON ou webhooks externes)
CSRF_EXEMPT_PATHS = {
    '/api/notifications/count',
}
# Endpoints publics qui font POST avant que la session existe
CSRF_BOOTSTRAP_ENDPOINTS = {'login', 'portail_login', 'portail_register'}


def _ensure_csrf_token():
    """Génère un token CSRF unique par session si absent."""
    if '_csrf_token' not in session:
        session['_csrf_token'] = _csrf_secrets.token_urlsafe(32)
    return session['_csrf_token']


@app.context_processor
def _inject_csrf_token():
    """Rend csrf_token() disponible dans tous les templates."""
    return {'csrf_token': _ensure_csrf_token}


@app.context_processor
def _inject_doc_params():
    """v162 : rend les paramètres de documents (entête/pied) disponibles dans TOUS les templates
    → personnalisables depuis Admin → Paramètres documents."""
    try:
        return {'doc_params': get_doc_params()}
    except Exception:
        return {'doc_params': dict(DEFAULT_DOC_PARAMS)}


@app.after_request
def _set_csrf_cookie(response):
    """Pose le token CSRF dans un cookie lisible par JS (pour double-submit)."""
    if 'user_id' in session or 'client_user_id' in session:
        token = _ensure_csrf_token()
        # Cookie NON HTTPOnly (doit être lisible par JS pour le poser dans header)
        response.set_cookie('csrftoken', token,
                           secure=app.config.get('SESSION_COOKIE_SECURE', True),
                           samesite='Lax', httponly=False)
    return response


@app.before_request
def _csrf_protect():
    """Vérifie le token CSRF sur toutes les requêtes mutantes."""
    if request.method not in ('POST', 'PUT', 'PATCH', 'DELETE'):
        return
    if request.endpoint in CSRF_BOOTSTRAP_ENDPOINTS:
        return
    if request.path in CSRF_EXEMPT_PATHS:
        return
    expected = session.get('_csrf_token')
    if not expected:
        # Pas de session active → on laisse Flask traiter, ça redirigera vers login
        return
    # Token accepté depuis : form _csrf, header X-CSRFToken, ou cookie csrftoken (double-submit)
    received = (request.form.get('_csrf')
                or request.headers.get('X-CSRFToken')
                or request.cookies.get('csrftoken'))
    if not received or not _csrf_secrets.compare_digest(expected, received):
        try:
            from models import log_security_event
            log_security_event('csrf_rejected',
                user_id=session.get('user_id'),
                ip=request.remote_addr,
                user_agent=request.headers.get('User-Agent', ''),
                path=request.path,
                details=f"method={request.method}",
                severity='warning')
        except: pass
        flash("⚠️ Action refusée pour des raisons de sécurité (token CSRF invalide). Rechargez la page et réessayez.", "error")
        return abort(403)


