# v149 : Routes exemptées du middleware pointage forcé
_POINTAGE_EXEMPT_PATHS = (
    '/login', '/logout', '/login/2fa', '/login/2fa/cancel',
    '/pointage', '/pointage/action', '/pointage/qr',
    '/static/', '/uploads/', '/manifest.json', '/sw.js', '/favicon.ico',
    '/api/csrf', '/api/health',
    '/closure/today', '/closure/submit', '/closure/justify',  # v149 : autoriser clôture (qui pointe le départ)
    '/notifications/read',  # marquage lu via lien
)

# v149 : Rôles exemptés (peuvent accéder sans pointer)
_POINTAGE_EXEMPT_ROLES = ('admin',)  # admin pour ne pas se bloquer en debug

@app.before_request
def _force_arrival_pointage():
    """v149 / v150 : Force l'utilisateur connecté à pointer son arrivée avant d'accéder au logiciel.
    v150 : Conditionné à la permission 'pointage_force_arrival' attribuable par rôle/utilisateur.
    Admin et utilisateurs sans cette permission ne sont pas forcés."""
    uid = session.get('user_id')
    if not uid: return
    
    # Routes/chemins exemptés
    path = request.path or ''
    for prefix in _POINTAGE_EXEMPT_PATHS:
        if path == prefix or path.startswith(prefix):
            return
    
    user = get_user_by_id(uid)
    if not user: return
    
    # v150 : Vérifier la permission (au lieu d'une liste de rôles en dur)
    try:
        user_perms = get_role_permissions(user['role'])
    except: user_perms = []
    
    # Admin n'est jamais forcé (sauf si on lui retire spécifiquement la perm 'admin')
    if user['role'] == 'admin' and 'admin' in user_perms:
        return
    
    # v150 : Si la permission 'pointage_force_arrival' n'est pas attribuée, on ne force pas
    if 'pointage_force_arrival' not in user_perms:
        return
    
    # v149 : Si l'utilisateur a déjà pointé son départ → déconnexion (sauf si auto_logout désactivé)
    if _user_has_pointed_today(uid, 'depart'):
        if 'pointage_auto_logout_closure' in user_perms:
            session.clear()
            flash("🌙 Votre journée est clôturée (pointage départ effectué). Reconnectez-vous demain.", "info")
            return redirect('/login')
    
    # Si pas encore pointé arrivée → forcer le pointage
    if not _user_has_pointed_today(uid, 'arrivee'):
        flash("⏰ Pointage d'arrivée obligatoire avant d'accéder au logiciel.", "warning")
        return redirect('/pointage')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        ip = request.remote_addr
        
        # Rate limiting par IP (anti brute-force distribué)
        if not _check_login_rate_limit(ip):
            flash("⛔ Trop de tentatives échouées depuis votre adresse IP. Réessayez dans 5 minutes.", "error")
            return render_template('login.html'), 429
        
        # Vérifier verrouillage par compte (5 tentatives en 15 min)
        if get_failed_attempts(username) >= 5:
            _record_login_attempt(ip, False)
            flash("Compte temporairement verrouillé (trop de tentatives). Réessayez dans 15 minutes.", "error")
            return render_template('login.html')
        
        user = authenticate_user(username, request.form['password'])
        if user:
            _record_login_attempt(ip, True)
            record_login_attempt(username, True, ip)
            from models import log_security_event
            log_security_event('login_success', user_id=user['id'], username=user['full_name'],
                ip=ip, user_agent=request.headers.get('User-Agent',''), severity='info')
            # ===== 2FA : si activé, ne pas finaliser la session, demander code =====
            if user.get('totp_enabled') and user.get('totp_secret'):
                session.clear()
                session['_pending_2fa_user_id'] = user['id']
                session['_pending_2fa_username'] = user['full_name']
                session['_pending_2fa_ip'] = ip
                return redirect(url_for('login_2fa'))
            # Régénération du session ID pour empêcher la session fixation
            session.clear()
            session['user_id'] = user['id']
            session['last_active'] = datetime.now().isoformat()
            session.permanent = True
            log_activity(user['id'], user['full_name'], 'Connexion', f"Connexion réussie", ip)
            flash(f"Bienvenue {user['full_name']} !", "success")
            if user['role'] == 'client':
                return redirect('/portail/dashboard')
            return redirect(url_for('dashboard'))
        
        # Try client_users table
        conn = _gdb()
        import hashlib
        cu = conn.execute("SELECT * FROM client_users WHERE username=? AND is_active=1", (username,)).fetchone()
        if cu:
            cu = dict(cu)
            ph = hashlib.sha256((request.form['password'] + (cu.get('salt','') or '')).encode()).hexdigest()
            if ph == cu['password_hash']:
                _record_login_attempt(ip, True)
                session.clear()
                session['client_user_id'] = cu['id']
                session['client_id'] = cu['client_id']
                session['client_name'] = cu['full_name']
                session.permanent = True
                conn.execute("UPDATE client_users SET last_login=? WHERE id=?", (datetime.now().isoformat(), cu['id']))
                conn.commit(); conn.close()
                record_login_attempt(username, True, ip)
                flash(f"Bienvenue {cu['full_name']} !", "success")
                return redirect('/portail/dashboard')
        conn.close()
        
        _record_login_attempt(ip, False)
        record_login_attempt(username, False, ip)
        try:
            from models import log_security_event
            log_security_event('login_failed', username=username, ip=ip,
                user_agent=request.headers.get('User-Agent',''),
                details=f"Failed login for {username}", severity='warning')
        except: pass
        remaining = 5 - get_failed_attempts(username)
        flash(f"Identifiants incorrects ({remaining} tentative(s) restante(s))", "error")
    return render_template('login.html')

@app.route('/register', methods=['GET', 'POST'])
@login_required
def register():
    # Only admin can create users
    u = get_user_by_id(session['user_id'])
    if u['role'] not in ('admin', 'dg'):
        flash("Seul l'administrateur peut créer des comptes", "error")
        return redirect('/dashboard')
    if request.method == 'POST':
        pwd = request.form['password']
        pwd2 = request.form['password2']
        if pwd != pwd2:
            flash("Les mots de passe ne correspondent pas", "error")
            return render_template('register.html')
        if len(pwd) < 6:
            flash("Le mot de passe doit faire au moins 6 caractères", "error")
            return render_template('register.html')
        role = request.form.get('role', 'technicien')
        ok, msg = create_user(
            request.form['username'], request.form['email'],
            pwd, request.form['full_name'], role
        )
        if ok:
            flash(f"Compte '{request.form['username']}' créé avec le rôle {role} !", "success")
            return redirect('/admin')
        flash(msg, "error")
    return render_template('register.html')

