@app.route('/traitement/generate', methods=['POST'])
@permission_required('traitement')
def traitement_generate():
    merge_id = request.form.get('merge_id', '').strip()
    
    if merge_id:
        merge_dir = os.path.join(app.config['UPLOAD_FOLDER'], merge_id)
        merged_file = os.path.join(merge_dir, 'Presence_fusionnee.xlsx')
        if not os.path.exists(merged_file):
            flash("Fichier fusionné expiré. Refaites la fusion.", "error")
            return redirect(url_for('traitement'))
        xlsx_source = merged_file
        filename = 'Presence_fusionnee.xlsx'
    else:
        if 'excel_file' not in request.files or not request.files['excel_file'].filename:
            flash("Aucun fichier sélectionné", "error")
            return redirect(url_for('traitement'))
        file = request.files['excel_file']
        if not allowed_file(file.filename):
            flash("Format non supporté", "error")
            return redirect(url_for('traitement'))
        xlsx_source = None
        filename = secure_filename(file.filename)
    
    provider_name = request.form.get('provider_name', '').strip() or "RAMYA TECHNOLOGIE & INNOVATION"
    provider_info = request.form.get('provider_info', '').strip() or "Tél: 2722204498 | Email: techniqueramya@gmail.com"
    client_name = request.form.get('client_name', '').strip()
    client_tel = request.form.get('client_tel', '').strip()
    client_email = request.form.get('client_email', '').strip()
    client_id_str = request.form.get('client_id', '').strip()
    hp_str = request.form.get('required_hours', '0').strip()
    hp_we_str = request.form.get('required_hours_weekend', '0').strip()
    hourly_cost_str = request.form.get('hourly_cost', '0').strip()
    employee_costs_json = request.form.get('employee_costs_json', '{}')
    
    # v73 : Pause globale optionnelle
    global_has_pause = request.form.get('global_has_pause') == '1'
    global_pause_minutes = 0
    if global_has_pause:
        try:
            gps = request.form.get('global_pause_start', '12:00')
            gpe = request.form.get('global_pause_end', '13:00')
            sh, sm = map(int, gps.split(':'))
            eh, em = map(int, gpe.split(':'))
            global_pause_minutes = max(0, (eh*60 + em) - (sh*60 + sm))
        except:
            global_pause_minutes = 60

    
    # Auto-fill from client database
    client_id = int(client_id_str) if client_id_str else None
    if client_id:
        db_client = get_client_by_id(client_id)
        if db_client:
            if not client_name: client_name = db_client['name']
            if not client_tel: client_tel = db_client.get('tel', '')
            if not client_email: client_email = db_client.get('email', '')
    
    client_info_parts = []
    if client_tel: client_info_parts.append(f"Tél: {client_tel}")
    if client_email: client_info_parts.append(f"Email: {client_email}")
    client_info = " | ".join(client_info_parts)
    
    try:
        hp = float(hp_str) if hp_str else 0
    except:
        hp = 0
    try:
        hp_weekend = float(hp_we_str) if hp_we_str else 0
    except:
        hp_weekend = 0
    try:
        hourly_cost = float(hourly_cost_str) if hourly_cost_str else 0
    except:
        hourly_cost = 0
    try:
        employee_costs = json.loads(employee_costs_json) if employee_costs_json else {}
    except:
        employee_costs = {}
    
    # Rest days
    rest_days = request.form.getlist('rest_days')
    try:
        employee_rest_days = json.loads(request.form.get('employee_rest_days_json', '{}'))
    except:
        employee_rest_days = {}
    
    # NOUVEAU v46 : jours obligatoires (saisie manuelle, applique à TOUS) + jours non ouvrables du calendrier
    days_required_raw = (request.form.get('days_required', '') or '').strip()
    days_required_default = None
    if days_required_raw and days_required_raw.isdigit():
        v = int(days_required_raw)
        if 0 < v <= 31:
            days_required_default = v
    # Liste de jours non ouvrables sélectionnés sur calendrier (CSV "2026-04-15,2026-04-16")
    non_working_days_raw = (request.form.get('non_working_days', '') or '').strip()
    non_working_days_set = set()
    if non_working_days_raw:
        for d in non_working_days_raw.split(','):
            d = d.strip()
            if d and len(d) == 10:
                non_working_days_set.add(d)
    
    # NOUVEAU v50 : override par employé (dict name -> nb_jours)
    try:
        employee_days_required = json.loads(request.form.get('employee_days_required_json', '{}'))
        # Validation : valeurs entières entre 1 et 31
        employee_days_required = {k: int(v) for k, v in employee_days_required.items()
                                   if isinstance(v, (int, float)) and 0 < int(v) <= 31}
    except:
        employee_days_required = {}
    
    # NOUVEAU v57 : override heures par jour par employé (dict name -> nb_heures)
    try:
        employee_hours = json.loads(request.form.get('employee_hours_json', '{}'))
        employee_hours = {k: float(v) for k, v in employee_hours.items()
                          if isinstance(v, (int, float)) and 0 < float(v) <= 24}
    except:
        employee_hours = {}
    
    # NOUVEAU v54 : override des emplois du temps (par personne, groupe, ou tous)
    # Format : {"all": {start, end, has_pause, pause_start, pause_end} ou null,
    #          "groups": [{name, members[], start, end, has_pause, pause_start, pause_end}],
    #          "persons": {name: {start, end, has_pause, pause_start, pause_end}}}
    raw_override = request.form.get('schedule_override_json', '{}')
    print(f"[traitement_generate] schedule_override_json reçu (len={len(raw_override)}): {raw_override[:300]}", flush=True)
    try:
        schedule_override = json.loads(raw_override)
        if not isinstance(schedule_override, dict):
            schedule_override = {}
    except:
        schedule_override = {}
    print(f"[traitement_generate] schedule_override parsé: all={bool(schedule_override.get('all'))}, "
          f"groups={len(schedule_override.get('groups',[]) or [])}, "
          f"persons={len(schedule_override.get('persons',{}) or {})}", flush=True)
    
    job_id = str(uuid.uuid4())[:8]
    job_dir = os.path.join(app.config['UPLOAD_FOLDER'], job_id)
    os.makedirs(job_dir, exist_ok=True)
    
    try:
        if xlsx_source:
            xlsx_path = os.path.join(job_dir, filename)
            shutil.copy2(xlsx_source, xlsx_path)
        else:
            file = request.files['excel_file']
            xlsx_path = os.path.join(job_dir, filename)
            file.save(xlsx_path)
        
        # Logo
        logo_path = None
        if 'logo_file' in request.files:
            lf = request.files['logo_file']
            if lf.filename:
                logo_path = os.path.join(job_dir, 'custom_logo.png')
                lf.save(logo_path)
        if not logo_path:
            for n in ['logo_ramya.png', 'logo_wannygest.png']:
                c = os.path.join(BASE_DIR, n)
                if os.path.exists(c):
                    logo_path = os.path.join(job_dir, n)
                    shutil.copy2(c, logo_path)
                    break
        
        emps, detected_client = extract_from_excel(xlsx_path)
        from models import save_known_employees
        save_known_employees([e['name'] for e in emps])
        if not emps:
            flash("Aucun employé trouvé", "error")
            return redirect(url_for('traitement'))
        
        if not client_name:
            client_name = detected_client
            # Try to find client in database
            db_client = find_client_by_name(detected_client)
            if db_client:
                client_id = db_client['id']
                if not client_tel: client_tel = db_client.get('tel', '')
                if not client_email: client_email = db_client.get('email', '')
                client_info_parts = []
                if client_tel: client_info_parts.append(f"Tél: {client_tel}")
                if client_email: client_info_parts.append(f"Email: {client_email}")
                client_info = " | ".join(client_info_parts)
        
        all_dates = [rec['date'] for emp in emps for rec in emp['records']]
        all_dates.sort()
        period = f"Période du {all_dates[0]} au {all_dates[-1]}" if all_dates else "Rapport"
        
        # Si days_required pas saisi mais jours non ouvrables sélectionnés sur calendrier
        # → calculer auto = nb jours uniques de la période - jours non ouvrables
        if days_required_default is None and non_working_days_set and all_dates:
            unique_dates = set(all_dates)
            ouvrables = unique_dates - non_working_days_set
            days_required_default = len(ouvrables)
        
        # NOUVEAU v54 : appliquer schedule_override aux records des employés
        # v64 : ajout de "days" (par jour de la semaine) et "person_days" (personne + jour)
        # Priorité (du plus prioritaire au moins prioritaire) :
        #   Personne+Jour > Personne > Groupe+Jour > Groupe > Tous+Jour > Tous > Original
        override_applied_to = []
        override_not_matched = []
        if schedule_override:
            sched_all = schedule_override.get('all')
            sched_groups = schedule_override.get('groups') or []
            sched_persons = schedule_override.get('persons') or {}
            sched_days = schedule_override.get('days') or {}            # v64 : {jour: {start,end,...}}
            sched_person_days = schedule_override.get('person_days') or {}  # v64 : {nom: {jour: {...}}}
            sched_group_days = schedule_override.get('group_days') or []   # v64 : groupes avec days={...}
            
            # Helper : normalisation pour matching tolérant
            def _norm(s): return ''.join((s or '').strip().upper().split())
            
            # Helper : nom du jour de la semaine en français pour une date
            from datetime import datetime as _dt2
            _DAY_NAMES = ['lundi','mardi','mercredi','jeudi','vendredi','samedi','dimanche']
            def _day_of(date_str):
                try:
                    d = _dt2.strptime(date_str[:10], '%Y-%m-%d')
                    return _DAY_NAMES[d.weekday()]
                except:
                    return None
            
            # Pour chaque (employé, record) appliquer la priorité
            for emp in emps:
                norm_key = _norm(emp['name'])
                # Person-level overrides applicables à cet employé
                pers_sch = None
                for pname, psched in sched_persons.items():
                    if _norm(pname) == norm_key and isinstance(psched, dict) and psched.get('start') and psched.get('end'):
                        pers_sch = psched; break
                pers_days = sched_person_days.get(emp['name']) or {}
                # tolérant : essayer de retrouver via _norm
                if not pers_days:
                    for pname, pdays in sched_person_days.items():
                        if _norm(pname) == norm_key:
                            pers_days = pdays; break
                # Group-level
                grp_sch = None
                grp_days = {}
                for grp in sched_groups:
                    if not isinstance(grp, dict): continue
                    members = grp.get('members') or []
                    if not members: continue
                    if any(_norm(m) == norm_key for m in members):
                        if grp.get('start') and grp.get('end'):
                            grp_sch = grp
                        if isinstance(grp.get('days'), dict):
                            grp_days = grp['days']
                        break
                
                applied_for_this_emp = False
                for rec in emp['records']:
                    day_name = _day_of(rec.get('date',''))
                    chosen = None
                    # Priorité descendante
                    if day_name and pers_days.get(day_name) and pers_days[day_name].get('start') and pers_days[day_name].get('end'):
                        chosen = pers_days[day_name]
                    elif pers_sch:
                        chosen = pers_sch
                    elif day_name and grp_days.get(day_name) and grp_days[day_name].get('start') and grp_days[day_name].get('end'):
                        chosen = grp_days[day_name]
                    elif grp_sch:
                        chosen = grp_sch
                    elif day_name and sched_days.get(day_name) and sched_days[day_name].get('start') and sched_days[day_name].get('end'):
                        chosen = sched_days[day_name]
                    elif sched_all and isinstance(sched_all, dict) and sched_all.get('start') and sched_all.get('end'):
                        chosen = sched_all
                    
                    if chosen:
                        # v121 FIX DÉFINITIF : NE PAS écraser sched_start/sched_end.
                        # Auparavant, le matching écrasait ces valeurs et cassait les heures
                        # obligatoires. On stocke maintenant le matching dans des champs
                        # séparés (_matched). Les heures du fichier source restent intactes.
                        # 'sched_start_original' est gardé pour compat ascendante.
                        if 'sched_start_original' not in rec:
                            rec['sched_start_original'] = rec.get('sched_start', '')
                            rec['sched_end_original'] = rec.get('sched_end', '')
                        rec['sched_start_matched'] = chosen['start']
                        rec['sched_end_matched'] = chosen['end']
                        # IMPORTANT : on n'écrase PAS rec['sched_start'] et rec['sched_end']
                        # Ils gardent la valeur du fichier source pour les calculs.
                        applied_for_this_emp = True
                
                if applied_for_this_emp:
                    override_applied_to.append(emp['name'])
            
            # Détecter overrides non-matched (saisis mais pas trouvés dans le fichier)
            existing_norms = {_norm(e['name']) for e in emps}
            for pname in sched_persons.keys():
                if _norm(pname) not in existing_norms:
                    override_not_matched.append(pname)
            for pname in sched_person_days.keys():
                if _norm(pname) not in existing_norms and pname not in override_not_matched:
                    override_not_matched.append(pname)
        
        # Flash de feedback (visible après génération)
        if override_applied_to:
            flash(f"🕒 EDT personnalisé appliqué à {len(override_applied_to)} employé(s) : "
                  + ", ".join(override_applied_to[:5])
                  + ("..." if len(override_applied_to) > 5 else ""), "success")
        if override_not_matched:
            flash(f"⚠️ Overrides non appliqués (employé non trouvé dans le fichier) : "
                  + ", ".join(override_not_matched), "warning")
        
        base = os.path.splitext(filename)[0]
        pdf_name = f"{base}_RAPPORT_DE_PRESENCE.pdf"
        output_path = os.path.join(job_dir, pdf_name)
        
        # v126 : Lire le checkbox d'inversion auto (par défaut désactivé)
        _auto_inv_night = str(request.form.get('auto_invert_night', '')).strip().lower() in ('1', 'true', 'on', 'yes')
        
        generate_full_pdf(emps, output_path, provider_name, provider_info,
                         client_name, period, logo_path, hp=hp, client_info=client_info,
                         work_dir=job_dir, hp_weekend=hp_weekend, hourly_cost=hourly_cost,
                         employee_costs=employee_costs, rest_days=rest_days,
                         employee_rest_days=employee_rest_days,
                         days_required_default=days_required_default,
                         employee_days_required=employee_days_required,
                         employee_hours=employee_hours,
                         pause_minutes=global_pause_minutes,
                         auto_invert_night=_auto_inv_night)
        
        if not os.path.exists(output_path):
            flash("Erreur génération PDF", "error")
            return redirect(url_for('traitement'))
        
        # Sauvegarder dans le dossier files
        files_dir = os.path.join(app.config['FILES_FOLDER'], job_id)
        os.makedirs(files_dir, exist_ok=True)
        shutil.copy2(output_path, os.path.join(files_dir, pdf_name))
        
        # Copier le xlsx fusionné si dispo
        xlsx_out = None
        if merge_id:
            merged_xlsx = os.path.join(app.config['UPLOAD_FOLDER'], merge_id, 'Presence_fusionnee.xlsx')
            if os.path.exists(merged_xlsx):
                xlsx_out = 'Presence_fusionnee.xlsx'
                shutil.copy2(merged_xlsx, os.path.join(files_dir, xlsx_out))
        
        # Enregistrer dans la BDD
        hp_text = f"{hp}h/sem" if hp > 0 else "Auto"
        if hp_weekend > 0: hp_text += f" | {hp_weekend}h/we"
        create_job(job_id, session['user_id'], client_name, provider_name,
                   filename, pdf_name, xlsx_out, len(emps), period, hp_text, client_id)
        
        user = get_user_by_id(session['user_id'])
        log_activity(session['user_id'], user['full_name'] if user else '?',
                    'Traitement', f"Rapport PDF généré — {client_name}, {len(emps)} employés",
                    request.remote_addr)
        flash(f"Rapport généré avec succès — {len(emps)} employés, {client_name}", "success")
        return send_file(output_path, as_attachment=True, download_name=pdf_name, mimetype='application/pdf')
    
    except Exception as e:
        flash(f"Erreur : {str(e)}", "error")
        return redirect(url_for('traitement'))
    finally:
        _cleanup_old(app.config['UPLOAD_FOLDER'])


