@app.route('/clients')
@permission_required('clients')
def clients_page():
    clients = get_all_clients()
    # v119 : can_edit pour masquer les boutons d'action en lecture seule
    user = get_user_by_id(session['user_id'])
    perms = get_role_permissions(user['role']) if user else []
    can_edit = ('clients_edit' in perms or 'admin' in perms)
    return render_template('clients.html', page='clients', clients=clients, can_edit=can_edit)


# ═══════════════════════════════════════════════════════════════════
# v131 : CRM > Nouveau Projet — Liste les remontées transformées en
# projet ou opportunité, en attente de création du projet roadmap
# ═══════════════════════════════════════════════════════════════════
@app.route('/crm/nouveau-projet')
@permission_required_any('clients', 'resp_projet', 'admin')
def crm_nouveau_projet():
    """v131 : Onglet CRM > Nouveau Projet. Liste les remontées avec statut
    'transformee_projet' ou 'transformee_opportunite' qui n'ont pas encore
    été converties en projet roadmap. Lien direct vers création de projet."""
    conn = _gdb()
    
    filter_type = (request.args.get('type', '') or '').strip()  # 'projet' | 'opportunite' | ''
    
    where_clauses = ["statut IN ('transformee_projet', 'transformee_opportunite')"]
    params = []
    if filter_type == 'projet':
        where_clauses = ["statut = 'transformee_projet'"]
    elif filter_type == 'opportunite':
        where_clauses = ["statut = 'transformee_opportunite'"]
    
    where_sql = ' AND '.join(where_clauses)
    
    # Liste avec infos d'origine
    reports = [dict(r) for r in conn.execute(f"""
        SELECT * FROM field_reports
        WHERE {where_sql}
        ORDER BY decision_date DESC NULLS LAST, updated_at DESC
    """, tuple(params)).fetchall()]
    
    # Enrichir : statut label, type label, priorité
    for r in reports:
        r['_is_projet'] = r['statut'] == 'transformee_projet'
        r['_is_opportunite'] = r['statut'] == 'transformee_opportunite'
        r['_type_origin_label'] = FIELD_REPORT_TYPES.get(r.get('type_info'), r.get('type_info'))
        pl = FIELD_REPORT_PRIORITIES.get(r.get('priorite'), (r.get('priorite'), '#888'))
        r['_prio_label'] = pl[0]
        r['_prio_color'] = pl[1]
        # Indique si déjà converti en projet (linked_project_id rempli)
        r['_is_converted'] = bool(r.get('linked_project_id'))
    
    # Compteurs
    counts = {
        'projet': sum(1 for r in reports if r['_is_projet']),
        'opportunite': sum(1 for r in reports if r['_is_opportunite']),
        'converted': sum(1 for r in reports if r['_is_converted']),
        'pending': sum(1 for r in reports if not r['_is_converted']),
    }
    counts['total'] = len(reports)
    
    conn.close()
    return render_template('crm_nouveau_projet.html', page='crm_nouveau_projet',
        reports=reports, counts=counts, filter_type=filter_type)


@app.route('/clients/export')
@permission_required('clients')
def clients_export():
    """Exporte la base clients (clients + prospects) en Excel."""
    import openpyxl
    from openpyxl.styles import Font, PatternFill, Alignment
    from flask import Response
    import io as _io
    
    clients = get_all_clients()
    
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Clients"
    
    headers = ['ID', 'Type', 'Nom', 'Contact', 'Téléphone', 'Email', 'Adresse', 'Notes', 'Date création']
    fields = ['id', 'type', 'name', 'contact_name', 'tel', 'email', 'address', 'notes', 'created_at']
    widths = [6, 12, 28, 22, 14, 22, 28, 30, 18]
    
    for col, h in enumerate(headers, 1):
        cell = ws.cell(row=1, column=col, value=h)
        cell.font = Font(bold=True, color='FFFFFF', size=10)
        cell.fill = PatternFill(start_color='1A7A6D', end_color='1A7A6D', fill_type='solid')
        cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
        ws.column_dimensions[openpyxl.utils.get_column_letter(col)].width = widths[col-1] if col-1 < len(widths) else 16
    ws.row_dimensions[1].height = 26
    
    for r, cli in enumerate(clients, 2):
        for c, field in enumerate(fields, 1):
            val = cli.get(field, '') if isinstance(cli, dict) else getattr(cli, field, '')
            ws.cell(row=r, column=c, value=val if val is not None else '')
    
    buf = _io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    
    try:
        log_activity(session.get('user_id'),
                    get_user_by_id(session['user_id'])['full_name'],
                    'Clients', f"Export base clients ({len(clients)} entrées)",
                    request.remote_addr)
    except: pass
    
    from datetime import datetime as _dt83
    fname = f"clients_{_dt83.now().strftime('%Y%m%d_%H%M')}.xlsx"
    return Response(buf.getvalue(),
                   mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                   headers={'Content-Disposition': f'attachment; filename="{fname}"'})


# v83 : Convertir un client en prospect (et inversement)
@app.route('/clients/<int:cid>/toggle-type')
@permission_required('clients_edit')
def clients_toggle_type(cid):
    """Bascule le type entre 'client' et 'prospect'."""
    conn = _gdb()
    row = conn.execute("SELECT type, name FROM clients WHERE id=?", (cid,)).fetchone()
    if not row:
        conn.close()
        flash("Client introuvable", "error")
        return redirect('/clients')
    current_type = row['type'] or 'client'
    new_type = 'prospect' if current_type == 'client' else 'client'
    conn.execute("UPDATE clients SET type=? WHERE id=?", (new_type, cid))
    conn.commit(); conn.close()
    
    try:
        log_activity(session.get('user_id'), get_user_by_id(session['user_id'])['full_name'],
                    'Clients', f"{row['name']} : {current_type} → {new_type}", request.remote_addr)
    except: pass
    
    label = "🎯 Prospect" if new_type == 'prospect' else "✅ Client"
    flash(f"{row['name']} converti en {label}", "success")
    return redirect('/clients')


@app.route('/clients/<int:cid>')
@permission_required('clients')
def client_profile(cid):
    conn = _gdb()
    client = conn.execute("SELECT * FROM clients WHERE id=?", (cid,)).fetchone()
    if not client: flash("Client non trouvé","error"); return redirect('/clients')
    client = dict(client)
    tab = request.args.get('tab', 'profil')
    data = {'tab': tab, 'client': client}
    
    # Notes
    try: data['notes'] = [dict(r) for r in conn.execute("SELECT n.*, u.full_name as author FROM client_notes n LEFT JOIN users u ON n.created_by=u.id WHERE n.client_id=? ORDER BY n.created_at DESC", (cid,)).fetchall()]
    except: data['notes'] = []
    # Devis
    try: data['devis'] = [dict(r) for r in conn.execute("SELECT * FROM devis WHERE client_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['devis'] = []
    # Factures
    try: data['factures'] = [dict(r) for r in conn.execute("SELECT * FROM invoices WHERE client_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['factures'] = []
    # Contrats
    try: data['contrats'] = [dict(r) for r in conn.execute("SELECT * FROM achats_contrats WHERE fournisseur_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['contrats'] = []
    # Visites
    try: data['visites'] = [dict(r) for r in conn.execute("SELECT * FROM visits WHERE client_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['visites'] = []
    # Tickets
    try: data['tickets'] = [dict(r) for r in conn.execute("SELECT * FROM tickets WHERE client_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['tickets'] = []
    # Projets
    try: data['projets'] = [dict(r) for r in conn.execute("SELECT * FROM projects WHERE client_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['projets'] = []
    # Attachments
    try: data['attachments'] = [dict(r) for r in conn.execute("SELECT * FROM client_attachments WHERE client_id=? ORDER BY created_at DESC", (cid,)).fetchall()]
    except: data['attachments'] = []
    # Reminders
    try: data['reminders'] = [dict(r) for r in conn.execute("SELECT * FROM client_reminders WHERE client_id=? ORDER BY date ASC", (cid,)).fetchall()]
    except: data['reminders'] = []
    # Pieces caisse (expenses linked to client)
    try: data['depenses'] = [dict(r) for r in conn.execute("SELECT * FROM pieces_caisse WHERE supplier LIKE ? ORDER BY date DESC", (f'%{client["name"]}%',)).fetchall()]
    except: data['depenses'] = []
    
    conn.close()
    return render_template('extra_pages.html', page='client_profile', **data)

