def dpci_page():
    return render_template('dpci.html', page='dpci')

@app.route('/dpci/preview', methods=['POST'])
@login_required
def dpci_preview():
    if 'excel_file' not in request.files:
        return jsonify({"error": "Fichier requis"}), 400
    f = request.files['excel_file']
    if not f.filename:
        return jsonify({"error": "Fichier vide"}), 400
    
    import tempfile
    tmp = os.path.join(tempfile.gettempdir(), f'dpci_{uuid.uuid4().hex[:8]}.xlsx')
    f.save(tmp)
    try:
        from rapport_core import parse_dpci_excel
        emps, period = parse_dpci_excel(tmp)
        
        # Save known employees
        from models import save_known_employees
        save_known_employees([e['name'] for e in emps])
        
        # Extract client from department (first part before >)
        client = ''
        if emps:
            dept = emps[0].get('department', '')
            if '>' in dept:
                client = dept.split('>')[1].strip()
            else:
                client = dept
        
        return jsonify({
            "count": len(emps),
            "period": period,
            "client": client,
            "employees": [{"name": e['name'], "id": e['id'], "dept": e['department'], "days": len(e['records'])} for e in emps]
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    finally:
        if os.path.exists(tmp): os.remove(tmp)

@app.route('/dpci/generate', methods=['POST'])
@permission_required('traitement')
def dpci_generate():
    if 'excel_file' not in request.files:
        flash("Fichier requis", "error")
        return redirect('/dpci')
    
    f = request.files['excel_file']
    client_name = request.form.get('client_name', '').strip() or 'DPCI'
    provider_name = request.form.get('provider_name', '').strip() or 'RAMYA TECHNOLOGIE & INNOVATION'
    default_cost = float(request.form.get('default_cost', 0) or 0)
    try:
        hp = float(request.form.get('required_hours', 0) or 0)
    except:
        hp = 0
    try:
        hp_weekend = float(request.form.get('required_hours_weekend', 0) or 0)
    except:
        hp_weekend = 0
    
    try:
        employee_costs = json.loads(request.form.get('employee_costs_json', '{}'))
    except:
        employee_costs = {}
    
    # v73 : Pause globale optionnelle
    global_has_pause = request.form.get('global_has_pause') == '1'
    global_pause_minutes = 0
    if global_has_pause:
        try:
            gps = request.form.get('global_pause_start', '12:00')
            gpe = request.form.get('global_pause_end', '13:00')
            sh, sm = map(int, gps.split(':'))
            eh, em = map(int, gpe.split(':'))
            global_pause_minutes = max(0, (eh*60 + em) - (sh*60 + sm))
        except:
            global_pause_minutes = 60
    
    # Save file
    job_id = str(uuid.uuid4())[:8]
    job_dir = os.path.join(app.config['UPLOAD_FOLDER'], f'dpci_{job_id}')
    os.makedirs(job_dir, exist_ok=True)
    
    xlsx_path = os.path.join(job_dir, secure_filename(f.filename))
    f.save(xlsx_path)
    
    try:
        from rapport_core import parse_dpci_excel, generate_dpci_pdf
        emps, period = parse_dpci_excel(xlsx_path)
        
        if not emps:
            flash("Aucun employé trouvé dans le fichier", "error")
            return redirect('/dpci')
        
        # Filter by period
        period_mode = request.form.get('period_mode', 'all')
        period_start = request.form.get('period_start', '').strip()
        period_end = request.form.get('period_end', '').strip()
        
        if period_mode == 'day' and period_start:
            period_end = period_start
        elif period_mode == 'week' and period_start:
            from datetime import datetime as dt2, timedelta
            try:
                d = dt2.strptime(period_start, '%Y-%m-%d')
                period_end = (d + timedelta(days=6)).strftime('%Y-%m-%d')
            except: pass
        
        if period_start or period_end:
            for emp in emps:
                emp['records'] = [r for r in emp['records'] 
                    if (not period_start or r['date'] >= period_start) and 
                       (not period_end or r['date'] <= period_end)]
            emps = [e for e in emps if e['records']]
        
        if not emps:
            flash("Aucun enregistrement pour la période sélectionnée", "error")
            return redirect('/dpci')
        
        # Build period string
        all_dates = sorted([r['date'] for e in emps for r in e['records']])
        if all_dates:
            period_str = f"Débuté le {all_dates[0]} au {all_dates[-1]}"
        elif period:
            parts = period.split(' - ')
            period_str = f"Débuté le {parts[0].strip()} au {parts[-1].strip()}" if len(parts) > 1 else period
        else:
            period_str = "Rapport DPCI"
        conn = _gdb()
        scheds = [dict(r) for r in conn.execute("SELECT * FROM schedules").fetchall()]
        conn.close()
        
        schedules_map = {}
        for s in scheds:
            name = s['employee_name']
            if name not in schedules_map:
                schedules_map[name] = s  # Use first found (e.g., Monday schedule)
        
        # v82 : Sauvegarder l'EDT d'origine (avant matching) pour l'affichage Planning
        # Le matching modifiera schedules_map pour les calculs, mais l'affichage
        # gardera les EDT originaux du fichier/BDD pour respecter le souhait utilisateur
        schedules_map_original = {name: dict(s) for name, s in schedules_map.items()}
        
        # v62 NOUVEAU : appliquer schedule_override aux employés
        # v64 : ajout du support "days" (par jour de semaine) et "person_days" (personne+jour)
        try:
            schedule_override = json.loads(request.form.get('schedule_override_json', '{}'))
            if not isinstance(schedule_override, dict):
                schedule_override = {}
        except:
            schedule_override = {}
        print(f"[dpci_generate] schedule_override reçu: all={bool(schedule_override.get('all'))}, "
              f"groups={len(schedule_override.get('groups',[]) or [])}, "
              f"persons={len(schedule_override.get('persons',{}) or {})}, "
              f"days={len(schedule_override.get('days',{}) or {})}, "
              f"person_days={len(schedule_override.get('person_days',{}) or {})}", flush=True)
        
        schedules_per_day_map = {}  # v64 : {emp_name: {jour: {start_time, end_time, ...}}}
        
        if schedule_override:
            sched_all = schedule_override.get('all')
            sched_groups = schedule_override.get('groups') or []
            sched_persons = schedule_override.get('persons') or {}
            sched_days = schedule_override.get('days') or {}
            sched_person_days = schedule_override.get('person_days') or {}
            
            # Helper : normalisation pour matching tolérant
            def _norm(s): return ''.join((s or '').strip().upper().split())
            
            # Construire schedules_map (override total) ET schedules_per_day_map (par jour) pour chaque employé
            override_count = 0
            for emp in emps:
                norm_key = _norm(emp['name'])
                # Trouver les overrides applicables (priorité : Person > Group > Tous)
                pers_sch = None
                pers_days_dict = None
                for pname, psched in sched_persons.items():
                    if _norm(pname) == norm_key and isinstance(psched, dict) and psched.get('start') and psched.get('end'):
                        pers_sch = psched; break
                for pname, pdays in sched_person_days.items():
                    if _norm(pname) == norm_key and isinstance(pdays, dict):
                        pers_days_dict = pdays; break
                
                grp_sch = None
                grp_days_dict = None
                for grp in sched_groups:
                    if not isinstance(grp, dict): continue
                    members = grp.get('members') or []
                    if any(_norm(m) == norm_key for m in members):
                        if grp.get('start') and grp.get('end'):
                            grp_sch = grp
                        if isinstance(grp.get('days'), dict):
                            grp_days_dict = grp['days']
                        break
                
                # Le schedule de base le plus prioritaire
                final_sched = pers_sch or grp_sch or (sched_all if (sched_all and isinstance(sched_all,dict) and sched_all.get('start') and sched_all.get('end')) else None)
                if final_sched:
                    schedules_map[emp['name']] = {
                        'employee_name': emp['name'],
                        'start_time': final_sched.get('start'),
                        'end_time': final_sched.get('end'),
                        'break_start': final_sched.get('pause_start', '12:00') if final_sched.get('has_pause', False) else None,
                        'break_end': final_sched.get('pause_end', '13:00') if final_sched.get('has_pause', False) else None,
                    }
                    override_count += 1
                
                # Construire schedules_per_day pour cet employé (priorité : Person+Day > Group+Day > Tous+Day)
                per_day = {}
                _DAYS = ['lundi','mardi','mercredi','jeudi','vendredi','samedi','dimanche']
                for dn in _DAYS:
                    chosen_d = None
                    if pers_days_dict and pers_days_dict.get(dn) and pers_days_dict[dn].get('start') and pers_days_dict[dn].get('end'):
                        chosen_d = pers_days_dict[dn]
                    elif grp_days_dict and grp_days_dict.get(dn) and grp_days_dict[dn].get('start') and grp_days_dict[dn].get('end'):
                        chosen_d = grp_days_dict[dn]
                    elif sched_days and sched_days.get(dn) and sched_days[dn].get('start') and sched_days[dn].get('end'):
                        chosen_d = sched_days[dn]
                    if chosen_d:
                        per_day[dn] = {
                            'start_time': chosen_d.get('start'),
                            'end_time': chosen_d.get('end'),
                            'break_start': chosen_d.get('pause_start', '12:00') if chosen_d.get('has_pause', False) else None,
                            'break_end': chosen_d.get('pause_end', '13:00') if chosen_d.get('has_pause', False) else None,
                        }
                if per_day:
                    schedules_per_day_map[emp['name']] = per_day
                    if not final_sched:
                        override_count += 1  # compté comme override aussi
            
            print(f"[dpci_generate] Override appliqué à {override_count} employé(s) (per_day_map={len(schedules_per_day_map)})", flush=True)
            if override_count > 0:
                flash(f"🕒 EDT personnalisé appliqué à {override_count} employé(s)", "success")
        
        # Generate PDF
        pdf_name = f"DPCI_{client_name.replace(' ', '_')}_{job_id}.pdf"
        output_path = os.path.join(job_dir, pdf_name)
        
        user = get_user_by_id(session['user_id'])
        treated_by = user['full_name'] if user else 'Admin'
        
        # v73 : Si pause globale activée, injecter break_start/end dans tous les schedules
        if global_has_pause and global_pause_minutes > 0:
            gps_v = request.form.get('global_pause_start', '12:00')
            gpe_v = request.form.get('global_pause_end', '13:00')
            for emp in emps:
                if emp['name'] not in schedules_map:
                    # Créer un schedule minimal avec juste la pause
                    schedules_map[emp['name']] = {
                        'employee_name': emp['name'],
                        'start_time': '', 'end_time': '',
                        'break_start': gps_v, 'break_end': gpe_v,
                    }
                else:
                    # Override pause sur schedule existant
                    schedules_map[emp['name']] = dict(schedules_map[emp['name']])
                    schedules_map[emp['name']]['break_start'] = gps_v
                    schedules_map[emp['name']]['break_end'] = gpe_v
            # Aussi sur les per-day overrides
            for name, per_day in schedules_per_day_map.items():
                for dn, day_s in per_day.items():
                    if not day_s.get('break_start'):
                        day_s['break_start'] = gps_v
                        day_s['break_end'] = gpe_v
        
        # v82 : Propager l'EDT d'origine (avant matching) sur chaque record
        # pour que generate_dpci_pdf affiche le Planning d'origine.
        # Si pas d'EDT en BDD, on utilise les defaults 07:00-17:00 (ceux de calc_dpci_stats)
        # pour garantir que l'affichage Planning ne change PAS après matching.
        for emp in emps:
            orig = schedules_map_original.get(emp['name'])
            if orig:
                orig_s = orig.get('start_time', '') or '07:00'
                orig_e = orig.get('end_time', '') or '17:00'
            else:
                # Pas d'EDT en BDD → utiliser les defaults DPCI
                orig_s = '07:00'
                orig_e = '17:00'
            for rec in emp['records']:
                if 'sched_start_original' not in rec:
                    rec['sched_start_original'] = orig_s
                    rec['sched_end_original'] = orig_e
        
        generate_dpci_pdf(emps, output_path, client_name, period_str,
                         schedules_map=schedules_map, employee_costs=employee_costs,
                         default_cost=default_cost, hp=hp, hp_weekend=hp_weekend,
                         provider_name=provider_name, treated_by=treated_by, period_mode=period_mode,
                         rest_days=request.form.getlist('rest_days'),
                         schedules_per_day_map=schedules_per_day_map,
                         show_pause=global_has_pause)  # v73 : colonnes pause selon checkbox
        
        if not os.path.exists(output_path):
            flash("Erreur de génération PDF", "error")
            return redirect('/dpci')
        
        # Save to files folder
        files_dir = os.path.join(app.config['FILES_FOLDER'], f'dpci_{job_id}')
        os.makedirs(files_dir, exist_ok=True)
        shutil.copy2(output_path, os.path.join(files_dir, pdf_name))
        shutil.copy2(xlsx_path, os.path.join(files_dir, os.path.basename(xlsx_path)))
        
        # Log
        user = get_user_by_id(session['user_id'])
        log_activity(session['user_id'], user['full_name'] if user else '?',
                    'DPCI', f"Rapport {client_name} — {len(emps)} employés", request.remote_addr)
        
        flash(f"Rapport DPCI généré — {len(emps)} employés", "success")
        return send_file(output_path, as_attachment=True, download_name=pdf_name)
    
    except Exception as e:
        flash(f"Erreur: {e}", "error")
        return redirect('/dpci')


# ======================== ENVOI EMAIL ========================

@app.route('/fichiers/email/<job_id>', methods=['GET', 'POST'])
@permission_required('envoyer')
def fichiers_email(job_id):
    job = get_job_by_id(job_id)
    if not job:
        flash("Rapport non trouvé", "error")
        return redirect(url_for('fichiers'))
    
    # Pré-remplir avec les infos client
    client = get_client_by_id(job['client_id']) if job.get('client_id') else None
    default_email = client['email'] if client and client.get('email') else ''
    # v159 : montant à facturer mémorisé pour ce client (pré-remplissage)
    montant_memo = _get_rapport_montant(job.get('client_name', '') or '', "Calcul d'heures")

    if request.method == 'POST':
        to_email = request.form.get('to_email', '').strip()
        cc_email = (request.form.get('cc_email', '') or '').strip()  # v161 : destinataires en copie
        subject = request.form.get('subject', '').strip()
        body = request.form.get('body', '').strip()
        smtp_host = request.form.get('smtp_host', '').strip()
        smtp_port = int(request.form.get('smtp_port', 587))
        smtp_user = request.form.get('smtp_user', '').strip()
        smtp_pass = request.form.get('smtp_pass', '').strip()
        
        # Sauvegarder les paramètres SMTP
        if smtp_host and smtp_user:
            save_smtp_settings(session['user_id'], smtp_host, smtp_port, smtp_user, smtp_pass)
        
        if not all([to_email, subject, smtp_host, smtp_user, smtp_pass]):
            flash("Tous les champs SMTP sont obligatoires", "error")
            smtp = get_smtp_settings(session['user_id'])
            return render_template('email_send.html', page='fichiers', job=job,
                                 default_email=default_email, smtp=smtp, montant_memo=montant_memo)
        
        # Préparer le fichier PDF
        files_dir = os.path.join(app.config['FILES_FOLDER'], secure_filename(job_id))
        pdf_path = None
        if os.path.isdir(files_dir):
            for f in os.listdir(files_dir):
                if f.endswith('.pdf'):
                    pdf_path = os.path.join(files_dir, f)
                    break
        
        if not pdf_path:
            flash("Fichier PDF non trouvé", "error")
            return redirect(url_for('fichiers'))
        
        try:
            msg = MIMEMultipart()
            msg['From'] = smtp_user
            msg['To'] = to_email
            # v161 : destinataires en copie (CC) — séparés par , ou ;
            cc_list = [e.strip() for e in cc_email.replace(';', ',').split(',') if e.strip()] if cc_email else []
            if cc_list:
                msg['Cc'] = ', '.join(cc_list)
            msg['Subject'] = subject
            msg.attach(MIMEText(body, 'plain', 'utf-8'))
            
            # Joindre le PDF
            with open(pdf_path, 'rb') as f:
                part = MIMEBase('application', 'pdf')
                part.set_payload(f.read())
                encoders.encode_base64(part)
                part.add_header('Content-Disposition', f'attachment; filename="{os.path.basename(pdf_path)}"')
                msg.attach(part)
            
            server = smtplib.SMTP(smtp_host, smtp_port)
            server.starttls()
            server.login(smtp_user, smtp_pass)
            server.send_message(msg)
            server.quit()
            
            # Marquer comme envoyé
            mark_job_sent(job_id, session['user_id'])
            user = get_user_by_id(session['user_id'])
            log_activity(session['user_id'], user['full_name'] if user else '?',
                        'Email', f"Rapport envoyé par email à {to_email}", request.remote_addr)

            # v159 : si un montant à facturer est saisi → créer l'entrée « Facturation à décider »
            fac_ref = None
            try:
                montant_fac = float((request.form.get('montant_facture', '') or '0').replace(',', '.').strip() or 0)
            except ValueError:
                montant_fac = 0
            if montant_fac > 0:
                fac_ref = _creer_rapport_heures_facturation(
                    user, job.get('client_name', '') or 'Client', job.get('client_id'),
                    "Calcul d'heures", job.get('period', '') or '', montant_fac)

            if fac_ref:
                flash(f"Email envoyé à {to_email} · Rapport {fac_ref} envoyé en « Facturation à décider » ({int(montant_fac)} XOF) — le DG valide.", "success")
            else:
                flash(f"Email envoyé avec succès à {to_email}", "success")
            return redirect(url_for('fichiers'))
        
        except Exception as e:
            flash(f"Erreur d'envoi : {str(e)}", "error")
    
    smtp = get_smtp_settings(session['user_id'])
    return render_template('email_send.html', page='fichiers', job=job, default_email=default_email, smtp=smtp, montant_memo=montant_memo)


