@app.route('/devis/new', methods=['GET', 'POST'])
@permission_required('proforma_edit')
def devis_new():
    if request.method == 'POST':
      try:
        # v162 : parseurs robustes (espaces, virgules, valeurs vides) — évite les 500 « non numérique »
        def _num(v, default=0.0):
            try: return float(str(v).replace('\xa0', '').replace(' ', '').replace(',', '.') or default)
            except: return default
        def _int(v, default=1):
            try: return int(round(_num(v, default)))
            except: return default
        items = []
        i = 1
        while request.form.get(f'item_{i}_designation'):
            items.append({
                'num': i,
                'designation': request.form.get(f'item_{i}_designation', ''),
                'detail': request.form.get(f'item_{i}_detail', ''),
                'qty': _int(request.form.get(f'item_{i}_qty', 1), 1),
                'prix': _num(request.form.get(f'item_{i}_prix', 0), 0),
                'remise': _num(request.form.get(f'item_{i}_remise', 0), 0),
            })
            i += 1
        
        total_ht = sum(it['qty'] * it['prix'] - it['remise'] for it in items)
        main_oeuvre = _num(request.form.get('main_oeuvre', 0), 0)
        petites_fourn = _num(request.form.get('petites_fournitures', 0), 0)
        # v155 : Remise globale — accepte pourcentage OU montant fixe
        remise_pct_raw = (request.form.get('remise_pct', '') or '').strip()
        if remise_pct_raw:
            pct = _num(remise_pct_raw, 0)
            base_remise = total_ht + main_oeuvre + petites_fourn
            remise_glob = round(base_remise * pct / 100, 0) if pct else _num(request.form.get('remise', 0), 0)
        else:
            remise_glob = _num(request.form.get('remise', 0), 0)
        # TVA optionnelle
        tva_active = 1 if request.form.get('tva_active') in ('1','true','on','yes') else 0
        tva_rate = _num(request.form.get('tva_rate', 18), 18)
        # v160 : la MAIN D'ŒUVRE fait partie de la base HT (taxable) et du TTC
        base_ht = total_ht + main_oeuvre
        tva_amount = round((base_ht - remise_glob) * tva_rate / 100, 0) if tva_active else 0
        total_ttc = base_ht + petites_fourn - remise_glob + tva_amount

        client_id = request.form.get('client_id', '')
        client_id = _int(client_id, 0) if client_id else None
        
        # Rédacteur = utilisateur connecté + horodatage
        cur_u = get_user_by_id(session['user_id'])
        redacteur_name = (cur_u['full_name'] if cur_u else '') or 'Utilisateur'
        redacteur_dt = datetime.now().strftime('%d/%m/%Y à %H:%M')
        
        did, ref = create_devis(
            client_id, request.form.get('client_name', ''),
            request.form.get('client_code', ''),
            request.form.get('contact_commercial', ''),
            request.form.get('objet', ''),
            json.dumps(items), total_ht, petites_fourn, total_ttc,
            main_oeuvre, remise_glob,
            request.form.get('notes', ''),
            session['user_id'],
            request.form.get('doc_type', 'devis')
        )
        # Post-update extra columns (TVA + rédacteur) — defensive (columns added by v47)
        try:
            conn = _gdb()
            conn.execute("UPDATE devis SET tva_active=?, tva_rate=?, tva_amount=?, redacteur=?, redacteur_date=? WHERE id=?",
                         (tva_active, tva_rate, tva_amount, redacteur_name, redacteur_dt, did))
            conn.commit(); conn.close()
        except Exception: pass
        
        user = get_user_by_id(session['user_id'])
        log_activity(session['user_id'], user['full_name'] if user else '?',
                    'Devis', f"{ref} créé pour {request.form.get('client_name', '')}" + (f" (TVA {tva_rate:.0f}%)" if tva_active else ""), request.remote_addr)
        flash(f"Devis {ref} créé — {total_ttc:,.0f} FCFA TTC" + (f" (dont {tva_amount:,.0f} F TVA)" if tva_active else ""), "success")
        return redirect(url_for('devis_page'))
      except Exception as _e:
        import traceback as _tb
        print("[v162-DEVIS-NEW] Erreur création devis :", _e, flush=True)
        _tb.print_exc()
        flash(f"⚠️ Impossible de créer le devis : {_e}. Vérifiez les montants saisis.", "error")
        return redirect('/devis/new')

    clients = get_all_clients()
    try:
        from models import db_get_all
        stock_items = db_get_all('stock_items', order='name ASC')
    except: stock_items = []
    current_user = get_user_by_id(session['user_id'])
    default_commercial = current_user['full_name'] if current_user else ''
    return render_template('devis_new.html', page='devis', clients=clients, stock_items=stock_items,
                           default_commercial=default_commercial)

@app.route('/devis/pdf/<int:did>')
@permission_required('proforma')
def devis_pdf(did):
    devis = get_devis_by_id(did)
    if not devis:
        flash("Devis non trouvé", "error")
        return redirect(url_for('devis_page'))
    
    export_dir = os.path.join(app.config['UPLOAD_FOLDER'], 'devis')
    os.makedirs(export_dir, exist_ok=True)
    output = os.path.join(export_dir, f"{devis['reference']}.pdf")
    
    devis['date'] = devis.get('created_at', '')[:10]
    # PDF options: prefer DB-stored values; fallback to sensible defaults
    devis.setdefault('tva_active', devis.get('tva_active') or False)
    devis.setdefault('tva_rate', devis.get('tva_rate') or 18)
    devis.setdefault('tva_amount', devis.get('tva_amount') or 0)
    if not devis.get('redacteur'):
        u = get_user_by_id(devis.get('created_by')) if devis.get('created_by') else None
        devis['redacteur'] = u['full_name'] if u else ''
    if not devis.get('redacteur_date'):
        ca = devis.get('created_at', '') or ''
        if ca:
            try:
                dt = datetime.strptime(ca[:19], '%Y-%m-%d %H:%M:%S')
                devis['redacteur_date'] = dt.strftime('%d/%m/%Y à %H:%M')
            except: devis['redacteur_date'] = ca[:16]
    logo_r = next((os.path.join(BASE_DIR, n) for n in ["logo_ramya.png","logo_wannygest.png"] if os.path.exists(os.path.join(BASE_DIR, n))), None)
    generate_devis_pdf(devis, output, logo_path=logo_r, doc_params=get_doc_params())
    
    return send_file(output, as_attachment=True, download_name=f"{devis['reference']}.pdf")


@app.route('/devis/<int:did>/sign', methods=['POST'])
@permission_required('proforma')
def devis_sign(did):
    """Signature électronique d'un devis (canvas dataURL)."""
    devis = get_devis_by_id(did)
    if not devis:
        return jsonify({"error": "Devis introuvable"}), 404
    
    sig_data = request.form.get('signature_data', '').strip()
    if not sig_data or not sig_data.startswith('data:image'):
        return jsonify({"error": "Signature invalide"}), 400
    
    user = get_user_by_id(session['user_id'])
    signed_by = (request.form.get('signed_by') or '').strip() or (user['full_name'] if user else 'Signataire')
    signed_role = (request.form.get('signed_role') or '').strip() or (user.get('role','') if user else '')
    from datetime import datetime as _dt
    signed_at = _dt.now().strftime('%d/%m/%Y à %H:%M')
    
    conn = _gdb()
    conn.execute("""UPDATE devis SET signature_data=?, signed_at=?, signed_by=?, signed_role=?
                    WHERE id=?""", (sig_data, signed_at, signed_by, signed_role, did))
    conn.commit()
    conn.close()
    
    try:
        log_activity(session.get('user_id'), signed_by, 'Signature',
                    f"Devis {devis.get('reference','')} signé électroniquement", request.remote_addr)
    except: pass
    
    # v84 : Tentative de création automatique du projet (déclenchée si un acompte existe déjà)
    try:
        conn2 = _gdb()
        # Chercher une facture liée à ce devis avec un montant
        inv = conn2.execute(
            "SELECT id, amount FROM invoices WHERE notes LIKE ? OR notes LIKE ? ORDER BY id DESC LIMIT 1",
            (f"%{devis.get('reference','')}%", f"%devis%{did}%")).fetchone()
        conn2.close()
        if inv:
            _auto_create_project_if_needed(did, invoice_id=inv['id'], acompte_amount=inv['amount'])
    except: pass
    
    return jsonify({"ok": True, "signed_at": signed_at, "signed_by": signed_by})


