@app.route('/rh/paie/<int:pid>/view')
@login_required
def rh_paie_view(pid):
    p = get_payslip_detail_v2(pid)
    if not p: flash("Non trouvé","error"); return redirect('/dashboard')
    # Check access: RH/comptable/admin OR own payslip
    user = get_user_by_id(session['user_id'])
    perms = get_role_permissions(user['role']) if user else []
    # NOUVEAU v56 : la comptable doit pouvoir consulter les bulletins envoyés par RH
    is_authorized = ('fichiers' in perms or 'admin' in perms or
                     'comptabilite' in perms or 'comptabilite_view' in perms or
                     'comptabilite_edit' in perms or 'compta_pro' in perms)
    if not is_authorized:
        # Check if this is the employee's own payslip
        conn = _gdb()
        emp = conn.execute("SELECT id FROM employees WHERE email=? OR LOWER(first_name||' '||last_name)=LOWER(?)",
            (user.get('email',''), user.get('full_name',''))).fetchone()
        conn.close()
        if not emp or emp['id'] != p.get('employee_id'):
            flash("Accès non autorisé","error"); return redirect('/dashboard')
    # v63 : forcer le navigateur à NE PAS mettre cette page en cache
    # car le contenu (libellés, retenues...) peut changer entre versions
    response = make_response(render_template('rh_paie_view.html', page='paie', p=p))
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    response.headers['Pragma'] = 'no-cache'
    response.headers['Expires'] = '0'
    return response

@app.route('/rh/paie/<int:pid>/status/<status>')
@login_required
def rh_paie_status(pid, status):
    valid_statuses = ('brouillon','en_attente_compta','valide_compta','envoye')
    if status not in valid_statuses:
        flash("Statut invalide","error"); return redirect(url_for('rh_paie'))
    
    p = get_payslip_detail_v2(pid)
    if not p: flash("Bulletin non trouvé","error"); return redirect(url_for('rh_paie'))
    
    user = get_user_by_id(session['user_id'])
    uname = user['full_name'] if user else '?'
    
    update_payslip(pid, status=status)
    if status == 'envoye':
        update_payslip(pid, sent_at=datetime.now().isoformat())
    
    conn = _gdb()
    
    # Notifications based on workflow
    if status == 'en_attente_compta':
        compta_users = [dict(r) for r in conn.execute("SELECT id FROM users WHERE role IN ('comptable','admin','dg')").fetchall()]
        for cu in compta_users:
            conn.execute("""INSERT INTO notifications (user_id, type, title, message, link) VALUES (?,?,?,?,?)""",
                (cu['id'], 'bulletin', f"📋 Bulletin à valider — {p['employee_name']}",
                 f"Le bulletin de paie {p['period']} de {p['employee_name']} (Net: {p.get('net_salary',0):,.0f} F) est en attente de validation comptable.",
                 f"/rh/paie/{pid}/view"))
        conn.commit(); conn.close()
        log_activity(session['user_id'], uname, 'Paie', f"Bulletin {p['period']} {p['employee_name']} → Compta", request.remote_addr)
    
    elif status == 'valide_compta':
        rh_users = [dict(r) for r in conn.execute("SELECT id FROM users WHERE role IN ('rh','admin','dg')").fetchall()]
        for ru in rh_users:
            conn.execute("""INSERT INTO notifications (user_id, type, title, message, link) VALUES (?,?,?,?,?)""",
                (ru['id'], 'bulletin', f"✅ Bulletin validé — {p['employee_name']}",
                 f"Le bulletin {p['period']} de {p['employee_name']} a été validé par la comptabilité. Prêt à envoyer.",
                 f"/rh/paie/{pid}/view"))
        conn.commit(); conn.close()
        log_activity(session['user_id'], uname, 'Paie', f"Bulletin {p['period']} {p['employee_name']} validé compta", request.remote_addr)
    else:
        conn.close()
    
    labels = {'brouillon':'Brouillon','en_attente_compta':'En attente comptabilité','valide_compta':'Validé comptabilité','envoye':'Envoyé'}
    flash(f"Statut → {labels.get(status, status)}", "success")
    return redirect(url_for('rh_paie'))


@app.route('/rh/paie/bulk-compta', methods=['POST'])
@permission_required('fichiers')
def rh_paie_bulk_compta():
    """Send all brouillon payslips to comptabilité for validation."""
    conn = _gdb()
    brouillons = conn.execute("SELECT id FROM payslips WHERE status='brouillon'").fetchall()
    count = 0
    for b in brouillons:
        conn.execute("UPDATE payslips SET status='en_attente_compta' WHERE id=?", (b['id'],))
        count += 1
    if count:
        # Notify comptables
        compta_users = [dict(r) for r in conn.execute("SELECT id FROM users WHERE role IN ('comptable','admin','dg')").fetchall()]
        for cu in compta_users:
            conn.execute("INSERT INTO notifications (user_id, type, title, message, link) VALUES (?,?,?,?,?)",
                (cu['id'], 'bulletin', f"📋 {count} bulletin(s) à valider", 
                 f"{count} bulletin(s) de paie en attente de validation comptable.",
                 '/comptabilite/validation-paie'))
        conn.commit(); conn.close()
        user = get_user_by_id(session['user_id'])
        log_activity(session['user_id'], user['full_name'] if user else '?', 'Paie', 
                    f"{count} bulletins envoyés à la comptabilité", request.remote_addr)
    else:
        conn.close()
    flash(f"{count} bulletin(s) envoyé(s) à la comptabilité pour validation", "success")
    return redirect(url_for('rh_paie'))

@app.route('/comptabilite/validation-paie')
@permission_required('comptabilite')
def compta_validation_paie():
    """Comptabilité: view and validate pending payslips.
    v117 : Affiche aussi les banques disponibles pour rattachement."""
    conn = _gdb()
    pending = [dict(r) for r in conn.execute(
        """SELECT p.*, e.first_name||' '||e.last_name as employee_name, e.department, e.position
        FROM payslips p LEFT JOIN employees e ON p.employee_id=e.id 
        WHERE p.status='en_attente_compta' ORDER BY p.period DESC, e.last_name""").fetchall()]
    validated = [dict(r) for r in conn.execute(
        """SELECT p.*, e.first_name||' '||e.last_name as employee_name, e.department,
           b.nom as bank_nom, b.banque as bank_etab, b.type_compte as bank_type
        FROM payslips p 
        LEFT JOIN employees e ON p.employee_id=e.id 
        LEFT JOIN tresorerie_comptes_bancaires b ON b.id=p.bank_account_id
        WHERE p.status='valide_compta' ORDER BY p.period DESC, e.last_name LIMIT 20""").fetchall()]
    # v117 : liste des banques disponibles pour rattachement
    banks = [dict(r) for r in conn.execute(
        "SELECT id, nom, banque, type_compte, numero_compte FROM tresorerie_comptes_bancaires WHERE COALESCE(is_active,1)=1 ORDER BY nom"
    ).fetchall()]
    # v162 : caisses disponibles (la comptable peut décaisser d'une caisse, ex. « caisse salaire »)
    caisses = [dict(r) for r in conn.execute(
        "SELECT id, name FROM caisses WHERE COALESCE(is_active,1)=1 ORDER BY name"
    ).fetchall()]
    conn.close()
    return render_template('extra_pages.html', page='compta_paie',
        pending=pending, validated=validated, banks=banks, caisses=caisses)

@app.route('/comptabilite/validation-paie/bulk-validate', methods=['POST'])
@permission_required('comptabilite')
def compta_bulk_validate():
    """v117 / v162 : Validate pending payslips + attach bank account OU caisse + generate accounting entries.
    La comptable choisit un compte bancaire OU une caisse (ex. « caisse salaire ») à débiter."""
    # v162 : compte de paiement encodé "banque:<id>" ou "caisse:<id>" (rétro-compat bank_account_id)
    sel = (request.form.get('compte_paiement', '') or '').strip()
    if not sel and request.form.get('bank_account_id'):
        sel = f"banque:{request.form.get('bank_account_id')}"
    src_type, src_id = '', 0
    if ':' in sel:
        src_type, _sid = sel.split(':', 1)
        try: src_id = int(_sid)
        except: src_id = 0
    if src_type not in ('banque', 'caisse') or not src_id:
        flash("⚠️ Vous devez choisir un compte bancaire OU une caisse de paiement avant de valider les bulletins", "error")
        return redirect('/comptabilite/validation-paie')

    user = get_user_by_id(session['user_id'])
    conn = _gdb()

    if src_type == 'banque':
        bank = conn.execute("SELECT nom, banque, type_compte, numero_compte, compta_compte_numero FROM tresorerie_comptes_bancaires WHERE id=?", (src_id,)).fetchone()
        if not bank:
            conn.close()
            flash("⚠️ Compte bancaire introuvable", "error")
            return redirect('/comptabilite/validation-paie')
        bank = dict(bank)
        src_label = f"{bank['nom']}" + (f" ({bank['banque']})" if bank['banque'] else "")
        compta_bank_account = bank.get('compta_compte_numero') or '521'  # 521 banque par défaut
        bank_id, caisse_id = src_id, None
    else:  # caisse
        caisse = conn.execute("SELECT name FROM caisses WHERE id=?", (src_id,)).fetchone()
        if not caisse:
            conn.close()
            flash("⚠️ Caisse introuvable", "error")
            return redirect('/comptabilite/validation-paie')
        caisse = dict(caisse)
        src_label = f"Caisse {caisse['name']}"
        compta_bank_account = '571'  # 571 caisse (SYSCOHADA)
        bank_id, caisse_id = None, src_id

    pending = conn.execute("""SELECT p.id, p.net_salary, p.period, p.employee_id, 
        e.first_name||' '||e.last_name AS employee_name
        FROM payslips p LEFT JOIN employees e ON p.employee_id=e.id 
        WHERE p.status='en_attente_compta'""").fetchall()
    count = 0
    total_paid = 0
    now_iso = datetime.now().isoformat()
    now_date = datetime.now().strftime('%Y-%m-%d')
    
    for p in pending:
        p = dict(p)
        net = float(p.get('net_salary') or 0)
        if net <= 0:
            continue
        ref_compta = f"PAIE-{p['id']}-{datetime.now().strftime('%Y%m%d%H%M%S')}"
        mvt_libelle = f"Paie {p.get('period','')} — {p.get('employee_name','?')}"
        # 1. Marquer le bulletin comme validé + lié au compte/caisse
        conn.execute("""UPDATE payslips SET
            status='valide_compta',
            bank_account_id=?,
            caisse_id=?,
            compta_paid_at=?,
            compta_paid_by=?,
            compta_paid_by_name=?,
            compta_reference=?
            WHERE id=?""",
            (bank_id, caisse_id, now_iso, session['user_id'], user['full_name'] if user else '?', ref_compta, p['id']))

        # 2. Écriture comptable partie double : 661 (Rémunérations) DÉBIT / 521 banque ou 571 caisse CRÉDIT
        try:
            auto_ecriture(conn, now_date,
                f"Paie {p.get('period','')} — {p.get('employee_name','?')} ({src_label})",
                '661', compta_bank_account, net, ref_compta)
        except Exception as _e:
            print(f"[v117-Paie] Erreur écriture comptable : {_e}", flush=True)

        # 3. Mouvement de trésorerie (sortie) — banque OU caisse
        try:
            if src_type == 'banque':
                conn.execute("""INSERT INTO tresorerie_mouvements
                    (type, sens, source, banque_id, reference, date, montant, libelle, mode_paiement, created_by, created_at)
                    VALUES ('banque','sortie','paie',?,?,?,?,?,'virement',?,?)""",
                    (bank_id, ref_compta, now_date, net, mvt_libelle, session['user_id'], now_iso))
            else:
                # v162 : sortie de caisse — caisse_operations (alimente le détail/solde caisse) + journal trésorerie
                conn.execute("""INSERT INTO caisse_operations
                    (caisse_id, type, amount, description, reference, category, created_by, created_at)
                    VALUES (?, 'sortie', ?, ?, ?, 'salaire', ?, ?)""",
                    (caisse_id, net, mvt_libelle, ref_compta, session['user_id'], now_iso))
                conn.execute("""INSERT INTO tresorerie_mouvements
                    (type, sens, source, caisse_id, reference, date, montant, libelle, mode_paiement, created_by, created_at)
                    VALUES ('caisse','sortie','paie',?,?,?,?,?,'espece',?,?)""",
                    (caisse_id, ref_compta, now_date, net, mvt_libelle, session['user_id'], now_iso))
        except Exception as _e:
            print(f"[v162-Paie] Erreur mvt trésorerie : {_e}", flush=True)

        # 4. Injection dans la table depenses (suivi unifié)
        try:
            existing = conn.execute("SELECT id FROM depenses WHERE source_type='paie' AND source_id=?", (p['id'],)).fetchone()
            if not existing:
                conn.execute("""INSERT INTO depenses
                    (reference, date, category, amount, description, beneficiaire,
                     source_type, source_id, source_reference, bank_id, caisse_id,
                     status, created_by, created_by_name)
                    VALUES (?,?,?,?,?,?,'paie',?,?,?,?,'comptabilisee',?,?)""",
                    (f"DEP-PAIE-{p['id']}", now_date, 'salaire', net,
                     f"Bulletin de paie {p.get('period','')} via {src_label}",
                     p.get('employee_name',''), p['id'], ref_compta, bank_id, caisse_id,
                     session['user_id'], user['full_name'] if user else '?'))
        except Exception as _e:
            print(f"[v117-Paie] Erreur dépense : {_e}", flush=True)
        
        count += 1
        total_paid += net
    
    if count:
        rh_users = [dict(r) for r in conn.execute("SELECT id FROM users WHERE role IN ('rh','admin','dg')").fetchall()]
        for ru in rh_users:
            conn.execute("INSERT INTO notifications (user_id, type, title, message, link) VALUES (?,?,?,?,?)",
                (ru['id'], 'bulletin', f"✅ {count} bulletin(s) validé(s)",
                 f"La comptabilité a validé {count} bulletin(s) ({total_paid:,.0f} F) via {src_label}. Prêts à envoyer aux employés.",
                 '/rh/paie'))
        conn.commit(); conn.close()
        log_activity(session['user_id'], user['full_name'] if user else '?', 'Paie',
                    f"{count} bulletins validés via {src_label} — {total_paid:,.0f} F", request.remote_addr)
        flash(f"✅ {count} bulletin(s) validé(s) — {total_paid:,.0f} F décaissés de {src_label} (écritures 661/{compta_bank_account} créées)", "success")
    else:
        conn.close()
        flash("Aucun bulletin à valider", "error")
    return redirect('/comptabilite/validation-paie')

@app.route('/rh/paie/<int:pid>/delete')
@permission_required('fichiers')
def rh_paie_delete(pid):
    conn = _gdb()
    p = conn.execute("SELECT p.*, e.first_name||' '||e.last_name as employee_name FROM payslips p LEFT JOIN employees e ON p.employee_id=e.id WHERE p.id=?", (pid,)).fetchone()
    if p:
        conn.execute("DELETE FROM payslips WHERE id=?", (pid,))
        conn.commit()
        flash(f"Bulletin de paie supprimé ({p['employee_name']} — {p['period']})", "success")
    else:
        flash("Bulletin non trouvé", "error")
    conn.close()
    return redirect(url_for('rh_paie'))

@app.route('/rh/paie/<int:pid>/email', methods=['GET','POST'])
@permission_required('fichiers')
def rh_paie_email(pid):
    p = get_payslip_detail_v2(pid)
    if not p: flash("Non trouvé","error"); return redirect(url_for('rh_paie'))
    
    if request.method == 'POST':
        to_email = request.form.get('to_email','').strip()
        cc_email = (request.form.get('cc_email','') or '').strip()  # v161 : copie (Cc)
        smtp_host = request.form.get('smtp_host','').strip()
        smtp_port = int(request.form.get('smtp_port', 587) or 587)
        smtp_user = request.form.get('smtp_user','').strip()
        smtp_pass = request.form.get('smtp_pass','').strip()
        
        if smtp_host and smtp_user:
            save_smtp_settings(session['user_id'], smtp_host, smtp_port, smtp_user, smtp_pass)
        
        if not all([to_email, smtp_host, smtp_user, smtp_pass]):
            flash("Paramètres SMTP requis","error")
            smtp = get_admin_smtp()
            return render_template('rh_paie_view.html', page='paie', p=p, send_email=True, smtp=smtp)
        
        # Generate full bulletin PDF
        try:
            pdf_path = _generate_bulletin_pdf(pid)
            if not pdf_path:
                flash("Erreur génération PDF: bulletin non trouvé", "error")
                return redirect(url_for('rh_paie'))
        except Exception as pdf_err:
            flash(f"Erreur génération PDF: {str(pdf_err)}", "error")
            return redirect(url_for('rh_paie'))
        
        if not os.path.exists(pdf_path):
            flash("Erreur génération PDF","error")
            return redirect(url_for('rh_paie'))
        
        try:
            msg = MIMEMultipart()
            msg['From'] = smtp_user
            msg['To'] = to_email
            cc_list = [e.strip() for e in cc_email.replace(';', ',').split(',') if e.strip()] if cc_email else []
            if cc_list:
                msg['Cc'] = ', '.join(cc_list)
            msg['Subject'] = f"Bulletin de paie — {p['period']} — {p['employee_name']}"
            
            body = f"""Bonjour {p['employee_name']},

Veuillez trouver ci-joint votre bulletin de paie pour la période {p['period']}.

Net à payer : {p.get('net_salary',0):,.0f} FCFA

Cordialement,
RAMYA TECHNOLOGIE & INNOVATION
Service des Ressources Humaines"""
            
            msg.attach(MIMEText(body, 'plain', 'utf-8'))
            
            with open(pdf_path, 'rb') as f:
                part = MIMEBase('application', 'pdf')
                part.set_payload(f.read())
                encoders.encode_base64(part)
                part.add_header('Content-Disposition', f'attachment; filename="Bulletin_{p["period"]}_{p["employee_name"]}.pdf"')
                msg.attach(part)
            
            server = smtplib.SMTP(smtp_host, smtp_port)
            server.starttls()
            server.login(smtp_user, smtp_pass)
            server.send_message(msg)
            server.quit()
            
            # Mark as sent
            update_payslip(pid, status='envoye', sent_at=datetime.now().isoformat())
            user = get_user_by_id(session['user_id'])
            log_activity(session['user_id'], user['full_name'] if user else '?',
                        'Email Paie', f"Bulletin {p['period']} envoyé à {to_email}", request.remote_addr)
            
            # Create notification for employee
            try:
                conn_n = _gdb()
                # Find user account linked to employee
                emp_user = conn_n.execute("SELECT id FROM users WHERE email=? OR LOWER(full_name)=LOWER(?)",
                    (to_email, p['employee_name'])).fetchone()
                user_id_notif = emp_user['id'] if emp_user else None
                conn_n.execute("""INSERT INTO notifications (user_id, employee_id, type, title, message, link)
                    VALUES (?,?,?,?,?,?)""",
                    (user_id_notif, p.get('employee_id'), 'bulletin',
                     f"Bulletin de paie — {p['period']}",
                     f"Votre bulletin de paie pour la période {p['period']} est disponible. Net à payer : {p.get('net_salary',0):,.0f} FCFA",
                     f"/rh/paie/{pid}/view"))
                conn_n.commit(); conn_n.close()
            except: pass
            
            flash(f"Bulletin envoyé par email à {to_email}", "success")
            return redirect(url_for('rh_paie'))
        except Exception as e:
            flash(f"Erreur d'envoi : {str(e)}", "error")
    
    smtp = get_admin_smtp()
    return render_template('rh_paie_view.html', page='paie', p=p, send_email=True, smtp=smtp)

