@app.route('/interventions/<int:iid>/fiche')
@login_required
def intervention_fiche(iid):
    conn = _gdb()
    inter = conn.execute("SELECT * FROM interventions WHERE id=?", (iid,)).fetchone()
    if not inter: flash("Intervention non trouvée","error"); conn.close(); return redirect('/interventions')
    inter = dict(inter)
    # Client info
    if inter.get('client_id'):
        client = conn.execute("SELECT * FROM clients WHERE id=?", (inter['client_id'],)).fetchone()
        inter['client_info'] = dict(client) if client else {}
    # Technician info
    if inter.get('technician_id'):
        tech = conn.execute("SELECT * FROM users WHERE id=?", (inter['technician_id'],)).fetchone()
        inter['tech_info'] = dict(tech) if tech else {}
    # Project info
    if inter.get('project_id'):
        proj = conn.execute("SELECT name FROM projects WHERE id=?", (inter['project_id'],)).fetchone()
        inter['project_name'] = proj['name'] if proj else ''
    # Equipment
    equips = []
    if inter.get('client_id'):
        equips = [dict(r) for r in conn.execute("SELECT * FROM tech_center WHERE client_id=?", (inter['client_id'],)).fetchall()]
    conn.close()
    return render_template('extra_pages.html', page='fiche_intervention', inter=inter, equips=equips, now_str=datetime.now().strftime('%d/%m/%Y %H:%M'))



# ======================== PROGRAMME DU JOUR ========================

@app.route('/interventions/programme')
@login_required
def interventions_programme():
    conn = _gdb()
    today = datetime.now().strftime('%Y-%m-%d')
    date = request.args.get('date', today)
    user = get_user_by_id(session['user_id'])
    # v135 : Tous les techniciens (et rôles manager) voient le programme complet du jour
    # Avant : seul admin/dg/resp_projet voyait tout, les techniciens ne voyaient que leurs interventions
    can_view_all = user and user['role'] in (
        'admin','dg','directeur','resp_projet','coordinateur','gestionnaire_projet',
        'technicien','tech_chef','chef_chantier','centre_technique','informatique',
        'commercial','rh','comptable','comptabilite','moyens_generaux','secretaire'
    )
    is_admin = user and user['role'] in ('admin','dg','resp_projet')
    
    if can_view_all:
        interventions = [dict(r) for r in conn.execute(
            "SELECT * FROM interventions WHERE scheduled_date=? ORDER BY scheduled_time, id", (date,)).fetchall()]
    else:
        interventions = [dict(r) for r in conn.execute(
            "SELECT * FROM interventions WHERE scheduled_date=? AND (technician_id=? OR created_by=?) ORDER BY scheduled_time",
            (date, session['user_id'], session['user_id'])).fetchall()]
    
    # Enrich each intervention with client info (zone = city or site_address, code = client_code)
    for inter in interventions:
        try:
            inter['daily_reports'] = [dict(r) for r in conn.execute(
                "SELECT * FROM intervention_daily_reports WHERE intervention_id=? ORDER BY date DESC", (inter['id'],)).fetchall()]
        except: inter['daily_reports'] = []
        # Pull client code + zone from clients table
        inter['client_code'] = ''
        inter['zone'] = ''
        if inter.get('client_id'):
            try:
                c = conn.execute("SELECT client_code, city, address FROM clients WHERE id=?", (inter['client_id'],)).fetchone()
                if c:
                    inter['client_code'] = c['client_code'] or ''
                    inter['zone'] = c['city'] or c['address'] or ''
            except: pass
        # Fallback: use site_address as zone if no client city
        if not inter.get('zone') and inter.get('site_address'):
            inter['zone'] = inter['site_address']
    
    # Group by type for the 3 tables (entretien / depannage / installation = projet neuf)
    by_type = {'entretien': [], 'depannage': [], 'projet_neuf': []}
    for inter in interventions:
        t = (inter.get('type') or '').lower().strip()
        if t in ('entretien','maintenance'):
            by_type['entretien'].append(inter)
        elif t in ('depannage','depanage','panne','dépannage'):
            by_type['depannage'].append(inter)
        else:
            # installation, projet, autre => projet neuf
            by_type['projet_neuf'].append(inter)
    
    # Format date for display (DD/MM/YYYY)
    try:
        y,m,d = date.split('-')
        date_display = f"{d}/{m}/{y}"
    except: date_display = date
    
    # Visites CRM du jour pour le carrousel
    visits_today = []
    try:
        visits_today = [dict(r) for r in conn.execute(
            "SELECT * FROM visits WHERE date=? ORDER BY id DESC LIMIT 20", (date,)).fetchall()]
    except: pass
    
    conn.close()
    return render_template('extra_pages.html', page='programme_jour', interventions=interventions,
                          by_type=by_type, date=date, date_display=date_display, today=today,
                          is_admin=is_admin, visits_today=visits_today)


def _generate_intervention_fiche_pdf(inter, conn):
    """Génère un PDF complet de la fiche d'intervention (à attacher en email/WhatsApp).
    Retourne (filename, bytes) ou (None, None) en cas d'erreur."""
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.units import mm
        from reportlab.lib.colors import HexColor
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.enums import TA_CENTER, TA_LEFT
        from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, Image as PLImage)
        import io
        
        TEAL = HexColor('#1A7A6D')
        ORANGE = HexColor('#F29F2F')
        BLUE = HexColor('#1a3a5c')
        GREY = HexColor('#666666')
        LIGHT = HexColor('#f0f0f0')
        
        # Récupérer infos client
        client_info = {}
        if inter.get('client_id'):
            c = conn.execute("SELECT name, tel, email, address FROM clients WHERE id=?", (inter['client_id'],)).fetchone()
            if c: client_info = dict(c)
        
        # Récupérer technicien
        tech_name = ''
        if inter.get('technician_id'):
            t = conn.execute("SELECT full_name FROM users WHERE id=?", (inter['technician_id'],)).fetchone()
            if t: tech_name = t['full_name']
        
        # Timeline
        timeline = []
        try:
            timeline = [dict(r) for r in conn.execute("""
                SELECT * FROM intervention_timeline WHERE intervention_id=? ORDER BY created_at ASC""",
                (inter['id'],)).fetchall()]
        except: pass
        
        buf = io.BytesIO()
        doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=12*mm, rightMargin=12*mm,
                                topMargin=12*mm, bottomMargin=12*mm)
        story = []
        
        # En-tête : logo + nom société
        try:
            logo_path = os.path.join(BASE_DIR, 'logo_ramya.png')
            if os.path.exists(logo_path):
                story.append(PLImage(logo_path, width=40*mm, height=20*mm))
        except: pass
        story.append(Paragraph("<b>RAMYA TECHNOLOGIE &amp; INNOVATION</b>",
            ParagraphStyle('h', fontSize=14, textColor=TEAL, alignment=TA_CENTER)))
        story.append(Paragraph("Abidjan, Côte d'Ivoire — CCTV · Contrôle d'accès · IT",
            ParagraphStyle('sub', fontSize=9, textColor=GREY, alignment=TA_CENTER)))
        story.append(Spacer(1, 6*mm))
        
        story.append(Paragraph(f"<b>FICHE D'INTERVENTION — {inter.get('reference','')}</b>",
            ParagraphStyle('ti', fontSize=13, textColor=BLUE, alignment=TA_CENTER, backColor=HexColor('#fff3e0'),
                          borderPadding=6, borderColor=ORANGE, borderWidth=1)))
        story.append(Spacer(1, 5*mm))
        
        # Bloc client + intervention
        info_data = [
            [Paragraph("<b>CLIENT</b>", ParagraphStyle('h1', fontSize=10, textColor=HexColor('#ffffff'))),
             Paragraph("<b>INTERVENTION</b>", ParagraphStyle('h2', fontSize=10, textColor=HexColor('#ffffff')))],
            [
                Paragraph(
                    f"<b>{client_info.get('name', inter.get('client_name','-'))}</b><br/>"
                    f"📞 {client_info.get('tel','-')}<br/>"
                    f"✉️ {client_info.get('email','-')}<br/>"
                    f"📍 {client_info.get('address','-')}",
                    ParagraphStyle('ci', fontSize=9, leading=13)),
                Paragraph(
                    f"<b>Type:</b> {inter.get('type','-')}<br/>"
                    f"<b>Date prévue:</b> {inter.get('scheduled_date','-')} {inter.get('scheduled_time','') or ''}<br/>"
                    f"<b>Statut:</b> {inter.get('status','-').upper()}<br/>"
                    f"<b>Technicien:</b> {tech_name or '-'}",
                    ParagraphStyle('ii', fontSize=9, leading=13)),
            ]
        ]
        t_info = Table(info_data, colWidths=[90*mm, 90*mm])
        t_info.setStyle(TableStyle([
            ('BACKGROUND',(0,0),(-1,0),TEAL),
            ('TEXTCOLOR',(0,0),(-1,0),HexColor('#ffffff')),
            ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
            ('GRID',(0,0),(-1,-1),0.4,HexColor('#cccccc')),
            ('VALIGN',(0,0),(-1,-1),'TOP'),
            ('PADDING',(0,0),(-1,-1),6),
        ]))
        story.append(t_info)
        story.append(Spacer(1, 5*mm))
        
        # Description / titre
        if inter.get('title'):
            story.append(Paragraph(f"<b>Objet :</b> {inter['title']}",
                ParagraphStyle('obj', fontSize=10, textColor=BLUE)))
            story.append(Spacer(1, 2*mm))
        if inter.get('description'):
            story.append(Paragraph("<b>Description des travaux</b>",
                ParagraphStyle('lbl', fontSize=10, textColor=BLUE)))
            story.append(Paragraph(inter['description'],
                ParagraphStyle('desc', fontSize=9, leading=12, textColor=HexColor('#333333'),
                              backColor=LIGHT, borderPadding=6)))
            story.append(Spacer(1, 4*mm))
        
        # Récap horaires
        if inter.get('start_work_at') or inter.get('end_work_at') or inter.get('delivered_at'):
            story.append(Paragraph("<b>Suivi temporel</b>",
                ParagraphStyle('lbl', fontSize=10, textColor=BLUE)))
            time_data = [['Évènement', 'Date/Heure']]
            if inter.get('start_work_at'): time_data.append(['🚀 Début travaux', str(inter['start_work_at'])[:16]])
            if inter.get('end_work_at'): time_data.append(['🏗️ Fin travaux', str(inter['end_work_at'])[:16]])
            if inter.get('cq_at'): time_data.append(['🔍 Contrôle qualité', str(inter['cq_at'])[:16]])
            if inter.get('delivered_at'): time_data.append(['✅ Livrée', str(inter['delivered_at'])[:16]])
            t_time = Table(time_data, colWidths=[90*mm, 90*mm])
            t_time.setStyle(TableStyle([
                ('BACKGROUND',(0,0),(-1,0),BLUE),
                ('TEXTCOLOR',(0,0),(-1,0),HexColor('#ffffff')),
                ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                ('FONTSIZE',(0,0),(-1,-1),9),
                ('GRID',(0,0),(-1,-1),0.3,HexColor('#cccccc')),
                ('PADDING',(0,0),(-1,-1),5),
            ]))
            story.append(t_time)
            story.append(Spacer(1, 4*mm))
        
        # Timeline (max 10 derniers évènements)
        if timeline:
            story.append(Paragraph("<b>Historique des étapes</b>",
                ParagraphStyle('lbl', fontSize=10, textColor=BLUE)))
            tl_data = [['Date', 'Étape', 'Description']]
            for ev in timeline[-10:]:
                desc = (ev.get('description') or '')[:80]
                tl_data.append([
                    str(ev.get('created_at',''))[:16],
                    ev.get('title',''),
                    desc,
                ])
            t_tl = Table(tl_data, colWidths=[35*mm, 50*mm, 95*mm])
            t_tl.setStyle(TableStyle([
                ('BACKGROUND',(0,0),(-1,0),HexColor('#e0f5f1')),
                ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                ('FONTSIZE',(0,0),(-1,-1),8),
                ('GRID',(0,0),(-1,-1),0.25,HexColor('#cccccc')),
                ('PADDING',(0,0),(-1,-1),4),
                ('VALIGN',(0,0),(-1,-1),'TOP'),
            ]))
            story.append(t_tl)
            story.append(Spacer(1, 4*mm))
        
        # Montant si facturable
        if inter.get('is_billable') and (inter.get('total_cost') or 0) > 0:
            story.append(Spacer(1, 3*mm))
            mont_data = [['MONTANT TOTAL', f"{float(inter['total_cost']):,.0f} F CFA"]]
            t_mont = Table(mont_data, colWidths=[120*mm, 60*mm])
            t_mont.setStyle(TableStyle([
                ('BACKGROUND',(0,0),(0,0),ORANGE),
                ('BACKGROUND',(1,0),(1,0),HexColor('#fff3e0')),
                ('TEXTCOLOR',(0,0),(0,0),HexColor('#ffffff')),
                ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                ('FONTSIZE',(0,0),(-1,-1),12),
                ('ALIGN',(0,0),(-1,-1),'CENTER'),
                ('PADDING',(0,0),(-1,-1),8),
                ('GRID',(0,0),(-1,-1),0.5,ORANGE),
            ]))
            story.append(t_mont)
        
        # Bloc signatures
        story.append(Spacer(1, 8*mm))
        sig_data = [
            ['Signature client', 'Signature technicien', 'Cachet RAMYA'],
            ['', '', ''],
        ]
        t_sig = Table(sig_data, colWidths=[60*mm, 60*mm, 60*mm], rowHeights=[7*mm, 28*mm])
        t_sig.setStyle(TableStyle([
            ('FONTSIZE',(0,0),(-1,0),9),
            ('TEXTCOLOR',(0,0),(-1,0),GREY),
            ('ALIGN',(0,0),(-1,0),'CENTER'),
            ('GRID',(0,0),(-1,-1),0.5,HexColor('#cccccc')),
            ('VALIGN',(0,0),(-1,-1),'TOP'),
            ('PADDING',(0,0),(-1,0),4),
        ]))
        story.append(t_sig)
        
        # Pied
        story.append(Spacer(1, 6*mm))
        story.append(Paragraph(
            f"<i>Document généré le {datetime.now().strftime('%d/%m/%Y à %H:%M')} — RAMYA Technologie &amp; Innovation, Abidjan</i>",
            ParagraphStyle('foot', fontSize=8, textColor=GREY, alignment=TA_CENTER)))
        
        doc.build(story)
        buf.seek(0)
        filename = f"fiche-intervention-{inter.get('reference','sans-ref').replace('/','-')}.pdf"
        return filename, buf.getvalue()
    except Exception as e:
        import traceback; traceback.print_exc()
        return None, None


@app.route('/interventions/<int:iid>/fiche.pdf')
@login_required
def intervention_fiche_pdf(iid):
    """Télécharge la fiche d'intervention en PDF."""
    conn = _gdb()
    inter = conn.execute("SELECT * FROM interventions WHERE id=?", (iid,)).fetchone()
    if not inter:
        flash("Intervention introuvable", "error")
        conn.close(); return redirect(url_for('interventions_programme'))
    inter = dict(inter)
    filename, data = _generate_intervention_fiche_pdf(inter, conn)
    conn.close()
    if not data:
        flash("Erreur génération PDF", "error")
        return redirect(f'/interventions/{iid}/fiche')
    return Response(data, mimetype='application/pdf',
        headers={'Content-Disposition': f'attachment; filename={filename}'})


@app.route('/public/fiche/<token>')
def public_intervention_fiche_pdf(token):
    """Téléchargement public d'une fiche PDF via token (utilisé pour WhatsApp).
    Le token est généré au moment de l'envoi WA et valide 72h."""
    if not token or len(token) < 8:
        return "Token invalide", 404
    conn = _gdb()
    try:
        row = conn.execute("""SELECT * FROM public_pdf_tokens WHERE token=?
            AND expires_at > ?""", (token, datetime.now().isoformat())).fetchone()
        if not row:
            conn.close()
            return "Lien expiré ou invalide. Demandez un nouveau lien à votre interlocuteur.", 404
        iid = row['intervention_id']
        inter = conn.execute("SELECT * FROM interventions WHERE id=?", (iid,)).fetchone()
        if not inter:
            conn.close()
            return "Intervention introuvable", 404
        inter = dict(inter)
        filename, data = _generate_intervention_fiche_pdf(inter, conn)
        conn.close()
        if not data:
            return "Erreur génération PDF", 500
        return Response(data, mimetype='application/pdf',
            headers={'Content-Disposition': f'inline; filename={filename}'})
    except Exception as e:
        conn.close()
        return f"Erreur: {e}", 500


@app.route('/interventions/<int:iid>/fiche/send-mail', methods=['POST', 'GET'])
@login_required
def intervention_fiche_send_mail(iid):
    """Envoie la fiche d'intervention en PDF par email au client.
    SEULS le coordinateur projet, resp_projet, admin et dg peuvent envoyer (après exécution des travaux)."""
    user = get_user_by_id(session['user_id'])
    if not user or user['role'] not in ('admin', 'dg', 'resp_projet', 'coordinateur'):
        flash("⛔ Seul le coordinateur projet peut envoyer la fiche au client.", "error")
        return redirect(f'/interventions/{iid}/fiche')
    
    conn = _gdb()
    inter = conn.execute("SELECT * FROM interventions WHERE id=?", (iid,)).fetchone()
    if not inter:
        flash("Intervention introuvable", "error")
        conn.close(); return redirect(url_for('interventions_programme'))
    inter = dict(inter)
    
    # L'intervention doit être terminée/livrée avant envoi au client
    if inter.get('status') not in ('livre', 'termine', 'terminee', 'travaux_termines', 'controle_qualite'):
        flash("⚠️ La fiche ne peut être envoyée qu'après la fin des travaux. Statut actuel : " + str(inter.get('status','-')), "warning")
        conn.close()
        return redirect(f'/interventions/{iid}/fiche')
    
    # Récupérer email client
    client_email = ''
    client_name = inter.get('client_name', '')
    if inter.get('client_id'):
        c = conn.execute("SELECT email, name FROM clients WHERE id=?", (inter['client_id'],)).fetchone()
        if c:
            client_email = c['email'] or ''
            if not client_name: client_name = c['name'] or ''
    conn.close()
    
    custom_email = (request.values.get('email','') or '').strip()
    if custom_email: client_email = custom_email
    if not client_email:
        flash(f"⚠️ Aucun email pour {client_name}. Renseignez l'email du client ou utilisez WhatsApp.", "warning")
        return redirect(f'/interventions/{iid}/fiche')
    
    # Construire le contenu du mail
    subject = f"Fiche d'intervention {inter.get('reference','')} — {datetime.now().strftime('%d/%m/%Y')}"
    body = f"""Bonjour {client_name},

Veuillez trouver ci-joint la fiche d'intervention concernant les travaux réalisés sur votre site.

Référence : {inter.get('reference','-')}
Type : {inter.get('type','-')}
Date : {inter.get('scheduled_date','-')}
Statut : {inter.get('status','-')}
Description : {inter.get('description','-') or inter.get('title','-')}

Pour toute question, n'hésitez pas à nous contacter.

Cordialement,
{user.get('full_name','RAMYA Technologie') if user else 'RAMYA Technologie'}
RAMYA TECHNOLOGIE & INNOVATION
Abidjan, Côte d'Ivoire"""
    
    # Générer le PDF de la fiche pour l'attacher
    conn2 = _gdb()
    pdf_filename, pdf_bytes = _generate_intervention_fiche_pdf(inter, conn2)
    conn2.close()
    
    # Tentative d'envoi via SMTP en utilisant les paramètres admin sauvegardés (fonction existante)
    sent = False
    try:
        from models import get_admin_smtp
        smtp_cfg = get_admin_smtp()
        if smtp_cfg and smtp_cfg.get('smtp_host') and smtp_cfg.get('smtp_user'):
            import smtplib
            from email.mime.text import MIMEText
            from email.mime.multipart import MIMEMultipart
            from email.mime.application import MIMEApplication
            msg = MIMEMultipart()
            msg['From'] = smtp_cfg.get('smtp_user')
            msg['To'] = client_email
            msg['Subject'] = subject
            msg.attach(MIMEText(body, 'plain', 'utf-8'))
            # Pièce jointe PDF
            if pdf_bytes:
                attach = MIMEApplication(pdf_bytes, _subtype='pdf')
                attach.add_header('Content-Disposition', 'attachment', filename=pdf_filename)
                msg.attach(attach)
            with smtplib.SMTP(smtp_cfg['smtp_host'], int(smtp_cfg.get('smtp_port', 587)), timeout=15) as server:
                server.ehlo(); server.starttls(); server.ehlo()
                server.login(smtp_cfg['smtp_user'], smtp_cfg.get('smtp_pass', ''))
                server.send_message(msg)
            sent = True
    except Exception as e:
        print(f"SMTP admin error: {e}")
    
    # Fallback : SMTP via env vars (avec pièce jointe)
    if not sent:
        try:
            from models import send_email_smtp
            attachments = [(pdf_filename, pdf_bytes, 'application/pdf')] if pdf_bytes else None
            sent = send_email_smtp(client_email, subject, body, attachments=attachments)
        except Exception as e:
            print(f"SMTP env error: {e}")
    
    if sent:
        try:
            log_activity(session['user_id'], user['full_name'], 'Intervention',
                        f"Fiche {inter.get('reference')} envoyée par email à {client_email}",
                        request.remote_addr)
            # Marquer comme envoyée
            conn2 = _gdb()
            try: conn2.execute("ALTER TABLE interventions ADD COLUMN client_fiche_sent_at TEXT")
            except: pass
            try: conn2.execute("ALTER TABLE interventions ADD COLUMN client_fiche_sent_via TEXT")
            except: pass
            try: conn2.execute("ALTER TABLE interventions ADD COLUMN client_fiche_sent_to TEXT")
            except: pass
            conn2.execute("""UPDATE interventions SET client_fiche_sent_at=?, client_fiche_sent_via='email', client_fiche_sent_to=?
                WHERE id=?""", (datetime.now().isoformat(), client_email, iid))
            conn2.commit(); conn2.close()
        except: pass
        flash(f"✅ Fiche envoyée par email à {client_email}", "success")
    else:
        # Fallback : mailto: (ouvre le client mail local de l'utilisateur)
        from urllib.parse import quote
        mailto_url = f"mailto:{client_email}?subject={quote(subject)}&body={quote(body)}"
        flash("📧 Aucun SMTP configuré. Lien mailto: ouvert — vérifiez avec l'admin pour configurer le SMTP réel.", "warning")
        return redirect(mailto_url)
    
    return redirect(f'/interventions/{iid}/fiche')


@app.route('/interventions/<int:iid>/fiche/whatsapp')
@login_required
def intervention_fiche_whatsapp(iid):
    """Génère un lien WhatsApp Click-to-chat pré-rempli pour le client.
    SEULS le coordinateur projet, resp_projet, admin et dg peuvent envoyer."""
    user = get_user_by_id(session['user_id'])
    if not user or user['role'] not in ('admin', 'dg', 'resp_projet', 'coordinateur'):
        flash("⛔ Seul le coordinateur projet peut envoyer la fiche au client.", "error")
        return redirect(f'/interventions/{iid}/fiche')
    
    conn = _gdb()
    inter = conn.execute("SELECT * FROM interventions WHERE id=?", (iid,)).fetchone()
    if not inter:
        flash("Intervention introuvable", "error")
        conn.close(); return redirect(url_for('interventions_programme'))
    inter = dict(inter)
    
    if inter.get('status') not in ('livre', 'termine', 'terminee', 'travaux_termines', 'controle_qualite'):
        flash("⚠️ La fiche ne peut être envoyée qu'après la fin des travaux.", "warning")
        conn.close()
        return redirect(f'/interventions/{iid}/fiche')
    
    client_phone = ''
    client_name = inter.get('client_name','')
    if inter.get('client_id'):
        c = conn.execute("SELECT tel, name FROM clients WHERE id=?", (inter['client_id'],)).fetchone()
        if c:
            client_phone = c['tel'] or ''
            if not client_name: client_name = c['name']
    conn.close()
    
    custom_phone = (request.args.get('phone','') or '').strip()
    if custom_phone: client_phone = custom_phone
    if not client_phone:
        flash(f"⚠️ Aucun numéro WhatsApp pour {client_name}.", "warning")
        return redirect(f'/interventions/{iid}/fiche')
    
    # Nettoyer le numéro
    import re
    phone_clean = re.sub(r'[^\d+]', '', client_phone)
    if not phone_clean.startswith('+'):
        if phone_clean.startswith('00'):
            phone_clean = '+' + phone_clean[2:]
        elif len(phone_clean) == 10 and phone_clean[0] == '0':
            phone_clean = '+225' + phone_clean[1:]
        elif len(phone_clean) == 8:
            phone_clean = '+225' + phone_clean
        else:
            phone_clean = '+225' + phone_clean
    phone_clean = phone_clean.lstrip('+')
    
    # Générer un token d'accès public au PDF (24h)
    import secrets, hashlib
    token = secrets.token_urlsafe(16)
    conn_t = _gdb()
    try:
        conn_t.execute("""CREATE TABLE IF NOT EXISTS public_pdf_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            token TEXT UNIQUE NOT NULL,
            intervention_id INTEGER NOT NULL,
            expires_at TEXT NOT NULL,
            created_by INTEGER,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP
        )""")
        from datetime import timedelta as _td
        expires = (datetime.now() + _td(hours=72)).isoformat()
        conn_t.execute("INSERT INTO public_pdf_tokens (token, intervention_id, expires_at, created_by) VALUES (?,?,?,?)",
                      (token, iid, expires, session['user_id']))
        conn_t.commit()
    except Exception as e:
        print(f"token: {e}")
    conn_t.close()
    
    base_url = request.host_url.rstrip('/')
    pdf_url = f"{base_url}/public/fiche/{token}"
    
    msg = f"""Bonjour {client_name},
Veuillez trouver ci-dessous la fiche d'intervention {inter.get('reference','-')} du {inter.get('scheduled_date','-')}.
Type : {inter.get('type','-')}
Statut : {inter.get('status','-')}

📄 Télécharger la fiche PDF : {pdf_url}

(Lien valable 72 heures)

Cordialement,
RAMYA TECHNOLOGIE"""
    
    from urllib.parse import quote
    wa_url = f"https://wa.me/{phone_clean}?text={quote(msg)}"
    
    try:
        log_activity(session['user_id'], user['full_name'], 'Intervention',
                    f"Lien WhatsApp généré pour fiche {inter.get('reference')} → {phone_clean}",
                    request.remote_addr)
        # Marquer comme envoyée
        conn3 = _gdb()
        try: conn3.execute("ALTER TABLE interventions ADD COLUMN client_fiche_sent_at TEXT")
        except: pass
        try: conn3.execute("ALTER TABLE interventions ADD COLUMN client_fiche_sent_via TEXT")
        except: pass
        try: conn3.execute("ALTER TABLE interventions ADD COLUMN client_fiche_sent_to TEXT")
        except: pass
        conn3.execute("""UPDATE interventions SET client_fiche_sent_at=?, client_fiche_sent_via='whatsapp', client_fiche_sent_to=?
            WHERE id=?""", (datetime.now().isoformat(), phone_clean, iid))
        conn3.commit(); conn3.close()
    except: pass
    return redirect(wa_url)


@app.route('/interventions/<int:iid>/daily-report', methods=['POST'])
@login_required
def intervention_daily_report(iid):
    conn = _gdb()
    # Save images
    img_names = []
    files = request.files.getlist('photos')
    for f in files:
        if f and f.filename:
            ext = os.path.splitext(f.filename)[1].lower()
            if ext in ('.jpg','.jpeg','.png','.webp'):
                fname = f"int_{iid}_{datetime.now().strftime('%Y%m%d%H%M%S')}_{len(img_names)}{ext}"
                fdir = os.path.join(app.config['UPLOAD_FOLDER'], 'interventions')
                os.makedirs(fdir, exist_ok=True)
                f.save(os.path.join(fdir, fname))
                img_names.append(fname)
    
    progress_pct = int(request.form.get('progress',0) or 0)
    report_text = request.form.get('report','')
    now_iso = datetime.now().isoformat()
    
    conn.execute("""INSERT INTO intervention_daily_reports 
        (intervention_id, date, report, progress, technician_id, images) VALUES (?,?,?,?,?,?)""",
        (iid, datetime.now().strftime('%Y-%m-%d'), report_text,
         progress_pct, session['user_id'], ','.join(img_names)))
    
    # Mise à jour intervention parente : updated_at + progress
    try:
        conn.execute("UPDATE interventions SET updated_at=?, progress=? WHERE id=?",
                     (now_iso, progress_pct, iid))
    except: pass
    
    # Notifier le client portail (création notification)
    try:
        inter = conn.execute("SELECT reference, title, client_id FROM interventions WHERE id=?", (iid,)).fetchone()
        if inter and inter['client_id']:
            for cu in conn.execute(
                "SELECT id FROM client_users WHERE client_id=? AND account_status='approved' AND COALESCE(is_active,1)=1",
                (inter['client_id'],)).fetchall():
                conn.execute("""INSERT INTO notifications (client_user_id, type, title, message, link)
                    VALUES (?,?,?,?,?)""",
                    (cu['id'], 'intervention_progress',
                     f"📋 Nouveau rapport — {inter['reference']}",
                     f"Le technicien a publié un rapport d'avancement ({progress_pct}%) sur « {inter['title']} ». {report_text[:100]}",
                     f"/portail/interventions"))
    except Exception: pass
    
    conn.commit(); conn.close()
    flash("Rapport enregistré avec photos — le client a été notifié", "success")
    return redirect(request.referrer or '/interventions/tech')

