# v120 : Modification d'une caisse (admin uniquement)
@app.route('/comptabilite/caisses/<int:cid>/edit', methods=['POST'])
@login_required
def compta_caisse_edit(cid):
    """v120 : Modifier une caisse existante. Réservé à admin (ou caisse_create + comptabilite_edit)."""
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    is_admin = user and user['role'] == 'admin'
    can_edit = user and _hp(user['role'], 'caisse_create') and _hp(user['role'], 'comptabilite_edit')
    if not (is_admin or can_edit):
        flash("⚠️ Seul l'admin (ou les comptables avec permission caisse_create) peut modifier une caisse", "error")
        return redirect('/comptabilite/caisses')
    
    conn = _gdb()
    c = conn.execute("SELECT * FROM caisses WHERE id=?", (cid,)).fetchone()
    if not c:
        conn.close()
        flash("Caisse introuvable", "error")
        return redirect('/comptabilite/caisses')
    c = dict(c)
    
    new_name = (request.form.get('name','') or '').strip()
    new_desc = (request.form.get('description','') or '').strip()
    try: new_solde_init = float(request.form.get('solde_initial', c.get('solde_initial', 0)) or 0)
    except: new_solde_init = c.get('solde_initial', 0) or 0
    new_resp_id = int(request.form.get('responsible_id', 0) or 0)
    new_resp_name = ''
    if new_resp_id:
        u = conn.execute("SELECT full_name FROM users WHERE id=?", (new_resp_id,)).fetchone()
        new_resp_name = u['full_name'] if u else ''
    
    if not new_name:
        conn.close()
        flash("⚠️ Le nom est obligatoire", "error")
        return redirect('/comptabilite/caisses')
    
    try:
        # Recalculer le solde actuel à partir des opérations + nouveau solde_initial
        entrees = conn.execute("SELECT COALESCE(SUM(amount),0) FROM caisse_operations WHERE caisse_id=? AND type='entree'", (cid,)).fetchone()[0] or 0
        sorties = conn.execute("SELECT COALESCE(SUM(amount),0) FROM caisse_operations WHERE caisse_id=? AND type='sortie'", (cid,)).fetchone()[0] or 0
        trans_in = conn.execute("SELECT COALESCE(SUM(amount),0) FROM caisse_operations WHERE dest_caisse_id=? AND type='transfert'", (cid,)).fetchone()[0] or 0
        trans_out = conn.execute("SELECT COALESCE(SUM(amount),0) FROM caisse_operations WHERE source_caisse_id=? AND type='transfert'", (cid,)).fetchone()[0] or 0
        new_solde_actuel = new_solde_init + entrees + trans_in - sorties - trans_out
        
        conn.execute("""UPDATE caisses SET 
            name=?, description=?, responsible_id=?, responsible_name=?,
            solde_initial=?, solde_actuel=?
            WHERE id=?""",
            (new_name, new_desc, new_resp_id or None, new_resp_name,
             new_solde_init, new_solde_actuel, cid))
        conn.commit()
        log_activity(session['user_id'], user['full_name'], 'Caisse',
            f"Caisse #{cid} modifiée — {new_name} (solde initial: {new_solde_init:,.0f} F)", request.remote_addr)
        flash(f"✅ Caisse « {new_name} » modifiée — Solde actuel recalculé : {new_solde_actuel:,.0f} F", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect('/comptabilite/caisses')


@app.route('/comptabilite/caisses/<int:cid>/delete', methods=['POST','GET'])
@login_required
def compta_caisse_delete(cid):
    """v110 + v113 : Supprime (désactive ou hard delete) une caisse.
    v113 : permission 'caisse_delete' requise."""
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    is_admin = user and user['role'] == 'admin'
    has_perm = user and _hp(user['role'], 'caisse_delete')
    if not (is_admin or has_perm):
        flash("⚠️ Permission 'caisse_delete' requise", "error")
        return redirect('/comptabilite/caisses')
    
    conn = _gdb()
    ca = conn.execute("SELECT * FROM caisses WHERE id=?", (cid,)).fetchone()
    if not ca:
        flash("Caisse non trouvée", "error"); conn.close()
        return redirect('/comptabilite/caisses')
    ca = dict(ca)
    # Check solde
    if abs(ca.get('solde_actuel') or 0) > 0.01 and not request.args.get('force'):
        flash(f"⚠️ Impossible de supprimer « {ca['name']} » : solde actuel = {ca['solde_actuel']:,.0f} F. Videz la caisse d'abord (bouton 'Vider à zéro') ou utilisez 'Forcer la suppression'.", "error")
        conn.close()
        return redirect('/comptabilite/caisses')
    # Check opérations
    nb_ops = conn.execute("SELECT COUNT(*) FROM caisse_operations WHERE caisse_id=?", (cid,)).fetchone()[0]
    if nb_ops > 0 and not request.args.get('force'):
        # Soft delete : désactive la caisse
        conn.execute("UPDATE caisses SET is_active=0 WHERE id=?", (cid,))
        conn.commit(); conn.close()
        flash(f"✅ Caisse « {ca['name']} » désactivée ({nb_ops} opération(s) conservées en historique).", "success")
        return redirect('/comptabilite/caisses')
    # Hard delete : pas d'opérations ou force=1
    try:
        # v112 : SNAPSHOT avant DELETE pour permettre restauration
        try:
            snapshot, snap_stats = _snapshot_caisse(conn, cid)
            _save_trash_snapshot(conn, 'caisse', cid, ca['name'],
                snapshot, snap_stats, session['user_id'], user['full_name'],
                notes=f"Hard delete (force={bool(request.args.get('force'))})")
            conn.commit()
        except Exception as _e:
            print(f"[v112-Corbeille] Erreur snapshot delete : {_e}", flush=True)
        
        if request.args.get('force'):
            conn.execute("DELETE FROM caisse_operations WHERE caisse_id=?", (cid,))
        conn.execute("DELETE FROM caisses WHERE id=?", (cid,))
        conn.commit()
        flash(f"✅ Caisse « {ca['name']} » supprimée définitivement. 📦 Sauvegarde disponible dans la Corbeille.", "success")
    except Exception as e:
        flash(f"Erreur: {e}", "error")
    conn.close()
    log_activity(session['user_id'], user['full_name'], 'Caisse',
                 f"Suppression caisse {ca['name']} (force={bool(request.args.get('force'))})", request.remote_addr)
    return redirect('/comptabilite/caisses')


# v110 : Remise à zéro d'une caisse (sortie d'ajustement pour mettre solde_actuel à 0)
@app.route('/comptabilite/caisses/<int:cid>/reset-zero', methods=['POST', 'GET'])
@login_required
def compta_caisse_reset_zero(cid):
    """v110 + v113 : Vide une caisse en passant une écriture d'ajustement (solde → 0).
    v113 : permission 'caisse_reset_zero' requise."""
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    is_admin = user and user['role'] == 'admin'
    has_perm = user and _hp(user['role'], 'caisse_reset_zero')
    if not (is_admin or has_perm):
        flash("⚠️ Permission 'caisse_reset_zero' requise", "error")
        return redirect('/comptabilite/caisses')
    
    conn = _gdb()
    ca = conn.execute("SELECT * FROM caisses WHERE id=?", (cid,)).fetchone()
    if not ca:
        conn.close()
        flash("Caisse non trouvée", "error")
        return redirect('/comptabilite/caisses')
    ca = dict(ca)
    solde = float(ca.get('solde_actuel') or 0)
    
    if abs(solde) < 0.01:
        conn.close()
        flash(f"ℹ️ La caisse « {ca['name']} » est déjà à zéro", "info")
        return redirect('/comptabilite/caisses')
    
    # Créer une opération d'ajustement
    ref_op = f"AJUST-{datetime.now().strftime('%Y%m%d%H%M%S')}"
    today = datetime.now().strftime('%Y-%m-%d')
    motif = request.form.get('motif', f"Remise à zéro caisse par {user['full_name']}").strip()
    
    if solde > 0:
        # Sortie d'ajustement pour vider
        op_type = 'sortie'
        descr = f"Ajustement remise à zéro — {motif}"
        conn.execute("""INSERT INTO caisse_operations 
            (caisse_id, type, amount, description, reference, category, created_by) 
            VALUES (?,'sortie',?,?,?,'ajustement',?)""",
            (cid, solde, descr, ref_op, session['user_id']))
        # Écriture comptable 658 / 571 (charge exceptionnelle / caisse)
        try: auto_ecriture(conn, today, f"Ajustement caisse {ref_op}", '658', '571', solde, ref_op)
        except: pass
        # Sync journal de caisse
        try: _sync_caisse_op_to_journal(conn, 'sortie', today, solde,
            f"[{ca['name']}] {descr}", ref_op, session['user_id'])
        except: pass
    else:
        # Caisse négative → entrée d'ajustement
        op_type = 'entree'
        descr = f"Ajustement régularisation — {motif}"
        montant = abs(solde)
        conn.execute("""INSERT INTO caisse_operations 
            (caisse_id, type, amount, description, reference, category, created_by) 
            VALUES (?,'entree',?,?,?,'ajustement',?)""",
            (cid, montant, descr, ref_op, session['user_id']))
        try: auto_ecriture(conn, today, f"Régularisation caisse {ref_op}", '571', '758', montant, ref_op)
        except: pass
        try: _sync_caisse_op_to_journal(conn, 'entree', today, montant,
            f"[{ca['name']}] {descr}", ref_op, session['user_id'])
        except: pass
    
    # Mettre solde_actuel à 0
    conn.execute("UPDATE caisses SET solde_actuel=0 WHERE id=?", (cid,))
    conn.commit()
    conn.close()
    
    log_activity(session['user_id'], user['full_name'], 'Caisse',
                 f"Remise à zéro caisse {ca['name']} — ajustement {ref_op} ({solde:,.0f} F)", request.remote_addr)
    flash(f"✅ Caisse « {ca['name']} » remise à zéro — ajustement de {abs(solde):,.0f} F enregistré ({ref_op})", "success")
    return redirect('/comptabilite/caisses')


# v112 : Fonctions helpers pour le système de corbeille (snapshot + restauration)
def _snapshot_caisse(conn, cid):
    """v112 : Crée un snapshot JSON complet d'une caisse avant suppression.
    Retourne (snapshot_dict, stats_dict)."""
    import json
    snap = {'caisse': None, 'operations': [], 'entrees': [], 'sorties': [],
            'virements': [], 'mouvements': [], 'pieces': [], 'ecritures': [],
            'supplier_payments_links': [], 'interventions_links': []}
    stats = {}
    
    ca_row = conn.execute("SELECT * FROM caisses WHERE id=?", (cid,)).fetchone()
    if not ca_row: return snap, stats
    snap['caisse'] = dict(ca_row)
    
    # Opérations
    rows = conn.execute("SELECT * FROM caisse_operations WHERE caisse_id=? OR source_caisse_id=? OR dest_caisse_id=?",
                        (cid, cid, cid)).fetchall()
    snap['operations'] = [dict(r) for r in rows]
    stats['operations'] = len(snap['operations'])
    
    # Entrées
    try:
        rows = conn.execute("SELECT * FROM caisse_entrees WHERE caisse_id=?", (cid,)).fetchall()
        snap['entrees'] = [dict(r) for r in rows]
        stats['entrees'] = len(snap['entrees'])
    except: stats['entrees'] = 0
    
    # Sorties
    try:
        rows = conn.execute("SELECT * FROM caisse_sorties WHERE caisse_id=?", (cid,)).fetchall()
        snap['sorties'] = [dict(r) for r in rows]
        stats['sorties'] = len(snap['sorties'])
    except: stats['sorties'] = 0
    
    # Virements
    try:
        rows = conn.execute("SELECT * FROM caisse_virements WHERE caisse_id=?", (cid,)).fetchall()
        snap['virements'] = [dict(r) for r in rows]
        stats['virements'] = len(snap['virements'])
    except: stats['virements'] = 0
    
    # Références pour mouvements et écritures
    op_refs = [r['reference'] for r in snap['operations'] if r.get('reference')]
    sortie_refs = [r['reference'] for r in snap['sorties'] if r.get('reference')]
    entree_refs = [r['reference'] for r in snap['entrees'] if r.get('reference')]
    all_refs = list(set(op_refs + sortie_refs + entree_refs))
    
    # Mouvements de trésorerie
    rows = conn.execute("SELECT * FROM tresorerie_mouvements WHERE caisse_id=?", (cid,)).fetchall()
    snap['mouvements'] = [dict(r) for r in rows]
    if all_refs:
        rows2 = conn.execute("SELECT * FROM tresorerie_mouvements WHERE reference IN ({}) AND caisse_id != ?".format(
            ','.join('?' for _ in all_refs)), all_refs + [cid]).fetchall()
        snap['mouvements'].extend([dict(r) for r in rows2])
    stats['mouvements'] = len(snap['mouvements'])
    
    # Pièces
    try:
        rows = conn.execute("SELECT * FROM pieces_caisse WHERE caisse_id=?", (cid,)).fetchall()
        snap['pieces'] = [dict(r) for r in rows]
        stats['pieces'] = len(snap['pieces'])
    except: stats['pieces'] = 0
    
    # Écritures comptables liées
    if all_refs:
        try:
            rows = conn.execute("SELECT * FROM ecritures_comptables WHERE piece IN ({})".format(
                ','.join('?' for _ in all_refs)), all_refs).fetchall()
            snap['ecritures'] = [dict(r) for r in rows]
            stats['ecritures'] = len(snap['ecritures'])
        except: stats['ecritures'] = 0
    
    # Liens supplier_payments (pour restauration)
    sortie_ids = [r['id'] for r in snap['sorties']]
    if sortie_ids:
        try:
            rows = conn.execute("SELECT id, caisse_sortie_id FROM supplier_payments WHERE caisse_sortie_id IN ({})".format(
                ','.join('?' for _ in sortie_ids)), sortie_ids).fetchall()
            snap['supplier_payments_links'] = [dict(r) for r in rows]
        except: pass
    
    # Liens interventions
    try:
        rows = conn.execute("SELECT id, caisse_id FROM interventions WHERE caisse_id=?", (cid,)).fetchall()
        snap['interventions_links'] = [dict(r) for r in rows]
    except: pass
    
    return snap, stats


def _save_trash_snapshot(conn, entity_type, entity_id, entity_name, snapshot, stats, user_id, user_name, notes=''):
    """v112 : Enregistre un snapshot dans la table trash_snapshots."""
    import json
    cur = conn.execute("""INSERT INTO trash_snapshots 
        (entity_type, entity_id, entity_name, snapshot_json, stats_json, 
         deleted_by, deleted_by_name, deleted_at, notes)
        VALUES (?,?,?,?,?,?,?,datetime('now'),?)""",
        (entity_type, entity_id, entity_name,
         json.dumps(snapshot, ensure_ascii=False, default=str),
         json.dumps(stats, ensure_ascii=False, default=str),
         user_id, user_name, notes))
    return cur.lastrowid


# v111 : SUPPRESSION DÉFINITIVE d'une caisse + toutes ses traces (purge totale)
# Efface : la caisse, ses opérations, entrées, sorties, virements, mouvements journal,
# pièces, écritures comptables liées. Aucun retour possible.
@app.route('/comptabilite/caisses/<int:cid>/purge', methods=['POST', 'GET'])
@login_required
def compta_caisse_purge(cid):
    """v111 + v112 + v113 : Purge totale d'une caisse — supprime TOUTES les traces
    APRÈS avoir sauvegardé un snapshot complet dans la corbeille.
    v113 : Réservé aux rôles avec permission 'caisse_purge' (admin & RH par défaut)."""
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    is_admin = user and user['role'] == 'admin'
    has_perm = user and _hp(user['role'], 'caisse_purge')
    if not (is_admin or has_perm):
        flash("⚠️ Permission 'caisse_purge' requise — réservée à l'admin et au RH", "error")
        return redirect('/comptabilite/caisses')
    
    conn = _gdb()
    ca = conn.execute("SELECT * FROM caisses WHERE id=?", (cid,)).fetchone()
    if not ca:
        conn.close()
        flash("Caisse non trouvée", "error")
        return redirect('/comptabilite/caisses')
    ca = dict(ca)
    
    # Confirmation explicite obligatoire
    if request.method == 'POST' and request.form.get('confirm', '').strip().upper() != 'PURGE':
        conn.close()
        flash("⚠️ Confirmation invalide : tapez 'PURGE' en majuscules pour confirmer", "error")
        return redirect('/comptabilite/caisses')
    
    # Récupérer toutes les références d'opérations de cette caisse pour purger les écritures liées
    op_refs = [r[0] for r in conn.execute(
        "SELECT reference FROM caisse_operations WHERE caisse_id=? OR source_caisse_id=? OR dest_caisse_id=?",
        (cid, cid, cid)).fetchall() if r[0]]
    entree_refs = []
    try:
        entree_refs = [r[0] for r in conn.execute(
            "SELECT reference FROM caisse_entrees WHERE caisse_id=?", (cid,)).fetchall() if r[0]]
    except: pass
    sortie_refs = [r[0] for r in conn.execute(
        "SELECT reference FROM caisse_sorties WHERE caisse_id=?", (cid,)).fetchall() if r[0]]
    
    all_refs = list(set(op_refs + entree_refs + sortie_refs))
    
    stats = {'operations': 0, 'entrees': 0, 'sorties': 0, 'virements': 0,
             'mouvements': 0, 'pieces': 0, 'ecritures': 0, 'interventions_unlinked': 0,
             'supplier_payments_unlinked': 0}
    
    # v112 : SNAPSHOT AVANT PURGE pour permettre la restauration
    try:
        snapshot, snap_stats = _snapshot_caisse(conn, cid)
        trash_id = _save_trash_snapshot(conn, 'caisse', cid, ca['name'], 
            snapshot, snap_stats, session['user_id'], user['full_name'])
        conn.commit()
        print(f"[v112-Corbeille] Snapshot caisse {ca['name']} (id={cid}) sauvegardé en corbeille (trash_id={trash_id})", flush=True)
    except Exception as _e:
        print(f"[v112-Corbeille] Erreur snapshot : {_e}", flush=True)
        trash_id = None
    
    try:
        # 1. Opérations
        cur = conn.execute("DELETE FROM caisse_operations WHERE caisse_id=? OR source_caisse_id=? OR dest_caisse_id=?",
                           (cid, cid, cid))
        stats['operations'] = cur.rowcount or 0
        
        # 2. Entrées
        try:
            cur = conn.execute("DELETE FROM caisse_entrees WHERE caisse_id=?", (cid,))
            stats['entrees'] = cur.rowcount or 0
        except: pass
        
        # 3. Sorties (et déliage des supplier_payments)
        sortie_ids = [r[0] for r in conn.execute("SELECT id FROM caisse_sorties WHERE caisse_id=?", (cid,)).fetchall()]
        if sortie_ids:
            try:
                cur = conn.execute("UPDATE supplier_payments SET caisse_sortie_id=NULL WHERE caisse_sortie_id IN ({})".format(
                    ','.join('?' for _ in sortie_ids)), sortie_ids)
                stats['supplier_payments_unlinked'] = cur.rowcount or 0
            except: pass
        cur = conn.execute("DELETE FROM caisse_sorties WHERE caisse_id=?", (cid,))
        stats['sorties'] = cur.rowcount or 0
        
        # 4. Virements
        try:
            cur = conn.execute("DELETE FROM caisse_virements WHERE caisse_id=?", (cid,))
            stats['virements'] = cur.rowcount or 0
        except: pass
        
        # 5. Mouvements de trésorerie (par caisse_id direct OU par référence)
        cur = conn.execute("DELETE FROM tresorerie_mouvements WHERE caisse_id=?", (cid,))
        stats['mouvements'] = cur.rowcount or 0
        if all_refs:
            cur = conn.execute("DELETE FROM tresorerie_mouvements WHERE reference IN ({})".format(
                ','.join('?' for _ in all_refs)), all_refs)
            stats['mouvements'] += cur.rowcount or 0
        
        # 6. Pièces de caisse
        try:
            cur = conn.execute("DELETE FROM pieces_caisse WHERE caisse_id=?", (cid,))
            stats['pieces'] = cur.rowcount or 0
        except: pass
        
        # 7. Écritures comptables liées (par référence/piece)
        if all_refs:
            try:
                cur = conn.execute("DELETE FROM ecritures_comptables WHERE piece IN ({})".format(
                    ','.join('?' for _ in all_refs)), all_refs)
                stats['ecritures'] = cur.rowcount or 0
            except: pass
        
        # 8. Délier les interventions
        try:
            cur = conn.execute("UPDATE interventions SET caisse_id=NULL WHERE caisse_id=?", (cid,))
            stats['interventions_unlinked'] = cur.rowcount or 0
        except: pass
        
        # 9. Enfin, la caisse elle-même
        conn.execute("DELETE FROM caisses WHERE id=?", (cid,))
        
        conn.commit()
        conn.close()
        
        log_activity(session['user_id'], user['full_name'], 'Caisse',
                     f"PURGE TOTALE caisse {ca['name']} (id={cid}) — {stats}", request.remote_addr)
        
        msg = (f"🗑️ Caisse « {ca['name']} » purgée : "
               f"{stats['operations']} op., {stats['entrees']} entrées, {stats['sorties']} sorties, "
               f"{stats['virements']} virements, {stats['mouvements']} mvts journal, "
               f"{stats['pieces']} pièces, {stats['ecritures']} écritures comptables. "
               f"📦 Sauvegarde disponible dans la Corbeille — restauration possible.")
        flash(msg, "success")
    except Exception as e:
        try: conn.close()
        except: pass
        flash(f"Erreur lors de la purge : {e}", "error")
    
    return redirect('/comptabilite/caisses')


# v111 : Purge TOTALE de toutes les caisses (pour repartir de zéro)
@app.route('/comptabilite/caisses/purge-all', methods=['POST'])
@login_required
def compta_caisse_purge_all():
    """v111 : Purge TOUTES les caisses (mode reset complet).
    Réservé à admin uniquement. Confirmation 'PURGE TOUTES' obligatoire."""
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    is_admin = user and user['role'] == 'admin'
    has_perm = user and _hp(user['role'], 'caisse_purge_all')
    if not (is_admin or has_perm):
        flash("⚠️ Permission 'caisse_purge_all' requise — réservée à l'admin", "error")
        return redirect('/comptabilite/caisses')
    
    if request.form.get('confirm', '').strip().upper() != 'PURGE TOUTES':
        flash("⚠️ Confirmation invalide : tapez exactement 'PURGE TOUTES' pour confirmer", "error")
        return redirect('/comptabilite/caisses')
    
    conn = _gdb()
    nb_caisses = conn.execute("SELECT COUNT(*) FROM caisses").fetchone()[0]
    if nb_caisses == 0:
        conn.close()
        flash("ℹ️ Aucune caisse à purger", "info")
        return redirect('/comptabilite/caisses')
    
    # v112 : SNAPSHOT par caisse AVANT purge totale
    nb_snapshots = 0
    try:
        all_caisses = conn.execute("SELECT id, name FROM caisses").fetchall()
        for cr in all_caisses:
            try:
                snapshot, snap_stats = _snapshot_caisse(conn, cr['id'])
                _save_trash_snapshot(conn, 'caisse', cr['id'], cr['name'],
                    snapshot, snap_stats, session['user_id'], user['full_name'],
                    notes='Purge globale (PURGE TOUTES)')
                nb_snapshots += 1
            except Exception as _se:
                print(f"[v112-Corbeille] Erreur snapshot caisse {cr['id']} : {_se}", flush=True)
        conn.commit()
        print(f"[v112-Corbeille] {nb_snapshots} snapshots sauvegardés en corbeille avant purge globale", flush=True)
    except Exception as _e:
        print(f"[v112-Corbeille] Erreur purge-all snapshot : {_e}", flush=True)
    
    # Récupérer toutes les références pour purger les écritures liées
    op_refs = [r[0] for r in conn.execute("SELECT reference FROM caisse_operations").fetchall() if r[0]]
    try:
        entree_refs = [r[0] for r in conn.execute("SELECT reference FROM caisse_entrees").fetchall() if r[0]]
    except: entree_refs = []
    sortie_refs = [r[0] for r in conn.execute("SELECT reference FROM caisse_sorties").fetchall() if r[0]]
    all_refs = list(set(op_refs + entree_refs + sortie_refs))
    
    stats = {}
    try:
        # Vider toutes les tables liées
        try:
            r = conn.execute("DELETE FROM caisse_operations"); stats['operations'] = r.rowcount or 0
        except: stats['operations'] = 0
        try:
            r = conn.execute("DELETE FROM caisse_entrees"); stats['entrees'] = r.rowcount or 0
        except: stats['entrees'] = 0
        try:
            r = conn.execute("UPDATE supplier_payments SET caisse_sortie_id=NULL WHERE caisse_sortie_id IS NOT NULL")
            stats['supplier_payments_unlinked'] = r.rowcount or 0
        except: pass
        try:
            r = conn.execute("DELETE FROM caisse_sorties"); stats['sorties'] = r.rowcount or 0
        except: stats['sorties'] = 0
        try:
            r = conn.execute("DELETE FROM caisse_virements"); stats['virements'] = r.rowcount or 0
        except: stats['virements'] = 0
        # Mouvements caisse uniquement
        r = conn.execute("DELETE FROM tresorerie_mouvements WHERE type='caisse' OR caisse_id IS NOT NULL")
        stats['mouvements'] = r.rowcount or 0
        if all_refs:
            r = conn.execute("DELETE FROM tresorerie_mouvements WHERE reference IN ({})".format(
                ','.join('?' for _ in all_refs)), all_refs)
            stats['mouvements'] += r.rowcount or 0
        try:
            r = conn.execute("DELETE FROM pieces_caisse"); stats['pieces'] = r.rowcount or 0
        except: stats['pieces'] = 0
        # Écritures comptables liées
        if all_refs:
            try:
                r = conn.execute("DELETE FROM ecritures_comptables WHERE piece IN ({})".format(
                    ','.join('?' for _ in all_refs)), all_refs)
                stats['ecritures'] = r.rowcount or 0
            except: pass
        # Délier interventions
        try:
            r = conn.execute("UPDATE interventions SET caisse_id=NULL WHERE caisse_id IS NOT NULL")
            stats['interventions_unlinked'] = r.rowcount or 0
        except: pass
        # Enfin, toutes les caisses
        r = conn.execute("DELETE FROM caisses"); stats['caisses'] = r.rowcount or 0
        
        conn.commit()
        conn.close()
        
        log_activity(session['user_id'], user['full_name'], 'Caisse',
                     f"PURGE TOTALE de TOUTES les caisses — {stats}", request.remote_addr)
        
        msg = (f"🗑️ PURGE COMPLÈTE effectuée : {stats.get('caisses',0)} caisses, "
               f"{stats.get('operations',0)} op., {stats.get('entrees',0)} entrées, "
               f"{stats.get('sorties',0)} sorties, {stats.get('virements',0)} virements, "
               f"{stats.get('mouvements',0)} mvts journal, {stats.get('pieces',0)} pièces, "
               f"{stats.get('ecritures',0)} écritures comptables. Vous pouvez recréer des caisses propres.")
        flash(msg, "success")
    except Exception as e:
        try: conn.close()
        except: pass
        flash(f"Erreur lors de la purge globale : {e}", "error")
    
    return redirect('/comptabilite/caisses')


