# v137 : API client full-info — utilisé par le formulaire de remontée pour auto-remplir
# les infos Entreprise / Point focal / Commercial + la liste des sites du client.
@app.route('/api/clients/<int:cid>/full-info')
@login_required
def api_client_full_info(cid):
    """v137 / v140 : Retourne en JSON toutes les infos d'un client + ses sites (installations).
    v140 : Ajoute un site_code unique à chaque site (auto-généré depuis client_code si absent).
    Utilisé par /field-reports/new pour le pré-remplissage dynamique."""
    conn = _gdb()
    try:
        client = conn.execute("SELECT * FROM clients WHERE id=?", (cid,)).fetchone()
        if not client:
            conn.close()
            return jsonify({'error': 'Client introuvable'}), 404
        
        client_dict = dict(client)
        client_code = (client_dict.get('client_code') or f"CL-{cid:04d}")
        
        # v140 : Migration site_code dans installations si pas encore présente
        try:
            conn.execute("SELECT site_code FROM installations LIMIT 1")
        except:
            try: conn.execute("ALTER TABLE installations ADD COLUMN site_code TEXT")
            except: pass
            conn.commit()
        
        # Récupérer les sites (installations) du client
        sites = []
        try:
            sites_rows = conn.execute(
                "SELECT id, site_name, zone, address, equipment_type, equipment_count, status, "
                "COALESCE(site_code,'') as site_code "
                "FROM installations WHERE client_id=? ORDER BY id",
                (cid,)).fetchall()
            sites = [dict(r) for r in sites_rows]
            
            # v140 : Auto-générer le site_code s'il manque, basé sur le code client
            for idx, s in enumerate(sites, 1):
                if not s.get('site_code'):
                    auto_code = f"{client_code}-S{idx}"
                    s['site_code'] = auto_code
                    # Persister le code généré
                    try:
                        conn.execute("UPDATE installations SET site_code=? WHERE id=?", (auto_code, s['id']))
                    except: pass
            conn.commit()
        except Exception as _e:
            print(f"[v140] sites err: {_e}", flush=True)
        
        conn.close()
        return jsonify({
            'client': client_dict,
            'client_code': client_code,
            'sites': sites,
            'sites_count': len(sites),
        })
    except Exception as e:
        try: conn.close()
        except: pass
        return jsonify({'error': str(e)}), 500


@app.route('/field-reports/new', methods=['GET', 'POST'])
@permission_required('field_report_create')
def field_report_new():
    """Création d'une remontée d'information."""
    if request.method == 'GET':
        conn = _gdb()
        # v138 : Liste enrichie (nom, code, ville) pour la recherche client
        clients = [dict(r) for r in conn.execute(
            "SELECT id, name, COALESCE(client_code,'') as client_code, COALESCE(city,'') as city, "
            "COALESCE(sector,'') as sector FROM clients ORDER BY name").fetchall()]
        conn.close()
        return render_template('field_report_new.html', page='field_reports',
            clients=clients, types=FIELD_REPORT_TYPES, priorities=FIELD_REPORT_PRIORITIES)
    
    # POST
    client_id = request.form.get('client_id', '').strip()
    client_name = request.form.get('client_name', '').strip()
    type_info = request.form.get('type_info', 'autre')
    description = request.form.get('description', '').strip()
    priorite = request.form.get('priorite', 'moyen')
    date_constat = request.form.get('date_constat') or datetime.now().strftime('%Y-%m-%d')
    site_name = request.form.get('site_name', '').strip()
    site_address = request.form.get('site_address', '').strip()
    site_zone = request.form.get('site_zone', '').strip()  # v137
    site_code = request.form.get('site_code', '').strip()  # v140 : code client du site
    create_site = request.form.get('create_site') in ('1', 'on', 'true')  # v137
    # v159 : date de traitement planifiée — "maintenant" ou "plus tard" (à une date)
    traitement_mode = request.form.get('traitement_mode', 'maintenant')
    traiter_le = request.form.get('traiter_le', '').strip()
    if traitement_mode != 'plus_tard':
        traiter_le = ''  # traiter maintenant → visible dans les tâches du jour immédiatement

    if not description:
        flash("Description requise", "error")
        return redirect('/field-reports/new')
    
    user = get_user_by_id(session.get('user_id')) if session.get('user_id') else None
    
    # Si client_id mais pas client_name, récupérer le nom
    if client_id and not client_name:
        conn = _gdb()
        row = conn.execute("SELECT name FROM clients WHERE id=?", (client_id,)).fetchone()
        if row: client_name = row['name']
        conn.close()
    
    # v137 / v140 : Création automatique du site si demandée
    if create_site and site_name and client_id and client_id.isdigit():
        try:
            conn = _gdb()
            # v140 : Assurer la colonne site_code
            try: conn.execute("SELECT site_code FROM installations LIMIT 1")
            except:
                try: conn.execute("ALTER TABLE installations ADD COLUMN site_code TEXT")
                except: pass
            
            # Vérifier qu'il n'existe pas déjà (par nom OU code client)
            existing = conn.execute(
                "SELECT id FROM installations WHERE client_id=? AND (LOWER(site_name)=LOWER(?) OR (? != '' AND site_code=?))",
                (int(client_id), site_name, site_code, site_code)).fetchone()
            if not existing:
                # Auto-générer le site_code s'il est vide
                if not site_code:
                    # Récupérer le client_code et compter les sites existants
                    cl = conn.execute("SELECT client_code FROM clients WHERE id=?", (int(client_id),)).fetchone()
                    code_prefix = (cl['client_code'] if cl and cl['client_code'] else f"CL-{int(client_id):04d}")
                    nb_existing = conn.execute("SELECT COUNT(*) FROM installations WHERE client_id=?",
                        (int(client_id),)).fetchone()[0]
                    site_code = f"{code_prefix}-S{nb_existing + 1}"
                
                conn.execute("""INSERT INTO installations
                    (client_id, client_name, site_name, zone, address, site_code, status, created_by, created_at)
                    VALUES (?,?,?,?,?,?,'actif',?,datetime('now'))""",
                    (int(client_id), client_name, site_name, site_zone, site_address, site_code,
                     session.get('user_id')))
                conn.commit()
                print(f"[v140] Site créé : {site_code} ({site_name}) pour client {client_id}", flush=True)
            conn.close()
        except Exception as _e:
            print(f"[v140] err création site : {_e}", flush=True)
    
    ref = _gen_field_report_ref()
    try:
        conn = _gdb()
        # v140 : Assurer la colonne site_code dans field_reports
        try: conn.execute("SELECT site_code FROM field_reports LIMIT 1")
        except:
            try: conn.execute("ALTER TABLE field_reports ADD COLUMN site_code TEXT")
            except: pass
        
        cur = conn.execute("""INSERT INTO field_reports
            (reference, client_id, client_name, site_name, site_address, site_code, type_info,
             description, priorite, date_constat, auteur_id, auteur_name, statut, traiter_le,
             created_at, updated_at)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,'recue',?,datetime('now'),datetime('now'))""",
            (ref, int(client_id) if client_id and client_id.isdigit() else None,
             client_name or 'Non spécifié', site_name, site_address, site_code, type_info,
             description, priorite, date_constat,
             session.get('user_id'),
             user['full_name'] if user else 'Anonyme',
             traiter_le or None))
        report_id = cur.lastrowid
        conn.commit()
        conn.close()
        
        _field_report_log(report_id, 'Création', f"Type: {FIELD_REPORT_TYPES.get(type_info, type_info)}, Priorité: {priorite}")
        _field_report_notify(report_id, 'created')
        
        # v157 : Si la remontée est de type "nouveau projet"/installation → notifier les commerciaux
        tlow = (type_info or '').lower()
        if ('nouveau' in tlow and 'projet' in tlow) or 'installation' in tlow or 'projet_neuf' in tlow:
            try:
                notify_roles(['commercial','admin','dg'],
                    title=f"🎯 NOUVEAU PROJET — {ref} : {client_name}",
                    message=f"Une remontée de type nouveau projet a été créée par {user['full_name'] if user else 'Anonyme'}. "
                            f"Description : {description[:200]}. À traiter en devis / proforma.",
                    link=f'/field-reports/{report_id}',
                    type='info', module='clients', icon='🎯', priority='high', force=True)
            except Exception as _e: print(f"[v157] notif nouveau projet err : {_e}", flush=True)
        
        flash(f"✅ Remontée {ref} enregistrée et notifications envoyées", "success")
        return redirect(f'/field-reports/{report_id}')
    except Exception as e:
        flash(f"Erreur : {e}", "error")
        return redirect('/field-reports/new')


@app.route('/field-reports/<int:rid>')
@permission_required_any('field_report_view_all', 'field_report_view_mine', 'field_report_create')
def field_report_detail(rid):
    """Détail d'une remontée."""
    conn = _gdb()
    row = conn.execute("SELECT * FROM field_reports WHERE id=?", (rid,)).fetchone()
    if not row:
        conn.close()
        flash("Remontée introuvable", "error")
        return redirect('/field-reports')
    report = dict(row)
    
    # v105 : Permissions de vue — utiliser has_permission (BDD) au lieu de session (vide)
    from models import has_permission as _hp
    user_id = session.get('user_id')
    user = get_user_by_id(user_id) if user_id else None
    user_role = user['role'] if user else None
    
    can_view_all = (user_role == 'admin' or 
                    _hp(user_role, 'field_report_view_all') or 
                    _hp(user_role, 'admin'))
    is_author = (report.get('auteur_id') == user_id)
    
    if not can_view_all and not is_author:
        conn.close()
        flash("Accès refusé", "error")
        return redirect('/field-reports')
    
    # Enrichir
    sl = FIELD_REPORT_STATUTS.get(report['statut'], (report['statut'], '#888'))
    pl = FIELD_REPORT_PRIORITIES.get(report['priorite'], (report['priorite'], '#888'))
    report['statut_label'] = sl[0]; report['statut_color'] = sl[1]
    report['priorite_label'] = pl[0]; report['priorite_color'] = pl[1]
    report['type_label'] = FIELD_REPORT_TYPES.get(report['type_info'], report['type_info'])
    
    # Historique
    history = [dict(r) for r in conn.execute(
        "SELECT * FROM field_reports_history WHERE report_id=? ORDER BY created_at DESC", (rid,)).fetchall()]
    
    # Pièces jointes
    files = [dict(r) for r in conn.execute(
        "SELECT * FROM field_reports_files WHERE report_id=? ORDER BY uploaded_at DESC", (rid,)).fetchall()]
    
    # v131 : Liste des techniciens (pour transformer en intervention)
    technicians = []
    try:
        technicians = [dict(r) for r in conn.execute(
            """SELECT id, full_name, role FROM users 
            WHERE role IN ('technicien','tech_chef','centre_technique','informatique') 
            AND COALESCE(is_active,1)=1 ORDER BY full_name""").fetchall()]
    except: pass
    
    # v131 : Si remontée déjà transformée en intervention, récupérer infos intervention
    linked_intervention = None
    if report.get('linked_intervention_id'):
        try:
            linked_intervention = dict(conn.execute(
                "SELECT * FROM interventions WHERE id=?",
                (report['linked_intervention_id'],)).fetchone() or {})
        except: pass
    
    conn.close()
    return render_template('field_report_detail.html', page='field_reports',
        report=report, history=history, files=files, technicians=technicians,
        linked_intervention=linked_intervention,
        types=FIELD_REPORT_TYPES, priorities=FIELD_REPORT_PRIORITIES, statuts=FIELD_REPORT_STATUTS)


