# ============= v142 : WORKFLOW REMONTÉE → FACTURE → RECOUVREMENT → PAIEMENT =============

@app.route('/field-reports/<int:rid>/execute', methods=['POST'])
@permission_required_any('field_report_execute', 'admin')
def field_report_execute(rid):
    """v142 / v143 : Le technicien marque une remontée comme exécutée.
    v143 : Clôt aussi l'intervention liée (si existe) pour qu'elle sorte des tâches en attente.
    Notifie automatiquement DG + RH pour décision de facturation."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    notes = (request.form.get('execution_notes','') or '').strip()
    conn = _gdb()
    try:
        # Récupérer la remontée + l'éventuelle intervention liée
        r = conn.execute("SELECT reference, client_name, type_info, priorite, linked_intervention_id FROM field_reports WHERE id=?", (rid,)).fetchone()
        if not r:
            conn.close()
            flash("Remontée introuvable", "error")
            return redirect('/field-reports')
        
        # Mettre à jour la remontée
        conn.execute("""UPDATE field_reports
            SET executed_by=?, executed_at=datetime('now'),
                execution_notes=?, statut='executee',
                updated_at=datetime('now')
            WHERE id=?""",
            (user['id'], notes, rid))
        
        # v143 : Clôturer l'intervention liée si présente (pour qu'elle n'apparaisse plus
        # dans les tâches en attente du technicien lors de la clôture journalière)
        intervention_closed = False
        if r['linked_intervention_id']:
            try:
                conn.execute("""UPDATE interventions 
                    SET status='termine', updated_at=datetime('now')
                    WHERE id=? AND status NOT IN ('cloturee','annulee','close','termine')""",
                    (r['linked_intervention_id'],))
                intervention_closed = True
            except Exception as _e: print(f"[v143] close intervention err : {_e}", flush=True)
        
        conn.commit()
        conn.close()
        
        _field_report_log(rid, 'Exécutée', f"Technicien : {user['full_name']} — {notes[:200]}")
        
        # Notification DG + RH (décision facturation) — HIGH PRIORITY avec lien explicite
        try:
            notify_roles(['dg','directeur','rh','directrice_rh','admin'],
                title=f"💰 DÉCISION REQUISE — Facturation : {r['reference']}",
                message=f"Le technicien {user['full_name']} a terminé la remontée {r['reference']} "
                        f"({r['client_name']}). VOUS DEVEZ DÉCIDER si cette intervention est facturable. "
                        f"Cliquez pour accéder au formulaire de décision.",
                link=f"/decisions/facturation",  # v143 : lien vers page dédiée
                type='warning', module='remontees', icon='💰', priority='high', force=True)
        except Exception as _e: print(f"[v143] notif decision err : {_e}", flush=True)
        
        msg = "✅ Remontée marquée exécutée"
        if intervention_closed: msg += " · Intervention liée clôturée"
        msg += " — DG/RH notifié(e)s pour décision de facturation"
        flash(msg, "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect(f'/field-reports/{rid}')


# v143 : Page dédiée pour les décisions de facturation (DG/RH)
@app.route('/decisions/facturation')
@permission_required_any('facturation_decision', 'admin')
def decisions_facturation():
    """v143 / v144 / v145 : Page décisions facturation avec onglets et filtres.
    Onglets : nouvelles (en attente) / avec facture (facturable=1) / sans facture (facturable=0).
    Filtres : recherche client/ref, période."""
    # v161 : synchroniser les véhicules (statut + factures recharge) avant d'afficher
    try: _sync_vehicles_recharge()
    except: pass
    # Onglet actif
    tab = request.args.get('tab', 'nouvelles').strip()
    if tab not in ('nouvelles', 'avec_facture', 'sans_facture', 'tracking', 'pointage'):
        tab = 'nouvelles'
    
    # Filtres
    search = request.args.get('q', '').strip()
    date_from = request.args.get('date_from', '').strip()
    date_to = request.args.get('date_to', '').strip()
    
    conn = _gdb()
    
    # Construction de la requête selon l'onglet
    where_clauses = []
    params = []
    
    if tab == 'nouvelles':
        where_clauses.append("fr.statut IN ('executee','traitee')")
        where_clauses.append("fr.facturable IS NULL")
        # v159/v161 : interventions OU rapports d'heures OU recharges véhicule (puce internet)
        where_clauses.append("(fr.linked_intervention_id IS NOT NULL OR fr.type_info IN ('rapport_heures','recharge_vehicule'))")
        order_by = "COALESCE(fr.executed_at, fr.updated_at) DESC"
    elif tab == 'tracking':
        # v162 : nouvelles décisions de facture « tracking » (recharge internet véhicule)
        where_clauses.append("fr.statut IN ('executee','traitee')")
        where_clauses.append("fr.facturable IS NULL")
        where_clauses.append("fr.type_info='recharge_vehicule'")
        order_by = "COALESCE(fr.executed_at, fr.updated_at) DESC"
    elif tab == 'pointage':
        # v162 : nouvelles décisions de facture « pointage » (rapports d'heures RH)
        where_clauses.append("fr.statut IN ('executee','traitee')")
        where_clauses.append("fr.facturable IS NULL")
        where_clauses.append("fr.type_info='rapport_heures'")
        order_by = "COALESCE(fr.executed_at, fr.updated_at) DESC"
    elif tab == 'avec_facture':
        where_clauses.append("fr.facturable=1")
        order_by = "fr.facturation_decided_at DESC"
    else:  # sans_facture
        where_clauses.append("fr.facturable=0")
        order_by = "fr.facturation_decided_at DESC"
    
    # Filtres communs
    if search:
        where_clauses.append("(fr.reference LIKE ? OR fr.client_name LIKE ? OR fr.description LIKE ?)")
        params.extend([f"%{search}%"] * 3)
    if date_from:
        where_clauses.append("DATE(COALESCE(fr.executed_at, fr.facturation_decided_at)) >= ?")
        params.append(date_from)
    if date_to:
        where_clauses.append("DATE(COALESCE(fr.executed_at, fr.facturation_decided_at)) <= ?")
        params.append(date_to)
    
    where_sql = " AND ".join(where_clauses)
    
    items = [dict(r) for r in conn.execute(f"""
        SELECT fr.id, fr.reference, fr.client_name, fr.type_info, fr.priorite,
               fr.description, fr.execution_notes, fr.executed_at,
               fr.statut as fr_statut, fr.linked_intervention_id,
               fr.facturable, fr.cost_amount, fr.facturation_motif,
               fr.facturation_decided_at,
               u.full_name as executed_by_name,
               ud.full_name as decided_by_name,
               i.rapport as technicien_rapport
        FROM field_reports fr
        LEFT JOIN users u ON u.id = fr.executed_by
        LEFT JOIN users ud ON ud.id = fr.facturation_decided_by
        LEFT JOIN interventions i ON i.id = fr.linked_intervention_id
        WHERE {where_sql}
        ORDER BY {order_by} LIMIT 100""", params).fetchall()]
    
    # Compteurs pour les onglets
    counts = {
        'nouvelles': conn.execute(
            "SELECT COUNT(*) FROM field_reports WHERE statut IN ('executee','traitee') "
            "AND facturable IS NULL AND (linked_intervention_id IS NOT NULL OR type_info IN ('rapport_heures','recharge_vehicule'))"
        ).fetchone()[0],
        'avec_facture': conn.execute("SELECT COUNT(*) FROM field_reports WHERE facturable=1").fetchone()[0],
        'sans_facture': conn.execute("SELECT COUNT(*) FROM field_reports WHERE facturable=0").fetchone()[0],
        # v162 : compteurs dédiés des nouvelles décisions par origine
        'tracking': conn.execute(
            "SELECT COUNT(*) FROM field_reports WHERE statut IN ('executee','traitee') "
            "AND facturable IS NULL AND type_info='recharge_vehicule'"
        ).fetchone()[0],
        'pointage': conn.execute(
            "SELECT COUNT(*) FROM field_reports WHERE statut IN ('executee','traitee') "
            "AND facturable IS NULL AND type_info='rapport_heures'"
        ).fetchone()[0],
    }
    
    conn.close()
    
    return render_template('decisions_facturation.html', page='decisions_facturation',
        items=items, tab=tab, counts=counts,
        search=search, date_from=date_from, date_to=date_to)


@app.route('/field-reports/<int:rid>/decide-facturation', methods=['POST'])
@permission_required_any('facturation_decision', 'admin')
def field_report_decide_facturation(rid):
    """v142 / v147 : DG/RH décide si la remontée est facturable.
    v147 : Commentaire (motif) OBLIGATOIRE dans tous les cas, montant obligatoire si facturable."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    is_facturable = request.form.get('facturable') == '1'
    cost_str = (request.form.get('cost_amount','') or '0').replace(',','.').strip()
    motif = (request.form.get('motif','') or '').strip()
    
    try:
        cost = float(cost_str or 0)
    except:
        cost = 0
    
    # v147 : Commentaire obligatoire dans tous les cas
    if len(motif) < 5:
        flash("⚠️ Le commentaire (motif) est obligatoire — minimum 5 caractères. "
              "Justifiez votre décision (raison de la facturation ou de la non-facturation).", "error")
        return redirect(f'/decisions/facturation' if request.referrer and 'decisions' in request.referrer else f'/field-reports/{rid}')

    conn = _gdb()
    try:
        r = conn.execute("SELECT reference, client_name, cost_amount, type_info FROM field_reports WHERE id=?", (rid,)).fetchone()
        if not r:
            conn.close()
            flash("Remontée introuvable", "error")
            return redirect('/field-reports')

        # v159 : Montant déjà saisi en amont (ex: rapport d'heures envoyé par la RH) →
        # le DG valide sans ressaisir le montant ; on retombe sur le montant existant.
        if is_facturable and cost <= 0:
            try: cost = float(r['cost_amount'] or 0)
            except: cost = 0
        # Montant obligatoire si facturable
        if is_facturable and cost <= 0:
            conn.close()
            flash("⚠️ Si facturable, le montant doit être > 0 FCFA", "error")
            return redirect(f'/decisions/facturation' if request.referrer and 'decisions' in request.referrer else f'/field-reports/{rid}')
        
        # Mettre à jour la remontée
        conn.execute("""UPDATE field_reports
            SET facturable=?, cost_amount=?, cost_currency='XOF',
                facturation_decided_by=?, facturation_decided_at=datetime('now'),
                facturation_motif=?,
                updated_at=datetime('now')
            WHERE id=?""",
            (1 if is_facturable else 0, cost if is_facturable else 0,
             user['id'], motif, rid))
        
        if is_facturable:
            # v152 : Date limite par défaut = lendemain (J+1)
            deadline_default = (datetime.now() + timedelta(days=1)).strftime('%Y-%m-%d')
            # Créer l'enregistrement facture/recouvrement
            cur = conn.execute("""INSERT INTO field_report_invoices
                (field_report_id, amount, currency, decided_by, decided_at,
                 decision_motif, status, deadline_edit, created_at, updated_at)
                VALUES (?,?,?,?,datetime('now'),?,'a_facturer',?,datetime('now'),datetime('now'))""",
                (rid, cost, 'XOF', user['id'], motif, deadline_default))
            invoice_workflow_id = cur.lastrowid
            conn.commit()
            conn.close()
            
            _field_report_log(rid, 'Décision facturer',
                f"Facturable {cost:,.0f} XOF — décidée par {user['full_name']}")
            
            # v145 : Log événement timeline
            _log_fri_event(invoice_workflow_id, rid, user['id'], user['full_name'],
                'decision_facturer', f"Décision : facturable ({cost:,.0f} XOF)",
                '💰', motif, cost)
            
            # Notifier la comptabilité
            try:
                notify_roles(['comptable','comptabilite','admin'],
                    title=f"🧾 Nouvelle facture à éditer : {r['reference']}",
                    message=f"Le DG/RH a décidé de facturer la remontée {r['reference']} "
                            f"({r['client_name']}) pour {cost:,.0f} XOF. "
                            f"Veuillez éditer la facture pour le client.",
                    link=f"/recouvrement/factures-a-editer",
                    type='info', module='factures', icon='🧾', priority='high')
            except: pass
            
            flash(f"✅ Facturation décidée ({cost:,.0f} XOF) — Comptabilité notifiée", "success")
        else:
            # Non facturable → classer
            conn.execute("UPDATE field_reports SET statut='classee' WHERE id=?", (rid,))
            conn.commit()
            conn.close()
            _field_report_log(rid, 'Non facturable', motif or 'Décision non facturable')
            # v145 : Log événement
            _log_fri_event(None, rid, user['id'], user['full_name'],
                'decision_non_facturer', "Décision : non facturable",
                '❌', motif)
            flash("📁 Remontée marquée non facturable et classée", "info")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    
    return redirect(f'/field-reports/{rid}')


# ============= COMPTABILITÉ : Éditer la facture =============

@app.route('/recouvrement/factures-a-editer')
@permission_required_any('facture_edit', 'admin')
def factures_a_editer():
    """v142 / v145 : Page comptabilité avec onglets.
    - tab=a_editer : factures à éditer (status='a_facturer')
    - tab=editees : factures déjà éditées (status='facture_editee'+)"""
    tab = request.args.get('tab', 'a_editer').strip()
    search = request.args.get('q', '').strip()
    
    conn = _gdb()
    
    if tab == 'editees':
        where_sql = "fri.status IN ('facture_editee','en_recouvrement','caisse_choisie','paye')"
        order_by = "fri.emitted_at DESC"
    else:
        where_sql = "fri.status='a_facturer'"
        order_by = "fri.created_at DESC"
    
    params = []
    if search:
        where_sql += " AND (fr.reference LIKE ? OR fr.client_name LIKE ? OR fri.invoice_number LIKE ?)"
        params.extend([f"%{search}%"] * 3)
    
    items = [dict(r) for r in conn.execute(f"""
        SELECT fri.*, fr.reference as fr_ref, fr.client_name, fr.type_info,
               u.full_name as decided_by_name,
               ue.full_name as emitted_by_name
        FROM field_report_invoices fri
        JOIN field_reports fr ON fr.id = fri.field_report_id
        LEFT JOIN users u ON u.id = fri.decided_by
        LEFT JOIN users ue ON ue.id = fri.emitted_by
        WHERE {where_sql}
        ORDER BY {order_by} LIMIT 100""", params).fetchall()]
    
    counts = {
        'a_editer': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status='a_facturer'").fetchone()[0],
        'editees': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status IN ('facture_editee','en_recouvrement','caisse_choisie','paye')").fetchone()[0],
    }
    
    conn.close()
    return render_template('recouvrement_factures_a_editer.html', page='factures_a_editer',
        items=items, tab=tab, counts=counts, search=search)


@app.route('/recouvrement/facture/<int:fri_id>/preview')
@permission_required_any('facture_edit', 'recouvrement_view', 'admin')
def facture_preview(fri_id):
    """v145 : Prévisualisation HTML d'une facture (PDF-like)."""
    conn = _gdb()
    # v145 : Assurer la colonne site_code dans field_reports
    try: conn.execute("SELECT site_code FROM field_reports LIMIT 1")
    except:
        try: conn.execute("ALTER TABLE field_reports ADD COLUMN site_code TEXT")
        except: pass
        conn.commit()
    
    row = conn.execute("""SELECT fri.*, fr.reference as fr_ref, fr.client_name,
                          fr.type_info, fr.description, fr.execution_notes,
                          fr.site_name, fr.site_address,
                          COALESCE(fr.site_code, '') as site_code,
                          ud.full_name as decided_by_name,
                          ue.full_name as emitted_by_name,
                          ur.full_name as recovery_agent_name,
                          uc.full_name as cashier_name
                          FROM field_report_invoices fri
                          JOIN field_reports fr ON fr.id = fri.field_report_id
                          LEFT JOIN users ud ON ud.id = fri.decided_by
                          LEFT JOIN users ue ON ue.id = fri.emitted_by
                          LEFT JOIN users ur ON ur.id = fri.recovery_agent_id
                          LEFT JOIN users uc ON uc.id = fri.payment_validated_by
                          WHERE fri.id=?""", (fri_id,)).fetchone()
    if not row:
        conn.close()
        flash("Facture introuvable", "error")
        return redirect('/recouvrement/factures-a-editer')
    
    # Récupérer la timeline des événements
    events = [dict(r) for r in conn.execute(
        "SELECT * FROM fri_events WHERE fri_id=? ORDER BY created_at", (fri_id,)).fetchall()]
    
    conn.close()
    return render_template('facture_preview.html', page='facture_preview',
        f=dict(row), events=events,
        payment_types=PAYMENT_TYPES,
        recovery_methods=RECOVERY_METHODS)


@app.route('/recouvrement/facture/<int:fri_id>/modifier', methods=['POST'])
@permission_required_any('facture_edit', 'admin', 'dg')
def facture_modifier(fri_id):
    """v145 / v146 : Modification d'une facture.
    v146 : Accepte aussi modification AVANT édition (status='a_facturer').
    v160 : ouvert au DG ; modification interdite une fois la facture envoyée au client."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    new_amount_str = (request.form.get('amount','') or '').replace(',','.').strip()
    new_invoice_number = (request.form.get('invoice_number','') or '').strip()
    notes = (request.form.get('notes','') or '').strip()
    
    try:
        new_amount = float(new_amount_str or 0)
    except: new_amount = 0
    
    if new_amount <= 0:
        flash("⚠️ Montant invalide", "error")
        return redirect(f'/recouvrement/facture/{fri_id}/preview')
    
    conn = _gdb()
    try:
        old = conn.execute("SELECT amount, invoice_number, field_report_id, status, recovery_sent_at FROM field_report_invoices WHERE id=?",
            (fri_id,)).fetchone()
        if not old:
            conn.close()
            flash("Facture introuvable", "error")
            return redirect('/recouvrement/factures-a-editer')

        # v146 : Refuser modification si déjà payée
        if old['status'] == 'paye':
            conn.close()
            flash("⛔ Cette facture est déjà payée et ne peut plus être modifiée", "error")
            return redirect(f'/recouvrement/facture/{fri_id}/preview')

        # v160 : interdire la modification une fois la facture envoyée au client
        if old['recovery_sent_at'] or old['status'] in ('caisse_choisie', 'en_recouvrement'):
            conn.close()
            flash("⛔ Cette facture a déjà été envoyée au client — modification impossible.", "error")
            return redirect(f'/recouvrement/facture/{fri_id}/preview')
        
        old_amount = old['amount']
        old_inv_num = old['invoice_number']
        fr_id = old['field_report_id']

        # Conserver le numéro existant si pas fourni, sauf si vide volontairement
        final_inv_num = new_invoice_number if new_invoice_number else old_inv_num

        # v160 : TVA modifiable (appliquer ou non + taux). Mis à jour seulement si le
        # formulaire envoie le marqueur tva_form (sinon on préserve la TVA existante).
        if request.form.get('tva_form'):
            tva_apply = 1 if (request.form.get('tva_apply') in ('1', 'on', 'true', 'yes')) else 0
            try: tva_rate = float((request.form.get('tva_rate') or 18))
            except: tva_rate = 18
            conn.execute("""UPDATE field_report_invoices
                SET amount=?, invoice_number=?, tva_apply=?, tva_rate=?, updated_at=datetime('now')
                WHERE id=?""",
                (new_amount, final_inv_num, tva_apply, tva_rate, fri_id))
        else:
            conn.execute("""UPDATE field_report_invoices
                SET amount=?, invoice_number=?, updated_at=datetime('now')
                WHERE id=?""",
                (new_amount, final_inv_num, fri_id))
        
        # v146 : Si on était à 'a_facturer', sync field_reports.cost_amount aussi
        if old['status'] == 'a_facturer':
            try:
                conn.execute("UPDATE field_reports SET cost_amount=? WHERE id=?",
                    (new_amount, fr_id))
            except: pass
        
        conn.commit()
        conn.close()
        
        _log_fri_event(fri_id, fr_id, user['id'], user['full_name'],
            'facture_modifiee', f"Facture modifiée par {user['full_name']}",
            '✏️', f"Montant : {old_amount:,.0f} → {new_amount:,.0f} XOF. {notes}",
            new_amount)
        
        flash(f"✅ Facture modifiée ({new_amount:,.0f} XOF)", "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect(f'/recouvrement/facture/{fri_id}/preview')


# v152 : Reporter le traitement d'une facture au lendemain (compta)
@app.route('/recouvrement/facture/<int:fri_id>/reporter', methods=['POST'])
@permission_required_any('facture_edit', 'admin')
def facture_reporter(fri_id):
    """v152 : La comptabilité reporte le traitement d'une facture au lendemain (J+1).
    Permet à la compta de clôturer sa journée si elle reçoit une décision DG tardive.
    Justification obligatoire."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    reason = (request.form.get('reason','') or '').strip()
    if len(reason) < 5:
        flash("⚠️ Une justification est obligatoire pour reporter le traitement (min 5 caractères).", "error")
        return redirect('/recouvrement/factures-a-editer')
    
    conn = _gdb()
    try:
        fri = conn.execute("""SELECT fri.id, fri.status, fri.field_report_id, fr.client_name, fr.reference as fr_ref
            FROM field_report_invoices fri
            JOIN field_reports fr ON fr.id = fri.field_report_id
            WHERE fri.id=?""", (fri_id,)).fetchone()
        if not fri:
            conn.close()
            flash("Facture introuvable", "error")
            return redirect('/recouvrement/factures-a-editer')
        if fri['status'] != 'a_facturer':
            conn.close()
            flash("⛔ Cette facture n'est plus à éditer (déjà éditée)", "error")
            return redirect('/recouvrement/factures-a-editer')
        
        # Nouvelle deadline = lendemain
        new_deadline = (datetime.now() + timedelta(days=1)).strftime('%Y-%m-%d')
        conn.execute("""UPDATE field_report_invoices
            SET deadline_edit=?, edit_reported_at=datetime('now'), edit_report_reason=?,
                updated_at=datetime('now') WHERE id=?""",
            (new_deadline, reason, fri_id))
        conn.commit()
        conn.close()
        
        _log_fri_event(fri_id, fri['field_report_id'], user['id'], user['full_name'],
            'facture_reportee', f"Facture reportée à {new_deadline}",
            '📅', f"Raison : {reason}", None)
        
        flash(f"📅 Édition reportée au {new_deadline}. Vous pouvez clôturer votre journée.", "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect('/recouvrement/factures-a-editer')


@app.route('/recouvrement/facture/<int:fri_id>/edit', methods=['POST'])
@permission_required_any('facture_edit', 'admin')
def edit_invoice_v142(fri_id):
    """v142 / v145 / v147 / v156 : Comptabilité édite la facture.
    v147 : Commentaire obligatoire. v156 : TVA optionnelle (case à cocher tva_apply)."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    invoice_number = (request.form.get('invoice_number','') or '').strip()
    notes = (request.form.get('notes','') or '').strip()
    if not invoice_number:
        invoice_number = f"FAC-{datetime.now().strftime('%Y%m%d-%H%M%S')}"
    
    # v147 : Commentaire obligatoire
    if len(notes) < 5:
        flash("⚠️ Un commentaire est obligatoire lors de l'édition de la facture (min 5 caractères).", "error")
        return redirect('/recouvrement/factures-a-editer')
    
    # v156 : TVA optionnelle (par défaut activée si tva_apply absent du form pour rétrocompatibilité)
    tva_apply = request.form.get('tva_apply', '0').strip() in ('1', 'on', 'true', 'yes')
    tva_rate = float(request.form.get('tva_rate', '18') or 18)
    
    conn = _gdb()
    # Migration silencieuse : ajouter colonnes tva si manquantes
    try:
        conn.execute("SELECT tva_apply FROM field_report_invoices LIMIT 1")
    except:
        try: conn.execute("ALTER TABLE field_report_invoices ADD COLUMN tva_apply INTEGER DEFAULT 1")
        except: pass
    try:
        conn.execute("SELECT tva_rate FROM field_report_invoices LIMIT 1")
    except:
        try: conn.execute("ALTER TABLE field_report_invoices ADD COLUMN tva_rate REAL DEFAULT 18")
        except: pass
    conn.commit()
    
    try:
        fri = conn.execute("""SELECT fri.*, fr.client_name, fr.reference as fr_ref
                              FROM field_report_invoices fri
                              JOIN field_reports fr ON fr.id = fri.field_report_id
                              WHERE fri.id=?""", (fri_id,)).fetchone()
        if not fri:
            conn.close()
            flash("Facture introuvable", "error")
            return redirect('/recouvrement/factures-a-editer')
        
        # v156 : Sauvegarder le choix TVA
        conn.execute("""UPDATE field_report_invoices
            SET invoice_number=?, emitted_by=?, emitted_at=datetime('now'),
                status='facture_editee', tva_apply=?, tva_rate=?, updated_at=datetime('now')
            WHERE id=?""",
            (invoice_number, user['id'], 1 if tva_apply else 0, tva_rate, fri_id))
        conn.commit()
        conn.close()
        
        tva_msg = f"TVA {tva_rate}%" if tva_apply else "Sans TVA"
        # v145 : Log événement
        _log_fri_event(fri_id, fri['field_report_id'], user['id'], user['full_name'],
            'facture_editee', f"Facture {invoice_number} éditée ({tva_msg})",
            '🧾', f"Client : {fri['client_name']} · Montant : {fri['amount']:,.0f} XOF · {tva_msg} · Notes : {notes}",
            fri['amount'])
        
        try:
            notify_roles(['agent_recouvreur','admin'],
                title=f"📤 Nouvelle facture à recouvrer : {invoice_number}",
                message=f"Facture {invoice_number} ({fri['client_name']}, {fri['amount']:,.0f} XOF) "
                        f"prête à être envoyée/déposée au client.",
                link='/recouvrement',
                type='info', module='factures', icon='📤', priority='high')
        except: pass
        
        flash(f"✅ Facture {invoice_number} éditée — Agent recouvreur notifié", "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect('/recouvrement/factures-a-editer')


# ============= AGENT RECOUVREUR : envoi + caisse =============

@app.route('/recouvrement')
@permission_required_any('recouvrement_view', 'admin')
def recouvrement_dashboard():
    """v142 / v145 : Dashboard agent recouvreur avec onglets.
    - nouvelles : factures éditées par la compta, à recevoir/aller chercher
    - en_attente : envoyées au client, en attente du paiement physique
    - recouvrees : déjà encaissées (paiement validé par la caissière)"""
    tab = request.args.get('tab', 'nouvelles').strip()
    search = request.args.get('q', '').strip()
    
    conn = _gdb()
    
    if tab == 'en_attente':
        where_sql = "fri.status IN ('en_recouvrement','caisse_choisie')"
        order_by = "fri.recovery_sent_at"
    elif tab == 'recouvrees':
        where_sql = "fri.status='paye'"
        order_by = "fri.payment_validated_at DESC"
    else:  # nouvelles
        where_sql = "fri.status='facture_editee'"
        order_by = "fri.emitted_at"
    
    params = []
    if search:
        where_sql += " AND (fr.reference LIKE ? OR fr.client_name LIKE ? OR fri.invoice_number LIKE ?)"
        params.extend([f"%{search}%"] * 3)
    
    # v160 : LEFT JOIN (et non INNER) pour que TOUTE facture du compteur s'affiche,
    # même si sa remontée a été supprimée.
    items = [dict(r) for r in conn.execute(f"""
        SELECT fri.*, fr.reference as fr_ref, fr.client_name,
               u.full_name as emitted_by_name,
               cs.name as caisse_name,
               ucv.full_name as cashier_name
        FROM field_report_invoices fri
        LEFT JOIN field_reports fr ON fr.id = fri.field_report_id
        LEFT JOIN users u ON u.id = fri.emitted_by
        LEFT JOIN caisses cs ON cs.id = fri.target_caisse_id
        LEFT JOIN users ucv ON ucv.id = fri.payment_validated_by
        WHERE {where_sql}
        ORDER BY {order_by} LIMIT 100""", params).fetchall()]

    caisses = [dict(r) for r in conn.execute(
        "SELECT id, name FROM caisses WHERE COALESCE(is_active,1)=1 ORDER BY name").fetchall()]

    counts = {
        'nouvelles': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status='facture_editee'").fetchone()[0],
        'en_attente': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status IN ('en_recouvrement','caisse_choisie')").fetchone()[0],
        'recouvrees': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status='paye'").fetchone()[0],
    }
    # v160 : solde (somme des montants) par catégorie — affiché en face de chaque onglet
    totals = {
        'nouvelles': conn.execute("SELECT COALESCE(SUM(amount),0) FROM field_report_invoices WHERE status='facture_editee'").fetchone()[0],
        'en_attente': conn.execute("SELECT COALESCE(SUM(amount),0) FROM field_report_invoices WHERE status IN ('en_recouvrement','caisse_choisie')").fetchone()[0],
        'recouvrees': conn.execute("SELECT COALESCE(SUM(amount),0) FROM field_report_invoices WHERE status='paye'").fetchone()[0],
    }

    conn.close()

    return render_template('recouvrement_dashboard.html', page='recouvrement',
        items=items, caisses=caisses,
        recovery_methods=RECOVERY_METHODS,
        payment_types=PAYMENT_TYPES,
        tab=tab, counts=counts, totals=totals, search=search)


@app.route('/recouvrement/versements')
@permission_required_any('recouvrement_view', 'recouvrement_edit', 'caissiere_view', 'admin')
def recouvrement_versements():
    """v160 : Remise & versement — l'agent enregistre ses remises d'espèces / versements
    (bordereau) et suit l'historique. Registre justificatif (sans impact comptable :
    le crédit en caisse reste géré par la validation caissière)."""
    conn = _gdb()
    user = get_user_by_id(session['user_id'])
    is_admin = user and user['role'] == 'admin'
    # Un agent voit ses propres versements ; admin/caissière voient tout
    if is_admin or (user and user['role'] in ('caissiere', 'dg', 'directeur', 'comptable', 'comptabilite')):
        rows = conn.execute("SELECT * FROM recouvrement_versements ORDER BY date_versement DESC, id DESC LIMIT 200").fetchall()
    else:
        rows = conn.execute("SELECT * FROM recouvrement_versements WHERE agent_id=? ORDER BY date_versement DESC, id DESC LIMIT 200", (session['user_id'],)).fetchall()
    versements = [dict(r) for r in rows]
    # v162 : statut effectif d'une remise de chèque (en attente jusqu'à J+3 ouvrés, puis disponible)
    _today = datetime.now().strftime('%Y-%m-%d')
    for v in versements:
        v['est_remise'] = (v.get('type_operation') == 'remise')
        if v['est_remise'] and v.get('statut') != 'annule':
            v['dispo'] = bool(v.get('date_disponibilite')) and (v['date_disponibilite'][:10] <= _today)
        else:
            v['dispo'] = True
    total = sum(v['montant'] or 0 for v in versements)
    caisses = [dict(r) for r in conn.execute("SELECT id, name FROM caisses WHERE COALESCE(is_active,1)=1 ORDER BY name").fetchall()]
    banques = [dict(r) for r in conn.execute("SELECT id, nom, banque FROM tresorerie_comptes_bancaires WHERE COALESCE(is_active,1)=1 ORDER BY nom").fetchall()]
    conn.close()
    return render_template('recouvrement_versements.html', page='recouvrement_versements',
        versements=versements, total=total, caisses=caisses, banques=banques)


def _resoudre_destination_versement(conn, dest):
    """v160 : "caisse:ID" / "banque:ID" → (caisse_id, caisse_name, banque_id, banque_name)."""
    kind, _, wid_raw = (dest or '').partition(':')
    wid = int(wid_raw) if wid_raw.isdigit() else None
    if kind == 'caisse' and wid:
        r = conn.execute("SELECT name FROM caisses WHERE id=?", (wid,)).fetchone()
        if r: return wid, r['name'], None, None
    elif kind == 'banque' and wid:
        r = conn.execute("SELECT nom, banque FROM tresorerie_comptes_bancaires WHERE id=?", (wid,)).fetchone()
        if r: return None, None, wid, (r['nom'] + (f" ({r['banque']})" if r['banque'] else ''))
    return None, None, None, None


def _save_bordereau_file():
    f = request.files.get('bordereau_file')
    if f and f.filename:
        ext = os.path.splitext(f.filename)[1].lower()
        if ext in ('.jpg', '.jpeg', '.png', '.webp', '.pdf'):
            fname = f"vers_{session['user_id']}_{datetime.now().strftime('%Y%m%d%H%M%S')}{ext}"
            fdir = os.path.join(app.config['UPLOAD_FOLDER'], 'versements')
            os.makedirs(fdir, exist_ok=True)
            f.save(os.path.join(fdir, fname))
            return fname
    return None


def _add_business_days(date_str, n):
    """v162 : ajoute n jours OUVRÉS (lun-ven) à une date 'YYYY-MM-DD'."""
    try:
        d = datetime.strptime((date_str or '')[:10], '%Y-%m-%d')
    except Exception:
        d = datetime.now()
    added = 0
    while added < n:
        d += timedelta(days=1)
        if d.weekday() < 5:  # 0=lundi ... 4=vendredi
            added += 1
    return d.strftime('%Y-%m-%d')


@app.route('/recouvrement/versements/add', methods=['POST'])
@permission_required_any('recouvrement_edit', 'caissiere_validate', 'admin')
def recouvrement_versement_add():
    """v160 / v162 : enregistrer une remise OU un versement.
    v162 : une remise de chèque n'est créditée qu'après 3 jours ouvrés → statut « en attente »
    jusqu'à la date de disponibilité ; un versement (espèces/virement) est disponible immédiatement."""
    user = get_user_by_id(session['user_id'])
    try: montant = float((request.form.get('montant', '') or '0').replace(',', '.'))
    except: montant = 0
    if montant <= 0:
        flash("Montant invalide", "error"); return redirect('/recouvrement/versements')
    conn = _gdb()
    caisse_id, caisse_name, banque_id, banque_name = _resoudre_destination_versement(conn, request.form.get('destination', ''))
    bordereau_file = _save_bordereau_file() or ''
    date_versement = request.form.get('date_versement', '') or datetime.now().strftime('%Y-%m-%d')
    # v162 : type d'opération (versement immédiat ou remise de chèque différée à J+3 ouvrés)
    type_op = (request.form.get('type_operation', 'versement') or 'versement').strip()
    if type_op == 'remise':
        date_dispo = _add_business_days(date_versement, 3)
        statut = 'en_attente'
    else:
        date_dispo = date_versement
        statut = 'verse'
    conn.execute("""INSERT INTO recouvrement_versements
        (agent_id, agent_name, montant, mode, caisse_id, caisse_name, banque_id, banque_name,
         bordereau_number, bordereau_file, date_versement, notes, type_operation,
         date_disponibilite, statut, created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?, datetime('now'))""",
        (session['user_id'], user['full_name'] if user else '?', montant,
         request.form.get('mode', 'especes'), caisse_id, caisse_name, banque_id, banque_name,
         request.form.get('bordereau_number', ''), bordereau_file,
         date_versement, request.form.get('notes', ''), type_op, date_dispo, statut))
    conn.commit(); conn.close()
    _libelle = "Remise de chèque" if type_op == 'remise' else "Versement"
    try:
        notify_roles(['caissiere', 'comptable', 'comptabilite', 'admin'],
            f"💰 Nouvelle {_libelle.lower()} (recouvrement)",
            f"{(user['full_name'] if user else 'Agent')} a enregistré une {_libelle.lower()} de {montant:,.0f} XOF"
            + (f" — disponible le {date_dispo} (3 j. ouvrés)" if type_op == 'remise' else '')
            + (f" — bordereau {request.form.get('bordereau_number','')}" if request.form.get('bordereau_number') else ''),
            link='/recouvrement/versements', type='recouvrement', module='recouvrement', icon='💰')
    except: pass
    if type_op == 'remise':
        flash(f"✅ Remise de chèque de {montant:,.0f} XOF enregistrée — ⏳ en attente, créditée le {date_dispo} (3 jours ouvrés).", "success")
    else:
        flash(f"✅ Versement de {montant:,.0f} XOF enregistré.", "success")
    return redirect('/recouvrement/versements')


