@app.route('/recouvrement/<int:fri_id>/envoyer', methods=['POST'])
@permission_required_any('recouvrement_edit', 'admin')
def recouvrement_envoyer(fri_id):
    """v142 / v145 : L'agent recouvreur marque la facture comme envoyée + choisit la caisse.
    v145 : Enregistre la preuve de paiement (chèque, reçu, etc.) en fichier."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    method = (request.form.get('method','') or '').strip()
    caisse_id_str = (request.form.get('caisse_id','') or '').strip()
    notes = (request.form.get('notes','') or '').strip()
    
    # v145 : Type de paiement reçu + preuves
    payment_type = (request.form.get('payment_type','') or '').strip()
    cheque_number = (request.form.get('cheque_number','') or '').strip()
    cheque_bank = (request.form.get('cheque_bank','') or '').strip()
    cheque_date = (request.form.get('cheque_date','') or '').strip()
    recu_number = (request.form.get('recu_number','') or '').strip()
    amount_received_str = (request.form.get('amount_received','') or '').replace(',','.').strip()
    
    if method not in RECOVERY_METHODS:
        flash("⚠️ Méthode d'envoi invalide", "error")
        return redirect('/recouvrement')
    if not caisse_id_str.isdigit():
        flash("⚠️ Caisse cible requise", "error")
        return redirect('/recouvrement')
    
    # v147 : Notes obligatoires lors de l'envoi
    if len(notes) < 5:
        flash("⚠️ Un commentaire est obligatoire lors de l'envoi de la facture au client "
              "(min 5 caractères) — date de dépôt, contact client, observations...", "error")
        return redirect('/recouvrement')
    
    caisse_id = int(caisse_id_str)
    
    try:
        amount_planned = float(amount_received_str) if amount_received_str else None
    except: amount_planned = None
    
    conn = _gdb()
    try:
        fri = conn.execute("""SELECT fri.*, fr.client_name, fr.reference as fr_ref
                              FROM field_report_invoices fri
                              JOIN field_reports fr ON fr.id = fri.field_report_id
                              WHERE fri.id=?""", (fri_id,)).fetchone()
        if not fri:
            conn.close()
            flash("Facture introuvable", "error")
            return redirect('/recouvrement')
        
        caisse = conn.execute("SELECT name FROM caisses WHERE id=?", (caisse_id,)).fetchone()
        conn.close()
        
        # v145 : Upload fichier preuve (chèque scanné, reçu, etc.)
        proof_paths = []
        try:
            for fkey in ('proof_file', 'proof_file_2'):
                f = request.files.get(fkey) if hasattr(request, 'files') else None
                if f:
                    p = _save_proof_file(fri_id, f, kind='proof')
                    if p: proof_paths.append(p)
        except Exception as _e: print(f"[v145] upload preuves err : {_e}", flush=True)
        
        import json
        # Récupérer les preuves existantes
        conn = _gdb()
        existing = conn.execute("SELECT proof_files FROM field_report_invoices WHERE id=?", (fri_id,)).fetchone()
        existing_paths = []
        try:
            if existing and existing['proof_files']:
                existing_paths = json.loads(existing['proof_files'])
                if not isinstance(existing_paths, list): existing_paths = []
        except: pass
        all_paths = existing_paths + proof_paths
        
        conn.execute("""UPDATE field_report_invoices
            SET recovery_agent_id=?, recovery_status=?, recovery_sent_at=datetime('now'),
                recovery_method=?, recovery_notes=?,
                target_caisse_id=?, target_caisse_chosen_at=datetime('now'),
                payment_type=?, cheque_number=?, cheque_bank=?, cheque_date=?,
                recu_number=?, recovery_amount_planned=?,
                proof_files=?, agent_notes=?,
                status='caisse_choisie', updated_at=datetime('now')
            WHERE id=?""",
            (user['id'], 'envoyee', method, notes, caisse_id,
             payment_type or None, cheque_number or None, cheque_bank or None,
             cheque_date or None, recu_number or None, amount_planned,
             json.dumps(all_paths) if all_paths else None,
             notes, fri_id))
        conn.commit()
        conn.close()
        
        # v145 : Log événement timeline
        proof_summary = []
        if payment_type:
            proof_summary.append(PAYMENT_TYPES.get(payment_type, payment_type))
        if cheque_number: proof_summary.append(f"Chèque n°{cheque_number}")
        if recu_number: proof_summary.append(f"Reçu n°{recu_number}")
        proof_text = " · ".join(proof_summary) if proof_summary else "Pas de détails"
        
        _log_fri_event(fri_id, fri['field_report_id'], user['id'], user['full_name'],
            'recouvrement_envoye', f"Envoyée au client ({RECOVERY_METHODS.get(method, method)})",
            '📤', f"Caisse cible : {caisse['name'] if caisse else caisse_id} · "
                  f"Paiement reçu : {proof_text} · {len(all_paths)} preuve(s) jointe(s)",
            amount_planned)
        
        # Notifier la caissière
        try:
            notify_roles(['caissiere','admin'],
                title=f"💵 Paiement en attente : {fri['invoice_number'] or 'FRI-'+str(fri_id)}",
                message=f"Facture envoyée au client {fri['client_name']} pour {fri['amount']:,.0f} XOF. "
                        f"Caisse : {caisse['name'] if caisse else caisse_id}. "
                        f"Type : {PAYMENT_TYPES.get(payment_type, '?')}. À valider à réception.",
                link='/caissiere/paiements',
                type='warning', module='tresorerie', icon='💵', priority='high')
        except: pass
        
        flash(f"✅ Facture marquée envoyée ({RECOVERY_METHODS.get(method, method)}) — Caissière notifiée", "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect('/recouvrement')


# ============= CAISSIÈRE : Valide les paiements =============

@app.route('/caissiere/paiements')
@permission_required_any('caissiere_view', 'admin')
def caissiere_paiements():
    """v142 / v145 : Dashboard caissière avec onglets.
    - en_attente : paiements à valider (status='caisse_choisie')
    - recus : paiements déjà encaissés (status='paye')"""
    tab = request.args.get('tab', 'en_attente').strip()
    search = request.args.get('q', '').strip()
    
    conn = _gdb()
    
    if tab == 'recus':
        where_sql = "fri.status='paye'"
        order_by = "fri.payment_validated_at DESC"
    else:
        where_sql = "fri.status='caisse_choisie'"
        order_by = "fri.recovery_sent_at"
    
    params = []
    if search:
        where_sql += " AND (fr.reference LIKE ? OR fr.client_name LIKE ? OR fri.invoice_number LIKE ?)"
        params.extend([f"%{search}%"] * 3)
    
    # v160 : LEFT JOIN pour afficher toute facture du compteur (même remontée supprimée)
    items = [dict(r) for r in conn.execute(f"""
        SELECT fri.*, fr.reference as fr_ref, fr.client_name,
               u.full_name as recovery_agent_name,
               cs.name as caisse_name
        FROM field_report_invoices fri
        LEFT JOIN field_reports fr ON fr.id = fri.field_report_id
        LEFT JOIN users u ON u.id = fri.recovery_agent_id
        LEFT JOIN caisses cs ON cs.id = fri.target_caisse_id
        WHERE {where_sql}
        ORDER BY {order_by} LIMIT 100""", params).fetchall()]

    counts = {
        'en_attente': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status='caisse_choisie'").fetchone()[0],
        'recus': conn.execute("SELECT COUNT(*) FROM field_report_invoices WHERE status='paye'").fetchone()[0],
    }
    # v160 : solde (somme des montants) par catégorie
    totals = {
        'en_attente': conn.execute("SELECT COALESCE(SUM(amount),0) FROM field_report_invoices WHERE status='caisse_choisie'").fetchone()[0],
        'recus': conn.execute("SELECT COALESCE(SUM(amount),0) FROM field_report_invoices WHERE status='paye'").fetchone()[0],
    }

    conn.close()

    return render_template('caissiere_paiements.html', page='caissiere_paiements',
        items=items, tab=tab, counts=counts, totals=totals, search=search,
        payment_types=PAYMENT_TYPES)


@app.route('/caissiere/paiement/<int:fri_id>/valider', methods=['POST'])
@permission_required_any('caissiere_validate', 'admin')
def caissiere_valider(fri_id):
    """v142 / v145 : Caissière valide le paiement + uploade bordereau de versement."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    
    amount_str = (request.form.get('amount_received','') or '').replace(',','.').strip()
    bordereau_number = (request.form.get('bordereau_number','') or '').strip()
    cashier_notes = (request.form.get('cashier_notes','') or '').strip()
    
    try: amount_received = float(amount_str or 0)
    except: amount_received = 0
    
    if amount_received <= 0:
        flash("⚠️ Montant reçu invalide", "error")
        return redirect('/caissiere/paiements')
    
    # v147 : Notes caissière obligatoires
    if len(cashier_notes) < 5:
        flash("⚠️ Un commentaire est obligatoire (min 5 caractères) — observations, conformité, "
              "différence de montant éventuelle, etc.", "error")
        return redirect('/caissiere/paiements')
    
    conn = _gdb()
    try:
        fri = conn.execute("""SELECT fri.*, fr.client_name, fr.reference as fr_ref
                              FROM field_report_invoices fri
                              JOIN field_reports fr ON fr.id = fri.field_report_id
                              WHERE fri.id=?""", (fri_id,)).fetchone()
        if not fri:
            conn.close()
            flash("Paiement introuvable", "error")
            return redirect('/caissiere/paiements')
        conn.close()
        
        # v145 : Upload bordereau
        bordereau_path = None
        try:
            f = request.files.get('bordereau_file') if hasattr(request, 'files') else None
            if f and getattr(f, 'filename', ''):
                bordereau_path = _save_proof_file(fri_id, f, kind='bordereau')
        except Exception as _e: print(f"[v145] bordereau upload err : {_e}", flush=True)
        
        conn = _gdb()
        # 1. Marquer le paiement comme validé
        conn.execute("""UPDATE field_report_invoices
            SET payment_amount_received=?, payment_received_at=datetime('now'),
                payment_validated_by=?, payment_validated_at=datetime('now'),
                bordereau_number=?, bordereau_file=?, cashier_notes=?,
                status='paye', updated_at=datetime('now')
            WHERE id=?""",
            (amount_received, user['id'], bordereau_number or None,
             bordereau_path, cashier_notes, fri_id))
        
        # 2. Créer une opération d'entrée dans la caisse cible
        ref = f"PAY-{fri['invoice_number'] or 'FRI'+str(fri_id)}"
        try:
            conn.execute("""INSERT INTO caisse_operations
                (caisse_id, type, amount, description, reference, created_by, created_at)
                VALUES (?,'entree',?,?,?,?,datetime('now'))""",
                (fri['target_caisse_id'], amount_received,
                 f"Paiement facture {fri['invoice_number'] or fri['fr_ref']} — {fri['client_name']}",
                 ref, user['id']))
            try:
                _sync_caisse_op_to_journal(conn, 'entree', datetime.now().strftime('%Y-%m-%d'),
                    amount_received, 
                    f"Paiement facture {fri['invoice_number'] or fri['fr_ref']} ({fri['client_name']})",
                    ref, user['id'], caisse_id=fri['target_caisse_id'])
            except Exception as _e: print(f"[v145] sync journal err : {_e}", flush=True)
        except Exception as _e: print(f"[v145] caisse op err : {_e}", flush=True)
        
        conn.commit()
        conn.close()
        
        log_activity(user['id'], user['full_name'], 'Caisse',
            f"Validation paiement facture {fri['invoice_number'] or fri_id} : {amount_received:,.0f} XOF",
            request.remote_addr)
        
        # v145 : Log événement timeline
        _log_fri_event(fri_id, fri['field_report_id'], user['id'], user['full_name'],
            'paiement_valide', f"Paiement validé : {amount_received:,.0f} XOF",
            '✅', f"Bordereau : {bordereau_number or '-'} · {cashier_notes}",
            amount_received)
        
        try:
            if fri['recovery_agent_id']:
                notify_user(fri['recovery_agent_id'],
                    title=f"✅ Paiement reçu : {fri['invoice_number']}",
                    message=f"La caissière {user['full_name']} a validé le paiement de "
                            f"{amount_received:,.0f} XOF pour {fri['client_name']}.",
                    link='/recouvrement?tab=recouvrees', module='tresorerie', priority='normal')
            notify_roles(['comptable','comptabilite','admin'],
                title=f"💰 Paiement encaissé : {fri['invoice_number']}",
                message=f"Encaissement {amount_received:,.0f} XOF — {fri['client_name']}",
                link='/comptabilite/caisses',
                type='success', module='comptabilite', icon='💰', priority='normal')
        except: pass
        
        flash(f"✅ Paiement validé — Caisse créditée de {amount_received:,.0f} XOF", "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect('/caissiere/paiements')


# v145 : Servir les fichiers preuves (chèque scanné, reçu, bordereau)
@app.route('/uploads/fri_proofs/<int:fri_id>/<path:filename>')
# v162 : alias — les chemins sont stockés en BDD avec le préfixe « data/ » (data/uploads/fri_proofs/...),
# donc les liens des pièces jointes pointaient vers /data/uploads/... (aucune route → illisible).
@app.route('/data/uploads/fri_proofs/<int:fri_id>/<path:filename>')
@login_required
def serve_fri_proof(fri_id, filename):
    """v145 / v162 : Servir les fichiers preuves de paiement (pièces jointes des factures).
    Cherche dans le dossier persistant, puis dans l'ancien emplacement (compat) si présent."""
    import os
    from flask import send_from_directory
    candidates = [
        os.path.join(app.config['UPLOAD_FOLDER'], 'fri_proofs', str(fri_id)),               # persistant (v162)
        os.path.join(os.path.dirname(__file__), 'data', 'uploads', 'fri_proofs', str(fri_id)),  # ancien (legacy)
    ]
    for directory in candidates:
        if os.path.isfile(os.path.join(directory, filename)):
            return send_from_directory(directory, filename)
    flash("Fichier introuvable : la pièce jointe n'est plus disponible sur le serveur (à ré-importer).", "error")
    return redirect(request.referrer or '/recouvrement')


# v147 : Tableau de bord centralisé des transferts caisse en attente de validation DG/RH
@app.route('/tresorerie/transferts-en-attente')
@login_required
def transferts_en_attente():
    """v147 / v151 : Vue unifiée DG/RH de tous les transferts caisse/banque en attente de validation.
    Regroupe : caisse_virements (banque→caisse) et ordres_virement (caisse→banque ou bénéficiaires).
    v151 : Correction colonnes pour ordres_virement (requested_at au lieu de created_at)."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    if user['role'] not in ('admin','dg','directeur','rh','directrice_rh'):
        flash("⛔ Accès réservé à la direction (DG/RH)", "error")
        return redirect('/dashboard')
    
    conn = _gdb()
    
    # 1. Virements banque → caisse en attente
    virements_bk = []
    try:
        virements_bk = [dict(r) for r in conn.execute("""
            SELECT id, reference, date, bank_name, caisse_name, amount, motif,
                   status, requested_by_name, created_at, 'banque_to_caisse' as direction
            FROM caisse_virements WHERE status='en_attente'
            ORDER BY created_at DESC""").fetchall()]
    except Exception as _e:
        print(f"[v151] caisse_virements query err : {_e}", flush=True)
    
    # 2. Ordres de virement — v151 : utiliser requested_at (ordres_virement n'a pas created_at)
    ordres = []
    try:
        ordres = [dict(r) for r in conn.execute("""
            SELECT id, reference, type_virement, amount, date,
                   source_caisse_name, dest_bank_name,
                   description, status, requested_by_name,
                   requested_at as created_at
            FROM ordres_virement
            WHERE status IN ('en_attente','en_attente_dg','en_attente_validation','attente_dg')
            ORDER BY requested_at DESC""").fetchall()]
    except Exception as _e:
        print(f"[v151] ordres_virement query err : {_e}", flush=True)
        ordres = []
    
    conn.close()
    
    total_amount = sum(v['amount'] or 0 for v in virements_bk) + sum(o['amount'] or 0 for o in ordres)
    
    return render_template('transferts_en_attente.html', page='transferts_en_attente',
        virements_bk=virements_bk, ordres=ordres, total_amount=total_amount,
        nb_pending=len(virements_bk) + len(ordres))


# v152 : Résumé quotidien des virements et transferts (DG/RH/Compta)
@app.route('/tresorerie/resume-virements')
@login_required
def resume_virements_quotidien():
    """v152 : Résumé quotidien des transferts/virements.
    Pour chaque jour : combien de virements + montant total.
    Filtrable par période, type et statut."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    if user['role'] not in ('admin','dg','directeur','rh','directrice_rh','comptable','comptabilite'):
        flash("⛔ Accès réservé à la direction et à la comptabilité", "error")
        return redirect('/dashboard')
    
    # Filtres
    date_from = request.args.get('date_from', '').strip()
    date_to = request.args.get('date_to', '').strip()
    today_only = request.args.get('today', '').strip() == '1'
    
    # Période par défaut : 30 derniers jours
    if not date_from and not today_only:
        date_from = (datetime.now() - timedelta(days=30)).strftime('%Y-%m-%d')
    if not date_to:
        date_to = datetime.now().strftime('%Y-%m-%d')
    if today_only:
        date_from = date_to = datetime.now().strftime('%Y-%m-%d')
    
    conn = _gdb()
    
    # 1. Caisse_virements (banque → caisse)
    cv_rows = []
    try:
        cv_rows = [dict(r) for r in conn.execute("""
            SELECT DATE(created_at) as jour, COUNT(*) as nb, COALESCE(SUM(amount),0) as total,
                   status
            FROM caisse_virements
            WHERE DATE(created_at) >= ? AND DATE(created_at) <= ?
            GROUP BY DATE(created_at), status
            ORDER BY jour DESC, status""", (date_from, date_to)).fetchall()]
    except Exception as _e: print(f"[v152] cv rows err : {_e}", flush=True)
    
    # 2. Ordres_virement
    ov_rows = []
    try:
        ov_rows = [dict(r) for r in conn.execute("""
            SELECT DATE(requested_at) as jour, COUNT(*) as nb, COALESCE(SUM(amount),0) as total,
                   status, type_virement
            FROM ordres_virement
            WHERE DATE(requested_at) >= ? AND DATE(requested_at) <= ?
            GROUP BY DATE(requested_at), status, type_virement
            ORDER BY jour DESC""", (date_from, date_to)).fetchall()]
    except Exception as _e: print(f"[v152] ov rows err : {_e}", flush=True)
    
    # Agrégation par jour
    days_map = {}
    for r in cv_rows:
        j = r['jour']
        if j not in days_map:
            days_map[j] = {'jour': j, 'cv': {'nb':0,'total':0,'valide':0,'en_attente':0,'refuse':0},
                            'ov': {'nb':0,'total':0,'valide':0,'en_attente':0,'refuse':0,'execute':0}}
        days_map[j]['cv']['nb'] += r['nb']
        days_map[j]['cv']['total'] += r['total']
        s = (r['status'] or '').strip()
        if s in days_map[j]['cv']: days_map[j]['cv'][s] += r['total']
    
    for r in ov_rows:
        j = r['jour']
        if j not in days_map:
            days_map[j] = {'jour': j, 'cv': {'nb':0,'total':0,'valide':0,'en_attente':0,'refuse':0},
                            'ov': {'nb':0,'total':0,'valide':0,'en_attente':0,'refuse':0,'execute':0}}
        days_map[j]['ov']['nb'] += r['nb']
        days_map[j]['ov']['total'] += r['total']
        s = (r['status'] or '').strip()
        # Mapper en_attente_dg, etc.
        if 'attente' in s: days_map[j]['ov']['en_attente'] += r['total']
        elif s == 'valide' or s == 'validé': days_map[j]['ov']['valide'] += r['total']
        elif s in ('execute','executed','effectue'): days_map[j]['ov']['execute'] += r['total']
        elif 'refus' in s: days_map[j]['ov']['refuse'] += r['total']
    
    # Tri par jour décroissant
    days = sorted(days_map.values(), key=lambda x: x['jour'], reverse=True)
    
    # Totaux globaux
    total_cv = sum(d['cv']['total'] for d in days)
    total_ov = sum(d['ov']['total'] for d in days)
    nb_cv = sum(d['cv']['nb'] for d in days)
    nb_ov = sum(d['ov']['nb'] for d in days)
    
    # Détail des virements du jour (jour le plus récent)
    today_str = datetime.now().strftime('%Y-%m-%d')
    cv_today = []
    ov_today = []
    try:
        cv_today = [dict(r) for r in conn.execute("""
            SELECT reference, amount, bank_name, caisse_name, status, motif, requested_by_name
            FROM caisse_virements WHERE DATE(created_at) = ? ORDER BY id DESC""",
            (today_str,)).fetchall()]
    except: pass
    try:
        ov_today = [dict(r) for r in conn.execute("""
            SELECT reference, amount, type_virement, source_caisse_name, dest_bank_name,
                   status, description, requested_by_name
            FROM ordres_virement WHERE DATE(requested_at) = ? ORDER BY id DESC""",
            (today_str,)).fetchall()]
    except: pass
    
    conn.close()
    
    return render_template('resume_virements.html', page='resume_virements',
        days=days, total_cv=total_cv, total_ov=total_ov, nb_cv=nb_cv, nb_ov=nb_ov,
        cv_today=cv_today, ov_today=ov_today,
        date_from=date_from, date_to=date_to,
        today_total=sum(d['cv']['total']+d['ov']['total'] for d in days if d['jour']==today_str))


# v145 : Page d'historique global du workflow
@app.route('/workflow/historique')
@login_required
def workflow_historique():
    """v145 : Timeline globale des événements du workflow recouvrement."""
    user = get_user_by_id(session['user_id'])
    if not user: return redirect('/login')
    perms = get_role_permissions(user['role'])
    if not any(p in perms for p in ['facturation_decision','facture_edit','recouvrement_view','caissiere_view','admin']):
        flash("⛔ Accès réservé aux acteurs du workflow", "error")
        return redirect('/dashboard')
    
    event_type_filter = request.args.get('event_type', '').strip()
    user_filter = request.args.get('user', '').strip()
    date_from = request.args.get('date_from', '').strip()
    date_to = request.args.get('date_to', '').strip()
    
    conn = _gdb()
    where_clauses = []
    params = []
    if event_type_filter:
        where_clauses.append("e.event_type=?")
        params.append(event_type_filter)
    if user_filter:
        where_clauses.append("e.user_name LIKE ?")
        params.append(f"%{user_filter}%")
    if date_from:
        where_clauses.append("DATE(e.created_at) >= ?")
        params.append(date_from)
    if date_to:
        where_clauses.append("DATE(e.created_at) <= ?")
        params.append(date_to)
    
    where_sql = " AND ".join(where_clauses) if where_clauses else "1=1"
    
    events = [dict(r) for r in conn.execute(f"""
        SELECT e.*, fr.reference as fr_ref, fr.client_name, fri.invoice_number
        FROM fri_events e
        LEFT JOIN field_reports fr ON fr.id = e.field_report_id
        LEFT JOIN field_report_invoices fri ON fri.id = e.fri_id
        WHERE {where_sql}
        ORDER BY e.created_at DESC LIMIT 200""", params).fetchall()]
    
    # Types d'événements distincts pour le filtre
    event_types = [r[0] for r in conn.execute(
        "SELECT DISTINCT event_type FROM fri_events ORDER BY event_type").fetchall()]
    
    conn.close()
    
    return render_template('workflow_historique.html', page='workflow_historique',
        events=events, event_types=event_types,
        event_type_filter=event_type_filter, user_filter=user_filter,
        date_from=date_from, date_to=date_to)


@app.route('/field-reports/<int:rid>/transform', methods=['POST'])
@permission_required('field_report_transform')
def field_report_transform(rid):
    """v131 : Transformer en projet, intervention ou opportunité.
    - intervention : technicien obligatoire → crée une intervention liée, statut 'en_execution'
    - projet : remontée visible dans CRM > Nouveau Projet
    - opportunite : remontée visible dans CRM > Nouveau Projet
    - classer : ferme la remontée"""
    decision = request.form.get('decision', '').strip()
    notes = request.form.get('decision_notes', '').strip()
    technician_id = request.form.get('technician_id', '').strip()
    scheduled_date = request.form.get('scheduled_date', '').strip()
    
    if decision not in ('projet', 'intervention', 'opportunite', 'classer'):
        flash("Décision invalide", "error")
        return redirect(f'/field-reports/{rid}')
    
    # v131 : Pour intervention, technicien OBLIGATOIRE
    if decision == 'intervention':
        if not technician_id or not technician_id.isdigit():
            flash("⚠️ Vous devez assigner un technicien pour transformer en intervention", "error")
            return redirect(f'/field-reports/{rid}')
        try: technician_id = int(technician_id)
        except: technician_id = 0
        if not technician_id:
            flash("⚠️ Technicien invalide", "error")
            return redirect(f'/field-reports/{rid}')
    
    user = get_user_by_id(session.get('user_id')) if session.get('user_id') else None
    try:
        conn = _gdb()
        report = dict(conn.execute("SELECT * FROM field_reports WHERE id=?", (rid,)).fetchone())
        
        # === Workflow spécifique selon la décision ===
        new_intervention_id = None
        
        if decision == 'intervention':
            # v131 : Créer une intervention dans le Centre Technique liée à cette remontée
            tech_row = conn.execute("SELECT id, full_name FROM users WHERE id=? AND COALESCE(is_active,1)=1", (technician_id,)).fetchone()
            if not tech_row:
                conn.close()
                flash("⚠️ Technicien introuvable ou inactif", "error")
                return redirect(f'/field-reports/{rid}')
            
            int_ref = f"INT-{datetime.now().strftime('%Y%m%d%H%M%S')}"
            int_title = f"Intervention suite remontée {report['reference']}"
            int_desc = f"Remontée d'origine : {report['reference']}\nClient : {report['client_name']}\nType : {report['type_info']}\nDescription : {report['description']}"
            if notes:
                int_desc += f"\n\nNotes coordinateur : {notes}"
            
            priority_map = {'urgent': 'urgent', 'eleve': 'haute', 'moyen': 'normale', 'faible': 'basse'}
            int_priority = priority_map.get(report.get('priorite'), 'normale')
            
            cur = conn.execute("""INSERT INTO interventions
                (reference, title, type, client_id, client_name, site_address,
                 technician_id, technician_name, scheduled_date, status, priority,
                 description, created_by, created_at)
                VALUES (?,?,?,?,?,?,?,?,?,'planifiee',?,?,?,datetime('now'))""",
                (int_ref, int_title, 'curative',
                 report.get('client_id'), report['client_name'], report.get('site_address') or report.get('site_name'),
                 technician_id, tech_row['full_name'],
                 scheduled_date or datetime.now().strftime('%Y-%m-%d'),
                 int_priority, int_desc, session['user_id']))
            new_intervention_id = cur.lastrowid
            
            # v131 : statut remontée = en_execution (technicien assigné, en attente fin)
            new_statut = 'en_execution'
        elif decision == 'projet':
            new_statut = 'transformee_projet'
        elif decision == 'opportunite':
            new_statut = 'transformee_opportunite'
        else:  # classer
            new_statut = 'classee'
        
        # Mettre à jour la remontée
        conn.execute("""UPDATE field_reports SET statut=?, decision=?, decision_date=datetime('now'),
            decision_by=?, decision_by_name=?, linked_intervention_id=?,
            updated_at=datetime('now') WHERE id=?""",
            (new_statut, decision, session.get('user_id'),
             user['full_name'] if user else None,
             new_intervention_id, rid))
        conn.commit()
        conn.close()
        
        action_label = {
            'projet': 'Transformée en projet (visible dans CRM > Nouveau Projet)',
            'intervention': f'Transformée en intervention (assignée à {tech_row["full_name"] if decision == "intervention" else "?"})',
            'opportunite': 'Transformée en opportunité (visible dans CRM > Nouveau Projet)',
            'classer': 'Classée sans suite',
        }[decision]
        _field_report_log(rid, action_label, notes[:200] if notes else None)
        _field_report_notify(rid, 'transformed')
        
        # v131 : Notification spécifique au technicien si intervention
        if decision == 'intervention' and new_intervention_id:
            try:
                notify_user(technician_id,
                    title=f"🛠️ Nouvelle intervention assignée : {int_ref}",
                    message=f"Client : {report['client_name']} · Date prévue : {scheduled_date or 'à définir'} · Priorité : {int_priority.upper()}",
                    link=f"/interventions/{new_intervention_id}/fiche",
                    type='info', module='interventions', icon='🛠️',
                    priority='high' if int_priority in ('urgent','haute') else 'normal')
            except Exception as _e:
                print(f"[v131] notif tech err : {_e}", flush=True)
        
        flash(f"✅ {action_label}", "success")
    except Exception as e:
        flash(f"Erreur : {e}", "error")
    return redirect(f'/field-reports/{rid}')


# v131 : Quand une intervention liée à une remontée est marquée comme terminée,
# la remontée passe automatiquement à 'traitee'. Helper appelable depuis le code intervention.
def _sync_remontee_status_from_intervention(intervention_id):
    """v131 / v144 : Si une intervention liée à une remontée passe à un statut final
    (terminee, livre), passe la remontée en 'executee' pour déclencher le workflow
    de décision de facturation (DG/RH). v144 : Notifie automatiquement DG/RH."""
    if not intervention_id: return
    try:
        conn = _gdb()
        int_row = conn.execute("SELECT status, technician_id FROM interventions WHERE id=?", (intervention_id,)).fetchone()
        if not int_row: 
            conn.close(); return
        if int_row['status'] not in ('terminee', 'termine', 'livre', 'cloturee'):
            conn.close(); return
        report = conn.execute(
            "SELECT id, reference, auteur_id, client_name, statut, executed_at FROM field_reports WHERE linked_intervention_id=?",
            (intervention_id,)).fetchone()
        if not report:
            conn.close(); return
        
        report_id = report['id']
        report_ref = report['reference']
        auteur_id = report['auteur_id']
        client_name = report['client_name'] or ''
        already_executed = bool(report['executed_at'])
        
        # v144 : Si pas déjà passée par /execute, la marquer executee MAINTENANT pour
        # déclencher le workflow de facturation DG/RH
        if not already_executed:
            tech_id = int_row['technician_id']
            tech_user = None
            if tech_id:
                try: tech_user = get_user_by_id(tech_id)
                except: pass
            tech_name = tech_user['full_name'] if tech_user else 'Technicien'
            
            conn.execute("""UPDATE field_reports
                SET statut='executee', executed_by=?, executed_at=datetime('now'),
                    execution_notes=?, updated_at=datetime('now')
                WHERE id=?""",
                (tech_id, f"Auto: intervention liée clôturée par {tech_name}", report_id))
            conn.commit()
            conn.close()
            
            # Notif DG/RH pour décision facturation (HIGH priority)
            try:
                notify_roles(['dg','directeur','rh','directrice_rh','admin'],
                    title=f"💰 DÉCISION REQUISE — Facturation : {report_ref}",
                    message=f"L'intervention sur la remontée {report_ref} ({client_name}) a été terminée. "
                            f"VOUS DEVEZ DÉCIDER si cette intervention est facturable au client.",
                    link='/decisions/facturation',
                    type='warning', module='remontees', icon='💰', priority='high', force=True)
            except Exception as _e: print(f"[v144] notif DG/RH err : {_e}", flush=True)
            
            # Notifier aussi l'auteur de la remontée
            try:
                notify_user(auteur_id if auteur_id else 1,
                    title=f"🛠️ Remontée {report_ref} exécutée",
                    message=f"L'intervention liée a été terminée. En attente de décision facturation DG/RH.",
                    link=f"/field-reports/{report_id}",
                    type='info', module='remontees', icon='🛠️')
            except: pass
        else:
            # Déjà passée par /execute → ne rien refaire (statut conservé)
            conn.close()
    except Exception as e:
        print(f"[v144] sync remontee from intervention err : {e}", flush=True)


