def _project_log(project_id, event_type, from_status=None, to_status=None, comment=''):
    """Trace une action dans l'historique d'un projet."""
    try:
        u = get_user_by_id(session.get('user_id')) if 'user_id' in session else None
        actor_id = u['id'] if u else None
        actor_name = u['full_name'] if u else 'Système'
    except:
        actor_id, actor_name = None, 'Système'
    conn = _gdb()
    conn.execute("""INSERT INTO wf_project_history
        (project_id, event_type, from_status, to_status, actor_id, actor_name, comment)
        VALUES (?,?,?,?,?,?,?)""",
        (project_id, event_type, from_status, to_status, actor_id, actor_name, comment))
    conn.commit(); conn.close()


def _project_notify(project_id, target_roles, title, message, link=None, target_user_id=None):
    """Crée une notification ciblée pour des rôles (ou un utilisateur).
    
    target_roles : liste ['comptabilite', 'rh'] OU None (si target_user_id fourni)
    Crée aussi un message dans le chat interne (canal général).
    """
    conn = _gdb()
    
    # 1. Notifications par rôle (badge dashboard)
    if target_roles:
        for role in target_roles:
            conn.execute("""INSERT INTO wf_project_notifications
                (project_id, target_role, title, message, link)
                VALUES (?,?,?,?,?)""",
                (project_id, role, title, message, link))
    if target_user_id:
        conn.execute("""INSERT INTO wf_project_notifications
            (project_id, target_user_id, title, message, link)
            VALUES (?,?,?,?,?)""",
            (project_id, target_user_id, title, message, link))
    
    # 2. Message dans le chat interne (canal général)
    try:
        admin_user = conn.execute("SELECT id FROM users WHERE role='admin' LIMIT 1").fetchone()
        if admin_user:
            chat_msg = f"🔔 [Projet #{project_id}] {title} — {message}"
            if link:
                chat_msg += f" — Voir : {link}"
            conn.execute("""INSERT INTO messages (sender_id, channel, content)
                VALUES (?, 'general', ?)""", (admin_user['id'], chat_msg))
    except Exception as _e:
        pass
    
    conn.commit(); conn.close()
    
    # 3. Email (best-effort, non bloquant)
    try:
        if target_roles:
            _conn2 = _gdb()
            users_to_email = []
            for role in target_roles:
                rows = _conn2.execute(
                    "SELECT email, full_name FROM users WHERE role=? AND email IS NOT NULL AND email != ''",
                    (role,)).fetchall()
                users_to_email.extend([dict(r) for r in rows])
            _conn2.close()
            # Si module mail dispo, envoyer
            if users_to_email:
                try:
                    _send_project_email(users_to_email, title, message, link)
                except: pass
    except: pass


def _send_project_email(users, title, message, link=None):
    """Envoie un email aux utilisateurs (best-effort).
    Utilise la fonction d'envoi mail existante si dispo, sinon ne fait rien."""
    try:
        # Si app.py a déjà un helper send_mail / send_email, l'utiliser
        for u in users:
            email = u.get('email')
            if not email: continue
            body = f"Bonjour {u.get('full_name','')},\n\n{message}\n"
            if link:
                body += f"\nLien : {link}\n"
            body += "\n--\nWannyGest — RAMYA Technologie"
            # Tentative via fonction globale send_email_html ou send_mail
            for fn_name in ('send_email_html', 'send_mail', '_send_email'):
                fn = globals().get(fn_name)
                if fn:
                    try:
                        fn(email, f"[WannyGest] {title}", body)
                        break
                    except: pass
    except: pass


def get_project_notifications_for_user(user):
    """Retourne les notifications projet non lues pour un utilisateur (selon son rôle)."""
    if not user: return []
    role = user.get('role', '')
    uid = user.get('id')
    conn = _gdb()
    try:
        rows = conn.execute("""SELECT n.*, p.reference as project_ref, p.title as project_title
            FROM wf_project_notifications n
            LEFT JOIN wf_projects p ON n.project_id = p.id
            WHERE n.is_read = 0 AND (n.target_role = ? OR n.target_user_id = ? OR ? = 'admin')
            ORDER BY n.created_at DESC LIMIT 50""",
            (role, uid, role)).fetchall()
    except:
        rows = []
    conn.close()
    return [dict(r) for r in rows]


def _gen_project_reference():
    """Génère une référence projet PRJ-YYYYMM-XXX."""
    from datetime import datetime as _dt
    import secrets as _s
    prefix = f"PRJ-{_dt.now().strftime('%Y%m')}"
    return f"{prefix}-{_s.token_hex(2).upper()}"


def _auto_create_project_if_needed(devis_id, invoice_id=None, acompte_amount=0):
    """Crée automatiquement un projet quand un devis est signé ET un acompte enregistré.
    Appelé depuis les routes de signature devis / paiement facture.
    Retourne le projet créé (ou None si conditions pas remplies / projet déjà existant)."""
    conn = _gdb()
    
    # Vérifier qu'aucun projet n'existe déjà pour ce devis
    existing = conn.execute("SELECT id FROM wf_projects WHERE devis_id=?", (devis_id,)).fetchone()
    if existing:
        conn.close()
        return None
    
    # Récupérer le devis
    devis = conn.execute("SELECT * FROM devis WHERE id=?", (devis_id,)).fetchone()
    if not devis:
        conn.close()
        return None
    devis = dict(devis)
    
    # Le devis doit être signé/validé (status 'signe', 'valide' ou avoir signature_data)
    is_signed = (devis.get('status') in ('signe', 'valide', 'envoye') 
                 or devis.get('signature_data'))
    if not is_signed:
        conn.close()
        return None
    
    # Créer le projet
    ref = _gen_project_reference()
    total = devis.get('total_ttc') or devis.get('total_ht') or 0
    title = devis.get('objet') or f"Projet {devis.get('reference','')}"
    
    cur = conn.execute("""INSERT INTO wf_projects
        (reference, client_id, client_name, devis_id, devis_reference, invoice_id,
         title, description, total_amount, acompte_amount, solde_amount,
         status, current_step, progress_pct, created_by)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (ref, devis.get('client_id'), devis.get('client_name'), devis_id,
         devis.get('reference'), invoice_id,
         title, devis.get('notes', '') or '',
         float(total), float(acompte_amount or 0), float(total) - float(acompte_amount or 0),
         'valide', 1, 10, session.get('user_id') if 'user_id' in session else None))
    pid = cur.lastrowid
    conn.commit(); conn.close()
    
    _project_log(pid, 'creation', None, 'valide',
        f"Projet créé automatiquement depuis devis {devis.get('reference')} (acompte {acompte_amount:,.0f} FCFA)")
    # v87 : Notification large à tous les acteurs potentiels du projet
    _project_notify(pid, ['admin', 'dg', 'directeur', 'coordinateur', 'gestionnaire_projet', 'resp_projet', 'commercial'],
        f"🆕 Nouveau projet validé : {title}",
        f"Le projet {ref} est validé (devis signé + acompte {acompte_amount:,.0f} FCFA). Un coordinateur doit prendre en charge le démarrage.",
        f"/projects/{pid}")
    
    return pid


def _project_advance(project_id, to_status, comment=''):
    """Fait avancer un projet d'une étape (avec validation).
    Met à jour status, current_step, progress_pct + log + notifications."""
    info = PROJECT_STATUS_INFO.get(to_status)
    if not info: return False, "Étape inconnue"
    
    conn = _gdb()
    row = conn.execute("SELECT status, title, reference FROM wf_projects WHERE id=?", (project_id,)).fetchone()
    if not row:
        conn.close()
        return False, "Projet introuvable"
    from_status = row['status']
    title = row['title']
    ref = row['reference']
    
    # Mise à jour
    extra_sql = ""
    extra_params = []
    if to_status == 'travaux_fin':
        extra_sql = ", end_date_actual=?"
        extra_params.append(datetime.now().strftime('%Y-%m-%d'))
    elif to_status == 'qc_valide':
        extra_sql = ", qc_validated_at=?, qc_validated_by=?"
        extra_params.extend([datetime.now().strftime('%Y-%m-%d %H:%M'), session.get('user_id')])
    elif to_status == 'qc_rejete':
        extra_sql = ", qc_rejected_count = COALESCE(qc_rejected_count, 0) + 1"
    elif to_status == 'livre':
        extra_sql = ", delivery_date=?"
        extra_params.append(datetime.now().strftime('%Y-%m-%d'))
    elif to_status == 'cloture':
        extra_sql = ", cloture_at=?, cloture_by=?"
        extra_params.extend([datetime.now().strftime('%Y-%m-%d %H:%M'), session.get('user_id')])
    
    conn.execute(f"UPDATE wf_projects SET status=?, current_step=?, progress_pct=?{extra_sql} WHERE id=?",
        [to_status, info['num'], info['pct']] + extra_params + [project_id])
    conn.commit(); conn.close()
    
    _project_log(project_id, 'transition', from_status, to_status, comment)
    
    # v87 + v132 : Notifications enrichies — chaque transition notifie le service responsable
    COORD_ROLES = ['coordinateur', 'gestionnaire_projet', 'resp_projet']
    notif_map = {
        'demarre':        (['mg', 'moyens_generaux', 'magasinier'] + COORD_ROLES,   "🚀 Démarrage validé — Préparer le matériel",  "Le coordinateur a validé le démarrage. Vérifier la disponibilité du matériel et préparer les ressources."),
        'preparation':    (['mg', 'moyens_generaux', 'magasinier'] + COORD_ROLES,   "📦 Préparation matériel demandée",            "Lister et réserver le matériel nécessaire au projet."),
        'planifie':       (['technicien', 'tech_chef', 'chef_chantier', 'centre_technique'] + COORD_ROLES, "📅 Projet planifié — Travaux gros œuvre à venir", "Vous êtes affecté à ce projet. Phase 1 : Gros œuvre."),
        'execution':      (['technicien', 'tech_chef', 'centre_technique'] + COORD_ROLES, "🔧 Travaux à exécuter maintenant", "Démarrer les travaux selon le programme défini."),
        # v132 : Gros œuvre + appareillage
        'execution_gros_oeuvre':   (['technicien', 'tech_chef', 'centre_technique'] + COORD_ROLES, "🏗️ Gros œuvre en cours", "Démarrer les travaux de gros œuvre (étape 1/2 de la phase technique)."),
        'prep_appareillage':       (['mg', 'moyens_generaux', 'magasinier'] + COORD_ROLES, "📦 Gros œuvre terminé — Préparer le matériel d'appareillage", "Les travaux de gros œuvre sont terminés. Préparer et mettre à disposition le matériel pour l'étape d'appareillage (étape 2/2)."),
        'planif_appareillage':     (COORD_ROLES, "📅 Matériel appareillage prêt — Planifier l'intervention", "Les Moyens Généraux ont livré le matériel d'appareillage. Planifiez la prochaine intervention pour l'étape d'appareillage."),
        'execution_appareillage':  (['technicien', 'tech_chef', 'centre_technique'] + COORD_ROLES, "⚙️ Appareillage en cours", "Démarrer les travaux d'appareillage (étape 2/2). L'étape de gros œuvre est déjà réalisée."),
        'travaux_fin':    (COORD_ROLES,                          "🏁 Travaux terminés — Contrôle qualité requis","Procéder au contrôle qualité avant livraison au client."),
        'qc_valide':      (COORD_ROLES,                          "🔍 Contrôle qualité validé — Programmer livraison","Le contrôle qualité est validé. Programmer le rendez-vous de livraison avec le client."),
        'qc_rejete':      (['technicien', 'tech_chef', 'centre_technique'] + COORD_ROLES, "❌ Contrôle qualité rejeté — Reprise requise", "Le contrôle qualité a été rejeté. Reprendre les travaux selon les observations du coordinateur."),
        'livre':          (['comptabilite', 'comptable'] + COORD_ROLES, "🚚 Projet livré — Facturer le solde",   "La livraison est effectuée (BL + ABE signés). Générer la facture du solde et suivre le paiement."),
        'attente_solde':  (['comptabilite', 'comptable'] + COORD_ROLES, "⏳ Solde en attente de paiement",       "Relancer le client pour le paiement du solde du projet."),
        'solde':          (['commercial'] + COORD_ROLES,         "💰 Projet soldé — Proposer contrat entretien", "Le solde est encaissé. Proposer un contrat d'entretien au client."),
        'contrat_oui':    (['commercial'] + COORD_ROLES,         "✅ Contrat entretien accepté",                "Le client accepte le contrat d'entretien. Procéder à la clôture du projet."),
        'contrat_non':    (['commercial'] + COORD_ROLES,         "🚫 Contrat entretien refusé",                 "Le client refuse le contrat d'entretien. Procéder à la clôture du projet."),
        'cloture':        (['admin', 'commercial', 'dg', 'directeur'] + COORD_ROLES, "🏆 Projet clôturé",         "Le projet est officiellement clôturé. Archivage disponible."),
    }
    if to_status in notif_map:
        roles, n_title, n_msg = notif_map[to_status]
        _project_notify(project_id, roles,
            f"{n_title} — {title}",
            f"{n_msg} (Réf. {ref})",
            f"/projects/{project_id}")
    
    return True, "OK"


def get_project_by_id_full(pid):
    """Récupère un projet avec ses relations (équipe, matériels, historique, rapports)."""
    conn = _gdb()
    p = conn.execute("SELECT * FROM wf_projects WHERE id=?", (pid,)).fetchone()
    if not p:
        conn.close()
        return None
    p = dict(p)
    p['team'] = [dict(r) for r in conn.execute(
        "SELECT pt.*, u.full_name, u.username FROM wf_project_team pt "
        "LEFT JOIN users u ON pt.user_id = u.id WHERE pt.project_id=?", (pid,)).fetchall()]
    p['materials'] = [dict(r) for r in conn.execute(
        """SELECT m.*, a.designation as article_designation, a.prix_unitaire as article_prix,
                  COALESCE(a.stock_initial,0) 
                    + COALESCE((SELECT SUM(quantite) FROM mg_stock_entries WHERE article_id=a.id),0)
                    - COALESCE((SELECT SUM(quantite) FROM mg_stock_exits WHERE article_id=a.id),0) as stock_actuel
           FROM wf_project_materials m 
           LEFT JOIN mg_stock_articles a ON m.mg_equipement_id = a.id
           WHERE m.project_id=? ORDER BY m.id""", (pid,)).fetchall()]
    # v103 : recalculer "available" en temps réel selon stock_actuel vs quantity
    for m in p['materials']:
        if m.get('mg_equipement_id') and m.get('stock_actuel') is not None:
            m['available'] = 1 if (m['stock_actuel'] or 0) >= (m['quantity'] or 0) else 0
    p['history'] = [dict(r) for r in conn.execute(
        "SELECT * FROM wf_project_history WHERE project_id=? ORDER BY created_at DESC", (pid,)).fetchall()]
    p['progress_reports'] = [dict(r) for r in conn.execute(
        "SELECT * FROM wf_project_progress WHERE project_id=? ORDER BY created_at DESC", (pid,)).fetchall()]
    p['coordinator'] = None
    if p.get('coordinator_id'):
        coord = conn.execute("SELECT id, full_name, username, email FROM users WHERE id=?",
            (p['coordinator_id'],)).fetchone()
        if coord: p['coordinator'] = dict(coord)
    conn.close()
    return p


def get_recharge_alerts():
    """Retourne les recharges en alerte (échéance dans <= alert_days_before jours, ou en retard).
    Le rappel reste actif tant que la recharge n'est pas confirmée (status='actif')."""
    from datetime import datetime as _dt
    conn = _gdb()
    try:
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM it_internet_recharge WHERE status='actif' ORDER BY next_due ASC").fetchall()]
    except:
        rows = []
    conn.close()
    today = _dt.now().date()
    alerts = []
    for r in rows:
        if not r.get('next_due'): continue
        try:
            due = _dt.strptime(r['next_due'][:10], '%Y-%m-%d').date()
        except:
            continue
        days_left = (due - today).days
        alert_before = int(r.get('alert_days_before') or 2)
        if days_left <= alert_before:
            r['days_left'] = days_left
            r['is_overdue'] = days_left < 0
            alerts.append(r)
    return alerts


def _filter_recharges(periode='tous', show_done=False):
    """v81 : Filtre les recharges selon la période et l'état.
    periode : 'jour' | 'semaine' | 'mois' | 'tous'
    show_done : si True, retourne l'historique des recharges déjà effectuées
    Retourne (liste, date_debut, date_fin, libelle_periode)
    """
    from datetime import datetime as _dt, timedelta as _td
    today = _dt.now().date()
    
    # Déterminer la fenêtre de dates
    if periode == 'jour':
        d_start = today
        d_end = today
        libelle = f"du {today.strftime('%d/%m/%Y')}"
    elif periode == 'semaine':
        d_start = today - _td(days=today.weekday())  # lundi
        d_end = d_start + _td(days=6)  # dimanche
        libelle = f"du {d_start.strftime('%d/%m/%Y')} au {d_end.strftime('%d/%m/%Y')}"
    elif periode == 'mois':
        d_start = today.replace(day=1)
        if today.month == 12:
            d_end = today.replace(year=today.year+1, month=1, day=1) - _td(days=1)
        else:
            d_end = today.replace(month=today.month+1, day=1) - _td(days=1)
        _mois_fr = ['','Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre']
        libelle = f"de {_mois_fr[today.month]} {today.year}"
    else:
        d_start = None
        d_end = None
        libelle = "(toutes périodes)"
    
    conn = _gdb()
    
    if show_done:
        # Historique des recharges effectuées
        sql = """SELECT h.*, r.equipment_name, r.operator, r.sim_number, r.location,
                 u.full_name as done_by_name
                 FROM it_internet_recharge_history h
                 LEFT JOIN it_internet_recharge r ON h.recharge_id = r.id
                 LEFT JOIN users u ON h.done_by = u.id"""
        params = []
        if d_start and d_end:
            sql += " WHERE h.recharge_date >= ? AND h.recharge_date <= ?"
            params = [d_start.strftime('%Y-%m-%d'), d_end.strftime('%Y-%m-%d')]
        sql += " ORDER BY h.recharge_date DESC"
        rows = [dict(r) for r in conn.execute(sql, params).fetchall()]
        conn.close()
        return rows, d_start, d_end, libelle
    else:
        # Recharges à effectuer (échéances)
        recharges = [dict(r) for r in conn.execute(
            "SELECT * FROM it_internet_recharge WHERE status='actif' ORDER BY next_due ASC").fetchall()]
        conn.close()
        result = []
        for r in recharges:
            if not r.get('next_due'): continue
            try:
                due = _dt.strptime(r['next_due'][:10], '%Y-%m-%d').date()
            except:
                continue
            # Filtre période : échéance dans la fenêtre OU déjà en retard (toujours inclus)
            if d_start and d_end:
                if not (due <= d_end):  # inclut les retards (due < d_start)
                    continue
            days_left = (due - today).days
            alert_before = int(r.get('alert_days_before') or 2)
            if days_left < 0:
                r['state'] = 'retard'
            elif days_left <= alert_before:
                r['state'] = 'bientot'
            else:
                r['state'] = 'ok'
            r['days_left'] = days_left
            result.append(r)
        return result, d_start, d_end, libelle


# ==================== v83 : MODULE CARTOGRAPHIE INSTALLATIONS ====================

def _cartographie_period_filter(periode):
    """Retourne (date_debut, date_fin, libelle) selon la période demandée."""
    from datetime import datetime as _dt, timedelta as _td
    today = _dt.now().date()
    if periode == 'mois':
        d_start = today.replace(day=1)
        if today.month == 12:
            d_end = today.replace(year=today.year+1, month=1, day=1) - _td(days=1)
        else:
            d_end = today.replace(month=today.month+1, day=1) - _td(days=1)
        libelle = f"de {['','Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'][today.month]} {today.year}"
    elif periode == 'trimestre':
        q = (today.month - 1) // 3
        d_start = today.replace(month=q*3 + 1, day=1)
        end_m = q*3 + 3
        if end_m == 12:
            d_end = today.replace(year=today.year+1, month=1, day=1) - _td(days=1)
        else:
            d_end = today.replace(month=end_m+1, day=1) - _td(days=1)
        libelle = f"du trimestre T{q+1} {today.year}"
    elif periode == 'semestre':
        if today.month <= 6:
            d_start = today.replace(month=1, day=1)
            d_end = today.replace(month=6, day=30)
            libelle = f"du 1er semestre {today.year}"
        else:
            d_start = today.replace(month=7, day=1)
            d_end = today.replace(month=12, day=31)
            libelle = f"du 2e semestre {today.year}"
    elif periode == 'annee':
        d_start = today.replace(month=1, day=1)
        d_end = today.replace(month=12, day=31)
        libelle = f"de l'année {today.year}"
    else:
        d_start = None
        d_end = None
        libelle = "(toutes périodes)"
    return d_start, d_end, libelle


@app.route('/installations')
@permission_required_any('clients', 'centre_technique', 'admin')
def installations_page():
    """Cartographie des installations + statistiques d'interventions."""
    periode = request.args.get('periode', 'annee')
    d_start, d_end, libelle = _cartographie_period_filter(periode)
    
    conn = _gdb()
    # Toutes les installations (+ v162 : nom de l'utilisateur qui a enregistré le site)
    installations = [dict(r) for r in conn.execute(
        "SELECT i.*, cl.name as client_name_ref, u.full_name as installed_by_name FROM installations i "
        "LEFT JOIN clients cl ON i.client_id = cl.id "
        "LEFT JOIN users u ON u.id = i.created_by "
        "ORDER BY i.created_at DESC").fetchall()]
    
    # Interventions filtrées par période
    int_sql = "SELECT * FROM installation_interventions"
    int_params = []
    if d_start and d_end:
        int_sql += " WHERE intervention_date >= ? AND intervention_date <= ?"
        int_params = [d_start.strftime('%Y-%m-%d'), d_end.strftime('%Y-%m-%d')]
    int_sql += " ORDER BY intervention_date DESC"
    interventions = [dict(r) for r in conn.execute(int_sql, int_params).fetchall()]
    
    conn.close()
    
    # Compteurs par zone
    zones_count = {}
    interventions_by_install = {}
    for it in interventions:
        interventions_by_install[it['installation_id']] = interventions_by_install.get(it['installation_id'], 0) + 1
    
    # Compteur d'équipements + zones
    total_equipements = 0
    zones_stats = {}  # zone -> {'installations': N, 'equipements': N, 'interventions': N}
    for inst in installations:
        eq = inst.get('equipment_count') or 0
        total_equipements += eq
        z = inst.get('zone') or 'Non précisée'
        if z not in zones_stats:
            zones_stats[z] = {'installations': 0, 'equipements': 0, 'interventions': 0}
        zones_stats[z]['installations'] += 1
        zones_stats[z]['equipements'] += eq
        zones_stats[z]['interventions'] += interventions_by_install.get(inst['id'], 0)
    
    # Zones avec le plus d'interventions (top 5)
    top_zones = sorted(zones_stats.items(), key=lambda x: x[1]['interventions'], reverse=True)[:5]
    
    # Stats interventions par type
    types_stats = {}
    for it in interventions:
        t = it.get('type') or 'autre'
        types_stats[t] = types_stats.get(t, 0) + 1
    
    return render_template('installations.html', page='installations',
        installations=installations, interventions=interventions,
        zones_stats=zones_stats, top_zones=top_zones, types_stats=types_stats,
        total_equipements=total_equipements,
        nb_installations=len(installations), nb_interventions=len(interventions),
        nb_zones=len(zones_stats),
        periode=periode, libelle=libelle, clients=get_all_clients())


@app.route('/installations/add', methods=['POST'])
@permission_required_any('clients', 'centre_technique', 'admin')
def installations_add():
    """Enregistre une nouvelle installation."""
    name = request.form.get('site_name', '').strip()
    if not name:
        flash("Nom du site requis", "error")
        return redirect('/installations')
    conn = _gdb()
    client_id = request.form.get('client_id') or None
    client_name = ''
    if client_id:
        row = conn.execute("SELECT name FROM clients WHERE id=?", (client_id,)).fetchone()
        if row: client_name = row['name']
    
    def _f(v, default=0.0):
        try: return float(v)
        except: return default
    
    conn.execute("""INSERT INTO installations
        (client_id, client_name, site_name, zone, address, latitude, longitude,
         install_date, equipment_count, equipment_type, status, notes, created_by)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (client_id, client_name, name,
         request.form.get('zone', '').strip(),
         request.form.get('address', '').strip(),
         _f(request.form.get('latitude'), None) if request.form.get('latitude') else None,
         _f(request.form.get('longitude'), None) if request.form.get('longitude') else None,
         request.form.get('install_date', '').strip() or None,
         int(request.form.get('equipment_count', 0) or 0),
         request.form.get('equipment_type', '').strip(),
         'actif',
         request.form.get('notes', '').strip(),
         session.get('user_id')))
    conn.commit(); conn.close()
    flash(f"Installation '{name}' enregistrée", "success")
    return redirect('/installations')


@app.route('/installations/<int:iid>/delete')
@permission_required_any('clients', 'centre_technique', 'admin')
def installations_delete(iid):
    conn = _gdb()
    conn.execute("DELETE FROM installation_interventions WHERE installation_id=?", (iid,))
    conn.execute("DELETE FROM installations WHERE id=?", (iid,))
    conn.commit(); conn.close()
    flash("Installation supprimée", "success")
    return redirect('/installations')

@app.route('/installations/<int:iid>/edit-gps', methods=['POST'])
@permission_required_any('clients', 'centre_technique', 'admin')
def installations_edit_gps(iid):
    """v162 : Renseigner / corriger la position GPS (+ zone) d'un site existant
    pour le rendre localisable sur la carte."""
    def _f(v):
        try: return float(str(v).replace(',', '.'))
        except: return None
    lat = _f(request.form.get('latitude'))
    lng = _f(request.form.get('longitude'))
    zone = (request.form.get('zone', '') or '').strip()
    conn = _gdb()
    if zone:
        conn.execute("UPDATE installations SET latitude=?, longitude=?, zone=? WHERE id=?", (lat, lng, zone, iid))
    else:
        conn.execute("UPDATE installations SET latitude=?, longitude=? WHERE id=?", (lat, lng, iid))
    conn.commit(); conn.close()
    flash("📍 Position du site mise à jour", "success")
    return redirect('/installations')


