@app.route('/installations/export-pdf')
@permission_required_any('clients', 'centre_technique', 'admin')
def installations_export_pdf():
    """Génère le rapport PDF de cartographie + interventions filtré par période."""
    from datetime import datetime as _dt
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import mm
    from reportlab.lib.colors import HexColor, white
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, PageBreak
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT
    from flask import Response
    import io as _io
    
    periode = request.args.get('periode', 'annee')
    d_start, d_end, libelle = _cartographie_period_filter(periode)
    
    conn = _gdb()
    installations = [dict(r) for r in conn.execute("SELECT * FROM installations").fetchall()]
    int_sql = "SELECT * FROM installation_interventions"
    int_params = []
    if d_start and d_end:
        int_sql += " WHERE intervention_date >= ? AND intervention_date <= ?"
        int_params = [d_start.strftime('%Y-%m-%d'), d_end.strftime('%Y-%m-%d')]
    interventions = [dict(r) for r in conn.execute(int_sql, int_params).fetchall()]
    conn.close()
    
    # Stats
    interventions_by_install = {}
    for it in interventions:
        interventions_by_install[it['installation_id']] = interventions_by_install.get(it['installation_id'], 0) + 1
    zones_stats = {}
    total_eq = 0
    for inst in installations:
        eq = inst.get('equipment_count') or 0
        total_eq += eq
        z = inst.get('zone') or 'Non précisée'
        if z not in zones_stats:
            zones_stats[z] = {'installations': 0, 'equipements': 0, 'interventions': 0}
        zones_stats[z]['installations'] += 1
        zones_stats[z]['equipements'] += eq
        zones_stats[z]['interventions'] += interventions_by_install.get(inst['id'], 0)
    top_zones = sorted(zones_stats.items(), key=lambda x: x[1]['interventions'], reverse=True)[:5]
    
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=12*mm, rightMargin=12*mm,
                            topMargin=10*mm, bottomMargin=10*mm)
    TEAL = HexColor('#1A7A6D'); GREY = HexColor('#888888'); ORANGE = HexColor('#e8672a')
    hw = ParagraphStyle('hw', fontName='Helvetica-Bold', fontSize=8, textColor=white, alignment=TA_CENTER)
    tc = ParagraphStyle('tc', fontSize=8, alignment=TA_CENTER)
    tl = ParagraphStyle('tl', fontSize=8)
    
    story = []
    story.append(Paragraph("RAMYA TECHNOLOGIE &amp; INNOVATION",
        ParagraphStyle('co', fontSize=9, textColor=GREY, alignment=TA_CENTER, spaceAfter=3*mm)))
    story.append(Paragraph("<b>RAPPORT DE CARTOGRAPHIE DES INSTALLATIONS</b>",
        ParagraphStyle('t', fontName='Helvetica-Bold', fontSize=16, textColor=TEAL, alignment=TA_CENTER, spaceAfter=2*mm)))
    story.append(Paragraph(f"Filtre : {libelle} — Généré le {_dt.now().strftime('%d/%m/%Y à %H:%M')}",
        ParagraphStyle('sub', fontSize=8, textColor=GREY, alignment=TA_CENTER, spaceAfter=6*mm)))
    
    # Résumé
    story.append(Paragraph("<b>📊 Résumé général</b>", ParagraphStyle('h', fontName='Helvetica-Bold', fontSize=11, textColor=TEAL, spaceAfter=3*mm)))
    resume_data = [
        [Paragraph("Installations", hw), Paragraph("Équipements", hw), Paragraph("Zones couvertes", hw), Paragraph("Interventions", hw)],
        [Paragraph(f"<b>{len(installations)}</b>", tc), Paragraph(f"<b>{total_eq}</b>", tc),
         Paragraph(f"<b>{len(zones_stats)}</b>", tc), Paragraph(f"<b>{len(interventions)}</b>", tc)],
    ]
    t = Table(resume_data, colWidths=[44*mm]*4)
    t.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,0),TEAL),
        ('BOX',(0,0),(-1,-1),0.5,GREY),('INNERGRID',(0,0),(-1,-1),0.3,HexColor('#ddd')),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE')]))
    story.append(t)
    story.append(Spacer(1, 6*mm))
    
    # Top zones
    story.append(Paragraph("<b>🗺️ Zones avec le plus d'interventions</b>", ParagraphStyle('h', fontName='Helvetica-Bold', fontSize=11, textColor=TEAL, spaceAfter=3*mm)))
    if top_zones:
        data = [[Paragraph(h, hw) for h in ['Rang', 'Zone', 'Installations', 'Équipements', 'Interventions']]]
        for i, (z, s) in enumerate(top_zones, 1):
            data.append([Paragraph(f"#{i}", tc), Paragraph(z, tl),
                         Paragraph(str(s['installations']), tc), Paragraph(str(s['equipements']), tc),
                         Paragraph(f"<b>{s['interventions']}</b>", tc)])
        t = Table(data, colWidths=[14*mm, 70*mm, 30*mm, 30*mm, 30*mm])
        t.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,0),TEAL),
            ('BOX',(0,0),(-1,-1),0.5,GREY),('INNERGRID',(0,0),(-1,-1),0.3,HexColor('#ddd')),
            ('ROWBACKGROUNDS',(0,1),(-1,-1),[white, HexColor('#f8faf9')])]))
        story.append(t)
    else:
        story.append(Paragraph("<i>Aucune intervention pour cette période</i>", ParagraphStyle('i', fontSize=9, textColor=GREY)))
    story.append(Spacer(1, 6*mm))
    
    # Détail installations
    story.append(Paragraph("<b>🏗️ Liste des installations</b>", ParagraphStyle('h', fontName='Helvetica-Bold', fontSize=11, textColor=TEAL, spaceAfter=3*mm)))
    if installations:
        data = [[Paragraph(h, hw) for h in ['#', 'Site', 'Client', 'Zone', 'Équipements', 'Interventions', 'Date install.']]]
        for i, inst in enumerate(installations, 1):
            data.append([Paragraph(str(i), tc),
                         Paragraph(inst.get('site_name', '-'), tl),
                         Paragraph(inst.get('client_name', '-') or '-', tl),
                         Paragraph(inst.get('zone', '-') or '-', tc),
                         Paragraph(str(inst.get('equipment_count', 0) or 0), tc),
                         Paragraph(str(interventions_by_install.get(inst['id'], 0)), tc),
                         Paragraph(inst.get('install_date', '-') or '-', tc)])
        t = Table(data, colWidths=[10*mm, 40*mm, 36*mm, 28*mm, 22*mm, 24*mm, 22*mm])
        t.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,0),TEAL),
            ('BOX',(0,0),(-1,-1),0.5,GREY),('INNERGRID',(0,0),(-1,-1),0.3,HexColor('#ddd')),
            ('ROWBACKGROUNDS',(0,1),(-1,-1),[white, HexColor('#f8faf9')])]))
        story.append(t)
    
    doc.build(story)
    buf.seek(0)
    
    try:
        log_activity(session.get('user_id'), get_user_by_id(session['user_id'])['full_name'],
                    'Cartographie', f"Export PDF rapport cartographie ({periode})", request.remote_addr)
    except: pass
    
    fname = f"cartographie_{periode}_{_dt.now().strftime('%Y%m%d')}.pdf"
    return Response(buf.getvalue(), mimetype='application/pdf',
                   headers={'Content-Disposition': f'attachment; filename="{fname}"'})


# ==================== v84 : ROUTES MODULE PROJETS ====================

@app.route('/projects')
@project_access_required
def projects_list():
    """Liste/dashboard des projets — vue coordinateur."""
    status_filter = request.args.get('status', '').strip()
    projects = []
    stats = {'total': 0, 'actifs': 0, 'cloture': 0, 'execution': 0, 'qc_attente': 0, 'solde_attente': 0}
    
    try:
        conn = _gdb()
        # S'assurer que les tables existent (filet de sécurité)
        try:
            from models import migrate_v75
            migrate_v75()
        except: pass
        
        sql = """SELECT p.*, u.full_name as coordinator_name
                 FROM wf_projects p
                 LEFT JOIN users u ON p.coordinator_id = u.id"""
        params = []
        if status_filter == 'actifs':
            sql += " WHERE p.status NOT IN ('cloture')"
        elif status_filter:
            sql += " WHERE p.status = ?"
            params.append(status_filter)
        sql += " ORDER BY p.created_at DESC"
        try:
            projects = [dict(r) for r in conn.execute(sql, params).fetchall()]
        except Exception as e:
            print(f"[projects_list] Erreur SELECT projets : {e}", flush=True)
            projects = []
        
        # Stats (chaque requête isolée)
        try: stats['total'] = conn.execute("SELECT COUNT(*) FROM wf_projects").fetchone()[0]
        except: pass
        try: stats['actifs'] = conn.execute("SELECT COUNT(*) FROM wf_projects WHERE status NOT IN ('cloture')").fetchone()[0]
        except: pass
        try: stats['cloture'] = conn.execute("SELECT COUNT(*) FROM wf_projects WHERE status='cloture'").fetchone()[0]
        except: pass
        try: stats['execution'] = conn.execute("SELECT COUNT(*) FROM wf_projects WHERE status='execution'").fetchone()[0]
        except: pass
        try: stats['qc_attente'] = conn.execute("SELECT COUNT(*) FROM wf_projects WHERE status='travaux_fin'").fetchone()[0]
        except: pass
        try: stats['solde_attente'] = conn.execute("SELECT COUNT(*) FROM wf_projects WHERE status IN ('livre','attente_solde')").fetchone()[0]
        except: pass
        conn.close()
    except Exception as e:
        print(f"[projects_list] Erreur globale : {e}", flush=True)
    
    # Enrichir avec info étape (sans crasher si statut inconnu)
    for p in projects:
        try:
            info = PROJECT_STATUS_INFO.get(p.get('status') or '', {})
            p['step_label'] = info.get('label', p.get('status') or 'Statut inconnu')
            p['step_icon'] = info.get('icon', '📋')
            p['step_pct'] = info.get('pct', p.get('progress_pct') or 0)
        except:
            p['step_label'] = p.get('status') or '?'
            p['step_icon'] = '📋'
            p['step_pct'] = 0
    
    # v132 : Visibilité limitée — calcul du flag pour le template
    user = get_user_by_id(session['user_id']) if session.get('user_id') else None
    user_role = user['role'] if user else None
    full_view = can_view_full_project(user_role)
    
    return render_template('projects.html', page='projects',
        projects=projects, stats=stats, status_filter=status_filter,
        steps=PROJECT_STEPS, full_view=full_view, user_role=user_role)


@app.route('/projects/new', methods=['GET', 'POST'])  # v136 : alias pour cohérence avec CRM Nouveau Projet
@app.route('/projects/create', methods=['GET', 'POST'])
@project_access_required
def projects_create():
    """v136 : Création manuelle d'un projet. Si appelée avec ?from_field_report=<id>,
    pré-remplit les champs depuis la remontée et lie automatiquement le projet créé."""
    # v136 : Récupération de la remontée d'origine si présente
    from_field_report_id = request.args.get('from_field_report', '').strip()
    if not from_field_report_id:
        from_field_report_id = request.form.get('from_field_report_id', '').strip()
    
    source_report = None
    if from_field_report_id and from_field_report_id.isdigit():
        try:
            _c = _gdb()
            row = _c.execute("SELECT * FROM field_reports WHERE id=?", (int(from_field_report_id),)).fetchone()
            if row: source_report = dict(row)
            _c.close()
        except: pass
    
    if request.method == 'POST':
        title = request.form.get('title', '').strip()
        if not title:
            flash("Titre du projet requis", "error")
            redirect_url = '/projects/create'
            if from_field_report_id: redirect_url += f"?from_field_report={from_field_report_id}"
            return redirect(redirect_url)
        
        conn = _gdb()
        devis_id = request.form.get('devis_id') or None
        devis_ref = ''
        if devis_id:
            d = conn.execute("SELECT reference, total_ttc FROM devis WHERE id=?", (devis_id,)).fetchone()
            if d:
                devis_ref = d['reference']
        
        client_id = request.form.get('client_id') or None
        client_name = request.form.get('client_name', '').strip()
        if client_id and not client_name:
            row = conn.execute("SELECT name FROM clients WHERE id=?", (client_id,)).fetchone()
            if row: client_name = row['name']
        
        ref = _gen_project_reference()
        total = float(request.form.get('total_amount', 0) or 0)
        acompte = float(request.form.get('acompte_amount', 0) or 0)
        coord_id = request.form.get('coordinator_id') or session.get('user_id')
        
        cur = conn.execute("""INSERT INTO wf_projects
            (reference, client_id, client_name, devis_id, devis_reference,
             title, description, total_amount, acompte_amount, solde_amount,
             status, current_step, progress_pct, coordinator_id, created_by)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (ref, client_id, client_name, devis_id, devis_ref,
             title, request.form.get('description', ''),
             total, acompte, total - acompte,
             'valide', 1, 10, coord_id, session.get('user_id')))
        pid = cur.lastrowid
        
        # v136 : Si projet créé depuis une remontée, lier les deux entités
        if source_report:
            try:
                conn.execute("UPDATE field_reports SET linked_project_id=?, updated_at=datetime('now') WHERE id=?",
                    (pid, source_report['id']))
                # Trace dans l'historique de la remontée
                try:
                    conn.execute("""INSERT INTO field_reports_history
                        (report_id, action, action_details, actor_id, actor_name)
                        VALUES (?,?,?,?,?)""",
                        (source_report['id'], 'Conversion en projet',
                         f"Projet {ref} créé depuis cette remontée",
                         session['user_id'],
                         get_user_by_id(session['user_id'])['full_name'] if session.get('user_id') else 'Système'))
                except: pass
            except Exception as _e: print(f"[v136] link field_report err : {_e}", flush=True)
        
        conn.commit(); conn.close()
        
        _project_log(pid, 'creation_manuelle', None, 'valide',
            f"Projet créé manuellement par {get_user_by_id(session['user_id'])['full_name']}"
            + (f" — Issu de la remontée {source_report['reference']}" if source_report else ""))
        # v87 : Notification à tous les acteurs potentiels — le coordinateur prend la suite
        notif_msg = f"Le projet {ref} vient d'être créé"
        if client_name: notif_msg += f" (client : {client_name})"
        if source_report: notif_msg += f" depuis la remontée {source_report['reference']}"
        notif_msg += ". Le coordinateur doit prendre en charge le démarrage."
        _project_notify(pid, ['admin', 'dg', 'directeur', 'coordinateur', 'gestionnaire_projet', 'resp_projet', 'commercial'],
            f"🆕 Nouveau projet à démarrer : {title}",
            notif_msg,
            f"/projects/{pid}")
        if coord_id:
            try:
                _project_notify(pid, [], 
                    f"🎯 Vous êtes affecté(e) au projet {ref}",
                    f"Vous avez été désigné(e) coordinateur du projet \"{title}\". Validez le démarrage pour notifier les Moyens Généraux.",
                    f"/projects/{pid}",
                    target_user_id=int(coord_id))
            except: pass
        
        success_msg = f"✅ Projet {ref} créé"
        if source_report:
            success_msg += f" — Lié à la remontée {source_report['reference']}"
        success_msg += " — Notifications envoyées"
        flash(success_msg, "success")
        return redirect(f'/projects/{pid}')
    
    # GET : formulaire
    conn = _gdb()
    clients = [dict(r) for r in conn.execute("SELECT id, name FROM clients ORDER BY name").fetchall()]
    devis_list = [dict(r) for r in conn.execute(
        "SELECT id, reference, client_name, total_ttc, status FROM devis "
        "WHERE id NOT IN (SELECT devis_id FROM wf_projects WHERE devis_id IS NOT NULL) "
        "ORDER BY created_at DESC LIMIT 100").fetchall()]
    users_coord = [dict(r) for r in conn.execute(
        "SELECT id, full_name, username FROM users WHERE role IN ('admin','coordinateur','dg','directeur') ORDER BY full_name").fetchall()]
    conn.close()
    
    # v136 : Pré-remplissage depuis remontée
    prefill = {}
    if source_report:
        prefill = {
            'title': f"Projet suite remontée {source_report['reference']} — {source_report.get('client_name','')}",
            'description': f"Source : Remontée terrain {source_report['reference']}\n"
                           f"Client : {source_report.get('client_name','')}\n"
                           f"Site : {source_report.get('site_name','') or source_report.get('site_address','')}\n"
                           f"Type : {source_report.get('type_info','')}\n"
                           f"Priorité : {source_report.get('priorite','')}\n\n"
                           f"Description initiale :\n{source_report.get('description','')}\n"
                           + (f"\nNotes d'analyse :\n{source_report.get('analyse_notes','')}" if source_report.get('analyse_notes') else ''),
            'client_name': source_report.get('client_name',''),
            'client_id': source_report.get('client_id') or '',
        }
    
    return render_template('project_create.html', page='projects',
        clients=clients, devis_list=devis_list, coordinators=users_coord,
        source_report=source_report, prefill=prefill,
        from_field_report_id=from_field_report_id)


# v87 : Suppression d'un projet clôturé (admin uniquement)
@app.route('/projects/<int:pid>/delete', methods=['POST'])
@permission_required('admin')
def project_delete(pid):
    """Suppression DÉFINITIVE d'un projet clôturé. Réservé aux admins.
    Supprime aussi : history, notifications, materials, team, progress reports."""
    conn = _gdb()
    p = conn.execute("SELECT status, reference, title FROM wf_projects WHERE id=?", (pid,)).fetchone()
    if not p:
        conn.close()
        flash("Projet introuvable", "error")
        return redirect('/projects')
    
    if p['status'] != 'cloture':
        conn.close()
        flash("⚠️ Seuls les projets clôturés peuvent être supprimés", "error")
        return redirect(f'/projects/{pid}')
    
    ref = p['reference']
    title = p['title']
    
    # Suppression en cascade
    for tbl in ['wf_project_notifications', 'wf_project_history', 'wf_project_materials',
                'wf_project_team', 'wf_project_progress']:
        try: conn.execute(f"DELETE FROM {tbl} WHERE project_id=?", (pid,))
        except: pass
    conn.execute("DELETE FROM wf_projects WHERE id=?", (pid,))
    conn.commit(); conn.close()
    
    # Trace l'action dans logs généraux
    try:
        from models import log_activity
        log_activity(session.get('user_id'), 'project_delete',
            f"Suppression projet clôturé {ref} ({title})")
    except: pass
    
    flash(f"🗑️ Projet {ref} supprimé définitivement", "success")
    return redirect('/projects')


@app.route('/projects/<int:pid>')
@project_access_required
def project_detail(pid):
    p = get_project_by_id_full(pid)
    if not p:
        flash("Projet introuvable", "error")
        return redirect('/projects')
    
    # Stats étape courante
    info = PROJECT_STATUS_INFO.get(p['status'], {})
    p['step_label'] = info.get('label', p['status'])
    p['step_icon'] = info.get('icon', '📋')
    
    # Techniciens disponibles
    conn = _gdb()
    available_techs = [dict(r) for r in conn.execute(
        "SELECT id, full_name, username, role FROM users "
        "WHERE role IN ('technicien','tech_chef','chef_chantier') "
        "AND COALESCE(is_active,1)=1 ORDER BY full_name").fetchall()]
    # v103 : utiliser mg_stock_articles (catalogue RAMYA 196 articles) au lieu de mg_equipements vide
    mg_equips_raw = conn.execute(
        """SELECT a.id, a.reference, a.designation as nom, a.unite, a.stock_initial,
                  a.prix_unitaire, a.seuil_alerte, a.categorie,
                  COALESCE(a.stock_initial,0) 
                    + COALESCE((SELECT SUM(quantite) FROM mg_stock_entries WHERE article_id=a.id),0)
                    - COALESCE((SELECT SUM(quantite) FROM mg_stock_exits WHERE article_id=a.id),0) as stock_actuel
           FROM mg_stock_articles a
           ORDER BY a.designation LIMIT 500""").fetchall()
    mg_equips = [dict(r) for r in mg_equips_raw]
    
    # v136 : Si le projet a été créé depuis une remontée, récupérer ses infos pour affichage
    source_report = None
    try:
        sr = conn.execute(
            "SELECT id, reference, type_info, priorite, date_constat, statut FROM field_reports WHERE linked_project_id=?",
            (pid,)).fetchone()
        if sr: source_report = dict(sr)
    except: pass
    
    conn.close()
    
    # v132 : Visibilité limitée des infos sensibles pour certains rôles
    user = get_user_by_id(session['user_id']) if session.get('user_id') else None
    user_role = user['role'] if user else None
    full_view = can_view_full_project(user_role)
    
    return render_template('project_detail.html', page='projects',
        project=p, steps=PROJECT_STEPS, status_info=PROJECT_STATUS_INFO,
        available_techs=available_techs, mg_equips=mg_equips,
        full_view=full_view, user_role=user_role,
        source_report=source_report)


@app.route('/projects/<int:pid>/rollback', methods=['POST'])
@project_access_required
def project_rollback(pid):
    """v161 : revenir à l'étape PRÉCÉDENTE du roadmap — réservé admin / gestionnaire / DG."""
    user = get_user_by_id(session.get('user_id', 0))
    if not user or user['role'] not in ('admin', 'dg', 'directeur', 'gestionnaire_projet'):
        flash("⛔ Réservé à l'admin, au gestionnaire de projet et au DG.", "error")
        return redirect(f'/projects/{pid}')
    comment = (request.form.get('comment', '') or '').strip()
    conn = _gdb()
    p = conn.execute("SELECT current_step FROM wf_projects WHERE id=?", (pid,)).fetchone()
    if not p:
        conn.close(); flash("Projet introuvable", "error"); return redirect('/projects')
    cur_step = p['current_step'] or 0
    conn.close()
    candidates = [s for s in PROJECT_STEPS if s['num'] < cur_step]
    if not candidates:
        flash("Impossible de revenir : projet déjà à la première étape.", "error")
        return redirect(f'/projects/{pid}')
    prev_key = max(candidates, key=lambda s: s['num'])['key']
    ok, msg = _project_advance(pid, prev_key, f"↩️ Retour à l'étape précédente — {comment}")
    flash("✅ Projet revenu à l'étape précédente" if ok else f"Erreur : {msg}", "success" if ok else "error")
    return redirect(f'/projects/{pid}')


@app.route('/projects/<int:pid>/advance', methods=['POST'])
@project_access_required
def project_advance(pid):
    """v132 / v148 / v156 : Fait avancer un projet vers le statut suivant.
    v156 : Seul le commercial (et admin/dg) peut démarrer un projet (valide → demarre)."""
    to_status = request.form.get('to_status', '').strip()
    comment = request.form.get('comment', '').strip()
    
    # Validations contextuelles
    conn = _gdb()
    p = conn.execute("SELECT status, current_step FROM wf_projects WHERE id=?", (pid,)).fetchone()
    if not p:
        conn.close()
        flash("Projet introuvable", "error")
        return redirect('/projects')
    current = p['status']
    
    # v156 : Seul le commercial (et admin/dg) peut démarrer un projet (valide → demarre)
    user_pa = get_user_by_id(session.get('user_id', 0))
    if current == 'valide' and to_status == 'demarre':
        if not user_pa or user_pa['role'] not in ('admin', 'dg', 'directeur', 'commercial'):
            conn.close()
            flash("⛔ Seul le commercial (ou la direction) peut démarrer un projet.", "error")
            return redirect(f'/projects/{pid}')
    
    # v132 : Transitions selon workflow métier strict avec 2 étapes techniques
    valid_transitions = {
        'valide':                  ['demarre'],
        'demarre':                 ['preparation'],
        'preparation':             ['planifie'],
        'planifie':                ['execution_gros_oeuvre', 'execution'],  # 'execution' = legacy
        # v132 : Fin gros œuvre → MG appareillage
        'execution_gros_oeuvre':   ['prep_appareillage'],
        # v132 : MG prépare appareillage → coordinateur planifie
        'prep_appareillage':       ['planif_appareillage'],
        # v132 : Coordinateur planifie appareillage → tech démarre
        'planif_appareillage':     ['execution_appareillage'],
        # v132 : Fin appareillage → QC
        'execution_appareillage':  ['travaux_fin'],
        # Legacy : si projet déjà 'execution' (avant v132), passage direct à travaux_fin possible
        'execution':               ['travaux_fin', 'execution_gros_oeuvre'],
        'travaux_fin':             ['qc_valide', 'qc_rejete'],
        'qc_rejete':               ['execution_appareillage', 'execution_gros_oeuvre', 'execution'],
        'qc_valide':               ['livre'],
        'livre':                   ['solde', 'attente_solde'],
        'attente_solde':           ['solde'],
        'solde':                   ['contrat_oui', 'contrat_non'],
        'contrat_oui':             ['cloture'],
        'contrat_non':             ['cloture'],
    }
    allowed_next = valid_transitions.get(current, [])
    if to_status not in allowed_next:
        conn.close()
        flash(f"Transition non autorisée : {current} → {to_status}", "error")
        return redirect(f'/projects/{pid}')
    
    # v86 : Validations métier strictes par étape
    # v148 : MG peut faire avancer "preparation→planifie" ou "prep_appareillage→planif_appareillage"
    #        sans avoir besoin de team+date (c'est l'étape suivante qui s'en charge — le coordinateur)
    user_advance = get_user_by_id(session.get('user_id', 0))
    is_mg = user_advance and user_advance['role'] in ('mg','moyens_generaux','magasinier')
    
    if to_status == 'planifie':
        # v148 : Si c'est MG qui fait avancer (matériel prêt), ne pas exiger team + date
        # car l'étape "planifie" sert justement à ce que le coordinateur planifie ensuite
        if is_mg:
            # Vérifier qu'au moins 1 matériel a été marqué disponible
            nb_mat_dispo = conn.execute(
                "SELECT COUNT(*) FROM wf_project_materials WHERE project_id=? AND (available=1 OR reserved=1)",
                (pid,)).fetchone()[0]
            if nb_mat_dispo == 0:
                conn.close()
                flash("⚠️ Impossible d'avancer : aucun matériel n'est marqué disponible/réservé. "
                      "Réservez d'abord le matériel.", "error")
                return redirect(f'/projects/{pid}')
            # OK : MG peut avancer, le coordinateur planifiera ensuite
        else:
            # Coordinateur / gestionnaire / admin : vérifier équipe + date début
            team_count = conn.execute("SELECT COUNT(*) FROM wf_project_team WHERE project_id=?", (pid,)).fetchone()[0]
            start_date = conn.execute("SELECT start_date FROM wf_projects WHERE id=?", (pid,)).fetchone()['start_date']
            if team_count == 0 or not start_date:
                conn.close()
                flash("Impossible de planifier : au moins 1 technicien + date de début requis", "error")
                return redirect(f'/projects/{pid}')
    elif to_status == 'planif_appareillage':
        # v148 : Idem pour la phase appareillage — MG peut avancer si matériel dispo
        if is_mg:
            nb_mat_dispo = conn.execute(
                "SELECT COUNT(*) FROM wf_project_materials WHERE project_id=? AND (available=1 OR reserved=1)",
                (pid,)).fetchone()[0]
            if nb_mat_dispo == 0:
                conn.close()
                flash("⚠️ Impossible d'avancer : aucun matériel d'appareillage marqué disponible/réservé.", "error")
                return redirect(f'/projects/{pid}')
    elif to_status == 'preparation':
        # Vérifier qu'au moins 1 matériel a été ajouté (sinon avertir mais ne pas bloquer)
        nb_mat = conn.execute("SELECT COUNT(*) FROM wf_project_materials WHERE project_id=?", (pid,)).fetchone()[0]
        if nb_mat == 0:
            flash("⚠️ Aucun matériel n'a été listé. Demandez aux Moyens Généraux de l'ajouter.", "warning")
    elif to_status == 'livre':
        # Vérifier que la livraison a bien été enregistrée (bon de livraison ou ABE)
        # On accepte le passage en livré, mais on flash un rappel
        flash("📋 Pensez à imprimer le bon de livraison et l'ABE depuis la page projet", "info")
    
    # v148 : Bloquer MG sur les transitions hors préparation matériel
    if is_mg and to_status not in ('planifie', 'planif_appareillage'):
        conn.close()
        flash("⛔ Les Moyens Généraux ne peuvent faire avancer le projet que sur les étapes de préparation matériel "
              "(vers planification ou planification appareillage).", "error")
        return redirect(f'/projects/{pid}')
    
    conn.close()
    
    ok, msg = _project_advance(pid, to_status, comment)
    if ok:
        flash(f"✅ Projet avancé : {PROJECT_STATUS_INFO[to_status]['label']}", "success")
        # v148 : Si MG a marqué le matériel prêt, notifier le coordinateur pour planifier
        if is_mg and to_status in ('planifie', 'planif_appareillage'):
            try:
                conn_n = _gdb()
                proj = conn_n.execute("SELECT reference, title, coordinator_id FROM wf_projects WHERE id=?", (pid,)).fetchone()
                conn_n.close()
                if proj:
                    msg_notif = (f"📦 Le matériel du projet {proj['reference']} ({proj['title']}) est prêt et "
                                 f"disponible. Vous pouvez maintenant planifier l'intervention (date début, équipe technique).")
                    if proj['coordinator_id']:
                        notify_user(proj['coordinator_id'],
                            title=f"📦 Matériel prêt — planification requise : {proj['reference']}",
                            message=msg_notif, link=f'/projects/{pid}',
                            type='info', module='projets', icon='📦', priority='high')
                    # Aussi les coordinateurs/gestionnaires en général
                    notify_roles(['coordinateur','gestionnaire_projet','resp_projet','admin'],
                        title=f"📦 Matériel prêt : {proj['reference']}",
                        message=msg_notif, link=f'/projects/{pid}',
                        type='info', module='projets', icon='📦', priority='normal')
            except Exception as _e: print(f"[v148] notif matériel prêt err : {_e}", flush=True)
    else:
        flash(f"Erreur : {msg}", "error")
    return redirect(f'/projects/{pid}')


@app.route('/projects/<int:pid>/plan', methods=['POST'])
@project_access_required
@mg_forbidden
def project_set_plan(pid):
    """Enregistre la planification : date début, fin prévue, coordinateur."""
    conn = _gdb()
    conn.execute("""UPDATE wf_projects SET
        start_date=?, end_date_planned=?, coordinator_id=COALESCE(?, coordinator_id)
        WHERE id=?""",
        (request.form.get('start_date', '').strip() or None,
         request.form.get('end_date_planned', '').strip() or None,
         request.form.get('coordinator_id') or None,
         pid))
    conn.commit(); conn.close()
    _project_log(pid, 'planification', None, None,
        f"Planning : {request.form.get('start_date','')} → {request.form.get('end_date_planned','')}")
    flash("📅 Planning enregistré", "success")
    return redirect(f'/projects/{pid}')


@app.route('/projects/<int:pid>/team/add', methods=['POST'])
@project_access_required
@mg_forbidden
def project_team_add(pid):
    """Affecte un technicien au projet."""
    user_id = request.form.get('user_id')
    role = request.form.get('role', 'technicien').strip()
    if not user_id:
        flash("Technicien requis", "error")
        return redirect(f'/projects/{pid}')
    conn = _gdb()
    try:
        conn.execute("INSERT INTO wf_project_team (project_id, user_id, role) VALUES (?,?,?)",
            (pid, int(user_id), role))
        conn.commit()
        u = conn.execute("SELECT full_name FROM users WHERE id=?", (user_id,)).fetchone()
        nm = u['full_name'] if u else f"User#{user_id}"
        flash(f"✅ {nm} affecté au projet", "success")
        _project_log(pid, 'team_add', None, None, f"{nm} affecté ({role})")
        _project_notify(pid, None, "Vous êtes affecté à un projet",
            f"Consultez le projet dans votre dashboard.",
            f"/projects/{pid}", target_user_id=int(user_id))
    except Exception as e:
        flash(f"Déjà affecté ou erreur : {e}", "warning")
    conn.close()
    return redirect(f'/projects/{pid}')


