    # Matériel
    story.append(Paragraph("📦 MATÉRIEL PRÉVU", section))
    if p['materials']:
        mat_data = [[Paragraph(h_, hw) for h_ in ['#', 'Désignation', 'Quantité', 'Unité', 'Disponible']]]
