@app.route('/it/recharge')
@recharge_access_required
def it_recharge():
    """Page de suivi des recharges Internet + calendrier."""
    from datetime import datetime as _dt, timedelta as _td
    import calendar as _cal
    conn = _gdb()
    recharges = [dict(r) for r in conn.execute(
        "SELECT * FROM it_internet_recharge ORDER BY status DESC, next_due ASC").fetchall()]
    conn.close()
    
    today = _dt.now().date()
    for r in recharges:
        r['days_left'] = None
        r['state'] = 'inconnu'
        if r.get('next_due'):
            try:
                due = _dt.strptime(r['next_due'][:10], '%Y-%m-%d').date()
                days_left = (due - today).days
                r['days_left'] = days_left
                alert_before = int(r.get('alert_days_before') or 2)
                if r['status'] != 'actif':
                    r['state'] = 'inactif'
                elif days_left < 0:
                    r['state'] = 'retard'
                elif days_left <= alert_before:
                    r['state'] = 'bientot'
                else:
                    r['state'] = 'ok'
            except:
                pass
    
    nb_total = len(recharges)
    nb_retard = sum(1 for r in recharges if r['state'] == 'retard')
    nb_bientot = sum(1 for r in recharges if r['state'] == 'bientot')
    nb_ok = sum(1 for r in recharges if r['state'] == 'ok')
    
    # === v80 : Données calendrier ===
    # Mois affiché (navigation via ?cal_year=&cal_month=)
    try:
        cal_year = int(request.args.get('cal_year', today.year))
        cal_month = int(request.args.get('cal_month', today.month))
    except:
        cal_year, cal_month = today.year, today.month
    if cal_month < 1: cal_month = 12; cal_year -= 1
    if cal_month > 12: cal_month = 1; cal_year += 1
    
    # Projeter les échéances futures sur 6 mois pour le calendrier
    # (next_due + récurrences suivantes selon la périodicité)
    events_by_date = {}  # 'YYYY-MM-DD' -> [ {equipment_name, state, operator, id, is_projection} ]
    
    def _project_due_dates(rec, horizon_months=6):
        """Génère les dates d'échéance projetées sur l'horizon."""
        dates = []
        if not rec.get('next_due'): return dates
        try:
            cur = _dt.strptime(rec['next_due'][:10], '%Y-%m-%d').date()
        except:
            return dates
        horizon_end = today + _td(days=horizon_months*31)
        count = 0
        while cur <= horizon_end and count < 30:
            dates.append(cur)
            # Calculer la suivante
            if rec.get('period_type') == 'mensuel':
                day = int(rec.get('period_monthly_day') or cur.day)
                m = cur.month + 1; y = cur.year
                if m > 12: m = 1; y += 1
                last_day = _cal.monthrange(y, m)[1]
                cur = cur.replace(year=y, month=m, day=min(day, last_day))
            else:
                cur = cur + _td(days=int(rec.get('period_days') or 30))
            count += 1
        return dates
    
    for r in recharges:
        if r['status'] != 'actif':
            continue
        due_dates = _project_due_dates(r)
        for idx, d in enumerate(due_dates):
            ds = d.strftime('%Y-%m-%d')
            # État de cette occurrence
            dl = (d - today).days
            alert_before = int(r.get('alert_days_before') or 2)
            if dl < 0:
                ev_state = 'retard'
            elif dl <= alert_before:
                ev_state = 'bientot'
            else:
                ev_state = 'ok'
            events_by_date.setdefault(ds, []).append({
                'id': r['id'],
                'equipment_name': r['equipment_name'],
                'operator': r.get('operator', ''),
                'state': ev_state,
                'is_projection': idx > 0,  # 1ère = échéance réelle, suivantes = projections
                'next_due': ds,
                'amount': r.get('amount', 0),
            })
    
    # Construire la grille du mois (semaines de lundi à dimanche)
    _cal.setfirstweekday(_cal.MONDAY)
    month_weeks = _cal.monthcalendar(cal_year, cal_month)  # liste de semaines, 0 = jour hors mois
    
    calendar_grid = []
    for week in month_weeks:
        week_days = []
        for day in week:
            if day == 0:
                week_days.append(None)
            else:
                ds = f"{cal_year:04d}-{cal_month:02d}-{day:02d}"
                week_days.append({
                    'day': day,
                    'date': ds,
                    'is_today': (ds == today.strftime('%Y-%m-%d')),
                    'events': events_by_date.get(ds, []),
                })
        calendar_grid.append(week_days)
    
    month_names_fr = ['', 'Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin',
                      'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre']
    
    # Navigation préc/suiv
    prev_month = cal_month - 1; prev_year = cal_year
    if prev_month < 1: prev_month = 12; prev_year -= 1
    next_month = cal_month + 1; next_year = cal_year
    if next_month > 12: next_month = 1; next_year += 1
    
    # === v81 : Filtre (jour/semaine/mois + effectuées) ===
    periode = request.args.get('periode', 'tous')
    show_done = request.args.get('done', '') == '1'
    filtered, f_start, f_end, f_libelle = _filter_recharges(periode, show_done)
    
    return render_template('it_recharge.html', page='it_recharge',
        recharges=recharges, nb_total=nb_total, nb_retard=nb_retard,
        nb_bientot=nb_bientot, nb_ok=nb_ok, today=today.strftime('%Y-%m-%d'),
        calendar_grid=calendar_grid, cal_year=cal_year, cal_month=cal_month,
        cal_month_name=month_names_fr[cal_month],
        prev_year=prev_year, prev_month=prev_month,
        next_year=next_year, next_month=next_month,
        filtered=filtered, periode=periode, show_done=show_done, f_libelle=f_libelle)


@app.route('/it/recharge/export-pdf')
@recharge_access_required
def it_recharge_export_pdf():
    """v81 : Export PDF de la liste des recharges (à effectuer ou effectuées) filtrée par période."""
    from datetime import datetime as _dt
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import mm
    from reportlab.lib.colors import HexColor, white
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT, TA_LEFT
    from flask import Response
    import io as _io
    
    periode = request.args.get('periode', 'tous')
    show_done = request.args.get('done', '') == '1'
    rows, d_start, d_end, libelle = _filter_recharges(periode, show_done)
    
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=12*mm, rightMargin=12*mm,
                            topMargin=10*mm, bottomMargin=10*mm)
    
    TEAL = HexColor('#1A7A6D'); ORANGE = HexColor('#e8672a'); RED = HexColor('#c53030')
    GREEN = HexColor('#2e7d32'); GREY = HexColor('#888888')
    
    hw = ParagraphStyle('hw', fontName='Helvetica-Bold', fontSize=8, textColor=white, alignment=TA_CENTER)
    tc = ParagraphStyle('tc', fontSize=8, alignment=TA_CENTER)
    tl = ParagraphStyle('tl', fontSize=8)
    tr_s = ParagraphStyle('tr', fontSize=8, alignment=TA_RIGHT)
    
    story = []
    story.append(Paragraph("RAMYA TECHNOLOGIE &amp; INNOVATION",
        ParagraphStyle('co', fontSize=9, textColor=GREY, alignment=TA_CENTER, spaceAfter=3*mm)))
    
    titre = "RECHARGES INTERNET EFFECTUÉES" if show_done else "RECHARGES INTERNET À EFFECTUER"
    story.append(Paragraph(f"<b>{titre}</b>",
        ParagraphStyle('t', fontName='Helvetica-Bold', fontSize=16, textColor=TEAL, alignment=TA_CENTER, spaceAfter=2*mm)))
    
    periode_label = {'jour': 'Aujourd\'hui', 'semaine': 'Cette semaine',
                     'mois': 'Ce mois', 'tous': 'Toutes périodes'}.get(periode, periode)
    story.append(Paragraph(f"Filtre : {periode_label} {libelle} — Généré le {_dt.now().strftime('%d/%m/%Y à %H:%M')}",
        ParagraphStyle('sub', fontSize=8, textColor=GREY, alignment=TA_CENTER, spaceAfter=6*mm)))
    
    pw = 186*mm
    
    if not rows:
        story.append(Paragraph("Aucune recharge pour cette période.",
            ParagraphStyle('empty', fontSize=11, textColor=GREY, alignment=TA_CENTER, spaceBefore=20*mm)))
    elif show_done:
        # Tableau historique des recharges effectuées
        data = [[Paragraph(h, hw) for h in ['Date', 'Équipement', 'Opérateur', 'Montant (FCFA)', 'Effectué par']]]
        total = 0
        for r in rows:
            total += (r.get('amount') or 0)
            data.append([
                Paragraph(r.get('recharge_date', '-'), tc),
                Paragraph(r.get('equipment_name', '-'), tl),
                Paragraph(r.get('operator', '-') or '-', tc),
                Paragraph(f"{r.get('amount', 0):,.0f}", tr_s),
                Paragraph(r.get('done_by_name', '-') or '-', tl),
            ])
        data.append([Paragraph('', tc), Paragraph('<b>TOTAL</b>', ParagraphStyle('tot', fontName='Helvetica-Bold', fontSize=9)),
                     Paragraph('', tc), Paragraph(f"<b>{total:,.0f}</b>", ParagraphStyle('totr', fontName='Helvetica-Bold', fontSize=9, alignment=TA_RIGHT)),
                     Paragraph('', tc)])
        t = Table(data, colWidths=[24*mm, pw-104*mm, 28*mm, 28*mm, 24*mm])
        t.setStyle(TableStyle([
            ('BACKGROUND',(0,0),(-1,0),TEAL),
            ('BOX',(0,0),(-1,-1),0.5,HexColor('#cccccc')),
            ('INNERGRID',(0,0),(-1,-1),0.3,HexColor('#e0e0e0')),
            ('BACKGROUND',(0,-1),(-1,-1),HexColor('#e8f5e9')),
            ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('ROWBACKGROUNDS',(0,1),(-1,-2),[white, HexColor('#f8faf9')]),
        ]))
        story.append(t)
    else:
        # Tableau des recharges à effectuer
        data = [[Paragraph(h, hw) for h in ['Échéance', 'Équipement', 'Opérateur', 'N° SIM', 'Périodicité', 'État', 'Montant']]]
        for r in rows:
            st = r.get('state', '')
            if st == 'retard':
                etat = Paragraph(f"<font color='#c53030'><b>⚠ Retard {-r['days_left']}j</b></font>", tc)
            elif st == 'bientot':
                etat = Paragraph(f"<font color='#e8672a'><b>Dans {r['days_left']}j</b></font>", tc)
            else:
                etat = Paragraph(f"<font color='#2e7d32'>Dans {r['days_left']}j</font>", tc)
            if r.get('period_type') == 'mensuel':
                period_txt = f"Le {r.get('period_monthly_day', '-')} du mois"
            else:
                period_txt = f"Tous les {r.get('period_days', '-')}j"
            data.append([
                Paragraph(r.get('next_due', '-'), tc),
                Paragraph(r.get('equipment_name', '-'), tl),
                Paragraph(r.get('operator', '-') or '-', tc),
                Paragraph(r.get('sim_number', '-') or '-', tc),
                Paragraph(period_txt, tc),
                etat,
                Paragraph(f"{r.get('amount', 0):,.0f} F", tr_s),
            ])
        t = Table(data, colWidths=[22*mm, pw-128*mm, 24*mm, 26*mm, 28*mm, 24*mm, 24*mm])
        t.setStyle(TableStyle([
            ('BACKGROUND',(0,0),(-1,0),TEAL),
            ('BOX',(0,0),(-1,-1),0.5,HexColor('#cccccc')),
            ('INNERGRID',(0,0),(-1,-1),0.3,HexColor('#e0e0e0')),
            ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('ROWBACKGROUNDS',(0,1),(-1,-1),[white, HexColor('#f8faf9')]),
        ]))
        story.append(t)
        story.append(Spacer(1, 4*mm))
        # Résumé
        nb_r = sum(1 for r in rows if r.get('state') == 'retard')
        nb_b = sum(1 for r in rows if r.get('state') == 'bientot')
        story.append(Paragraph(
            f"<b>Total : {len(rows)} recharge(s)</b> — En retard : {nb_r} — Bientôt dû : {nb_b}",
            ParagraphStyle('resume', fontSize=9, textColor=HexColor('#444'))))
    
    doc.build(story)
    buf.seek(0)
    
    try:
        log_activity(session.get('user_id'),
                    get_user_by_id(session['user_id'])['full_name'],
                    'IT', f"Export PDF recharges ({periode}{', effectuées' if show_done else ''})",
                    request.remote_addr)
    except: pass
    
    suffix = 'effectuees' if show_done else 'a_effectuer'
    fname = f"recharges_{suffix}_{periode}_{_dt.now().strftime('%Y%m%d')}.pdf"
    return Response(buf.getvalue(), mimetype='application/pdf',
                   headers={'Content-Disposition': f'attachment; filename="{fname}"'})


@app.route('/it/recharge/add', methods=['POST'])
@recharge_access_required
def it_recharge_add():
    """Enregistre un nouvel équipement à recharger."""
    equipment_name = request.form.get('equipment_name', '').strip()
    if not equipment_name:
        flash("Nom de l'équipement requis", "error")
        return redirect('/it/recharge')
    
    period_type = request.form.get('period_type', 'jours')
    period_days = int(request.form.get('period_days', 30) or 30)
    period_monthly_day = int(request.form.get('period_monthly_day', 1) or 1)
    alert_days_before = int(request.form.get('alert_days_before', 2) or 2)
    
    next_due = request.form.get('next_due', '').strip()
    if not next_due:
        from datetime import datetime as _dt
        next_due = _compute_next_due(_dt.now().strftime('%Y-%m-%d'),
                                     period_type, period_days, period_monthly_day)
    
    conn = _gdb()
    conn.execute("""INSERT INTO it_internet_recharge
        (equipment_name, equipment_type, operator, sim_number, location, amount,
         period_type, period_days, period_monthly_day, next_due, alert_days_before,
         status, notes, created_by)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (equipment_name, request.form.get('equipment_type', ''),
         request.form.get('operator', ''), request.form.get('sim_number', ''),
         request.form.get('location', ''), float(request.form.get('amount', 0) or 0),
         period_type, period_days, period_monthly_day, next_due, alert_days_before,
         'actif', request.form.get('notes', ''), session.get('user_id')))
    conn.commit(); conn.close()
    
    try:
        log_activity(session.get('user_id'), get_user_by_id(session['user_id'])['full_name'],
                    'IT', f"Équipement recharge ajouté : {equipment_name}", request.remote_addr)
    except: pass
    
    flash(f"✅ Équipement '{equipment_name}' enregistré. Prochaine recharge : {next_due}", "success")
    return redirect('/it/recharge')


@app.route('/it/recharge/<int:rid>/done', methods=['POST'])
@recharge_access_required
def it_recharge_done(rid):
    """Confirme qu'une recharge a été effectuée → recalcule la prochaine échéance."""
    from datetime import datetime as _dt
    conn = _gdb()
    rec = conn.execute("SELECT * FROM it_internet_recharge WHERE id=?", (rid,)).fetchone()
    if not rec:
        conn.close()
        flash("Équipement introuvable", "error")
        return redirect('/it/recharge')
    rec = dict(rec)
    
    recharge_date = request.form.get('recharge_date', '').strip() or _dt.now().strftime('%Y-%m-%d')
    amount = float(request.form.get('amount', rec.get('amount', 0)) or 0)
    
    # Recalculer la prochaine échéance À PARTIR de la date réelle de recharge
    next_due = _compute_next_due(recharge_date, rec['period_type'],
                                 rec['period_days'], rec['period_monthly_day'])
    
    conn.execute("""INSERT INTO it_internet_recharge_history
        (recharge_id, recharge_date, amount, done_by, notes)
        VALUES (?,?,?,?,?)""",
        (rid, recharge_date, amount, session.get('user_id'),
         request.form.get('notes', '')))
    
    conn.execute("""UPDATE it_internet_recharge
        SET last_recharge_date=?, next_due=?, status='actif' WHERE id=?""",
        (recharge_date, next_due, rid))
    conn.commit(); conn.close()
    
    try:
        log_activity(session.get('user_id'), get_user_by_id(session['user_id'])['full_name'],
                    'IT', f"Recharge effectuée : {rec['equipment_name']} ({recharge_date})", request.remote_addr)
    except: pass
    
    flash(f"✅ Recharge confirmée pour '{rec['equipment_name']}'. Prochaine échéance : {next_due}", "success")
    # v79 : revenir à la page d'origine (dashboard) si fournie
    next_url = request.form.get('next') or request.referrer
    if next_url and '/it/recharge' not in next_url:
        return redirect(next_url)
    return redirect('/it/recharge')


