# v112 : Inspecter un backup pour voir quelles caisses il contenait
@app.route('/admin/backup/<path:backup_name>/inspect-caisses')
@permission_required('admin')
def admin_backup_inspect_caisses(backup_name):
    """v112 : Liste les caisses présentes dans un backup, pour récupération sélective."""
    # Sécurité : empêcher path traversal
    if '/' in backup_name or '\\' in backup_name or '..' in backup_name or not backup_name.startswith('ramya-'):
        flash("Nom de backup invalide", "error")
        return redirect('/admin/backup/list')
    
    backup_dir = os.path.join(PERSISTENT_DIR, 'backups')
    backup_path = os.path.join(backup_dir, backup_name)
    if not os.path.exists(backup_path):
        flash("Backup introuvable", "error")
        return redirect('/admin/backup/list')
    
    # Ouvrir le backup en lecture seule
    import sqlite3 as _sql
    try:
        conn_bak = _sql.connect(f"file:{backup_path}?mode=ro", uri=True)
        conn_bak.row_factory = _sql.Row
        caisses = [dict(r) for r in conn_bak.execute("SELECT * FROM caisses ORDER BY name").fetchall()]
        # Compter les opérations pour chaque caisse
        for ca in caisses:
            try:
                ca['nb_ops'] = conn_bak.execute("SELECT COUNT(*) FROM caisse_operations WHERE caisse_id=?", (ca['id'],)).fetchone()[0]
            except: ca['nb_ops'] = 0
            try:
                ca['nb_mvts'] = conn_bak.execute("SELECT COUNT(*) FROM tresorerie_mouvements WHERE caisse_id=?", (ca['id'],)).fetchone()[0]
            except: ca['nb_mvts'] = 0
        conn_bak.close()
    except Exception as e:
        flash(f"Erreur lecture backup : {e}", "error")
        return redirect('/admin/backup/list')
    
    # Quelles caisses sont actuellement présentes en prod
    conn = _gdb()
    current_ids = [r[0] for r in conn.execute("SELECT id FROM caisses").fetchall()]
    conn.close()
    for ca in caisses:
        ca['exists_now'] = ca['id'] in current_ids
    
    return render_template('backup_inspect_caisses.html', page='backup_list',
        backup_name=backup_name, caisses=caisses)


# v112 : Restaurer une caisse spécifique depuis un backup vers la corbeille (snapshot)
@app.route('/admin/backup/<path:backup_name>/restore-caisse/<int:cid>', methods=['POST'])
@permission_required('admin')
def admin_backup_restore_caisse_to_trash(backup_name, cid):
    """v112 : Extrait une caisse + son contenu d'un backup et l'enregistre dans la corbeille
    (pour permettre ensuite une restauration sélective via /admin/corbeille)."""
    if '/' in backup_name or '\\' in backup_name or '..' in backup_name or not backup_name.startswith('ramya-'):
        flash("Nom de backup invalide", "error")
        return redirect('/admin/backup/list')
    
    backup_dir = os.path.join(PERSISTENT_DIR, 'backups')
    backup_path = os.path.join(backup_dir, backup_name)
    if not os.path.exists(backup_path):
        flash("Backup introuvable", "error")
        return redirect('/admin/backup/list')
    
    user = get_user_by_id(session['user_id'])
    
    # Ouvrir backup en read-only
    import sqlite3 as _sql
    try:
        conn_bak = _sql.connect(f"file:{backup_path}?mode=ro", uri=True)
        conn_bak.row_factory = _sql.Row
        snapshot, stats = _snapshot_caisse(conn_bak, cid)
        conn_bak.close()
    except Exception as e:
        flash(f"Erreur extraction backup : {e}", "error")
        return redirect(f'/admin/backup/{backup_name}/inspect-caisses')
    
    if not snapshot.get('caisse'):
        flash(f"Caisse {cid} non trouvée dans ce backup", "error")
        return redirect(f'/admin/backup/{backup_name}/inspect-caisses')
    
    # Sauvegarder en corbeille
    conn = _gdb()
    try:
        trash_id = _save_trash_snapshot(conn, 'caisse', cid, snapshot['caisse'].get('name', f'caisse-{cid}'),
            snapshot, stats, session['user_id'], user['full_name'],
            notes=f'Extrait du backup {backup_name}')
        conn.commit()
        conn.close()
        flash(f"✅ Caisse « {snapshot['caisse'].get('name')} » et ses {sum(stats.values())} éléments ajoutés à la corbeille — vous pouvez maintenant la restaurer sélectivement", "success")
        return redirect(f'/admin/corbeille/{trash_id}')
    except Exception as e:
        try: conn.close()
        except: pass
        flash(f"Erreur sauvegarde corbeille : {e}", "error")
        return redirect(f'/admin/backup/{backup_name}/inspect-caisses')


# v117 : Module Suivi des dépenses
# Recherche/filtres + CRUD + auto-sync depuis sorties caisse
@app.route('/depenses')
@login_required
def depenses_list():
    """v117 : Liste paginée avec filtres. Toutes les sorties caisse y sont automatiquement injectées."""
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    is_admin = user and user['role'] == 'admin'
    has_perm = user and (_hp(user['role'], 'comptabilite') or _hp(user['role'], 'tresorerie'))
    if not (is_admin or has_perm):
        flash("⚠️ Accès réservé à la comptabilité, trésorerie ou admin", "error")
        return redirect('/dashboard')
    
    # Filtres GET
    f_q = (request.args.get('q', '') or '').strip()
    f_cat = (request.args.get('category', '') or '').strip()
    f_source = (request.args.get('source_type', '') or '').strip()
    f_date_min = (request.args.get('date_min', '') or '').strip()
    f_date_max = (request.args.get('date_max', '') or '').strip()
    f_amount_min = request.args.get('amount_min', '')
    f_amount_max = request.args.get('amount_max', '')
    
    conn = _gdb()
    where = []
    params = []
    if f_q:
        where.append("(d.description LIKE ? OR d.beneficiaire LIKE ? OR d.reference LIKE ? OR d.source_reference LIKE ?)")
        like = f'%{f_q}%'
        params += [like, like, like, like]
    if f_cat:
        where.append("d.category = ?")
        params.append(f_cat)
    if f_source:
        where.append("d.source_type = ?")
        params.append(f_source)
    if f_date_min:
        where.append("d.date >= ?")
        params.append(f_date_min)
    if f_date_max:
        where.append("d.date <= ?")
        params.append(f_date_max)
    if f_amount_min:
        try:
            where.append("d.amount >= ?")
            params.append(float(f_amount_min))
        except: pass
    if f_amount_max:
        try:
            where.append("d.amount <= ?")
            params.append(float(f_amount_max))
        except: pass
    where_sql = (" WHERE " + " AND ".join(where)) if where else ""
    
    sql = f"""SELECT d.*, c.name as caisse_nom, b.nom as bank_nom
        FROM depenses d
        LEFT JOIN caisses c ON c.id = d.caisse_id
        LEFT JOIN tresorerie_comptes_bancaires b ON b.id = d.bank_id
        {where_sql}
        ORDER BY d.date DESC, d.id DESC LIMIT 500"""
    depenses = [dict(r) for r in conn.execute(sql, params).fetchall()]
    
    total = sum(d['amount'] for d in depenses)
    nb = len(depenses)
    
    cats = [r['category'] for r in conn.execute("SELECT DISTINCT category FROM depenses WHERE category IS NOT NULL AND category!='' ORDER BY category").fetchall()]
    sources = [r['source_type'] for r in conn.execute("SELECT DISTINCT source_type FROM depenses WHERE source_type IS NOT NULL AND source_type!='' ORDER BY source_type").fetchall()]
    
    conn.close()
    return render_template('depenses.html', page='depenses', depenses=depenses,
        total=total, nb=nb, cats=cats, sources=sources,
        f_q=f_q, f_cat=f_cat, f_source=f_source,
        f_date_min=f_date_min, f_date_max=f_date_max,
        f_amount_min=f_amount_min, f_amount_max=f_amount_max,
        today=datetime.now().strftime('%Y-%m-%d'))


