@app.route('/admin/pointage/penalites', methods=['GET', 'POST'])
@permission_required('pointage_edit')
def admin_pointage_penalites():
    """Configurer la pénalité par minute de retard (config globale RAMYA)."""
    conn = _gdb()
    if request.method == 'POST':
        try:
            ppm = float(request.form.get('penalty_per_minute', '0') or 0)
            grace = int(request.form.get('grace_minutes', '0') or 0)
            currency = request.form.get('currency', 'XOF')
            existing = conn.execute(
                "SELECT id FROM hr_penalty_config WHERE company_id IS NULL").fetchone()
            if existing:
                conn.execute("""UPDATE hr_penalty_config SET
                    penalty_per_minute=?, grace_minutes=?, currency=?, is_active=1, updated_at=?
                    WHERE id=?""", (ppm, grace, currency, datetime.now().isoformat(), existing['id']))
            else:
                conn.execute("""INSERT INTO hr_penalty_config
                    (company_id, penalty_per_minute, grace_minutes, currency, is_active)
                    VALUES (NULL, ?, ?, ?, 1)""", (ppm, grace, currency))
            conn.commit()
            flash(f"✅ Pénalité réglée : {ppm} F/min après {grace} min de tolérance", "success")
        except Exception as e:
            flash(f"❌ Erreur : {e}", "error")
    
    cfg = {'penalty_per_minute': 0, 'grace_minutes': 0, 'currency': 'XOF'}
    try:
        row = conn.execute(
            "SELECT * FROM hr_penalty_config WHERE company_id IS NULL ORDER BY id DESC LIMIT 1").fetchone()
        if row: cfg = dict(row)
    except: pass
    
    # Stats des pénalités du mois courant
    month_str = datetime.now().strftime('%Y-%m')
    stats = {'total_penalty': 0, 'total_late': 0, 'top_offenders': []}
    try:
        s = conn.execute("""SELECT
            COALESCE(SUM(penalty_amount),0) as total_penalty,
            COUNT(*) as total_late
            FROM hr_pointages WHERE date LIKE ? AND status='retard' AND type='arrivee'""",
            (f'{month_str}%',)).fetchone()
        stats.update({k:v for k,v in dict(s).items()})
        stats['top_offenders'] = [dict(r) for r in conn.execute("""
            SELECT u.full_name, u.department,
                COUNT(*) as nb_retards,
                SUM(p.ecart_minutes) as total_minutes,
                SUM(p.penalty_amount) as total_penalty
            FROM hr_pointages p LEFT JOIN users u ON p.user_id=u.id
            WHERE p.date LIKE ? AND p.status='retard' AND p.type='arrivee'
            GROUP BY p.user_id ORDER BY total_penalty DESC LIMIT 10""",
            (f'{month_str}%',)).fetchall()]
    except: pass
    conn.close()
    return render_template('extra_pages.html', page='pointage_penalites',
                          cfg=cfg, stats=stats, month_str=month_str)


# ============================================================
# RAPPORT MENSUEL PDF PAR EMPLOYÉ
# ============================================================

@app.route('/admin/pointage/rapport/<int:user_id>/<month>')
@login_required
def admin_pointage_rapport_pdf(user_id, month):
    """Génère un PDF mensuel pour un employé en utilisant rapport_core (même charte que rapports d'heures)."""
    user = get_user_by_id(session['user_id'])
    perms = get_role_permissions(user['role']) if user else []
    if not ('pointage_admin' in perms or 'admin' in perms or 'pointage_edit' in perms):
        if user_id != session.get('user_id'):
            flash("Accès refusé", "error")
            return redirect(url_for('dashboard'))
    
    target = get_user_by_id(user_id)
    if not target:
        flash("Utilisateur introuvable", "error")
        return redirect(url_for('admin_pointage_dashboard'))
    
    # Construire la liste des records au format attendu par rapport_core
    from models import get_user_planning
    planning = get_user_planning(user_id)
    sched_start = planning.get('heure_arrivee', '08:00')
    sched_end = planning.get('heure_depart', '17:00')
    
    conn = _gdb()
    pointages = [dict(r) for r in conn.execute(
        "SELECT * FROM hr_pointages WHERE user_id=? AND date LIKE ? ORDER BY date, time",
        (user_id, f'{month}%')).fetchall()]
    conn.close()
    
    # Regrouper par jour
    by_day = {}
    for p in pointages:
        d = p['date']
        if d not in by_day:
            by_day[d] = {'arrivee':None,'pause':None,'retour':None,'depart':None,'penalty':0}
        by_day[d][p['type']] = p
        by_day[d]['penalty'] += float(p.get('penalty_amount') or 0)
    
    # Construire records pour rapport_core
    records = []
    total_penalty = 0
    for d in sorted(by_day.keys()):
        dd = by_day[d]
        arrival = dd['arrivee']['time'] if dd['arrivee'] else ''
        departure = dd['depart']['time'] if dd['depart'] else ''
        # Durée travaillée
        dur = ''
        try:
            if dd['arrivee'] and dd['depart']:
                from datetime import datetime as _dt
                af = _dt.fromisoformat(dd['arrivee']['datetime_full'])
                df = _dt.fromisoformat(dd['depart']['datetime_full'])
                total_min = int((df - af).total_seconds() / 60)
                pause_min = 0
                if dd['pause'] and dd['retour']:
                    pf = _dt.fromisoformat(dd['pause']['datetime_full'])
                    rf = _dt.fromisoformat(dd['retour']['datetime_full'])
                    pause_min = int((rf - pf).total_seconds() / 60)
                worked = total_min - pause_min
                dur = f"{worked//60:02d}:{worked%60:02d}"
        except: pass
        records.append({
            'date': d, 'sched_start': sched_start, 'sched_end': sched_end,
            'arrival': arrival, 'departure': departure, 'duration': dur,
        })
        total_penalty += dd['penalty']
    
    # Compléter avec les jours sans pointage du mois (pour stats absences)
    try:
        from datetime import date as _date, timedelta as _td
        y, m_int = month.split('-')
        y, m_int = int(y), int(m_int)
        first = _date(y, m_int, 1)
        if m_int == 12: last = _date(y+1, 1, 1) - _td(days=1)
        else: last = _date(y, m_int+1, 1) - _td(days=1)
        existing_dates = set(r['date'] for r in records)
        cur = first
        while cur <= last:
            ds = cur.strftime('%Y-%m-%d')
            if ds not in existing_dates and cur.weekday() < 5:  # exclure week-end
                records.append({
                    'date': ds, 'sched_start': sched_start, 'sched_end': sched_end,
                    'arrival': '', 'departure': '', 'duration': '',
                })
            cur += _td(days=1)
        records.sort(key=lambda r: r['date'])
    except Exception as e:
        print(f"date fill: {e}")
    
    # Préparer pour rapport_core
    emp = {'name': target['full_name'], 'ref': target['username'], 'records': records}
    
    try:
        import rapport_core
        from reportlab.platypus import SimpleDocTemplate, Spacer, Paragraph
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.units import mm
        import io
        
        # Stats employé via la même fonction que les rapports d'heures
        # NOUVEAU v49 : period_total_days = nb de jours du mois (28-31 selon le mois)
        from calendar import monthrange
        try:
            year_m, mon_m = month.split('-')
            period_total_days = monthrange(int(year_m), int(mon_m))[1]
        except:
            period_total_days = len(records) if records else 30
        enriched, stats = rapport_core.calc_employee_stats(emp, hp=8, hp_weekend=0,
                                                          hourly_cost=0, rest_days=[5, 6],
                                                          period_total_days=period_total_days)
        # Ajouter le coût de pénalité dans les stats (extension custom)
        stats['total_penalty_cost'] = total_penalty
        
        all_stats = [(enriched, stats)]
        emps = [emp]
        
        S = rapport_core.make_styles()
        
        period = f"Période : {month}"
        provider_name = "RAMYA TECHNOLOGIE & INNOVATION"
        provider_info = "Abidjan, Côte d'Ivoire"
        client_name = "Rapport interne"
        client_info = ""
        
        from datetime import datetime as _dt
        now = _dt.now()
        
        buf = io.BytesIO()
        # v56 : retour en portrait
        doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=8*mm, rightMargin=8*mm,
                                topMargin=8*mm, bottomMargin=8*mm)
        story = []
        
        # Page individuelle (même format que rapport heures)
        rapport_core.gen_individual_pages(story, emps, all_stats, S,
                                          provider_name, provider_info,
                                          client_name, client_info, period, now)
        
        # Page graphique avec donut + logo RAMYA centré
        try:
            logo_path = os.path.join(BASE_DIR, 'logo_ramya.png') if os.path.exists(os.path.join(BASE_DIR, 'logo_ramya.png')) else None
            rapport_core.gen_graphique(story, emps, all_stats, S,
                                       provider_name, provider_info,
                                       client_name, client_info, now, logo_path=logo_path)
        except Exception as e:
            print(f"graphique: {e}")
        
        doc.build(story)
        buf.seek(0)
        filename = f"presence-{target['username']}-{month}.pdf"
        return Response(buf.getvalue(), mimetype='application/pdf',
                       headers={'Content-Disposition': f'attachment; filename={filename}'})
    except Exception as e:
        import traceback; traceback.print_exc()
        flash(f"Erreur génération PDF : {e}", "error")
        return redirect(url_for('admin_pointage_dashboard'))


@app.route('/admin/pointage/rapport-entreprise/<month>')
@permission_required_any('pointage_admin', 'admin')
def admin_pointage_rapport_entreprise(month):
    """PDF complet : tous les employés sur le mois.
    Param ?company_id= pour rapport d'une entreprise pointage spécifique (sinon = RAMYA)."""
    
    company_id = request.args.get('company_id', '').strip()
    company_name = "RAMYA TECHNOLOGIE & INNOVATION"
    company_subtitle = "Abidjan, Côte d'Ivoire"
    
    # NOUVEAU v45 : nombre de jours obligatoires saisi pour cette période (s'applique à TOUS)
    period_days_required_raw = (request.args.get('days_required', '') or '').strip()
    period_days_required = None
    if period_days_required_raw and period_days_required_raw.isdigit():
        v = int(period_days_required_raw)
        if 0 < v <= 31:
            period_days_required = v
    
    print(f"[rapport_entreprise] month={month}, company_id_param='{company_id}', days_required={period_days_required}")
    
    conn = _gdb()
    
    if company_id and company_id.isdigit():
        # Rapport pour une entreprise pointage spécifique
        cid = int(company_id)
        comp = conn.execute("SELECT * FROM pointage_companies WHERE id=?", (cid,)).fetchone()
        if not comp:
            flash("Entreprise introuvable", "error")
            conn.close()
            return redirect(url_for('admin_pointage_dashboard'))
        company_name = comp['name']
        company_subtitle = f"Espace pointage — slug: {comp['slug']}"
        
        # Récupérer les employés de cette entreprise
        users = [dict(r) for r in conn.execute("""
            SELECT id, username, full_name, poste as department, '' as role,
                   heure_arrivee, heure_pause, heure_retour, heure_depart
            FROM pointage_company_users WHERE company_id=? AND COALESCE(is_active,1)=1
            ORDER BY full_name
        """, (cid,)).fetchall()]
        
        if not users:
            flash(f"Aucun employé actif dans l'entreprise '{company_name}'", "warning")
            conn.close()
            return redirect(url_for('admin_pointage_dashboard'))
        
        # Construire emps (continu) ET emps_sessions (session)
        # NOUVEAU v56 : rapport SESSION dédié pour mode session
        from datetime import datetime as _dt, date as _date, timedelta as _td
        from models import get_user_pointage_mode
        emps = []  # mode continu : 1 record par jour
        emps_sessions = []  # mode session : liste détaillée des sessions
        for u in users:
            sched_start = u.get('heure_arrivee', '08:00')
            sched_end = u.get('heure_depart', '17:00')
            
            # Détecter le mode de l'employé (individuel ou hérité de l'entreprise)
            user_mode, _src = get_user_pointage_mode(u['id'])
            
            records = []
            
            if user_mode == 'continu':
                # === Mode CONTINU : lire pointage_company_records ===
                pointages = [dict(r) for r in conn.execute(
                    "SELECT * FROM pointage_company_records WHERE company_user_id=? AND date LIKE ? ORDER BY date, time",
                    (u['id'], f'{month}%')).fetchall()]
                
                by_day = {}
                for p in pointages:
                    d = p['date']
                    if d not in by_day:
                        by_day[d] = {'arrivee':None,'pause':None,'retour':None,'depart':None}
                    by_day[d][p['type']] = p
                
                for d in sorted(by_day.keys()):
                    dd = by_day[d]
                    arrival = dd['arrivee']['time'] if dd['arrivee'] else ''
                    departure = dd['depart']['time'] if dd['depart'] else ''
                    # v67 NOUVEAU : capturer pause début et pause fin
                    pause_start = dd['pause']['time'] if dd['pause'] else ''
                    pause_end = dd['retour']['time'] if dd['retour'] else ''
                    dur = ''
                    try:
                        if dd['arrivee'] and dd['depart']:
                            af = _dt.fromisoformat(dd['arrivee']['datetime_full'])
                            df = _dt.fromisoformat(dd['depart']['datetime_full'])
                            total_min = int((df - af).total_seconds() / 60)
                            pause_min = 0
                            if dd['pause'] and dd['retour']:
                                pf = _dt.fromisoformat(dd['pause']['datetime_full'])
                                rf = _dt.fromisoformat(dd['retour']['datetime_full'])
                                pause_min = int((rf - pf).total_seconds() / 60)
                            worked = total_min - pause_min
                            dur = f"{worked//60:02d}:{worked%60:02d}"
                    except: pass
                    records.append({
                        'date': d, 'sched_start': sched_start, 'sched_end': sched_end,
                        'arrival': arrival, 'departure': departure, 'duration': dur,
                        'pause_start': pause_start, 'pause_end': pause_end,  # v67
                    })
            else:
                # === Mode SESSION : collecter les sessions individuelles pour rapport dédié ===
                sessions_raw = [dict(r) for r in conn.execute("""
                    SELECT pps.id as planning_id, pps.date, pps.heure_prevue, pps.duree_minutes,
                           pps.libelle, pps.statut as planning_statut,
                           ps.heure_debut, ps.heure_fin, ps.duree_reelle_minutes,
                           ps.statut as session_statut
                    FROM pointage_planning_sessions pps
                    LEFT JOIN pointage_sessions ps ON ps.planning_id = pps.id
                    WHERE pps.company_user_id=? AND pps.date LIKE ?
                    ORDER BY pps.date, pps.heure_prevue
                """, (u['id'], f'{month}%')).fetchall()]
                
                # Construire la liste détaillée + statistiques
                sessions_list = []
                ok_count = 0
                retard_count = 0
                non_eff_count = 0
                total_dur_prev = 0
                total_dur_reel = 0
                
                for s in sessions_raw:
                    duree_prev = s['duree_minutes'] or 0
                    duree_reel = s['duree_reelle_minutes'] or 0
                    total_dur_prev += duree_prev
                    total_dur_reel += duree_reel
                    
                    # Détection du statut
                    if not s['heure_debut']:
                        statut = 'non_effectuee'
                        non_eff_count += 1
                    else:
                        # Calcul retard sur démarrage
                        try:
                            h1, m1 = map(int, s['heure_prevue'].split(':'))
                            h2, m2 = map(int, s['heure_debut'].split(':'))
                            ecart = (h2-h1)*60 + (m2-m1)
                            if ecart > 5:  # Plus de 5 min de retard
                                statut = 'retard'
                                retard_count += 1
                            else:
                                statut = 'ok'
                                ok_count += 1
                        except:
                            statut = 'ok'
                            ok_count += 1
                    
                    sessions_list.append({
                        'date': s['date'],
                        'libelle': s['libelle'] or '-',
                        'heure_prevue': s['heure_prevue'],
                        'duree_minutes': duree_prev,
                        'heure_debut': s['heure_debut'],
                        'heure_fin': s['heure_fin'],
                        'duree_reelle': duree_reel,
                        'statut': statut,
                    })
                
                emps_sessions.append({
                    'name': u['full_name'],
                    'ref': u['username'],
                    'sessions': sessions_list,
                    'total_sessions': len(sessions_list),
                    'sessions_ok': ok_count,
                    'sessions_retard': retard_count,
                    'sessions_non_effectuee': non_eff_count,
                    'total_duree_prevue': total_dur_prev,
                    'total_duree_reelle': total_dur_reel,
                })
                # Skip the legacy by_day records build below for sessions
                continue
            
            # Compléter avec jours sans pointage
            try:
                y, m_int = month.split('-')
                y, m_int = int(y), int(m_int)
                first = _date(y, m_int, 1)
                if m_int == 12: last = _date(y+1, 1, 1) - _td(days=1)
                else: last = _date(y, m_int+1, 1) - _td(days=1)
                existing = set(r['date'] for r in records)
                cur = first
                while cur <= last:
                    ds = cur.strftime('%Y-%m-%d')
                    if ds not in existing and cur.weekday() < 5:
                        records.append({'date': ds, 'sched_start': sched_start, 'sched_end': sched_end,
                                       'arrival': '', 'departure': '', 'duration': '',
                                       'pause_start': '', 'pause_end': ''})
                    cur += _td(days=1)
                records.sort(key=lambda r: r['date'])
            except: pass
            
            emps.append({
                'name': u['full_name'],
                'ref': u['username'],
                'records': records,
            })
    else:
        # Rapport RAMYA (défaut, comportement v31)
        users = [dict(r) for r in conn.execute("""
            SELECT id, username, full_name, role, department FROM users
            WHERE COALESCE(is_active,1)=1 AND role != 'client'
            ORDER BY full_name
        """).fetchall()]
        
        if not users:
            flash("Aucun employé actif", "warning")
            conn.close()
            return redirect(url_for('admin_pointage_dashboard'))
        
        # NOUVEAU v56 : initialiser emps_sessions vide pour le mode RAMYA (pas de session)
        emps_sessions = []
        from models import get_user_planning
        
        emps = []
        for u in users:
            planning = get_user_planning(u['id'])
            sched_start = planning.get('heure_arrivee', '08:00')
            sched_end = planning.get('heure_depart', '17:00')
            
            pointages = [dict(r) for r in conn.execute(
                "SELECT * FROM hr_pointages WHERE user_id=? AND date LIKE ? ORDER BY date, time",
                (u['id'], f'{month}%')).fetchall()]
            
            # Regrouper par jour
            by_day = {}
            for p in pointages:
                d = p['date']
                if d not in by_day:
                    by_day[d] = {'arrivee':None,'pause':None,'retour':None,'depart':None}
                by_day[d][p['type']] = p
            
            # Records pour rapport_core
            records = []
            for d in sorted(by_day.keys()):
                dd = by_day[d]
                arrival = dd['arrivee']['time'] if dd['arrivee'] else ''
                departure = dd['depart']['time'] if dd['depart'] else ''
                # v67 : capturer pause début et fin pour le PDF
                pause_start = dd['pause']['time'] if dd['pause'] else ''
                pause_end = dd['retour']['time'] if dd['retour'] else ''
                dur = ''
                try:
                    if dd['arrivee'] and dd['depart']:
                        af = datetime.fromisoformat(dd['arrivee']['datetime_full'])
                        df = datetime.fromisoformat(dd['depart']['datetime_full'])
                        total_min = int((df - af).total_seconds() / 60)
                        pause_min = 0
                        if dd['pause'] and dd['retour']:
                            pf = datetime.fromisoformat(dd['pause']['datetime_full'])
                            rf = datetime.fromisoformat(dd['retour']['datetime_full'])
                            pause_min = int((rf - pf).total_seconds() / 60)
                        worked = total_min - pause_min
                        dur = f"{worked//60:02d}:{worked%60:02d}"
                except: pass
                records.append({
                    'date': d, 'sched_start': sched_start, 'sched_end': sched_end,
                    'arrival': arrival, 'departure': departure, 'duration': dur,
                    'pause_start': pause_start, 'pause_end': pause_end,
                })
            
            # Compléter avec jours sans pointage
            try:
                from datetime import date as _date, timedelta as _td
                y, m_int = month.split('-')
                y, m_int = int(y), int(m_int)
                first = _date(y, m_int, 1)
                if m_int == 12: last = _date(y+1, 1, 1) - _td(days=1)
                else: last = _date(y, m_int+1, 1) - _td(days=1)
                existing_dates = set(r['date'] for r in records)
                cur = first
                while cur <= last:
                    ds = cur.strftime('%Y-%m-%d')
                    if ds not in existing_dates and cur.weekday() < 5:
                        records.append({
                            'date': ds, 'sched_start': sched_start, 'sched_end': sched_end,
                            'arrival': '', 'departure': '', 'duration': '',
                            'pause_start': '', 'pause_end': '',
                        })
                    cur += _td(days=1)
                records.sort(key=lambda r: r['date'])
            except: pass
            
            emps.append({
                'name': u['full_name'],
                'ref': u['username'],
                'records': records,
            })
    
    conn.close()
    
    try:
        import rapport_core
        from reportlab.platypus import SimpleDocTemplate, PageBreak
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.units import mm
        import io
        
        # Récupérer les jours obligatoires (override entreprise / par employé / défaut RAMYA)
        from models import get_days_required
        conn2 = _gdb()
        company_default = None  # défaut entreprise pointage
        ramya_default = None    # défaut système RAMYA
        employee_overrides = {}  # name -> int
        if company_id and company_id.isdigit():
            cid_int = int(company_id)
            row = conn2.execute("SELECT days_required_default FROM pointage_companies WHERE id=?", (cid_int,)).fetchone()
            if row and row[0] is not None and row[0] > 0:
                company_default = int(row[0])
            # Overrides par employé
            for u in conn2.execute("SELECT id, full_name, days_required_override FROM pointage_company_users WHERE company_id=?", (cid_int,)).fetchall():
                if u['days_required_override'] is not None and u['days_required_override'] > 0:
                    employee_overrides[u['full_name']] = int(u['days_required_override'])
        else:
            # Mode RAMYA : récupérer overrides depuis users + défaut système RAMYA
            for u in conn2.execute("SELECT id, full_name, days_required_override FROM users WHERE COALESCE(is_active,1)=1").fetchall():
                if u['days_required_override'] is not None and u['days_required_override'] > 0:
                    employee_overrides[u['full_name']] = int(u['days_required_override'])
            # Défaut système RAMYA
            try:
                rr = conn2.execute("SELECT value FROM app_settings WHERE key='ramya_days_required_default'").fetchone()
                if rr and rr[0] and str(rr[0]).strip().isdigit():
                    v = int(rr[0])
                    if v > 0:
                        ramya_default = v
            except: pass
        conn2.close()
        
        # NOUVEAU v49 : nombre total de jours du mois — IDENTIQUE pour tous les employés
        from calendar import monthrange
        try:
            year_m, mon_m = month.split('-')
            period_total_days = monthrange(int(year_m), int(mon_m))[1]
        except:
            period_total_days = 30
        
        # Calculer stats pour tous les employés (avec override jours obligatoires)
        all_stats = []
        for emp in emps:
            # Priorité MAXIMUM v45 : si saisi pour la période → s'applique à tous
            if period_days_required is not None:
                override = period_days_required
            else:
                # Sinon : override individuel > défaut entreprise/RAMYA > calcul auto (None)
                override = employee_overrides.get(emp['name'])
                if override is None and company_default:
                    override = company_default
                if override is None and ramya_default:
                    override = ramya_default
            enriched, stats = rapport_core.calc_employee_stats(emp, hp=8, hp_weekend=0,
                                                              hourly_cost=0, rest_days=[5, 6],
                                                              days_required_override=override,
                                                              period_total_days=period_total_days)
            all_stats.append((enriched, stats))
        
        S = rapport_core.make_styles()
        
        period = f"Période : {month}"
        # Utiliser le nom de l'entreprise dynamiquement (multi-entreprises ou RAMYA)
        provider_name = company_name
        provider_info = company_subtitle
        if company_id:
            client_name = f"Rapport personnel — {company_name}"
        else:
            client_name = "Rapport interne — Personnel RAMYA"
        client_info = ""
        
        now = datetime.now()
        
        buf = io.BytesIO()
        # v56 : retour en portrait
        doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=8*mm, rightMargin=8*mm,
                                topMargin=8*mm, bottomMargin=8*mm)
        story = []
        
        # Section 1 : Rapports individuels (un par employé en mode CONTINU)
        if emps:
            rapport_core.gen_individual_pages(story, emps, all_stats, S,
                                              provider_name, provider_info,
                                              client_name, client_info, period, now)
            story.append(PageBreak())
        
        # NOUVEAU v56 — Section 1bis : Rapports de SESSIONS (un par employé en mode SESSION)
        if emps_sessions:
            rapport_core.gen_session_pages(story, emps_sessions, S,
                                           provider_name, provider_info,
                                           client_name, client_info, period, now)
            story.append(PageBreak())
        
        # Section 2 : Rapport de présence global
        try:
            rapport_core.gen_rapport_presence(story, emps, all_stats, S,
                                              provider_name, provider_info,
                                              client_name, client_info, now)
            story.append(PageBreak())
        except Exception as e:
            print(f"gen_rapport_presence: {e}")
        
        # Section 3 : Classement par degré de retard / absence
        try:
            rapport_core.gen_classement(story, emps, all_stats, S,
                                        provider_name, provider_info,
                                        client_name, client_info, now)
            story.append(PageBreak())
        except Exception as e:
            print(f"gen_classement: {e}")
        
        # Section 4 : Graphique avec donut + logo RAMYA centré
        try:
            logo_path = os.path.join(BASE_DIR, 'logo_ramya.png')
            if not os.path.exists(logo_path): logo_path = None
            rapport_core.gen_graphique(story, emps, all_stats, S,
                                       provider_name, provider_info,
                                       client_name, client_info, now, logo_path=logo_path)
        except Exception as e:
            print(f"gen_graphique: {e}")
        
        doc.build(story)
        buf.seek(0)
        # Slugify name pour filename
        import re as _re
        slug = _re.sub(r'[^a-zA-Z0-9-]', '-', company_name).strip('-').lower()[:30]
        filename = f"rapport-{slug}-{month}.pdf"
        return Response(buf.getvalue(), mimetype='application/pdf',
                       headers={'Content-Disposition': f'attachment; filename={filename}'})
    except Exception as e:
        import traceback; traceback.print_exc()
        flash(f"Erreur génération PDF complet : {e}", "error")
        return redirect(url_for('admin_pointage_dashboard'))


# ============================================================
# DÉTECTION ABSENCES + GRAPHIQUES
# ============================================================

@app.route('/admin/pointage/absences')
@permission_required_any('pointage_admin', 'pointage_dept', 'admin')
def admin_pointage_absences():
    """Liste des absences détectées du jour + déclenchement notifications."""
    from models import detect_absences_today
    absent = detect_absences_today()
    # Notifier les RH/admin
    if absent:
        try:
            conn = _gdb()
            for r in conn.execute(
                "SELECT id, full_name FROM users WHERE role IN ('admin','dg','rh') AND COALESCE(is_active,1)=1").fetchall():
                msg = f"{len(absent)} employé(s) absent(s) ce matin : " + ", ".join([a['full_name'] for a in absent[:5]])
                if len(absent) > 5: msg += f" (+{len(absent)-5})"
                # Éviter doublon notification
                today = datetime.now().strftime('%Y-%m-%d')
                already = conn.execute(
                    "SELECT id FROM notifications WHERE user_id=? AND type='absence_alert' AND title LIKE ? AND created_at LIKE ?",
                    (r['id'], '%Absences%', f'{today}%')).fetchone()
                if not already:
                    conn.execute("""INSERT INTO notifications (user_id, type, title, message, link)
                        VALUES (?, ?, ?, ?, ?)""",
                        (r['id'], 'absence_alert',
                         f"⚠️ Absences du {today}", msg, "/admin/pointage/absences"))
            conn.commit(); conn.close()
        except: pass
    return render_template('extra_pages.html', page='pointage_absences',
                          absent=absent, today=datetime.now().strftime('%Y-%m-%d'))


@app.route('/admin/pointage/graphiques')
@permission_required_any('pointage_admin', 'pointage_dept', 'admin')
def admin_pointage_graphiques():
    """Page graphiques mensuels (présence/retard/heures)."""
    month = request.args.get('month', datetime.now().strftime('%Y-%m'))
    user_filter = request.args.get('user_id', '')
    
    conn = _gdb()
    where = ["date LIKE ?"]
    params = [f'{month}%']
    if user_filter and user_filter.isdigit():
        where.append("user_id = ?")
        params.append(int(user_filter))
    where_sql = " AND ".join(where)
    
    # Stats par jour
    daily = []
    try:
        for r in conn.execute(f"""SELECT date,
            SUM(CASE WHEN type='arrivee' AND status='normal' THEN 1 ELSE 0 END) as ok,
            SUM(CASE WHEN type='arrivee' AND status='retard' THEN 1 ELSE 0 END) as late,
            SUM(CASE WHEN type='arrivee' AND status='avance' THEN 1 ELSE 0 END) as early
            FROM hr_pointages WHERE {where_sql} GROUP BY date ORDER BY date""",
            tuple(params)).fetchall():
            daily.append(dict(r))
    except: pass
    
    # Stats par employé
    by_user = []
    try:
        for r in conn.execute(f"""SELECT u.id, u.full_name, u.department,
            SUM(CASE WHEN p.type='arrivee' THEN 1 ELSE 0 END) as nb_arrivees,
            SUM(CASE WHEN p.type='arrivee' AND p.status='retard' THEN 1 ELSE 0 END) as nb_retards,
            SUM(CASE WHEN p.type='arrivee' THEN p.ecart_minutes ELSE 0 END) as total_ecart,
            SUM(p.penalty_amount) as total_penalty
            FROM hr_pointages p LEFT JOIN users u ON p.user_id=u.id
            WHERE {where_sql} GROUP BY p.user_id ORDER BY nb_retards DESC""",
            tuple(params)).fetchall():
            by_user.append(dict(r))
    except: pass
    
    users = []
    try:
        users = [dict(r) for r in conn.execute(
            "SELECT id, full_name FROM users WHERE COALESCE(is_active,1)=1 AND role != 'client' ORDER BY full_name").fetchall()]
    except: pass
    conn.close()
    
    return render_template('extra_pages.html', page='pointage_graphiques',
                          daily=daily, by_user=by_user, month=month,
                          user_filter=user_filter, users=users)


# ============================================================
# MODULES RH (activation/désactivation)
# ============================================================

@app.route('/admin/hr-modules', methods=['GET', 'POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_hr_modules():
    """Activer/désactiver les modules RH."""
    conn = _gdb()
    if request.method == 'POST':
        mid = request.form.get('module_id')
        action = request.form.get('action', 'toggle')
        if mid and mid.isdigit():
            try:
                if action == 'enable':
                    conn.execute("UPDATE hr_modules SET is_active=1 WHERE id=?", (int(mid),))
                elif action == 'disable':
                    conn.execute("UPDATE hr_modules SET is_active=0 WHERE id=?", (int(mid),))
                else:
                    conn.execute("UPDATE hr_modules SET is_active=CASE WHEN is_active=1 THEN 0 ELSE 1 END WHERE id=?", (int(mid),))
                conn.commit()
                flash("✅ Module mis à jour", "success")
            except Exception as e:
                flash(f"❌ Erreur : {e}", "error")
    
    modules = []
    try:
        modules = [dict(r) for r in conn.execute(
            "SELECT * FROM hr_modules ORDER BY sort_order, id").fetchall()]
    except: pass
    conn.close()
    return render_template('extra_pages.html', page='hr_modules', modules=modules)


