@app.route('/admin/pointage/companies/<int:cid>/user/<int:uid>/delete', methods=['POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_user_delete(cid, uid):
    """Suppression définitive d'un employé d'une entreprise pointage."""
    conn = _gdb()
    try:
        u = conn.execute("SELECT full_name FROM pointage_company_users WHERE id=? AND company_id=?",
                        (uid, cid)).fetchone()
        if not u:
            flash("Employé introuvable", "error")
            conn.close(); return redirect(url_for('admin_pointage_company_detail', cid=cid))
        name = u['full_name']
        # Supprimer ses pointages d'abord
        conn.execute("DELETE FROM pointage_company_records WHERE company_user_id=?", (uid,))
        # Supprimer alertes éventuelles
        try: conn.execute("DELETE FROM hr_absence_alerts WHERE pointage_user_id=?", (uid,))
        except: pass
        # Supprimer l'employé
        conn.execute("DELETE FROM pointage_company_users WHERE id=? AND company_id=?", (uid, cid))
        conn.commit()
        flash(f"✅ Employé '{name}' supprimé définitivement (pointages et alertes inclus)", "success")
    except Exception as e:
        flash(f"❌ Erreur suppression : {e}", "error")
    conn.close()
    return redirect(url_for('admin_pointage_company_detail', cid=cid))


@app.route('/admin/pointage/companies/<int:cid>/delete', methods=['POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_delete(cid):
    """Suppression définitive d'une entreprise pointage et de tous ses employés/pointages."""
    conn = _gdb()
    try:
        c = conn.execute("SELECT name FROM pointage_companies WHERE id=?", (cid,)).fetchone()
        if not c:
            flash("Entreprise introuvable", "error")
            conn.close(); return redirect(url_for('admin_pointage_companies_list'))
        name = c['name']
        
        # Compter pour info
        nb_users = conn.execute("SELECT COUNT(*) FROM pointage_company_users WHERE company_id=?", (cid,)).fetchone()[0]
        nb_records = conn.execute("""SELECT COUNT(*) FROM pointage_company_records pcr
            WHERE pcr.company_user_id IN (SELECT id FROM pointage_company_users WHERE company_id=?)""", (cid,)).fetchone()[0]
        
        # Cascade : supprimer tous les pointages d'abord
        conn.execute("""DELETE FROM pointage_company_records WHERE company_user_id IN
            (SELECT id FROM pointage_company_users WHERE company_id=?)""", (cid,))
        # Alertes
        try: conn.execute("""DELETE FROM hr_absence_alerts WHERE pointage_user_id IN
            (SELECT id FROM pointage_company_users WHERE company_id=?)""", (cid,))
        except: pass
        # Employés
        conn.execute("DELETE FROM pointage_company_users WHERE company_id=?", (cid,))
        # Entreprise
        conn.execute("DELETE FROM pointage_companies WHERE id=?", (cid,))
        conn.commit()
        flash(f"✅ Entreprise '{name}' supprimée définitivement ({nb_users} employé(s) et {nb_records} pointage(s) effacés)", "success")
    except Exception as e:
        flash(f"❌ Erreur suppression : {e}", "error")
    conn.close()
    return redirect(url_for('admin_pointage_companies_list'))


@app.route('/admin/pointage/companies/<int:cid>/user/<int:uid>/edit', methods=['GET', 'POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_user_edit(cid, uid):
    """Modifier l'identité et les informations d'un employé multi-entreprise."""
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE id=?", (cid,)).fetchone()
    user = conn.execute("SELECT * FROM pointage_company_users WHERE id=? AND company_id=?", (uid, cid)).fetchone()
    if not company or not user:
        flash("Entreprise ou employé introuvable", "error")
        conn.close(); return redirect(url_for('admin_pointage_companies_list'))
    company = dict(company); user = dict(user)
    
    if request.method == 'POST':
        try:
            new_username = (request.form.get('username','') or '').strip().lower()
            if not new_username:
                flash("Identifiant requis", "error")
            else:
                # Vérifier doublon
                if new_username != user['username']:
                    dup = conn.execute(
                        "SELECT id FROM pointage_company_users WHERE company_id=? AND username=? AND id != ?",
                        (cid, new_username, uid)).fetchone()
                    if dup:
                        flash(f"⚠️ L'identifiant '{new_username}' est déjà utilisé dans cette entreprise.", "warning")
                        conn.close()
                        return redirect(url_for('admin_pointage_company_user_edit', cid=cid, uid=uid))
                
                dro_raw = (request.form.get('days_required_override','') or '').strip()
                dro = int(dro_raw) if dro_raw.isdigit() and int(dro_raw) > 0 else None
                
                tp_user = (request.form.get('type_pointage','') or '').strip()
                tp_user = tp_user if tp_user in ('continu','session') else None
                
                conn.execute("""UPDATE pointage_company_users SET
                    username=?, full_name=?, email=?, phone=?, poste=?,
                    heure_arrivee=?, heure_pause=?, heure_retour=?, heure_depart=?,
                    tolerance_retard_minutes=?, days_required_override=?, type_pointage=?
                    WHERE id=? AND company_id=?""",
                    (new_username,
                     (request.form.get('full_name','') or '').strip(),
                     (request.form.get('email','') or '').strip(),
                     (request.form.get('phone','') or '').strip(),
                     (request.form.get('poste','') or '').strip(),
                     request.form.get('heure_arrivee','08:00') or '08:00',
                     request.form.get('heure_pause','12:00') or '12:00',
                     request.form.get('heure_retour','13:00') or '13:00',
                     request.form.get('heure_depart','17:00') or '17:00',
                     int(request.form.get('tolerance','10') or 10),
                     dro, tp_user, uid, cid))
                conn.commit()
                flash("✅ Employé modifié", "success")
                conn.close()
                return redirect(url_for('admin_pointage_company_detail', cid=cid))
        except Exception as e:
            flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return render_template('extra_pages.html', page='pointage_company_user_edit',
                          company=company, user=user)


# ===== Interface employé multi-entreprise =====

@app.route('/pt/<slug>', methods=['GET', 'POST'])
def pointage_company_login(slug):
    """Login employé d'une entreprise externe."""
    import hashlib
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE slug=? AND COALESCE(is_active,1)=1",
                          (slug,)).fetchone()
    if not company:
        conn.close()
        return render_template('extra_pages.html', page='pt_not_found', slug=slug), 404
    company = dict(company)
    
    if request.method == 'POST':
        username = (request.form.get('username','') or '').strip().lower()
        password = request.form.get('password','') or ''
        u = conn.execute(
            "SELECT * FROM pointage_company_users WHERE company_id=? AND username=? AND COALESCE(is_active,1)=1",
            (company['id'], username)).fetchone()
        if u:
            u = dict(u)
            ph = hashlib.sha256((password + (u.get('salt') or '')).encode()).hexdigest()
            if ph == u['password_hash']:
                conn.execute("UPDATE pointage_company_users SET last_login=? WHERE id=?",
                            (datetime.now().isoformat(), u['id']))
                conn.commit(); conn.close()
                # Session séparée
                session.clear()
                session['pt_company_id'] = company['id']
                session['pt_company_slug'] = company['slug']
                session['pt_company_name'] = company['name']
                session['pt_user_id'] = u['id']
                session['pt_user_name'] = u['full_name']
                session['pt_must_change_password'] = bool(u.get('must_change_password', 0))
                session.permanent = True
                flash(f"✅ {company['welcome_message']}", "success")
                # Si force changement mot de passe → rediriger vers la page de changement
                if u.get('must_change_password'):
                    return redirect(url_for('pointage_company_password_change', slug=slug))
                # Si retour vers scan
                next_action = request.args.get('next','')
                pt_type = request.args.get('type','')
                planning_id = request.args.get('planning_id','')
                if next_action == 'scan' and pt_type:
                    return redirect(url_for('pointage_company_scan', slug=slug) + f'?type={pt_type}')
                if next_action == 'session_start' and planning_id:
                    return redirect(url_for('pointage_company_session_start', slug=slug, planning_id=int(planning_id)))
                if next_action == 'session_next':
                    return redirect(url_for('pointage_company_session_next', slug=slug))
                if next_action == 'session_current':
                    return redirect(url_for('pointage_company_session_current', slug=slug))
                return redirect(url_for('pointage_company_dashboard', slug=slug))
        conn.close()
        flash("❌ Identifiants incorrects", "error")
        return render_template('extra_pages.html', page='pt_login', company=company)
    
    conn.close()
    return render_template('extra_pages.html', page='pt_login', company=company)


@app.route('/pt/<slug>/dashboard', methods=['GET', 'POST'])
def pointage_company_dashboard(slug):
    """Dashboard employé multi-entreprise."""
    if session.get('pt_company_slug') != slug:
        return redirect(url_for('pointage_company_login', slug=slug))
    
    conn = _gdb()
    company = dict(conn.execute("SELECT * FROM pointage_companies WHERE id=?",
                               (session['pt_company_id'],)).fetchone())
    user = dict(conn.execute("SELECT * FROM pointage_company_users WHERE id=?",
                            (session['pt_user_id'],)).fetchone())
    
    today = datetime.now().strftime('%Y-%m-%d')
    pointages = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_company_records WHERE company_user_id=? AND date=? ORDER BY datetime_full",
        (user['id'], today)).fetchall()]
    
    if request.method == 'POST':
        from models import compute_penalty
        action = (request.form.get('type','') or '').strip().lower()
        if action not in ('arrivee','pause','retour','depart'):
            flash("Type invalide", "error")
        else:
            types_done = [p['type'] for p in pointages]
            labels = {'arrivee':"l'arrivée", 'pause':"le début de pause",
                      'retour':"le retour de pause", 'depart':"le départ"}
            error_msg = None
            if action in types_done:
                error_msg = f"❌ Vous avez déjà pointé {labels[action]} aujourd'hui."
            elif action != 'arrivee' and 'arrivee' not in types_done:
                error_msg = f"⛔ Vous devez d'abord pointer votre ARRIVÉE avant de pointer {labels[action]}."
            elif action == 'retour' and 'pause' not in types_done:
                error_msg = "⛔ Vous devez d'abord pointer le DÉBUT DE PAUSE avant le retour de pause."
            elif action == 'depart' and 'pause' in types_done and 'retour' not in types_done:
                error_msg = "⛔ Vous êtes en pause. Pointez d'abord le RETOUR DE PAUSE avant votre départ."
            
            if error_msg:
                flash(error_msg, "warning")
            else:
                    now = datetime.now()
                    time_str = now.strftime('%H:%M')
                    # Calcul statut
                    expected_field = {'arrivee':'heure_arrivee','pause':'heure_pause',
                                      'retour':'heure_retour','depart':'heure_depart'}[action]
                    expected = user.get(expected_field, '08:00')
                    tol = int(user.get('tolerance_retard_minutes', 10) or 10)
                    try:
                        eh, em = expected.split(':')[:2]
                        ah, am = time_str.split(':')[:2]
                        ecart = (int(ah)*60+int(am)) - (int(eh)*60+int(em))
                    except: ecart = 0
                    if action in ('arrivee','retour'):
                        status = 'retard' if ecart > tol else ('avance' if ecart < -tol else 'normal')
                    else:
                        status = 'avance' if ecart < -tol else ('retard' if ecart > tol else 'normal')
                    # Pénalité
                    pen = 0
                    if status == 'retard' and action == 'arrivee':
                        pen = compute_penalty(ecart, company['penalty_per_minute'] or 0,
                                            company['grace_minutes'] or 0)
                    lat = request.form.get('latitude')
                    lng = request.form.get('longitude')
                    try: lat = float(lat) if lat else None
                    except: lat = None
                    try: lng = float(lng) if lng else None
                    except: lng = None
                    conn.execute("""INSERT INTO pointage_company_records
                        (company_id, company_user_id, type, date, time, datetime_full,
                         latitude, longitude, status, ecart_minutes, penalty_amount, ip, user_agent, method)
                        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                        (company['id'], user['id'], action, today, time_str, now.isoformat(),
                         lat, lng, status, ecart, pen, request.remote_addr,
                         (request.headers.get('User-Agent','') or '')[:200], 'button'))
                    conn.commit()
                    if status == 'retard':
                        flash(f"⚠️ {action} enregistré à {time_str} — Retard {ecart}min" + (f" — Pénalité {pen:.0f} F CFA" if pen else ""), "warning")
                    elif status == 'avance':
                        flash(f"✅ {action} à {time_str} — Avance {abs(ecart)}min", "info")
                    else:
                        flash(f"✅ {action} enregistré à {time_str}", "success")
                    conn.close()
                    return redirect(url_for('pointage_company_dashboard', slug=slug))
        # Refresh pointages
        pointages = [dict(r) for r in conn.execute(
            "SELECT * FROM pointage_company_records WHERE company_user_id=? AND date=? ORDER BY datetime_full",
            (user['id'], today)).fetchall()]
    
    conn.close()
    types_done = [p['type'] for p in pointages]
    state = {}
    for t in ('arrivee','pause','retour','depart'):
        done = next((p for p in pointages if p['type'] == t), None)
        can = (t not in types_done)
        if can:
            # Arrivée requise pour tout sauf arrivée elle-même
            if t != 'arrivee' and 'arrivee' not in types_done: can = False
            # Retour exige pause
            if t == 'retour' and 'pause' not in types_done: can = False
            # Départ : si pause sans retour, bloqué
            if t == 'depart' and 'pause' in types_done and 'retour' not in types_done: can = False
        state[t] = {'done': done, 'can': can}
    
    # === Mode session : récupérer planning + sessions du jour ===
    # NOUVEAU v48 : utiliser le mode INDIVIDUEL de l'employé (override possible)
    from models import get_user_pointage_mode
    user_mode, _ = get_user_pointage_mode(user['id'])
    plannings_today = []
    sessions_today = []
    session_en_cours = None
    if user_mode == 'session':
        conn2 = _gdb()
        plannings_today = [dict(r) for r in conn2.execute("""
            SELECT * FROM pointage_planning_sessions
            WHERE company_user_id=? AND date=? AND COALESCE(is_active,1)=1
            ORDER BY heure_prevue""", (user['id'], today)).fetchall()]
        sessions_today = [dict(r) for r in conn2.execute("""
            SELECT * FROM pointage_sessions
            WHERE company_user_id=? AND date=?
            ORDER BY heure_debut""", (user['id'], today)).fetchall()]
        en_cours = conn2.execute(
            "SELECT * FROM pointage_sessions WHERE company_user_id=? AND date=? AND statut='en_cours' LIMIT 1",
            (user['id'], today)).fetchone()
        session_en_cours = dict(en_cours) if en_cours else None
        # Mapper plannings -> sessions exécutées
        sessions_by_planning = {s.get('planning_id'): s for s in sessions_today if s.get('planning_id')}
        for p in plannings_today:
            p['session_done'] = sessions_by_planning.get(p['id'])
        conn2.close()
    
    return render_template('extra_pages.html', page='pt_dashboard',
                          company=company, user=user, pointages=pointages,
                          state=state, today=today,
                          plannings_today=plannings_today,
                          sessions_today=sessions_today,
                          session_en_cours=session_en_cours,
                          user_mode=user_mode)


@app.route('/pt/<slug>/password', methods=['GET', 'POST'])
def pointage_company_password_change(slug):
    """Changement de mot de passe par l'employé (1ère connexion ou volontaire)."""
    if session.get('pt_company_slug') != slug or not session.get('pt_user_id'):
        return redirect(url_for('pointage_company_login', slug=slug))
    
    import hashlib, secrets as _s
    conn = _gdb()
    company = dict(conn.execute("SELECT * FROM pointage_companies WHERE id=?",
                               (session['pt_company_id'],)).fetchone())
    user = dict(conn.execute("SELECT * FROM pointage_company_users WHERE id=?",
                            (session['pt_user_id'],)).fetchone())
    
    must_change = bool(user.get('must_change_password', 0))
    
    if request.method == 'POST':
        old = request.form.get('old_password','') or ''
        new1 = request.form.get('new_password','') or ''
        new2 = request.form.get('new_password2','') or ''
        
        # Vérifier ancien mot de passe (sauf si forcé sans connaissance de l'ancien)
        if not must_change:
            old_ph = hashlib.sha256((old + (user.get('salt') or '')).encode()).hexdigest()
            if old_ph != user['password_hash']:
                flash("❌ Mot de passe actuel incorrect", "error")
                conn.close()
                return render_template('extra_pages.html', page='pt_password_change',
                                      company=company, user=user, must_change=must_change)
        
        if len(new1) < 4:
            flash("❌ Le nouveau mot de passe doit contenir au moins 4 caractères", "error")
        elif new1 != new2:
            flash("❌ Les deux mots de passe ne correspondent pas", "error")
        else:
            new_salt = _s.token_hex(8)
            new_hash = hashlib.sha256((new1 + new_salt).encode()).hexdigest()
            conn.execute("""UPDATE pointage_company_users SET password_hash=?, salt=?,
                must_change_password=0, password_changed_at=? WHERE id=?""",
                (new_hash, new_salt, datetime.now().isoformat(), user['id']))
            conn.commit()
            session.pop('pt_must_change_password', None)
            flash("✅ Mot de passe modifié avec succès", "success")
            conn.close()
            return redirect(url_for('pointage_company_dashboard', slug=slug))
    
    conn.close()
    return render_template('extra_pages.html', page='pt_password_change',
                          company=company, user=user, must_change=must_change)


@app.route('/admin/pointage/companies/<int:cid>/user/<int:uid>/reset-password', methods=['POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_user_reset_password(cid, uid):
    """Admin réinitialise le mot de passe d'un employé pointage.
    Le nouveau mot de passe est saisi par l'admin OU généré aléatoirement.
    L'employé devra le changer à sa prochaine connexion (must_change_password=1)."""
    import hashlib, secrets as _s
    
    new_pw = (request.form.get('new_password','') or '').strip()
    if not new_pw:
        # Générer un mot de passe simple aléatoire
        new_pw = _s.token_urlsafe(6)[:8]
    
    if len(new_pw) < 4:
        flash("Le mot de passe doit contenir au moins 4 caractères", "error")
        return redirect(url_for('admin_pointage_company_detail', cid=cid))
    
    conn = _gdb()
    try:
        u = conn.execute("SELECT full_name, username FROM pointage_company_users WHERE id=? AND company_id=?",
                        (uid, cid)).fetchone()
        if not u:
            flash("Employé introuvable", "error")
            conn.close(); return redirect(url_for('admin_pointage_company_detail', cid=cid))
        
        new_salt = _s.token_hex(8)
        new_hash = hashlib.sha256((new_pw + new_salt).encode()).hexdigest()
        conn.execute("""UPDATE pointage_company_users SET password_hash=?, salt=?,
            must_change_password=1 WHERE id=? AND company_id=?""",
            (new_hash, new_salt, uid, cid))
        conn.commit()
        flash(f"✅ Mot de passe réinitialisé pour {u['full_name']} (login: {u['username']}) — Nouveau mot de passe : {new_pw} — L'employé devra le changer à sa prochaine connexion.", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect(url_for('admin_pointage_company_detail', cid=cid))


@app.route('/pt/<slug>/logout')
def pointage_company_logout(slug):
    if session.get('pt_company_slug') == slug:
        session.clear()
    flash("👋 Vous êtes déconnecté(e).", "info")
    return redirect(url_for('pointage_company_login', slug=slug))


@app.route('/pt/<slug>/scan', methods=['GET', 'POST'])
def pointage_company_scan(slug):
    """Scan QR : si déjà connecté → enregistre directement le pointage.
    Si pas connecté → redirige vers login avec ?next=scan&type=...
    Le type de pointage vient de ?type=arrivee|pause|retour|depart."""
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE slug=? AND COALESCE(is_active,1)=1",
                          (slug,)).fetchone()
    if not company:
        conn.close()
        return render_template('extra_pages.html', page='pt_not_found', slug=slug), 404
    company = dict(company)
    
    pt_type = (request.args.get('type','arrivee') or 'arrivee').strip().lower()
    if pt_type not in ('arrivee','pause','retour','depart'):
        pt_type = 'arrivee'
    
    # Si pas connecté à cette entreprise → login avec retour vers scan
    if session.get('pt_company_slug') != slug or not session.get('pt_user_id'):
        conn.close()
        # Stocker le type dans la session pour redirection après login
        session['pt_pending_scan_type'] = pt_type
        session['pt_pending_scan_slug'] = slug
        flash(f"🔐 Connectez-vous pour pointer ({pt_type})", "info")
        return redirect(url_for('pointage_company_login', slug=slug) + f'?next=scan&type={pt_type}')
    
    # NOUVEAU v48 : vérifier le mode individuel de l'employé
    # Si l'employé est en mode 'session' (override individuel ou défaut entreprise),
    # il ne devrait pas pointer en continu → redirection vers session_next
    user_id = session['pt_user_id']
    from models import get_user_pointage_mode
    user_mode, mode_src = get_user_pointage_mode(user_id)
    if user_mode == 'session':
        conn.close()
        flash("ℹ️ Vous êtes en mode pointage par session. Utilisez les QR « Démarrer prochaine session » et « Terminer session en cours ».", "info")
        return redirect(url_for('pointage_company_dashboard', slug=slug))
    
    # Déjà connecté → enregistrer directement
    user_id = session['pt_user_id']
    user = dict(conn.execute("SELECT * FROM pointage_company_users WHERE id=?", (user_id,)).fetchone())
    today = datetime.now().strftime('%Y-%m-%d')
    
    pointages_today = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_company_records WHERE company_user_id=? AND date=? ORDER BY datetime_full",
        (user_id, today)).fetchall()]
    types_done = [p['type'] for p in pointages_today]
    
    labels = {'arrivee':"l'arrivée", 'pause':"le début de pause",
              'retour':"le retour de pause", 'depart':"le départ"}
    error_msg = None
    if pt_type in types_done:
        error_msg = f"❌ Vous avez déjà pointé {labels[pt_type]} aujourd'hui."
    elif pt_type != 'arrivee' and 'arrivee' not in types_done:
        error_msg = f"⛔ Vous devez d'abord pointer votre ARRIVÉE avant de pointer {labels[pt_type]}."
    elif pt_type == 'retour' and 'pause' not in types_done:
        error_msg = "⛔ Vous devez d'abord pointer le DÉBUT DE PAUSE avant le retour de pause."
    elif pt_type == 'depart' and 'pause' in types_done and 'retour' not in types_done:
        error_msg = "⛔ Vous êtes en pause. Pointez d'abord le RETOUR DE PAUSE avant votre départ."
    
    if error_msg:
        conn.close()
        flash(error_msg, "warning")
        return redirect(url_for('pointage_company_dashboard', slug=slug))
    
    # Enregistrer
    from models import compute_penalty
    now = datetime.now()
    time_str = now.strftime('%H:%M')
    expected_field = {'arrivee':'heure_arrivee','pause':'heure_pause',
                      'retour':'heure_retour','depart':'heure_depart'}[pt_type]
    expected = user.get(expected_field, '08:00')
    tol = int(user.get('tolerance_retard_minutes', 10) or 10)
    try:
        eh, em = expected.split(':')[:2]
        ah, am = time_str.split(':')[:2]
        ecart = (int(ah)*60+int(am)) - (int(eh)*60+int(em))
    except: ecart = 0
    if pt_type in ('arrivee','retour'):
        status = 'retard' if ecart > tol else ('avance' if ecart < -tol else 'normal')
    else:
        status = 'avance' if ecart < -tol else ('retard' if ecart > tol else 'normal')
    pen = 0
    if status == 'retard' and pt_type == 'arrivee':
        pen = compute_penalty(ecart, company['penalty_per_minute'] or 0,
                            company['grace_minutes'] or 0)
    
    try:
        conn.execute("""INSERT INTO pointage_company_records
            (company_id, company_user_id, type, date, time, datetime_full,
             status, ecart_minutes, penalty_amount, ip, user_agent, method)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?)""",
            (company['id'], user_id, pt_type, today, time_str, now.isoformat(),
             status, ecart, pen, request.remote_addr,
             (request.headers.get('User-Agent','') or '')[:200], 'qr'))
        conn.commit()
        if status == 'retard':
            flash(f"⚠️ {pt_type} enregistré à {time_str} — Retard {ecart}min" + (f" — Pénalité {pen:.0f} F CFA" if pen else ""), "warning")
        elif status == 'avance':
            flash(f"✅ {pt_type} à {time_str} — Avance {abs(ecart)}min", "info")
        else:
            flash(f"✅ {pt_type} enregistré à {time_str}", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect(url_for('pointage_company_dashboard', slug=slug))


@app.route('/admin/pointage/companies/<int:cid>/qr')
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_qr(cid):
    """Génère les QR codes adaptés au mode de pointage de l'entreprise.
    - Mode CONTINU : 4 QR (Arrivée/Pause/Retour/Départ) → /pt/<slug>/scan?type=...
    - Mode SESSION : 2 QR génériques (Démarrer prochaine / Terminer en cours)
                     + plannings du jour avec QR individuels.
    
    NOUVEAU v49 : Mode MIXTE détecté automatiquement. Si l'entreprise a au moins
    un employé avec un mode override différent du mode global → on génère LES DEUX
    jeux de QR (les 4 continus + les 2 session), pour que les employés des 2 modes
    puissent scanner le bon QR selon leur mode individuel.
    """
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE id=?", (cid,)).fetchone()
    if not company:
        flash("Entreprise introuvable", "error")
        conn.close(); return redirect(url_for('admin_pointage_companies_list'))
    company = dict(company)
    
    base_url = request.host_url.rstrip('/')
    type_pointage = company.get('type_pointage', 'continu') or 'continu'
    
    # === DÉTECTION MODE MIXTE ===
    # Vérifier si au moins un employé a un override différent du mode entreprise
    other_mode = 'session' if type_pointage == 'continu' else 'continu'
    has_mixed = False
    try:
        nb_overrides = conn.execute("""
            SELECT COUNT(*) FROM pointage_company_users
            WHERE company_id=? AND COALESCE(is_active,1)=1
            AND type_pointage = ?""", (cid, other_mode)).fetchone()[0]
        has_mixed = nb_overrides > 0
    except: pass
    
    # Compteurs par mode pour info admin
    nb_users_continu = 0
    nb_users_session = 0
    try:
        nb_users_continu = conn.execute("""
            SELECT COUNT(*) FROM pointage_company_users WHERE company_id=? AND COALESCE(is_active,1)=1
            AND (type_pointage='continu' OR (type_pointage IS NULL AND ?='continu'))""",
            (cid, type_pointage)).fetchone()[0]
        nb_users_session = conn.execute("""
            SELECT COUNT(*) FROM pointage_company_users WHERE company_id=? AND COALESCE(is_active,1)=1
            AND (type_pointage='session' OR (type_pointage IS NULL AND ?='session'))""",
            (cid, type_pointage)).fetchone()[0]
    except: pass
    
    def _gen_qr(url, color):
        try:
            import qrcode, io, base64
            qr = qrcode.QRCode(version=1, box_size=10, border=2)
            qr.add_data(url); qr.make(fit=True)
            img = qr.make_image(fill_color=color, back_color="white")
            buf = io.BytesIO(); img.save(buf, format='PNG')
            return "data:image/png;base64," + base64.b64encode(buf.getvalue()).decode()
        except Exception as e:
            print(f"QR err: {e}")
            return ''
    
    # === Génération des QR : LES 2 JEUX si mode mixte, sinon le mode actuel uniquement ===
    show_continu = (type_pointage == 'continu') or has_mixed
    show_session = (type_pointage == 'session') or has_mixed
    
    qrs_continu = []
    qrs_session = []
    plannings_qrs = []
    
    # QR continu (toujours si mode==continu OU si mixte)
    if show_continu:
        types_continu = [
            ('arrivee', '🟢 Arrivée', '#2e7d32',
             "Scannez à votre arrivée au bureau pour enregistrer votre heure d'arrivée."),
            ('pause', '🟡 Pause', '#f29f2f',
             "Scannez avant votre pause déjeuner pour enregistrer le début de pause."),
            ('retour', '🔵 Retour', '#1a7a6d',
             "Scannez à votre retour de pause pour reprendre le travail."),
            ('depart', '🔴 Départ', '#c53030',
             "Scannez en partant le soir pour enregistrer votre heure de départ."),
        ]
        for t, label, color, instr in types_continu:
            url = f"{base_url}/pt/{company['slug']}/scan?type={t}"
            qrs_continu.append({
                'type': t, 'label': label, 'url': url,
                'qr': _gen_qr(url, color), 'color': color, 'instr': instr,
            })
    
    # QR session (toujours si mode==session OU si mixte)
    if show_session:
        types_session = [
            ('next', '▶ Démarrer ma prochaine session', '#2e7d32',
             "Scannez à votre arrivée sur le lieu d'intervention pour démarrer la session planifiée."),
            ('current', '🛑 Terminer ma session en cours', '#c53030',
             "Scannez à la fin de votre intervention pour terminer la session en cours."),
        ]
        for t, label, color, instr in types_session:
            url = f"{base_url}/pt/{company['slug']}/session/{t}"
            qrs_session.append({
                'type': t, 'label': label, 'url': url,
                'qr': _gen_qr(url, color), 'color': color, 'instr': instr,
            })
        
        # QR individuels par session planifiée du jour (uniquement pour mode session)
        date_filter = request.args.get('date', datetime.now().strftime('%Y-%m-%d'))
        plannings = [dict(r) for r in conn.execute("""
            SELECT pps.*, pcu.full_name as user_name, pee.nom as externe_nom
            FROM pointage_planning_sessions pps
            LEFT JOIN pointage_company_users pcu ON pps.company_user_id = pcu.id
            LEFT JOIN pointage_entreprises_externes pee ON pps.entreprise_externe_id = pee.id
            WHERE pps.company_id=? AND pps.date=? AND COALESCE(pps.is_active,1)=1
              AND pps.statut IN ('prevue', 'en_cours')
            ORDER BY pps.heure_prevue""", (cid, date_filter)).fetchall()]
        
        for p in plannings:
            url = f"{base_url}/pt/{company['slug']}/session/start/{p['id']}?via=qr"
            plannings_qrs.append({
                'planning': p,
                'url': url,
                'qr': _gen_qr(url, '#7b1fa2'),
            })
    else:
        date_filter = request.args.get('date', datetime.now().strftime('%Y-%m-%d'))
    
    conn.close()
    return render_template('extra_pages.html', page='pt_company_qr',
                          company=company,
                          qrs_continu=qrs_continu, qrs_session=qrs_session,
                          plannings_qrs=plannings_qrs, date_filter=date_filter,
                          type_pointage=type_pointage, base_url=base_url,
                          has_mixed=has_mixed,
                          nb_users_continu=nb_users_continu,
                          nb_users_session=nb_users_session,
                          show_continu=show_continu, show_session=show_session)


# ============================================================
# 📅 POINTAGE PAR SESSION — Planning + Démarrer/Terminer
# ============================================================

@app.route('/admin/pointage/companies/<int:cid>/groupes', methods=['GET', 'POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_groupes(cid):
    """Gestion des groupes d'employés (mode continu)."""
    from models import groupe_creer, groupe_ajouter_membre, groupe_retirer_membre
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE id=?", (cid,)).fetchone()
    if not company:
        conn.close()
        flash("Entreprise introuvable", "error")
        return redirect(url_for('admin_pointage_companies_list'))
    company = dict(company)
    
    if request.method == 'POST':
        action = request.form.get('action', '')
        if action == 'add':
            nom = (request.form.get('nom','') or '').strip()
            desc = (request.form.get('description','') or '').strip()
            color = (request.form.get('color','#1A7A6D') or '#1A7A6D').strip()
            if not nom:
                flash("Nom du groupe requis", "error")
            else:
                gid, err = groupe_creer(cid, nom, desc, color, session.get('user_id'))
                if err: flash(f"❌ {err}", "error")
                else: flash(f"✅ Groupe '{nom}' créé", "success")
        elif action == 'delete':
            try:
                gid = int(request.form.get('groupe_id', 0))
                conn.execute("DELETE FROM pointage_groupe_membres WHERE groupe_id=?", (gid,))
                conn.execute("DELETE FROM pointage_groupes WHERE id=? AND company_id=?", (gid, cid))
                conn.commit()
                flash("✅ Groupe supprimé", "success")
            except Exception as e: flash(f"❌ {e}", "error")
        elif action == 'add_member':
            try:
                gid = int(request.form.get('groupe_id', 0))
                uid = int(request.form.get('user_id', 0))
                ok, err = groupe_ajouter_membre(gid, uid)
                if err: flash(f"❌ {err}", "error")
                else: flash("✅ Membre ajouté", "success")
            except: pass
        elif action == 'remove_member':
            try:
                gid = int(request.form.get('groupe_id', 0))
                uid = int(request.form.get('user_id', 0))
                groupe_retirer_membre(gid, uid)
                flash("✅ Membre retiré", "info")
            except: pass
        conn.close()
        return redirect(url_for('admin_pointage_company_groupes', cid=cid))
    
    # GET
    groupes = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_groupes WHERE company_id=? AND COALESCE(is_active,1)=1 ORDER BY nom",
        (cid,)).fetchall()]
    for g in groupes:
        g['membres'] = [dict(r) for r in conn.execute("""
            SELECT pcu.id, pcu.full_name, pcu.username FROM pointage_groupe_membres pgm
            JOIN pointage_company_users pcu ON pgm.company_user_id = pcu.id
            WHERE pgm.groupe_id=? ORDER BY pcu.full_name""", (g['id'],)).fetchall()]
        # Emplois du temps assignés au groupe
        g['edts'] = [dict(r) for r in conn.execute("""
            SELECT id, nom, heure_debut, heure_fin, jours_actifs
            FROM pointage_emploi_du_temps
            WHERE company_id=? AND groupe_id=? AND COALESCE(is_active,1)=1
            ORDER BY nom""", (cid, g['id'])).fetchall()]
        # Jours de repos assignés au groupe
        g['jours_repos'] = [dict(r) for r in conn.execute("""
            SELECT id, date, date_fin, libelle, type, recurrent_annuel
            FROM pointage_jours_repos
            WHERE company_id=? AND scope='groupe' AND groupe_id=? AND COALESCE(is_active,1)=1
            ORDER BY date""", (cid, g['id'])).fetchall()]
    
    users = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_company_users WHERE company_id=? AND COALESCE(is_active,1)=1 ORDER BY full_name",
        (cid,)).fetchall()]
    
    conn.close()
    return render_template('extra_pages.html', page='pt_company_groupes',
                          company=company, groupes=groupes, users=users)


@app.route('/admin/pointage/companies/<int:cid>/edt', methods=['GET', 'POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_edt(cid):
    """Gestion des emplois du temps (mode continu)."""
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE id=?", (cid,)).fetchone()
    if not company:
        conn.close()
        flash("Entreprise introuvable", "error")
        return redirect(url_for('admin_pointage_companies_list'))
    company = dict(company)
    
    if request.method == 'POST':
        action = request.form.get('action', '')
        if action == 'add':
            nom = (request.form.get('nom','') or '').strip()
            heure_debut = (request.form.get('heure_debut','08:00') or '08:00').strip()
            heure_fin = (request.form.get('heure_fin','17:00') or '17:00').strip()
            has_pause = request.form.get('has_pause') == '1'
            if has_pause:
                pause_debut = (request.form.get('pause_debut','') or '').strip() or None
                pause_fin = (request.form.get('pause_fin','') or '').strip() or None
            else:
                pause_debut = None
                pause_fin = None
            jours = (request.form.get('jours_actifs','1,2,3,4,5') or '1,2,3,4,5').strip()
            tol = int(request.form.get('tolerance_minutes', 10) or 10)
            ppm = float(request.form.get('penalty_per_minute', 0) or 0)
            cible = request.form.get('cible', 'individuel')  # 'individuel' ou 'groupe'
            cible_id = request.form.get('cible_id', '')
            
            if not nom or not cible_id:
                flash("Nom et cible requis", "error")
            else:
                user_id = int(cible_id) if cible == 'individuel' else None
                groupe_id = int(cible_id) if cible == 'groupe' else None
                try:
                    conn.execute("""INSERT INTO pointage_emploi_du_temps
                        (company_id, nom, heure_debut, heure_fin, pause_debut, pause_fin,
                         jours_actifs, tolerance_minutes, penalty_per_minute,
                         company_user_id, groupe_id, created_by)
                        VALUES (?,?,?,?,?,?,?,?,?,?,?,?)""",
                        (cid, nom, heure_debut, heure_fin, pause_debut, pause_fin,
                         jours, tol, ppm, user_id, groupe_id, session.get('user_id')))
                    conn.commit()
                    flash(f"✅ Emploi du temps '{nom}' créé", "success")
                except Exception as e:
                    flash(f"❌ {e}", "error")
        elif action == 'delete':
            try:
                eid = int(request.form.get('edt_id', 0))
                conn.execute("DELETE FROM pointage_emploi_du_temps WHERE id=? AND company_id=?", (eid, cid))
                conn.commit()
                flash("✅ Emploi du temps supprimé", "success")
            except: pass
        conn.close()
        return redirect(url_for('admin_pointage_company_edt', cid=cid))
    
    # GET
    edts = [dict(r) for r in conn.execute("""
        SELECT edt.*,
               pcu.full_name as user_name,
               pg.nom as groupe_nom, pg.color as groupe_color
        FROM pointage_emploi_du_temps edt
        LEFT JOIN pointage_company_users pcu ON edt.company_user_id = pcu.id
        LEFT JOIN pointage_groupes pg ON edt.groupe_id = pg.id
        WHERE edt.company_id=? AND COALESCE(edt.is_active,1)=1
        ORDER BY edt.nom""", (cid,)).fetchall()]
    
    users = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_company_users WHERE company_id=? AND COALESCE(is_active,1)=1 ORDER BY full_name",
        (cid,)).fetchall()]
    
    groupes = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_groupes WHERE company_id=? AND COALESCE(is_active,1)=1 ORDER BY nom",
        (cid,)).fetchall()]
    
    # Préselection groupe depuis URL ?groupe_id=X
    preselect_groupe_id = request.args.get('groupe_id', '').strip()
    
    conn.close()
    return render_template('extra_pages.html', page='pt_company_edt',
                          company=company, edts=edts, users=users, groupes=groupes,
                          preselect_groupe_id=preselect_groupe_id)


@app.route('/admin/pointage/companies/<int:cid>/jours-repos', methods=['GET', 'POST'])
@permission_required_any('admin', 'pointage_edit')
def admin_pointage_company_jours_repos(cid):
    """Gestion des jours de repos / fériés (entreprise / groupe / employé)."""
    conn = _gdb()
    company = conn.execute("SELECT * FROM pointage_companies WHERE id=?", (cid,)).fetchone()
    if not company:
        conn.close()
        flash("Entreprise introuvable", "error")
        return redirect(url_for('admin_pointage_companies_list'))
    company = dict(company)
    
    if request.method == 'POST':
        action = request.form.get('action', '')
        if action == 'add':
            try:
                libelle = (request.form.get('libelle','') or '').strip()
                mode = (request.form.get('mode','single') or 'single').strip()
                type_jour = (request.form.get('type','ferie') or 'ferie').strip()
                scope = (request.form.get('scope','entreprise') or 'entreprise').strip()
                recurrent = 1 if request.form.get('recurrent_annuel') == '1' else 0
                user_id = None
                groupe_id = None
                if scope == 'employe':
                    try: user_id = int(request.form.get('company_user_id', 0))
                    except: pass
                    if not user_id:
                        flash("Sélectionnez un employé", "error")
                        return redirect(url_for('admin_pointage_company_jours_repos', cid=cid))
                elif scope == 'groupe':
                    try: groupe_id = int(request.form.get('groupe_id', 0))
                    except: pass
                    if not groupe_id:
                        flash("Sélectionnez un groupe", "error")
                        return redirect(url_for('admin_pointage_company_jours_repos', cid=cid))
                
                if not libelle:
                    flash("Libellé requis", "error")
                elif mode == 'multi':
                    # Mode multi : liste de dates séparées par virgules
                    dates_csv = (request.form.get('dates_multiple','') or '').strip()
                    dates_list = [d.strip() for d in dates_csv.split(',') if d.strip()]
                    if not dates_list:
                        flash("Sélectionnez au moins une date", "error")
                    else:
                        # Recurrent désactivé en mode multi
                        for d in dates_list:
                            try:
                                conn.execute("""INSERT INTO pointage_jours_repos
                                    (company_id, date, date_fin, libelle, type, scope,
                                     company_user_id, groupe_id, recurrent_annuel, created_by)
                                    VALUES (?,?,?,?,?,?,?,?,?,?)""",
                                    (cid, d, None, libelle, type_jour, scope,
                                     user_id, groupe_id, 0, session.get('user_id')))
                            except: pass
                        conn.commit()
                        flash(f"✅ {len(dates_list)} jour(s) de repos '{libelle}' ajouté(s)", "success")
                elif mode == 'range':
                    date_start = (request.form.get('date_range_start','') or '').strip()
                    date_end = (request.form.get('date_fin','') or '').strip()
                    if not date_start or not date_end:
                        flash("Date début et date fin requises pour le mode plage", "error")
                    elif date_start > date_end:
                        flash("La date de fin doit être après la date de début", "error")
                    else:
                        # Recurrent désactivé en mode range (utilise date_fin)
                        conn.execute("""INSERT INTO pointage_jours_repos
                            (company_id, date, date_fin, libelle, type, scope,
                             company_user_id, groupe_id, recurrent_annuel, created_by)
                            VALUES (?,?,?,?,?,?,?,?,?,?)""",
                            (cid, date_start, date_end, libelle, type_jour, scope,
                             user_id, groupe_id, 0, session.get('user_id')))
                        conn.commit()
                        flash(f"✅ Jour de repos '{libelle}' ajouté ({date_start} → {date_end})", "success")
                else:
                    # Mode single
                    date = (request.form.get('date','') or '').strip()
                    if not date:
                        flash("Date requise", "error")
                    else:
                        conn.execute("""INSERT INTO pointage_jours_repos
                            (company_id, date, date_fin, libelle, type, scope,
                             company_user_id, groupe_id, recurrent_annuel, created_by)
                            VALUES (?,?,?,?,?,?,?,?,?,?)""",
                            (cid, date, None, libelle, type_jour, scope,
                             user_id, groupe_id, recurrent, session.get('user_id')))
                        conn.commit()
                        flash(f"✅ Jour de repos '{libelle}' ajouté", "success")
            except Exception as e:
                flash(f"❌ {e}", "error")
        elif action == 'delete':
            try:
                jid = int(request.form.get('jour_id', 0))
                conn.execute("DELETE FROM pointage_jours_repos WHERE id=? AND company_id=?", (jid, cid))
                conn.commit()
                flash("✅ Jour de repos supprimé", "success")
            except: pass
        elif action == 'add_feries_ci':
            # Ajouter automatiquement les jours fériés de Côte d'Ivoire (récurrents)
            feries_ci = [
                ('01-01', "Jour de l'An"),
                ('05-01', "Fête du Travail"),
                ('08-07', "Fête de l'Indépendance"),
                ('11-15', "Journée Nationale de la Paix"),
                ('12-25', "Noël"),
                ('12-31', "Veille du Nouvel An"),
            ]
            year = datetime.now().year
            count = 0
            for mmdd, libelle in feries_ci:
                date = f"{year}-{mmdd}"
                # Vérifier si déjà existant
                existing = conn.execute("""SELECT id FROM pointage_jours_repos
                    WHERE company_id=? AND libelle=? AND scope='entreprise'""",
                    (cid, libelle)).fetchone()
                if not existing:
                    conn.execute("""INSERT INTO pointage_jours_repos
                        (company_id, date, libelle, type, scope, recurrent_annuel, created_by)
                        VALUES (?, ?, ?, 'ferie', 'entreprise', 1, ?)""",
                        (cid, date, libelle, session.get('user_id')))
                    count += 1
            conn.commit()
            flash(f"✅ {count} jour(s) férié(s) CI ajoutés (récurrents annuels)", "success")
        conn.close()
        return redirect(url_for('admin_pointage_company_jours_repos', cid=cid))
    
    # GET
    from datetime import date as _date, timedelta as _td
    today = datetime.now()
    year = today.year
    date_from = f"{year}-01-01"
    date_to = f"{year}-12-31"
    
    jours_repos = [dict(r) for r in conn.execute("""
        SELECT jr.*, pcu.full_name as user_name, pg.nom as groupe_nom, pg.color as groupe_color
        FROM pointage_jours_repos jr
        LEFT JOIN pointage_company_users pcu ON jr.company_user_id = pcu.id
        LEFT JOIN pointage_groupes pg ON jr.groupe_id = pg.id
        WHERE jr.company_id=? AND COALESCE(jr.is_active,1)=1
        ORDER BY jr.date""", (cid,)).fetchall()]
    
    users = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_company_users WHERE company_id=? AND COALESCE(is_active,1)=1 ORDER BY full_name",
        (cid,)).fetchall()]
    groupes = [dict(r) for r in conn.execute(
        "SELECT * FROM pointage_groupes WHERE company_id=? AND COALESCE(is_active,1)=1 ORDER BY nom",
        (cid,)).fetchall()]
    
    # Préselection depuis URL : ?scope=groupe&groupe_id=X ou ?scope=employe&user_id=X
    preselect_scope = request.args.get('scope', 'entreprise')
    if preselect_scope not in ('entreprise', 'groupe', 'employe'):
        preselect_scope = 'entreprise'
    preselect_groupe_id = request.args.get('groupe_id', '').strip()
    preselect_user_id = request.args.get('user_id', '').strip()
    
    conn.close()
    return render_template('extra_pages.html', page='pt_company_jours_repos',
                          company=company, jours_repos=jours_repos,
                          users=users, groupes=groupes, today=today.strftime('%Y-%m-%d'),
                          preselect_scope=preselect_scope,
                          preselect_groupe_id=preselect_groupe_id,
                          preselect_user_id=preselect_user_id)


