@app.route('/fournisseurs')
@permission_required_any('fournisseurs', 'achats', 'admin')
def fournisseurs_list():
    """Liste des fournisseurs avec total achats / payé / reste.
    v128 : Admin voit TOUS les fournisseurs (actifs + inactifs) pour ne rien manquer."""
    from models import get_supplier_summary
    user = get_user_by_id(session['user_id']) if session.get('user_id') else None
    is_admin_view = user and user.get('role') == 'admin'
    
    conn = _gdb()
    suppliers = []
    try:
        if is_admin_view:
            # Admin : voit TOUT (actifs + inactifs/archivés)
            suppliers = [dict(r) for r in conn.execute(
                "SELECT * FROM suppliers ORDER BY COALESCE(is_active,1) DESC, nom").fetchall()]
        else:
            # Autres rôles : uniquement actifs
            suppliers = [dict(r) for r in conn.execute(
                "SELECT * FROM suppliers WHERE COALESCE(is_active,1)=1 ORDER BY nom").fetchall()]
        for s in suppliers:
            summary = get_supplier_summary(s['id'])
            s.update(summary)
    except: pass
    
    # Stats globales (uniquement sur les actifs pour les totaux)
    actives_only = [s for s in suppliers if (s.get('is_active') is None or s.get('is_active') == 1)]
    grand_total = sum(s.get('total_purchases', 0) for s in actives_only)
    grand_paid = sum(s.get('total_paid', 0) for s in actives_only)
    grand_rest = max(0, grand_total - grand_paid)
    
    # Compteurs
    nb_actifs = len(actives_only)
    nb_inactifs = len([s for s in suppliers if s.get('is_active') == 0])

    # v160 : soldes des portefeuilles FOURNISSEUR affichés directement ici
    caisses_fourn, banques_fourn = _fournisseur_wallets(conn)
    solde_caisse_fourn = sum(c['solde'] for c in caisses_fourn)
    solde_banque_fourn = sum(b['solde'] for b in banques_fourn)

    conn.close()
    return render_template('extra_pages.html', page='fournisseurs_list',
                          suppliers=suppliers, grand_total=grand_total,
                          grand_paid=grand_paid, grand_rest=grand_rest,
                          nb_actifs=nb_actifs, nb_inactifs=nb_inactifs,
                          is_admin_view=is_admin_view,
                          solde_caisse_fourn=solde_caisse_fourn,
                          solde_banque_fourn=solde_banque_fourn,
                          solde_total_fourn=solde_caisse_fourn + solde_banque_fourn)


@app.route('/fournisseurs/<int:sid>/toggle-active', methods=['POST'])
@permission_required_any('fournisseurs_edit', 'admin')
def fournisseur_toggle_active(sid):
    """v128 : Admin peut réactiver/désactiver un fournisseur."""
    user = get_user_by_id(session['user_id']) if session.get('user_id') else None
    if not user or user.get('role') != 'admin':
        flash("⚠️ Réservé à l'admin", "error")
        return redirect('/fournisseurs')
    conn = _gdb()
    row = conn.execute("SELECT nom, COALESCE(is_active,1) as active FROM suppliers WHERE id=?", (sid,)).fetchone()
    if not row:
        conn.close()
        flash("Fournisseur introuvable", "error")
        return redirect('/fournisseurs')
    new_active = 0 if row['active'] else 1
    try:
        conn.execute("UPDATE suppliers SET is_active=? WHERE id=?", (new_active, sid))
        conn.commit()
        action = "réactivé" if new_active else "désactivé"
        flash(f"✅ Fournisseur « {row['nom']} » {action}", "success")
        log_activity(session['user_id'], user['full_name'], 'Fournisseur',
                     f"Fournisseur #{sid} ({row['nom']}) {action}", request.remote_addr)
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect('/fournisseurs')


@app.route('/fournisseurs/add', methods=['POST'])
@permission_required_any('fournisseurs_edit', 'admin')
def fournisseurs_add():
    nom = (request.form.get('nom','') or '').strip()
    if not nom:
        flash("Nom requis", "error")
        return redirect(url_for('fournisseurs_list'))
    conn = _gdb()
    try:
        # v128 : Forcer is_active=1 à la création
        conn.execute("""INSERT INTO suppliers (nom, telephone, email, adresse, contact, notes, is_active, created_by)
            VALUES (?, ?, ?, ?, ?, ?, 1, ?)""",
            (nom,
             request.form.get('telephone','').strip(),
             request.form.get('email','').strip(),
             request.form.get('adresse','').strip(),
             request.form.get('contact','').strip(),
             request.form.get('notes','').strip(),
             session.get('user_id')))
        conn.commit()
        flash(f"✅ Fournisseur '{nom}' créé", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect(url_for('fournisseurs_list'))


@app.route('/fournisseurs/<int:sid>', methods=['GET', 'POST'])
@permission_required_any('fournisseurs', 'achats', 'admin')
def fournisseur_detail(sid):
    """Fiche fournisseur avec ses achats."""
    from models import get_supplier_summary, get_purchase_status
    conn = _gdb()
    supplier = conn.execute("SELECT * FROM suppliers WHERE id=?", (sid,)).fetchone()
    if not supplier:
        flash("Fournisseur introuvable", "error")
        conn.close(); return redirect(url_for('fournisseurs_list'))
    supplier = dict(supplier)
    
    user = get_user_by_id(session['user_id'])
    perms = get_role_permissions(user['role']) if user else []
    can_edit = ('fournisseurs_edit' in perms or 'admin' in perms)
    
    if request.method == 'POST' and can_edit:
        action = request.form.get('action', '')
        if action == 'update_supplier':
            try:
                conn.execute("""UPDATE suppliers SET nom=?, telephone=?, email=?, adresse=?, contact=?, notes=?, updated_at=?
                    WHERE id=?""",
                    (request.form.get('nom','').strip(),
                     request.form.get('telephone','').strip(),
                     request.form.get('email','').strip(),
                     request.form.get('adresse','').strip(),
                     request.form.get('contact','').strip(),
                     request.form.get('notes','').strip(),
                     datetime.now().isoformat(), sid))
                conn.commit()
                flash("✅ Fournisseur modifié", "success")
            except Exception as e:
                flash(f"❌ Erreur : {e}", "error")
        elif action == 'add_purchase':
            try:
                conn.execute("""INSERT INTO supplier_purchases
                    (supplier_id, description, categorie, montant_total, date, date_echeance, departement, notes, created_by)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                    (sid,
                     request.form.get('description','').strip(),
                     request.form.get('categorie','').strip(),
                     float(request.form.get('montant_total','0') or 0),
                     request.form.get('date', datetime.now().strftime('%Y-%m-%d')),
                     request.form.get('date_echeance','').strip(),
                     request.form.get('departement','').strip(),
                     request.form.get('notes','').strip(),
                     session.get('user_id')))
                conn.commit()
                flash("✅ Achat ajouté", "success")
            except Exception as e:
                flash(f"❌ Erreur : {e}", "error")
    
    purchases = []
    try:
        purchases = [dict(r) for r in conn.execute(
            "SELECT * FROM supplier_purchases WHERE supplier_id=? ORDER BY date DESC, id DESC", (sid,)).fetchall()]
        for p in purchases:
            status, paid, rest, pct = get_purchase_status(p['id'])
            p['status'] = status; p['total_paid'] = paid
            p['reste'] = rest; p['pct_paid'] = pct
            # Échéance dépassée ?
            if p.get('date_echeance') and rest > 0:
                if p['date_echeance'] < datetime.now().strftime('%Y-%m-%d'):
                    p['overdue'] = True
    except: pass
    
    summary = get_supplier_summary(sid)
    conn.close()
    return render_template('extra_pages.html', page='fournisseur_detail',
                          supplier=supplier, purchases=purchases,
                          summary=summary, can_edit=can_edit,
                          today_str=datetime.now().strftime('%Y-%m-%d'))


# v119 : Édition d'un achat fournisseur (montant, description, échéance, etc.)
@app.route('/fournisseurs/purchase/<int:pid>/edit', methods=['POST'])
@permission_required_any('fournisseurs_edit', 'admin')
def purchase_edit(pid):
    conn = _gdb()
    p = conn.execute("SELECT supplier_id FROM supplier_purchases WHERE id=?", (pid,)).fetchone()
    if not p:
        conn.close()
        flash("Achat introuvable", "error")
        return redirect(url_for('fournisseurs_list'))
    sid = p['supplier_id']
    try:
        conn.execute("""UPDATE supplier_purchases SET
            description=?, categorie=?, montant_total=?, date=?, date_echeance=?,
            departement=?, notes=? WHERE id=?""",
            (request.form.get('description','').strip(),
             request.form.get('categorie','').strip(),
             float(request.form.get('montant_total','0') or 0),
             request.form.get('date', datetime.now().strftime('%Y-%m-%d')),
             request.form.get('date_echeance','').strip() or None,
             request.form.get('departement','').strip(),
             request.form.get('notes','').strip(),
             pid))
        conn.commit()
        user = get_user_by_id(session['user_id'])
        log_activity(session['user_id'], user['full_name'] if user else '?', 'Fournisseur',
            f"Achat #{pid} modifié (fournisseur #{sid})", request.remote_addr)
        flash("✅ Achat modifié", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect(f'/fournisseurs/{sid}')


# v119 : Suppression d'un achat fournisseur
@app.route('/fournisseurs/purchase/<int:pid>/delete', methods=['POST'])
@permission_required_any('fournisseurs_edit', 'admin')
def purchase_delete(pid):
    conn = _gdb()
    p = conn.execute("SELECT supplier_id, description, montant_total FROM supplier_purchases WHERE id=?", (pid,)).fetchone()
    if not p:
        conn.close()
        flash("Achat introuvable", "error")
        return redirect(url_for('fournisseurs_list'))
    sid = p['supplier_id']
    try:
        nb_pay = conn.execute("SELECT COUNT(*) FROM supplier_payments WHERE purchase_id=?", (pid,)).fetchone()[0]
    except: nb_pay = 0
    if nb_pay > 0:
        conn.close()
        flash(f"⚠️ Impossible de supprimer : {nb_pay} paiement(s) associé(s). Supprimez d'abord les paiements.", "error")
        return redirect(f'/fournisseurs/{sid}')
    try:
        conn.execute("DELETE FROM supplier_purchases WHERE id=?", (pid,))
        conn.commit()
        user = get_user_by_id(session['user_id'])
        log_activity(session['user_id'], user['full_name'] if user else '?', 'Fournisseur',
            f"Achat #{pid} supprimé — {p['description'][:40]} ({float(p['montant_total']):,.0f} F)", request.remote_addr)
        flash("✅ Achat supprimé", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    conn.close()
    return redirect(f'/fournisseurs/{sid}')


# v119 : Rapport PDF complet d'un fournisseur
@app.route('/fournisseurs/<int:sid>/rapport.pdf')
@permission_required_any('fournisseurs', 'achats', 'admin')
def fournisseur_rapport_pdf(sid):
    from models import get_supplier_summary, get_purchase_status
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
    from io import BytesIO
    
    conn = _gdb()
    supplier = conn.execute("SELECT * FROM suppliers WHERE id=?", (sid,)).fetchone()
    if not supplier:
        conn.close()
        flash("Fournisseur introuvable", "error")
        return redirect(url_for('fournisseurs_list'))
    supplier = dict(supplier)
    purchases = [dict(r) for r in conn.execute(
        "SELECT * FROM supplier_purchases WHERE supplier_id=? ORDER BY date DESC", (sid,)).fetchall()]
    for p in purchases:
        status, paid, rest, pct = get_purchase_status(p['id'])
        p['status'] = status; p['total_paid'] = paid; p['reste'] = rest
    payments = []
    try:
        payments = [dict(r) for r in conn.execute("""SELECT sp.*, p.description as purchase_desc
            FROM supplier_payments sp 
            LEFT JOIN supplier_purchases p ON p.id=sp.purchase_id
            WHERE p.supplier_id=? ORDER BY sp.date DESC""", (sid,)).fetchall()]
    except: pass
    summary = get_supplier_summary(sid)
    conn.close()
    
    buf = BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, topMargin=1.5*cm, bottomMargin=1.5*cm, leftMargin=1.5*cm, rightMargin=1.5*cm)
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle('T', parent=styles['Heading1'], fontSize=18, textColor=colors.HexColor('#1A7A6D'), spaceAfter=10)
    h2 = ParagraphStyle('H2', parent=styles['Heading2'], fontSize=12, textColor=colors.HexColor('#1a3a5c'), spaceAfter=6)
    elems = []
    elems.append(Paragraph(f"Rapport fournisseur — {supplier['nom']}", title_style))
    elems.append(Paragraph(f"Édité le {datetime.now().strftime('%d/%m/%Y à %H:%M')} — RAMYA Technologie", styles['Normal']))
    elems.append(Spacer(1, 0.4*cm))
    elems.append(Paragraph("📇 Informations", h2))
    info = [['Nom', supplier.get('nom','')],
            ['Téléphone', supplier.get('telephone','')],
            ['Email', supplier.get('email','')],
            ['Adresse', supplier.get('adresse','')],
            ['Contact', supplier.get('contact','')],
            ['Notes', supplier.get('notes','')]]
    t = Table(info, colWidths=[4*cm, 13*cm])
    t.setStyle(TableStyle([('GRID',(0,0),(-1,-1),0.5,colors.lightgrey),
        ('BACKGROUND',(0,0),(0,-1),colors.HexColor('#f0f4f8')),
        ('FONTNAME',(0,0),(0,-1),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1),9),('VALIGN',(0,0),(-1,-1),'TOP'),
        ('PADDING',(0,0),(-1,-1),5)]))
    elems.append(t)
    elems.append(Spacer(1, 0.4*cm))
    elems.append(Paragraph("💰 Synthèse financière", h2))
    fmt = lambda x: f"{float(x or 0):,.0f}".replace(',', ' ') + " F"
    sumtab = [['Total achats', fmt(summary.get('total_achats',0))],
              ['Total payé', fmt(summary.get('total_paye',0))],
              ['Reste à payer', fmt(summary.get('total_reste',0))],
              ['Nb achats', str(summary.get('nb_achats',0))]]
    t2 = Table(sumtab, colWidths=[5*cm, 6*cm])
    t2.setStyle(TableStyle([('GRID',(0,0),(-1,-1),0.5,colors.lightgrey),
        ('BACKGROUND',(0,0),(0,-1),colors.HexColor('#fff3e0')),
        ('FONTNAME',(0,0),(0,-1),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1),10),('PADDING',(0,0),(-1,-1),6)]))
    elems.append(t2)
    elems.append(Spacer(1, 0.5*cm))
    elems.append(Paragraph(f"🛒 Achats ({len(purchases)})", h2))
    if purchases:
        rows = [['Date', 'Description', 'Catégorie', 'Montant', 'Payé', 'Reste', 'Statut']]
        for p in purchases:
            rows.append([str(p.get('date',''))[:10],
                (p.get('description','') or '')[:30],
                (p.get('categorie','') or '')[:15],
                fmt(p.get('montant_total',0)),
                fmt(p.get('total_paid',0)),
                fmt(p.get('reste',0)),
                p.get('status','')[:10]])
        t3 = Table(rows, colWidths=[2*cm, 4*cm, 2.5*cm, 2.5*cm, 2.5*cm, 2.5*cm, 2*cm], repeatRows=1)
        t3.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,0),colors.HexColor('#1A7A6D')),
            ('TEXTCOLOR',(0,0),(-1,0),colors.white),
            ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
            ('FONTSIZE',(0,0),(-1,-1),8),
            ('GRID',(0,0),(-1,-1),0.3,colors.lightgrey),
            ('ALIGN',(3,1),(-1,-1),'RIGHT'),
            ('PADDING',(0,0),(-1,-1),3)]))
        elems.append(t3)
    else:
        elems.append(Paragraph("Aucun achat enregistré.", styles['Normal']))
    elems.append(Spacer(1, 0.5*cm))
    elems.append(Paragraph(f"💳 Paiements ({len(payments)})", h2))
    if payments:
        rows = [['Date', 'Achat', 'Montant', 'Mode', 'Référence']]
        for p in payments:
            rows.append([str(p.get('date',''))[:10],
                (p.get('purchase_desc','') or '')[:30],
                fmt(p.get('montant',0)),
                (p.get('mode','') or '')[:10],
                (p.get('reference','') or '')[:15]])
        t4 = Table(rows, colWidths=[2*cm, 5*cm, 3*cm, 3*cm, 4*cm], repeatRows=1)
        t4.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,0),colors.HexColor('#2e7d32')),
            ('TEXTCOLOR',(0,0),(-1,0),colors.white),
            ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
            ('FONTSIZE',(0,0),(-1,-1),8),
            ('GRID',(0,0),(-1,-1),0.3,colors.lightgrey),
            ('ALIGN',(2,1),(2,-1),'RIGHT'),
            ('PADDING',(0,0),(-1,-1),3)]))
        elems.append(t4)
    else:
        elems.append(Paragraph("Aucun paiement enregistré.", styles['Normal']))
    doc.build(elems)
    buf.seek(0)
    from flask import send_file
    return send_file(buf, mimetype='application/pdf', as_attachment=True,
                     download_name=f"rapport_fournisseur_{supplier['nom'].replace(' ','_')}_{datetime.now().strftime('%Y%m%d')}.pdf")


@app.route('/fournisseurs/purchase/<int:pid>', methods=['GET', 'POST'])
@permission_required_any('fournisseurs', 'achats', 'admin')
def purchase_detail(pid):
    """Détail d'un achat avec ses paiements."""
    from models import get_purchase_status
    conn = _gdb()
    purchase = conn.execute("""SELECT p.*, s.nom as supplier_nom, s.id as supplier_id
        FROM supplier_purchases p LEFT JOIN suppliers s ON p.supplier_id=s.id WHERE p.id=?""",
        (pid,)).fetchone()
    if not purchase:
        flash("Achat introuvable", "error")
        conn.close(); return redirect(url_for('fournisseurs_list'))
    purchase = dict(purchase)
    
    user = get_user_by_id(session['user_id'])
    perms = get_role_permissions(user['role']) if user else []
    can_edit = ('fournisseurs_edit' in perms or 'admin' in perms)
    
    if request.method == 'POST' and can_edit:
        action = request.form.get('action', '')
        if action == 'add_payment':
            try:
                montant = float(request.form.get('montant','0') or 0)
                if montant <= 0:
                    flash("Montant doit être positif", "error")
                else:
                    date_pay = request.form.get('date', datetime.now().strftime('%Y-%m-%d'))
                    mode_pay = request.form.get('mode_paiement','espece')
                    conn.execute("""INSERT INTO supplier_payments
                        (purchase_id, montant, date, mode_paiement, reference, notes, created_by)
                        VALUES (?, ?, ?, ?, ?, ?, ?)""",
                        (pid, montant, date_pay, mode_pay,
                         request.form.get('reference','').strip(),
                         request.form.get('notes','').strip(),
                         session.get('user_id')))
                    payment_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
                    conn.commit()
                    
                    # Intégration auto Compta Pro (écriture en brouillard)
                    compta_msg = ""
                    try:
                        eid_auto, err_auto = _compta_auto_paiement_fournisseur(
                            purchase['supplier_id'], pid, payment_id,
                            montant, date_pay, mode_pay)
                        if eid_auto and not err_auto:
                            compta_msg = f" — Écriture comptable #{eid_auto} créée en brouillard"
                    except Exception as ex:
                        print(f"Compta auto: {ex}")
                    
                    flash(f"✅ Paiement de {montant:,.0f} F enregistré{compta_msg}", "success")
            except Exception as e:
                flash(f"❌ Erreur : {e}", "error")
        elif action == 'delete_payment':
            try:
                pay_id = int(request.form.get('payment_id', 0))
                conn.execute("DELETE FROM supplier_payments WHERE id=? AND purchase_id=?", (pay_id, pid))
                conn.commit()
                flash("✅ Paiement supprimé", "success")
            except: pass
    
    payments = []
    try:
        payments = [dict(r) for r in conn.execute("""
            SELECT pay.*, u.full_name as creator
            FROM supplier_payments pay LEFT JOIN users u ON pay.created_by=u.id
            WHERE pay.purchase_id=? ORDER BY pay.date DESC, pay.id DESC""", (pid,)).fetchall()]
    except: pass
    
    status, total_paid, reste, pct = get_purchase_status(pid)
    purchase['status'] = status; purchase['total_paid'] = total_paid
    purchase['reste'] = reste; purchase['pct_paid'] = pct
    
    conn.close()
    return render_template('extra_pages.html', page='purchase_detail',
                          purchase=purchase, payments=payments, can_edit=can_edit,
                          today_str=datetime.now().strftime('%Y-%m-%d'))


@app.route('/fournisseurs/<int:sid>/delete', methods=['POST'])
@permission_required_any('fournisseurs_edit', 'admin')
def fournisseur_delete(sid):
    """Désactiver un fournisseur (soft delete)."""
    conn = _gdb()
    try:
        conn.execute("UPDATE suppliers SET is_active=0 WHERE id=?", (sid,))
        conn.commit()
        flash("Fournisseur archivé", "info")
    except: pass
    conn.close()
    return redirect(url_for('fournisseurs_list'))


# v134 : Admin peut supprimer DÉFINITIVEMENT un fournisseur (hard delete)
@app.route('/fournisseurs/<int:sid>/hard-delete', methods=['POST'])
@permission_required('admin')
def fournisseur_hard_delete(sid):
    """v134 : Admin peut supprimer définitivement un fournisseur de la BDD.
    ATTENTION : suppression irréversible. Les achats liés sont aussi supprimés."""
    user = get_user_by_id(session['user_id']) if session.get('user_id') else None
    if not user or user['role'] != 'admin':
        flash("⚠️ Réservé à l'admin", "error")
        return redirect('/fournisseurs')
    
    conn = _gdb()
    try:
        # Récupérer info pour snapshot
        sup = conn.execute("SELECT * FROM suppliers WHERE id=?", (sid,)).fetchone()
        if not sup:
            flash("Fournisseur introuvable", "error")
            conn.close()
            return redirect('/fournisseurs')
        
        nom = sup['nom']
        
        # 1. Snapshot dans la corbeille
        try:
            import json
            sup_dict = dict(sup)
            try:
                purchases = [dict(r) for r in conn.execute("SELECT * FROM supplier_purchases WHERE supplier_id=?", (sid,)).fetchall()]
            except: purchases = []
            sup_dict['_linked_purchases'] = purchases
            conn.execute("""INSERT INTO trash_snapshots (entity_type, entity_id, entity_name, snapshot_json, deleted_by, deleted_by_name, deleted_at)
                VALUES ('fournisseur', ?, ?, ?, ?, ?, datetime('now'))""",
                (sid, nom, json.dumps(sup_dict, default=str), session['user_id'], user['full_name']))
        except Exception as _e: print(f"[v134] snapshot fournisseur err : {_e}", flush=True)
        
        # 2. Supprimer les achats liés
        try: conn.execute("DELETE FROM supplier_purchases WHERE supplier_id=?", (sid,))
        except: pass
        
        # 3. Supprimer le fournisseur lui-même
        conn.execute("DELETE FROM suppliers WHERE id=?", (sid,))
        conn.commit()
        
        log_activity(session['user_id'], user['full_name'], 'Fournisseur',
            f"Suppression DÉFINITIVE fournisseur #{sid} ({nom})", request.remote_addr)
        
        flash(f"🗑️ Fournisseur « {nom} » supprimé définitivement (et tous ses achats liés). Snapshot sauvegardé dans la corbeille.", "success")
    except Exception as e:
        flash(f"❌ Erreur : {e}", "error")
    finally:
        conn.close()
    return redirect('/fournisseurs')


@app.route('/fournisseurs/export.csv')
@permission_required_any('fournisseurs', 'admin')
def fournisseurs_export_csv():
    from models import get_supplier_summary
    conn = _gdb()
    suppliers = [dict(r) for r in conn.execute(
        "SELECT * FROM suppliers WHERE COALESCE(is_active,1)=1 ORDER BY nom").fetchall()]
    conn.close()
    import io, csv
    buf = io.StringIO()
    w = csv.writer(buf, delimiter=';')
    w.writerow(['Fournisseur','Téléphone','Email','Adresse','Total achats','Total payé','Reste','% payé'])
    for s in suppliers:
        sum_ = get_supplier_summary(s['id'])
        w.writerow([s['nom'], s.get('telephone',''), s.get('email',''), s.get('adresse',''),
                    f"{sum_['total_purchases']:.0f}",
                    f"{sum_['total_paid']:.0f}",
                    f"{sum_['reste']:.0f}",
                    f"{sum_['pct_paid']:.1f}%"])
    return Response(buf.getvalue(), mimetype='text/csv; charset=utf-8',
        headers={'Content-Disposition': 'attachment; filename=fournisseurs.csv'})


@app.route('/fournisseurs/recap-pdf')
@permission_required_any('fournisseurs', 'admin')
def fournisseurs_recap_pdf():
    """Récap PDF du suivi paiement fournisseurs sur une période donnée.
    Params : ?from=YYYY-MM-DD&to=YYYY-MM-DD"""
    from datetime import datetime as _dt, date as _date, timedelta as _td
    
    today_str = _dt.now().strftime('%Y-%m-%d')
    date_from = (request.args.get('from','') or '').strip()
    date_to = (request.args.get('to','') or '').strip()
    
    # Valeurs par défaut : début du mois -> aujourd'hui
    if not date_from:
        date_from = _date.today().replace(day=1).strftime('%Y-%m-%d')
    if not date_to:
        date_to = today_str
    
    conn = _gdb()
    
    # Récupérer toutes les transactions de la période
    suppliers_data = []
    try:
        suppliers = [dict(r) for r in conn.execute(
            "SELECT * FROM suppliers WHERE COALESCE(is_active,1)=1 ORDER BY nom").fetchall()]
        
        for s in suppliers:
            # Achats sur la période
            purchases = [dict(r) for r in conn.execute("""
                SELECT * FROM supplier_purchases
                WHERE supplier_id=? AND date BETWEEN ? AND ?
                ORDER BY date""", (s['id'], date_from, date_to)).fetchall()]
            
            # Paiements sur la période
            payments = [dict(r) for r in conn.execute("""
                SELECT pay.*, p.description as purchase_desc
                FROM supplier_payments pay
                LEFT JOIN supplier_purchases p ON pay.purchase_id=p.id
                WHERE p.supplier_id=? AND pay.date BETWEEN ? AND ?
                ORDER BY pay.date""", (s['id'], date_from, date_to)).fetchall()]
            
            total_achats_periode = sum(float(p.get('montant_total') or 0) for p in purchases)
            total_paye_periode = sum(float(p.get('montant') or 0) for p in payments)
            
            # Solde global du fournisseur (toutes périodes)
            total_all = conn.execute(
                "SELECT COALESCE(SUM(montant_total),0) FROM supplier_purchases WHERE supplier_id=?",
                (s['id'],)).fetchone()[0] or 0
            paid_all = conn.execute("""SELECT COALESCE(SUM(pay.montant),0)
                FROM supplier_payments pay JOIN supplier_purchases p ON pay.purchase_id=p.id
                WHERE p.supplier_id=?""", (s['id'],)).fetchone()[0] or 0
            
            if purchases or payments:
                suppliers_data.append({
                    'supplier': s,
                    'purchases': purchases,
                    'payments': payments,
                    'total_achats_periode': total_achats_periode,
                    'total_paye_periode': total_paye_periode,
                    'reste_global': max(0, float(total_all) - float(paid_all)),
                    'total_all': float(total_all),
                    'paid_all': float(paid_all),
                })
    except Exception as e:
        print(f"recap query: {e}")
    
    conn.close()
    
    # Générer PDF
    try:
        from reportlab.lib.pagesizes import A4, landscape
        from reportlab.lib.units import mm
        from reportlab.lib.colors import HexColor
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
        from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, Image, PageBreak)
        import io
        
        buf = io.BytesIO()
        doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=12*mm, rightMargin=12*mm,
                                topMargin=12*mm, bottomMargin=12*mm)
        story = []
        
        # En-tête
        TEAL = HexColor('#1A7A6D')
        ORANGE = HexColor('#F29F2F')
        story.append(Paragraph("<b>RAMYA TECHNOLOGIE &amp; INNOVATION</b>",
            ParagraphStyle('h', fontSize=14, textColor=TEAL, alignment=TA_CENTER)))
        story.append(Paragraph("Récapitulatif suivi paiement fournisseurs",
            ParagraphStyle('h2', fontSize=12, textColor=HexColor('#1a3a5c'), alignment=TA_CENTER)))
        story.append(Paragraph(f"Période : du {date_from} au {date_to}",
            ParagraphStyle('p', fontSize=10, alignment=TA_CENTER, textColor=HexColor('#666666'))))
        story.append(Spacer(1, 6*mm))
        
        if not suppliers_data:
            story.append(Paragraph("<i>Aucune transaction (achat ou paiement) sur la période sélectionnée.</i>",
                ParagraphStyle('empty', fontSize=11, alignment=TA_CENTER)))
        else:
            # Synthèse globale
            grand_achats = sum(s['total_achats_periode'] for s in suppliers_data)
            grand_payes = sum(s['total_paye_periode'] for s in suppliers_data)
            grand_reste = sum(s['reste_global'] for s in suppliers_data)
            
            synth = [
                ['Indicateur', 'Montant'],
                ['Nombre de fournisseurs avec activité', f"{len(suppliers_data)}"],
                ['Total achats sur la période', f"{grand_achats:,.0f} F CFA"],
                ['Total paiements sur la période', f"{grand_payes:,.0f} F CFA"],
                ['Reste à payer global (toutes périodes)', f"{grand_reste:,.0f} F CFA"],
            ]
            t_synth = Table(synth, colWidths=[100*mm, 75*mm])
            t_synth.setStyle(TableStyle([
                ('BACKGROUND',(0,0),(-1,0),TEAL),
                ('TEXTCOLOR',(0,0),(-1,0),HexColor('#ffffff')),
                ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                ('FONTSIZE',(0,0),(-1,-1),10),
                ('GRID',(0,0),(-1,-1),0.4,HexColor('#cccccc')),
                ('PADDING',(0,0),(-1,-1),5),
                ('ALIGN',(1,0),(1,-1),'RIGHT'),
                ('BACKGROUND',(0,-1),(-1,-1),HexColor('#fde8e8')),
                ('TEXTCOLOR',(0,-1),(-1,-1),HexColor('#c53030')),
                ('FONTNAME',(0,-1),(-1,-1),'Helvetica-Bold'),
            ]))
            story.append(t_synth)
            story.append(Spacer(1, 8*mm))
            
            # Détail par fournisseur
            for sdata in suppliers_data:
                s = sdata['supplier']
                story.append(Paragraph(f"<b>{s['nom']}</b>",
                    ParagraphStyle('sup', fontSize=12, textColor=TEAL)))
                contact_line = []
                if s.get('telephone'): contact_line.append(f"📞 {s['telephone']}")
                if s.get('email'): contact_line.append(f"✉️ {s['email']}")
                if contact_line:
                    story.append(Paragraph(' &nbsp; '.join(contact_line),
                        ParagraphStyle('contact', fontSize=8, textColor=HexColor('#888888'))))
                story.append(Spacer(1, 2*mm))
                
                # Synthèse fournisseur
                sup_synth = [
                    ['Achats période', 'Paiements période', 'Reste global'],
                    [f"{sdata['total_achats_periode']:,.0f} F",
                     f"{sdata['total_paye_periode']:,.0f} F",
                     f"{sdata['reste_global']:,.0f} F"],
                ]
                t = Table(sup_synth, colWidths=[58*mm, 58*mm, 58*mm])
                t.setStyle(TableStyle([
                    ('BACKGROUND',(0,0),(-1,0),HexColor('#e0f5f1')),
                    ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                    ('FONTSIZE',(0,0),(-1,-1),9),
                    ('ALIGN',(0,0),(-1,-1),'CENTER'),
                    ('GRID',(0,0),(-1,-1),0.3,HexColor('#cccccc')),
                    ('PADDING',(0,0),(-1,-1),4),
                    ('FONTNAME',(0,1),(-1,1),'Helvetica-Bold'),
                    ('TEXTCOLOR',(2,1),(2,1),HexColor('#c53030')),
                ]))
                story.append(t)
                story.append(Spacer(1, 3*mm))
                
                # Tableau achats
                if sdata['purchases']:
                    story.append(Paragraph("<b>Achats sur la période</b>",
                        ParagraphStyle('lbl', fontSize=9, textColor=HexColor('#1a3a5c'))))
                    p_data = [['Date', 'Description', 'Montant', 'Échéance']]
                    for p in sdata['purchases']:
                        desc = (p.get('description') or '')[:50]
                        p_data.append([p.get('date',''), desc,
                                      f"{float(p.get('montant_total',0) or 0):,.0f} F",
                                      p.get('date_echeance','') or '-'])
                    t_p = Table(p_data, colWidths=[22*mm, 90*mm, 35*mm, 25*mm])
                    t_p.setStyle(TableStyle([
                        ('BACKGROUND',(0,0),(-1,0),HexColor('#1a3a5c')),
                        ('TEXTCOLOR',(0,0),(-1,0),HexColor('#ffffff')),
                        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                        ('FONTSIZE',(0,0),(-1,-1),8),
                        ('GRID',(0,0),(-1,-1),0.25,HexColor('#cccccc')),
                        ('PADDING',(0,0),(-1,-1),3),
                        ('ALIGN',(2,0),(2,-1),'RIGHT'),
                    ]))
                    story.append(t_p)
                    story.append(Spacer(1, 3*mm))
                
                # Tableau paiements
                if sdata['payments']:
                    story.append(Paragraph("<b>Paiements (acomptes) sur la période</b>",
                        ParagraphStyle('lbl', fontSize=9, textColor=HexColor('#1a3a5c'))))
                    pay_data = [['Date', 'Achat associé', 'Mode', 'Référence', 'Montant']]
                    for pay in sdata['payments']:
                        desc = (pay.get('purchase_desc') or '')[:35]
                        mode_lbl = {'espece':'Espèces','cheque':'Chèque','virement':'Virement','mobile':'Mobile'}.get(pay.get('mode_paiement',''), pay.get('mode_paiement','-'))
                        pay_data.append([pay.get('date',''), desc, mode_lbl,
                                        pay.get('reference','') or '-',
                                        f"{float(pay.get('montant',0) or 0):,.0f} F"])
                    t_pay = Table(pay_data, colWidths=[22*mm, 65*mm, 22*mm, 30*mm, 33*mm])
                    t_pay.setStyle(TableStyle([
                        ('BACKGROUND',(0,0),(-1,0),HexColor('#2e7d32')),
                        ('TEXTCOLOR',(0,0),(-1,0),HexColor('#ffffff')),
                        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                        ('FONTSIZE',(0,0),(-1,-1),8),
                        ('GRID',(0,0),(-1,-1),0.25,HexColor('#cccccc')),
                        ('PADDING',(0,0),(-1,-1),3),
                        ('ALIGN',(4,0),(4,-1),'RIGHT'),
                        ('TEXTCOLOR',(4,1),(4,-1),HexColor('#2e7d32')),
                        ('FONTNAME',(4,1),(4,-1),'Helvetica-Bold'),
                    ]))
                    story.append(t_pay)
                
                story.append(Spacer(1, 8*mm))
        
        # Pied de page
        story.append(Spacer(1, 4*mm))
        story.append(Paragraph(
            f"<i>Document généré le {datetime.now().strftime('%d/%m/%Y à %H:%M')} par WannyGest — RAMYA Technologie &amp; Innovation</i>",
            ParagraphStyle('foot', fontSize=8, textColor=HexColor('#888888'), alignment=TA_CENTER)))
        
        doc.build(story)
        buf.seek(0)
        filename = f"recap-fournisseurs-{date_from}-au-{date_to}.pdf"
        return Response(buf.getvalue(), mimetype='application/pdf',
                       headers={'Content-Disposition': f'attachment; filename={filename}'})
    except Exception as e:
        import traceback; traceback.print_exc()
        flash(f"Erreur génération PDF récap : {e}", "error")
        return redirect(url_for('fournisseurs_list'))


@app.route('/achats')
@permission_required_any('achats', 'comptabilite')
def achats_page():
    tab = request.args.get('tab', 'stock')  # default = stock now (fournisseurs moved)
    # Redirect ancien onglet fournisseurs vers le nouveau module unifié
    if tab == 'fournisseurs':
        return redirect(url_for('fournisseurs_list'))
    conn = _gdb()
    from models import db_get_all
    
    data = {'tab': tab}
    data['stock_items'] = db_get_all('stock_items', order='name ASC')
    data['stock_total'] = sum((s.get('quantity',0) or 0) * (s.get('unit_price',0) or 0) for s in data['stock_items'])
    try: data['stock_categories'] = [dict(r) for r in conn.execute("SELECT * FROM stock_categories ORDER BY name").fetchall()]
    except: data['stock_categories'] = []
    data['fournisseurs'] = [dict(r) for r in conn.execute("SELECT * FROM achats_fournisseurs ORDER BY name").fetchall()]
    data['demandes'] = [dict(r) for r in conn.execute("""SELECT ad.*, u.full_name as requester FROM achats_demandes ad 
        LEFT JOIN users u ON ad.requested_by=u.id ORDER BY ad.created_at DESC LIMIT 50""").fetchall()]
    data['devis_achats'] = [dict(r) for r in conn.execute("""SELECT ad.*, f.name as fournisseur_name FROM achats_devis ad
        LEFT JOIN achats_fournisseurs f ON ad.fournisseur_id=f.id ORDER BY ad.created_at DESC LIMIT 50""").fetchall()]
    data['commandes'] = [dict(r) for r in conn.execute("""SELECT ac.*, f.name as fournisseur_name FROM achats_commandes ac
        LEFT JOIN achats_fournisseurs f ON ac.fournisseur_id=f.id ORDER BY ac.created_at DESC LIMIT 50""").fetchall()]
    data['contrats'] = [dict(r) for r in conn.execute("""SELECT ac.*, f.name as fournisseur_name FROM achats_contrats ac
        LEFT JOIN achats_fournisseurs f ON ac.fournisseur_id=f.id ORDER BY ac.created_at DESC""").fetchall()]
    
    # Stats
    data['total_commandes'] = conn.execute("SELECT COALESCE(SUM(total),0) FROM achats_commandes").fetchone()[0]
    data['pending_demandes'] = conn.execute("SELECT COUNT(*) FROM achats_demandes WHERE status='en_attente'").fetchone()[0]
    conn.close()
    return render_template('achats.html', page='achats', **data)

