@app.route('/mg/demandes')
@permission_required_any('mg_view', 'admin')
def mg_demandes():
    conn = _gdb()
    statut = request.args.get('statut', '').strip()
    if statut:
        rows = conn.execute("""
            SELECT d.*, u.username as requester_name,
                f.name as fournisseur_name,
                COALESCE((SELECT COUNT(*) FROM achats_demande_items WHERE demande_id=d.id),0) as nb_items
            FROM achats_demandes d
            LEFT JOIN users u ON d.requested_by = u.id
            LEFT JOIN achats_fournisseurs f ON d.fournisseur_id = f.id
            WHERE d.status=? ORDER BY d.created_at DESC""", (statut,)).fetchall()
    else:
        rows = conn.execute("""
            SELECT d.*, u.username as requester_name,
                f.name as fournisseur_name,
                COALESCE((SELECT COUNT(*) FROM achats_demande_items WHERE demande_id=d.id),0) as nb_items
            FROM achats_demandes d
            LEFT JOIN users u ON d.requested_by = u.id
            LEFT JOIN achats_fournisseurs f ON d.fournisseur_id = f.id
            ORDER BY d.created_at DESC""").fetchall()
    demandes = [dict(r) for r in rows]
    # v160 : liste des fournisseurs pour le formulaire de demande
    fournisseurs = [dict(r) for r in conn.execute(
        "SELECT id, name FROM achats_fournisseurs WHERE status='actif' OR status IS NULL ORDER BY name").fetchall()]
    conn.close()
    return render_template('mg_demandes.html', demandes=demandes, current_statut=statut, fournisseurs=fournisseurs)


@app.route('/mg/demandes/add', methods=['POST'])
@permission_required_any('mg_demande', 'admin')
def mg_demandes_add():
    """v110 : Création d'une demande MG.
    Si l'auteur a la permission de valider (mg_valider — typiquement le service MG lui-même),
    la demande est créée + auto-validée + auto-envoyée à la Comptabilité.
    Sinon, elle reste en attente d'une validation MG."""
    ref = f"DM-{datetime.now().strftime('%Y%m%d%H%M%S')}-{secrets.token_hex(2).upper()}"
    
    # Détecter si l'auteur peut valider directement (c'est le MG lui-même)
    user = get_user_by_id(session['user_id'])
    from models import has_permission as _hp
    user_role = user['role'] if user else None
    can_self_validate = (user_role == 'admin' or 
                         user_role in ('moyens_generaux', 'mg') or
                         _hp(user_role, 'mg_valider'))
    
    initial_status = 'validee' if can_self_validate else 'en_attente'
    approved_by = session['user_id'] if can_self_validate else None
    approved_at = datetime.now().isoformat() if can_self_validate else None
    
    # v151 : Récupérer le montant estimé saisi par l'auteur
    try:
        montant_estime_raw = (request.form.get('montant_estime','') or '').replace(',','.').strip()
        montant_estime = float(montant_estime_raw) if montant_estime_raw else 0
    except: montant_estime = 0
    
    # v160 : fournisseur + site associés à la demande
    fourn_raw = request.form.get('fournisseur_id', '') or ''
    fournisseur_id = int(fourn_raw) if fourn_raw.isdigit() else None
    site_name = (request.form.get('site_name', '') or '').strip()

    conn = _gdb()
    cur = conn.execute("""INSERT INTO achats_demandes
        (reference, date, department, requested_by, description, urgency, status, notes,
         approved_by, approved_at, compta_montant_estime, fournisseur_id, site_name, created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,datetime('now'))""",
        (ref,
         request.form.get('date', datetime.now().strftime('%Y-%m-%d')),
         request.form.get('department', ''),
         session['user_id'],
         request.form.get('description', ''),
         request.form.get('urgency', 'normale'),
         initial_status,
         request.form.get('notes', ''),
         approved_by, approved_at, montant_estime, fournisseur_id, site_name))
    did = cur.lastrowid
    
    # v110 : Insérer les items du formulaire (s'il y en a)
    designations = request.form.getlist('item_designation[]')
    quantities = request.form.getlist('item_quantity[]')
    prices = request.form.getlist('item_price[]')
    notes_items = request.form.getlist('item_notes[]')
    nb_items = 0
    for i, des in enumerate(designations):
        des = (des or '').strip()
        if not des: continue
        try: qty = int(quantities[i]) if i < len(quantities) else 1
        except: qty = 1
        try: prix = float(prices[i]) if i < len(prices) and prices[i] else 0
        except: prix = 0
        note = (notes_items[i] if i < len(notes_items) else '').strip()
        try:
            conn.execute("""INSERT INTO achats_demande_items 
                (demande_id, designation, quantity, estimated_price, notes)
                VALUES (?,?,?,?,?)""", (did, des, qty, prix, note))
            nb_items += 1
        except: pass
    
    # v110 : Auto-envoi compta si auto-validé
    if can_self_validate:
        total_items_row = conn.execute("""SELECT COALESCE(SUM(quantity * COALESCE(estimated_price,0)), 0) as total
            FROM achats_demande_items WHERE demande_id=?""", (did,)).fetchone()
        montant_calc = float(total_items_row['total'] or 0) if total_items_row else 0
        
        conn.execute("""UPDATE achats_demandes SET 
            compta_status='a_valider',
            compta_visible_at=datetime('now'),
            compta_montant_estime=?
            WHERE id=?""", 
            (montant_calc if montant_calc > 0 else None, did))
        
        # v130 : Notifier les comptables via notify_user multi-canal
        try:
            users_compta = conn.execute("""SELECT id FROM users 
                WHERE role IN ('comptable','comptabilite','dg','directeur','admin') AND is_active=1""").fetchall()
            target_compta_ids = [u['id'] for u in users_compta]
            # Anti-doublon : vérifier qu'aucune notif similaire récente n'existe
            existing_ids = set()
            for uid in target_compta_ids:
                ex = conn.execute("""SELECT id FROM notifications 
                    WHERE user_id=? AND message LIKE ? AND type='info' AND module='comptabilite'
                    AND date(created_at) = date('now')""",
                    (uid, f"%{ref}%")).fetchone()
                if ex: existing_ids.add(uid)
            conn.commit()
            conn.close()
            for uid in target_compta_ids:
                if uid in existing_ids: continue
                notify_user(uid,
                    title=f"💰 Demande MG à valider",
                    message=f"{ref} — Validation budgétaire requise",
                    link='/comptabilite/demandes-mg',
                    type='info', module='comptabilite', icon='💰', priority='normal')
        except Exception as _e:
            try: conn.close()
            except: pass
            print(f"[v130-MG] notif err : {_e}", flush=True)
    else:
        conn.commit()
        conn.close()
    
    if can_self_validate:
        flash(f"✅ Demande {ref} créée et transmise à la Comptabilité ({nb_items} article{'s' if nb_items > 1 else ''})", "success")
    else:
        flash(f"Demande {ref} créée — En attente de validation MG ({nb_items} article{'s' if nb_items > 1 else ''})", "success")
    return redirect('/mg/demandes')


@app.route('/mg/demandes/<int:did>/valider/<action>')
@permission_required_any('mg_valider', 'admin')
def mg_demandes_valider(did, action):
    """Valider ou refuser une demande. action ∈ {validee, refusee}.
    v103 : protection contre double validation."""
    if action not in ('validee', 'refusee', 'en_attente'):
        flash("Action invalide", "error")
        return redirect('/mg/demandes')
    conn = _gdb()
    row = conn.execute("SELECT reference, status, compta_status, department FROM achats_demandes WHERE id=?", (did,)).fetchone()
    if not row:
        conn.close()
        flash("Demande introuvable", "error")
        return redirect('/mg/demandes')
    ref = row['reference']
    dem_department = row['department'] if 'department' in row.keys() else ''
    
    # v103 : protection — ne pas re-valider si déjà dans cet état
    if row['status'] == action:
        conn.close()
        flash(f"⚠️ Demande {ref} déjà {action}", "warning")
        return redirect('/mg/demandes')
    
    conn.execute("""UPDATE achats_demandes SET status=?, approved_by=?, approved_at=?
                    WHERE id=? AND status != ?""",
                 (action, session['user_id'], datetime.now().isoformat(), did, action))
    
    # v102 : auto-envoi à la Comptabilité (uniquement si pas déjà envoyé)
    if action == 'validee' and not row['compta_status']:
        total_items_row = conn.execute("""SELECT COALESCE(SUM(quantity * COALESCE(estimated_price,0)), 0) as total
            FROM achats_demande_items WHERE demande_id=?""", (did,)).fetchone()
        montant_calc = float(total_items_row['total'] or 0) if total_items_row else 0
        
        conn.execute("""UPDATE achats_demandes SET 
            compta_status='a_valider',
            compta_visible_at=datetime('now'),
            compta_montant_estime=COALESCE(compta_montant_estime, ?)
            WHERE id=? AND (compta_visible_at IS NULL OR compta_status='en_attente')""", 
            (montant_calc if montant_calc > 0 else None, did))
        
        # Notifier les comptables (sans doublons : un user reçoit max 1 notif par demande)
        try:
            users_compta = conn.execute("""SELECT id FROM users 
                WHERE role IN ('comptable','comptabilite','dg','directeur','admin') AND is_active=1""").fetchall()
            for u in users_compta:
                # Anti-doublon : vérifier si une notif existe déjà
                existing = conn.execute("""SELECT id FROM notifications 
                    WHERE user_id=? AND message LIKE ? AND type='mg_demande'""",
                    (u['id'], f"%{ref}%")).fetchone()
                if existing: continue
                try:
                    conn.execute("""INSERT INTO notifications (user_id, type, title, message, link) 
                        VALUES (?,?,?,?,?)""",
                        (u['id'], 'mg_demande', f"💰 Demande MG à valider",
                         f"{ref} — Validation budgétaire requise",
                         '/comptabilite/demandes-mg'))
                except: pass
        except: pass
    
    conn.commit()
    conn.close()
    # v160 : notifier le département concerné par la demande (ou tous si "Tous")
    try:
        _lbl = 'validée' if action == 'validee' else ('refusée' if action == 'refusee' else action)
        notify_department(dem_department,
            f"📋 Demande interne {ref} {_lbl}",
            f"La demande interne {ref} a été {_lbl}.",
            link=f'/mg/demandes/{did}/preview', type='mg_demande', module='moyens_generaux', icon='📋')
    except Exception as _e: print(f"[v160-NotifDept] {_e}", flush=True)
    if action == 'validee':
        flash(f"✅ Demande {ref} validée et transmise à la Comptabilité", "success")
    else:
        flash(f"Demande {ref} {action}", "success")
    return redirect('/mg/demandes')


