        buf = io.BytesIO()
        doc = SimpleDocTemplate(buf, pagesize=landscape(A4), leftMargin=10*mm, rightMargin=10*mm,
                                topMargin=8*mm, bottomMargin=8*mm)
        story = []
        TEAL = HexColor('#1A7A6D')
        
