# ════════════════════════════════════════════════════════════════════
# v159 : RAPPORTS DE CALCUL D'HEURES À FACTURER (RH → Facturation à décider)
#   La RH envoie un rapport d'heures avec le montant à facturer.
#   → crée une "remontée" type 'rapport_heures' en statut 'executee' (montant pré-saisi)
#   → apparaît dans /decisions/facturation où le DG valide SANS ressaisir le montant
#   → comptable édite la facture, puis recouvrement (pipeline existant).
# ════════════════════════════════════════════════════════════════════
def _get_rapport_montant(client_name, type_label):
    """v159 : Montant mémorisé pour ce client + type (pré-remplissage), ou 0."""
    try:
        conn = _gdb()
        r = conn.execute("SELECT montant FROM rapport_heures_montants WHERE client_name=? AND type_label=?",
                         (client_name, type_label)).fetchone()
        conn.close()
        return float(r['montant']) if r and r['montant'] is not None else 0
    except Exception:
        return 0


def _remember_rapport_montant(client_name, type_label, montant):
    """v159 : Mémorise le dernier montant saisi pour ce client + type (upsert manuel)."""
    if not client_name or montant <= 0:
        return
    try:
        conn = _gdb()
        ex = conn.execute("SELECT id FROM rapport_heures_montants WHERE client_name=? AND type_label=?",
                          (client_name, type_label)).fetchone()
        if ex:
            conn.execute("UPDATE rapport_heures_montants SET montant=?, updated_at=datetime('now') WHERE id=?",
                         (montant, ex['id']))
        else:
            conn.execute("INSERT INTO rapport_heures_montants (client_name, type_label, montant, updated_at) VALUES (?,?,?,datetime('now'))",
                         (client_name, type_label, montant))
        conn.commit(); conn.close()
    except Exception as _e:
        print(f"[v159-RH] memoire montant err : {_e}", flush=True)


def _creer_rapport_heures_facturation(user, client_name, client_id, type_label, periode, montant, notes=''):
    """v159 : Crée un rapport d'heures facturable (statut executee, montant pré-saisi),
    le place en « Facturation à décider », mémorise le montant et notifie le DG.
    Retourne la référence ou None."""
    if not client_name or not montant or montant <= 0:
        return None
    ref = _gen_field_report_ref()
    description = f"Rapport de calcul d'heures — {type_label}" + (f" — {periode}" if periode else "")
    if notes:
        description += f"\n{notes}"
    conn = _gdb()
    try:
        cur = conn.execute("""INSERT INTO field_reports
            (reference, client_id, client_name, type_info, description, priorite, date_constat,
             auteur_id, auteur_name, statut, cost_amount, cost_currency,
             executed_by, executed_at, execution_notes, created_at, updated_at)
            VALUES (?,?,?, 'rapport_heures', ?, 'moyen', date('now'),
             ?,?, 'executee', ?, 'XOF', ?, datetime('now'), ?, datetime('now'), datetime('now'))""",
            (ref, client_id, client_name, description,
             user['id'], user['full_name'], montant,
             user['id'], f"Montant à facturer saisi par la RH ({user['full_name']})"))
        rid = cur.lastrowid
        conn.commit(); conn.close()
    except Exception as e:
        try: conn.close()
        except Exception: pass
        print(f"[v159-RH] creation facturation err : {e}", flush=True)
        return None
    try: _field_report_log(rid, 'Rapport heures envoyé', f"Montant à facturer : {int(montant)} XOF — {type_label}")
    except Exception: pass
    _remember_rapport_montant(client_name, type_label, montant)
    try:
        notify_roles(['dg', 'directeur', 'rh', 'directrice_rh', 'admin'],
            title=f"💰 VALIDATION FACTURATION — Rapport d'heures {ref}",
            message=f"Rapport d'heures à facturer pour {client_name} : {int(montant)} XOF. "
                    f"À valider dans « Facturation à décider » (le montant est déjà saisi).",
            link='/decisions/facturation',
            type='warning', module='factures', icon='💰', priority='high', force=True)
    except Exception: pass
    return ref


@app.route('/rapports-heures/montant')
@permission_required_any('traitement', 'admin')
def rapports_heures_montant():
    """v159 : Renvoie le montant mémorisé pour un client + type (pré-remplissage JS)."""
    client = (request.args.get('client','') or '').strip()
    type_label = (request.args.get('type','') or '').strip()
    return jsonify({'montant': _get_rapport_montant(client, type_label)})


@app.route('/rapports-heures')
@permission_required_any('traitement', 'admin')
def rapports_heures_list():
    conn = _gdb()
    rows = [dict(r) for r in conn.execute("""
        SELECT fr.*, fri.status AS fri_status, fri.invoice_number
        FROM field_reports fr
        LEFT JOIN field_report_invoices fri ON fri.field_report_id = fr.id
        WHERE fr.type_info='rapport_heures'
        ORDER BY fr.id DESC LIMIT 200""").fetchall()]
    clients = [dict(r) for r in conn.execute("SELECT id, name FROM clients ORDER BY name").fetchall()]
    conn.close()

    # v159 : regrouper par mois (en attente + envoyés ensemble), ordre décroissant
    _MOIS_FR = ['', 'Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin', 'Juillet',
                'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre']
    from collections import OrderedDict as _OD
    _groups = _OD()
    for r in rows:
        ym = (r.get('created_at') or '')[:7]
        _groups.setdefault(ym, []).append(r)
    groupes = []
    for ym, lst in _groups.items():
        try:
            y, m = ym.split('-'); label = f"{_MOIS_FR[int(m)]} {y}"
        except Exception:
            label = ym or 'Sans date'
        en_attente = [x for x in lst if x.get('facturable') is None]
        traites = [x for x in lst if x.get('facturable') is not None]
        groupes.append({'mois': label, 'rapports': lst,
                        'nb_attente': len(en_attente), 'nb_traites': len(traites)})

    return render_template('rapports_heures.html', page='rapports_heures',
        rapports=rows, groupes=groupes, clients=clients,
        recovery_status=FACTURATION_RECOVERY_STATUS)


@app.route('/rapports-heures/envoyer', methods=['POST'])
@permission_required_any('traitement', 'admin')
def rapports_heures_envoyer():
    user = get_user_by_id(session['user_id'])
    client_name = (request.form.get('client_name','') or '').strip()
    client_id = request.form.get('client_id') or None
    periode = (request.form.get('periode','') or '').strip()
    type_label = (request.form.get('type_label','') or 'Calcul d\'heures').strip()
    notes = (request.form.get('notes','') or '').strip()
    montant_str = (request.form.get('montant','') or '0').replace(',', '.').strip()
    try:
        montant = float(montant_str or 0)
    except ValueError:
        montant = 0
    if not client_name:
        flash("Le client est obligatoire.", "error")
        return redirect('/rapports-heures')
    # v162 : la RH ne saisit le montant qu'UNE seule fois par client + type.
    # Les mois suivants, on réutilise automatiquement le montant mémorisé.
    if montant <= 0:
        montant = _get_rapport_montant(client_name, type_label)
    if montant <= 0:
        flash("Aucun montant mémorisé pour ce client : saisissez le montant à facturer (1ère fois seulement).", "error")
        return redirect('/rapports-heures')

    if client_id:
        try: client_id = int(client_id)
        except ValueError: client_id = None

    ref = _gen_field_report_ref()
    description = f"Rapport de calcul d'heures — {type_label}" + (f" — {periode}" if periode else "")
    if notes:
        description += f"\n{notes}"
    conn = _gdb()
    try:
        cur = conn.execute("""INSERT INTO field_reports
            (reference, client_id, client_name, type_info, description, priorite, date_constat,
             auteur_id, auteur_name, statut, cost_amount, cost_currency,
             executed_by, executed_at, execution_notes, created_at, updated_at)
            VALUES (?,?,?, 'rapport_heures', ?, 'moyen', date('now'),
             ?,?, 'executee', ?, 'XOF', ?, datetime('now'), ?, datetime('now'), datetime('now'))""",
            (ref, client_id, client_name, description,
             user['id'], user['full_name'], montant,
             user['id'], f"Montant à facturer saisi par la RH ({user['full_name']})"))
        rid = cur.lastrowid
        conn.commit()
        conn.close()
    except Exception as e:
        try: conn.close()
        except Exception: pass
        flash(f"Erreur : {e}", "error")
        return redirect('/rapports-heures')

    try: _field_report_log(rid, 'Rapport heures envoyé', f"Montant à facturer : {int(montant)} XOF — {type_label}")
    except Exception: pass
    # v159 : mémoriser le montant pour ce client + type (pré-remplissage des prochains envois)
    _remember_rapport_montant(client_name, type_label, montant)
    # Notifier DG/RH pour validation (sans montant à saisir)
    try:
        notify_roles(['dg', 'directeur', 'rh', 'directrice_rh', 'admin'],
            title=f"💰 VALIDATION FACTURATION — Rapport d'heures {ref}",
            message=f"La RH a envoyé un rapport d'heures à facturer pour {client_name} : "
                    f"{int(montant)} XOF. À valider dans « Facturation à décider » (le montant est déjà saisi).",
            link='/decisions/facturation',
            type='warning', module='factures', icon='💰', priority='high', force=True)
    except Exception: pass
    flash(f"✅ Rapport d'heures {ref} envoyé en « Facturation à décider » ({int(montant)} XOF). Le DG n'a plus qu'à valider.", "success")
    return redirect('/rapports-heures')
